CREATE OR REPLACE FUNCTION "public"."activate_bundle_subscription"("p_user_id" "uuid", "p_whop_membership_id" "text", "p_whop_user_id" "text", "p_plan_id" "text", "p_billing_interval" "text", "p_is_trial" boolean DEFAULT false, "p_trial_ends_at" "text" DEFAULT NULL::"text", "p_renewal_period_end" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_email TEXT;
  v_expires_at TIMESTAMPTZ;
  v_trial_ends TIMESTAMPTZ;
  v_status TEXT;
  v_had_newsletter BOOLEAN;
  v_had_top_secret BOOLEAN;
  v_newsletter_membership TEXT;
  v_top_secret_membership TEXT;
BEGIN
  -- Get user info and check existing subscriptions
  SELECT 
    email,
    COALESCE(newsletter_enabled, FALSE),
    COALESCE(top_secret_enabled, FALSE),
    newsletter_whop_membership_id,
    top_secret_whop_membership_id
  INTO v_user_email, v_had_newsletter, v_had_top_secret, v_newsletter_membership, v_top_secret_membership
  FROM profiles WHERE id = p_user_id;
  
  IF v_user_email IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found: ' || p_user_id::TEXT);
  END IF;
  
  -- Calculate dates (handle empty strings)
  IF p_is_trial AND p_trial_ends_at IS NOT NULL AND p_trial_ends_at != '' THEN
    v_trial_ends := p_trial_ends_at::TIMESTAMPTZ;
    v_expires_at := v_trial_ends;
    v_status := 'trial';
  ELSIF p_renewal_period_end IS NOT NULL AND p_renewal_period_end != '' THEN
    v_expires_at := p_renewal_period_end::TIMESTAMPTZ;
    v_status := 'active';
  ELSE
    v_expires_at := CASE WHEN p_billing_interval = 'yearly' THEN NOW() + INTERVAL '1 year' ELSE NOW() + INTERVAL '1 month' END;
    v_status := CASE WHEN p_is_trial THEN 'trial' ELSE 'active' END;
  END IF;
  
  -- Update ALL fields - Bundle + Newsletter + Top Secret
  UPDATE profiles SET
    -- Bundle fields
    bundle_enabled = TRUE,
    bundle_status = v_status,
    bundle_interval = p_billing_interval,
    bundle_whop_membership_id = p_whop_membership_id,
    bundle_whop_user_id = p_whop_user_id,
    bundle_started_at = NOW(),
    bundle_expires_at = v_expires_at,
    bundle_is_in_trial = p_is_trial,
    bundle_trial_ends_at = v_trial_ends,
    bundle_cancel_at_period_end = FALSE,
    
    -- Track paused subscriptions
    newsletter_paused_for_bundle = CASE WHEN v_had_newsletter AND v_newsletter_membership IS NOT NULL THEN TRUE ELSE FALSE END,
    top_secret_paused_for_bundle = CASE WHEN v_had_top_secret AND v_top_secret_membership IS NOT NULL THEN TRUE ELSE FALSE END,
    
    -- 🔥 Enable Newsletter access via Bundle
    newsletter_enabled = TRUE,
    newsletter_status = v_status,
    newsletter_expires_at = v_expires_at,
    newsletter_started_at = COALESCE(newsletter_started_at, NOW()),
    
    -- 🔥 Enable Top Secret access via Bundle
    top_secret_enabled = TRUE,
    top_secret_status = v_status,
    top_secret_expires_at = v_expires_at,
    top_secret_started_at = COALESCE(top_secret_started_at, NOW()),
    top_secret_interval = p_billing_interval,
    
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- Log event
  INSERT INTO subscription_events (user_id, event_type, old_plan, new_plan, metadata)
  VALUES (p_user_id, 'bundle_activated', 'none', 'bundle',
    jsonb_build_object(
      'whop_membership_id', p_whop_membership_id,
      'billing_interval', p_billing_interval,
      'is_trial', p_is_trial,
      'expires_at', v_expires_at,
      'newsletter_enabled', true,
      'top_secret_enabled', true,
      'newsletter_paused', v_had_newsletter AND v_newsletter_membership IS NOT NULL,
      'top_secret_paused', v_had_top_secret AND v_top_secret_membership IS NOT NULL
    ));
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', p_user_id,
    'email', v_user_email,
    'bundle_status', v_status,
    'billing_interval', p_billing_interval,
    'is_trial', p_is_trial,
    'expires_at', v_expires_at,
    'newsletter_enabled', true,
    'top_secret_enabled', true
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'sqlstate', SQLSTATE);
END;
$$;


ALTER FUNCTION "public"."activate_bundle_subscription"("p_user_id" "uuid", "p_whop_membership_id" "text", "p_whop_user_id" "text", "p_plan_id" "text", "p_billing_interval" "text", "p_is_trial" boolean, "p_trial_ends_at" "text", "p_renewal_period_end" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."activate_newsletter_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_finotaur_user_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_is_first_time BOOLEAN;
  v_is_new_user BOOLEAN := FALSE;
  v_trial_days INTEGER;
  v_trial_ends_at TIMESTAMPTZ;
  v_expires_at TIMESTAMPTZ;
  v_status TEXT;
  v_new_user_id UUID;
  v_display_name TEXT;
  v_affiliate_code TEXT;
BEGIN
  -- ========================================
  -- STEP 1: Find User (multiple lookup methods)
  -- ========================================
  
  -- Try finotaur_user_id first (internal signup)
  IF p_finotaur_user_id IS NOT NULL AND p_finotaur_user_id != '' THEN
    BEGIN
      SELECT id INTO v_user_id 
      FROM profiles 
      WHERE id = p_finotaur_user_id::UUID;
      
      IF v_user_id IS NOT NULL THEN
        RAISE NOTICE '✅ Found user by finotaur_user_id: %', v_user_id;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      RAISE NOTICE '⚠️ Invalid finotaur_user_id format: %', p_finotaur_user_id;
    END;
  END IF;
  
  -- Try email (fallback)
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    SELECT id INTO v_user_id 
    FROM profiles 
    WHERE LOWER(email) = LOWER(p_user_email);
    
    IF v_user_id IS NOT NULL THEN
      RAISE NOTICE '✅ Found user by email: %', v_user_id;
    END IF;
  END IF;
  
  -- Try membership_id (for recurring events)
  IF v_user_id IS NULL AND p_whop_membership_id IS NOT NULL THEN
    SELECT id INTO v_user_id 
    FROM profiles 
    WHERE newsletter_whop_membership_id = p_whop_membership_id;
    
    IF v_user_id IS NOT NULL THEN
      RAISE NOTICE '✅ Found user by membership_id: %', v_user_id;
    END IF;
  END IF;
  
  -- ========================================
  -- STEP 2: Create New User if Not Found
  -- ========================================
  IF v_user_id IS NULL THEN
    IF p_user_email IS NULL OR p_user_email = '' THEN
      RETURN jsonb_build_object(
        'success', false,
        'error', 'No email provided and user not found',
        'lookup_attempted', jsonb_build_object(
          'finotaur_user_id', p_finotaur_user_id,
          'email', p_user_email,
          'membership_id', p_whop_membership_id
        )
      );
    END IF;
    
    v_new_user_id := gen_random_uuid();
    v_display_name := SPLIT_PART(p_user_email, '@', 1);
    v_affiliate_code := UPPER(LEFT(v_display_name, 3)) || LPAD(FLOOR(RANDOM() * 10000)::TEXT, 4, '0');
    
    WHILE EXISTS (SELECT 1 FROM profiles WHERE affiliate_code = v_affiliate_code) LOOP
      v_affiliate_code := UPPER(LEFT(v_display_name, 3)) || LPAD(FLOOR(RANDOM() * 10000)::TEXT, 4, '0');
    END LOOP;
    
    INSERT INTO profiles (
      id, email, display_name, affiliate_code,
      account_type, subscription_status, max_trades,
      role, is_banned, onboarding_completed,
      newsletter_unsubscribe_token,
      created_at, updated_at
    ) VALUES (
      v_new_user_id, LOWER(p_user_email), v_display_name, v_affiliate_code,
      'free', NULL, 10,
      'user', FALSE, FALSE,
      encode(gen_random_bytes(32), 'hex'),
      NOW(), NOW()
    );
    
    v_user_id := v_new_user_id;
    v_is_new_user := TRUE;
    RAISE NOTICE '🆕 Created new user: % with email: %', v_user_id, p_user_email;
  END IF;
  
  -- ========================================
  -- STEP 3: Check if First Time Subscriber
  -- ========================================
  SELECT 
    newsletter_started_at IS NULL OR newsletter_status = 'inactive' OR newsletter_status IS NULL
  INTO v_is_first_time
  FROM profiles 
  WHERE id = v_user_id;
  
  v_is_first_time := COALESCE(v_is_first_time, TRUE);
  

v_trial_days := get_product_trial_days(p_whop_product_id);

IF v_trial_days > 0 AND v_is_first_time THEN
  v_trial_ends_at := NOW() + (v_trial_days || ' days')::INTERVAL;
  v_status := 'trial';
  v_expires_at := v_trial_ends_at;
ELSE
  v_trial_ends_at := NULL;
  v_status := 'active';
  v_expires_at := NOW() + INTERVAL '1 month';
END IF;
  -- ========================================
  -- STEP 5: Update Newsletter Fields ONLY
  -- ========================================
  UPDATE profiles SET
    newsletter_enabled = TRUE,
    newsletter_whop_membership_id = p_whop_membership_id,
    newsletter_started_at = COALESCE(newsletter_started_at, NOW()),
    newsletter_expires_at = v_expires_at,
    newsletter_trial_ends_at = CASE 
      WHEN v_is_first_time THEN v_trial_ends_at 
      ELSE newsletter_trial_ends_at 
    END,
    newsletter_cancel_at_period_end = FALSE,
    newsletter_status = v_status,
    updated_at = NOW()
  WHERE id = v_user_id;
  
  -- ========================================
  -- STEP 6: Log Event
  -- ========================================
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    v_user_id,
    CASE 
      WHEN v_is_new_user THEN 'newsletter_signup_new_user'
      WHEN v_is_first_time THEN 'trial_started'
      ELSE 'payment_succeeded'
    END,
    'none', 'newsletter',
    jsonb_build_object(
      'whop_membership_id', p_whop_membership_id,
      'whop_product_id', p_whop_product_id,
      'whop_user_id', p_whop_user_id,
      'is_new_user', v_is_new_user,
      'is_first_time', v_is_first_time,
      'trial_ends_at', v_trial_ends_at,
      'subscription_type', 'newsletter'
    )
  );
  
  -- ========================================
  -- STEP 7: Return Result
  -- ========================================
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'email', p_user_email,
    'newsletter_status', v_status,
    'is_new_user', v_is_new_user,
    'is_new_trial', v_is_first_time,
    'trial_ends_at', v_trial_ends_at,
    'expires_at', v_expires_at
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'sqlstate', SQLSTATE,
    'email', p_user_email,
    'finotaur_user_id', p_finotaur_user_id
  );
END;
$$;


ALTER FUNCTION "public"."activate_newsletter_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_finotaur_user_id" "text") OWNER TO "postgres";


