ALTER FUNCTION "public"."activate_newsletter_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_finotaur_user_id" "text", "p_billing_interval" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."activate_platform_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_whop_plan_id" "text" DEFAULT NULL::"text", "p_finotaur_user_id" "text" DEFAULT NULL::"text", "p_affiliate_code" "text" DEFAULT NULL::"text", "p_newsletter_choice" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_plan_info RECORD;
  v_trial_end TIMESTAMPTZ;
  v_subscription_end TIMESTAMPTZ;
  v_is_trial BOOLEAN := FALSE;
  v_can_use_trial BOOLEAN := FALSE;
  v_old_plan TEXT;
BEGIN
  -- Find user
  IF p_finotaur_user_id IS NOT NULL AND p_finotaur_user_id != '' THEN
    BEGIN
      SELECT id INTO v_user_id FROM profiles WHERE id = p_finotaur_user_id::UUID;
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END IF;
  
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    SELECT id INTO v_user_id FROM profiles WHERE LOWER(email) = LOWER(p_user_email);
  END IF;
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  SELECT platform_plan INTO v_old_plan FROM profiles WHERE id = v_user_id;
  
  -- Get plan info
  SELECT * INTO v_plan_info 
  FROM platform_plan_mapping 
  WHERE whop_product_id = p_whop_product_id AND is_active = TRUE;
  
  IF v_plan_info IS NULL THEN
    SELECT * INTO v_plan_info 
    FROM platform_plan_mapping 
    WHERE whop_plan_id = p_whop_plan_id AND is_active = TRUE;
  END IF;
  
  IF v_plan_info IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Unknown platform product');
  END IF;
  
  -- Check trial eligibility
  IF v_plan_info.trial_days > 0 THEN
    IF v_plan_info.trial_once_only THEN
      IF v_plan_info.finotaur_plan = 'pro' THEN
        SELECT (platform_pro_trial_used_at IS NULL) INTO v_can_use_trial FROM profiles WHERE id = v_user_id;
      ELSIF v_plan_info.finotaur_plan = 'core' THEN
        SELECT (platform_core_trial_used_at IS NULL) INTO v_can_use_trial FROM profiles WHERE id = v_user_id;
      ELSE
        v_can_use_trial := TRUE;
      END IF;
    ELSE
      v_can_use_trial := TRUE;
    END IF;
    v_is_trial := v_can_use_trial;
  END IF;
  
  -- Calculate dates
  IF v_is_trial THEN
    v_trial_end := NOW() + (v_plan_info.trial_days || ' days')::INTERVAL;
    v_subscription_end := v_trial_end;
  ELSE
    v_subscription_end := CASE 
      WHEN v_plan_info.billing_interval = 'monthly' THEN NOW() + INTERVAL '1 month'
      ELSE NOW() + INTERVAL '1 year'
    END;
  END IF;
  
  -- Update profile
  UPDATE profiles SET
    platform_plan = v_plan_info.finotaur_plan,
    platform_subscription_status = CASE WHEN v_is_trial THEN 'trial' ELSE 'active' END,
    platform_billing_interval = v_plan_info.billing_interval,
    platform_subscription_started_at = NOW(),
    platform_subscription_expires_at = v_subscription_end,
    platform_cancelled_at = NULL,
    platform_cancel_at_period_end = FALSE,
    platform_trial_ends_at = CASE WHEN v_is_trial THEN v_trial_end ELSE NULL END,
    platform_is_in_trial = v_is_trial,
    platform_pro_trial_used_at = CASE 
      WHEN v_is_trial AND v_plan_info.finotaur_plan = 'pro' THEN NOW() 
      ELSE platform_pro_trial_used_at 
    END,
    platform_core_trial_used_at = CASE 
      WHEN v_is_trial AND v_plan_info.finotaur_plan = 'core' THEN NOW() 
      ELSE platform_core_trial_used_at 
    END,
    platform_whop_user_id = p_whop_user_id,
    platform_whop_membership_id = p_whop_membership_id,
    platform_whop_product_id = p_whop_product_id,
    platform_whop_plan_id = p_whop_plan_id,
    platform_whop_customer_email = p_user_email,
    platform_payment_provider = 'whop',
    platform_bundle_newsletter_choice = p_newsletter_choice,
    updated_at = NOW()
  WHERE id = v_user_id;
  
  -- Apply bundle
  PERFORM apply_platform_bundle(v_user_id, v_plan_info.finotaur_plan, p_newsletter_choice);
  
  -- Log event
  INSERT INTO platform_subscription_events (user_id, event_type, old_plan, new_plan, metadata)
  VALUES (v_user_id, CASE WHEN v_is_trial THEN 'trial_started' ELSE 'activated' END,
    COALESCE(v_old_plan, 'free'), v_plan_info.finotaur_plan,
    jsonb_build_object('whop_membership_id', p_whop_membership_id, 'is_trial', v_is_trial));
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'plan', v_plan_info.finotaur_plan,
    'is_trial', v_is_trial,
    'expires_at', v_subscription_end
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."activate_platform_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_whop_plan_id" "text", "p_finotaur_user_id" "text", "p_affiliate_code" "text", "p_newsletter_choice" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."activate_top_secret_from_checkout"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_current_status TEXT;
  v_expires_at TIMESTAMPTZ;
BEGIN
  -- Check current status
  SELECT top_secret_status, top_secret_expires_at
  INTO v_current_status, v_expires_at
  FROM profiles 
  WHERE id = p_user_id;
  
  -- If already active, just return success
  IF v_current_status = 'active' THEN
    RETURN jsonb_build_object(
      'success', true,
      'already_active', true,
      'expires_at', v_expires_at
    );
  END IF;
  
  -- Activate with default monthly interval
  -- (webhook will update with correct interval when it arrives)
  v_expires_at := NOW() + INTERVAL '1 month';
  
  UPDATE profiles SET
    top_secret_enabled = TRUE,
    top_secret_status = 'active',
    top_secret_started_at = COALESCE(top_secret_started_at, NOW()),
    top_secret_expires_at = v_expires_at,
    top_secret_interval = COALESCE(top_secret_interval, 'monthly'),
    top_secret_cancel_at_period_end = FALSE,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- Log event
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    p_user_id,
    'checkout_return_activation',
    COALESCE(v_current_status, 'none'),
    'top_secret',
    jsonb_build_object(
      'activation_method', 'frontend_checkout_return',
      'note', 'Webhook will update with payment details'
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'already_active', false,
    'expires_at', v_expires_at,
    'status', 'active'
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."activate_top_secret_from_checkout"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."activate_top_secret_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_whop_plan_id" "text", "p_finotaur_user_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_interval TEXT;
  v_price NUMERIC;
  v_expires_at TIMESTAMPTZ;
  v_is_new_user BOOLEAN := FALSE;
  v_new_user_id UUID;
  v_display_name TEXT;
  v_affiliate_code TEXT;
BEGIN
  -- ========================================
  -- STEP 1: Determine interval from plan_id
  -- ========================================
  
  IF p_whop_plan_id = 'plan_YoeD6wWBxss7Q' THEN
    v_interval := 'yearly';
    v_price := 300.00;
    v_expires_at := NOW() + INTERVAL '1 year';
  ELSE
    v_interval := 'monthly';
    v_price := 35.00;
    v_expires_at := NOW() + INTERVAL '1 month';
  END IF;

  -- ========================================
  -- STEP 2: Find User (multiple lookup methods)
  -- ========================================
  
  -- Try finotaur_user_id first
  IF p_finotaur_user_id IS NOT NULL AND p_finotaur_user_id != '' THEN
    BEGIN
      SELECT id INTO v_user_id 
      FROM profiles 
      WHERE id = p_finotaur_user_id::UUID;
    EXCEPTION WHEN OTHERS THEN
      NULL;
    END;
  END IF;
  
  -- Try email
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    SELECT id INTO v_user_id 
    FROM profiles 
    WHERE LOWER(email) = LOWER(p_user_email);
  END IF;
  
  -- Try membership_id (for recurring)
  IF v_user_id IS NULL AND p_whop_membership_id IS NOT NULL THEN
    SELECT id INTO v_user_id 
    FROM profiles 
    WHERE top_secret_whop_membership_id = p_whop_membership_id;
  END IF;
  
  -- ========================================
  -- STEP 3: Create New User if Not Found
  -- ========================================
  
  IF v_user_id IS NULL THEN
    IF p_user_email IS NULL OR p_user_email = '' THEN
      RETURN jsonb_build_object(
        'success', false,
        'error', 'No email provided and user not found'
      );
    END IF;
    
    v_new_user_id := gen_random_uuid();
    v_display_name := SPLIT_PART(p_user_email, '@', 1);
    v_affiliate_code := UPPER(LEFT(v_display_name, 3)) || LPAD(FLOOR(RANDOM() * 10000)::TEXT, 4, '0');
    
    WHILE EXISTS (SELECT 1 FROM profiles WHERE affiliate_code = v_affiliate_code) LOOP
      v_affiliate_code := UPPER(LEFT(v_display_name, 3)) || LPAD(FLOOR(RANDOM() * 10000)::TEXT, 4, '0');
    END LOOP;
    
    INSERT INTO profiles (
      id, email, display_name, affiliate_code,
      account_type, subscription_status, max_trades,
      role, is_banned, onboarding_completed,
      newsletter_unsubscribe_token,
      created_at, updated_at
    ) VALUES (
      v_new_user_id, LOWER(p_user_email), v_display_name, v_affiliate_code,
      'free', NULL, 10,
      'user', FALSE, FALSE,
      encode(gen_random_bytes(32), 'hex'),
      NOW(), NOW()
    );
    
    v_user_id := v_new_user_id;
    v_is_new_user := TRUE;
    RAISE NOTICE '🆕 Created new user: % with email: %', v_user_id, p_user_email;
  END IF;
  
  -- ========================================
  -- STEP 4: Update Top Secret Fields ONLY
  -- (Does NOT touch newsletter or journal subscription)
  -- ========================================
  
  UPDATE profiles SET
    top_secret_enabled = TRUE,
    top_secret_whop_membership_id = p_whop_membership_id,
    top_secret_started_at = COALESCE(top_secret_started_at, NOW()),
    top_secret_expires_at = v_expires_at,
    top_secret_interval = v_interval,
    top_secret_cancel_at_period_end = FALSE,
    top_secret_status = 'active',
    top_secret_unsubscribed_at = NULL,
    updated_at = NOW()
  WHERE id = v_user_id;
  
  -- ========================================
  -- STEP 5: Log Event
  -- ========================================
  
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    v_user_id,
    'payment_succeeded',
    'none',
    'top_secret',
    jsonb_build_object(
      'whop_membership_id', p_whop_membership_id,
      'whop_product_id', p_whop_product_id,
      'whop_plan_id', p_whop_plan_id,
      'whop_user_id', p_whop_user_id,
      'interval', v_interval,
      'price_usd', v_price,
      'is_new_user', v_is_new_user,
      'subscription_type', 'top_secret'
    )
  );
  
  -- ========================================
  -- STEP 6: Return Result
  -- ========================================
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'email', p_user_email,
    'interval', v_interval,
    'price_usd', v_price,
    'expires_at', v_expires_at,
    'top_secret_status', 'active',
    'is_new_user', v_is_new_user
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'sqlstate', SQLSTATE,
    'email', p_user_email,
    'finotaur_user_id', p_finotaur_user_id
  );
END;
$$;


ALTER FUNCTION "public"."activate_top_secret_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_whop_plan_id" "text", "p_finotaur_user_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."activate_whop_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_finotaur_user_id" "text" DEFAULT NULL::"text", "p_affiliate_code" "text" DEFAULT NULL::"text", "p_click_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_plan_info RECORD;
  v_subscription_ends_at TIMESTAMPTZ;
  v_max_trades INTEGER;
  v_affiliate_id UUID;
  v_referral_id UUID;
  v_retry_count INTEGER := 0;
  v_lookup_method TEXT := 'none';
  v_old_plan TEXT;
BEGIN
  -- ========================================
  -- STEP 1: Find User (MULTIPLE METHODS)
  -- Priority: finotaur_user_id → email → whop_customer_email → membership_id → retry
  -- ========================================
  
  -- Method 1: Try finotaur_user_id from metadata (BEST - user logged in during checkout)
  IF p_finotaur_user_id IS NOT NULL AND p_finotaur_user_id != '' THEN
    BEGIN
      SELECT id INTO v_user_id 
      FROM profiles 
      WHERE id = p_finotaur_user_id::UUID;
      
      IF v_user_id IS NOT NULL THEN
        v_lookup_method := 'finotaur_user_id';
        RAISE NOTICE '✅ Found user by finotaur_user_id: %', v_user_id;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      RAISE NOTICE '⚠️ Invalid finotaur_user_id format: %', p_finotaur_user_id;
    END;
  END IF;
  
  -- Method 2: Try exact email match (user registered with same email)
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    SELECT id INTO v_user_id 
    FROM profiles 
    WHERE LOWER(email) = LOWER(p_user_email);
    
    IF v_user_id IS NOT NULL THEN
      v_lookup_method := 'email_exact';
      RAISE NOTICE '✅ Found user by email: %', v_user_id;
    END IF;
  END IF;
  
  -- Method 3: Try whop_customer_email (returning customer with different Whop email)
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    SELECT id INTO v_user_id 
    FROM profiles 
    WHERE LOWER(whop_customer_email) = LOWER(p_user_email);
    
    IF v_user_id IS NOT NULL THEN
      v_lookup_method := 'whop_customer_email';
      RAISE NOTICE '✅ Found user by whop_customer_email: %', v_user_id;
    END IF;
  END IF;
  
  -- Method 4: Try membership_id (renewal/reactivation of existing subscription)
  IF v_user_id IS NULL AND p_whop_membership_id IS NOT NULL THEN
    SELECT id INTO v_user_id 
    FROM profiles 
    WHERE whop_membership_id = p_whop_membership_id;
    
    IF v_user_id IS NOT NULL THEN
      v_lookup_method := 'whop_membership_id';
      RAISE NOTICE '✅ Found user by membership_id: %', v_user_id;
    END IF;
  END IF;
  
  -- Method 5: Retry with delay (race condition - user might be registering right now)
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    LOOP
      EXIT WHEN v_retry_count >= 3;  -- Max 3 retries = 6 seconds total
      
      v_retry_count := v_retry_count + 1;
      RAISE NOTICE '⏳ User not found, retry % of 3 in 2 seconds...', v_retry_count;
      PERFORM pg_sleep(2);
      
      -- Try all methods again after delay
      SELECT id INTO v_user_id 
      FROM profiles 
      WHERE LOWER(email) = LOWER(p_user_email)
         OR LOWER(whop_customer_email) = LOWER(p_user_email);
      
      EXIT WHEN v_user_id IS NOT NULL;
    END LOOP;
    
    IF v_user_id IS NOT NULL THEN
      v_lookup_method := 'email_retry_' || v_retry_count;
      RAISE NOTICE '✅ Found user after % retries: %', v_retry_count, v_user_id;
    END IF;
  END IF;
  
  -- ========================================
  -- STEP 2: User NOT found = Return Error
  -- (Cannot auto-create due to FK constraint to auth.users)
  -- ========================================
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object(
      'success', false, 
      'error', 'User not found. User must register on Finotaur before purchasing.',
      'error_code', 'USER_NOT_FOUND',
      'lookup_attempted', jsonb_build_object(
        'finotaur_user_id', p_finotaur_user_id,
        'email', p_user_email,
        'membership_id', p_whop_membership_id
      ),
      'retries', v_retry_count,
      'suggestion', 'Ensure checkout URL includes finotaur_user_id in metadata, or user registers with same email before purchase'
    );
  END IF;
  
  -- ========================================
  -- STEP 3: Get Plan Info from Mapping
  -- ========================================
  
  SELECT * INTO v_plan_info 
  FROM whop_plan_mapping 
  WHERE whop_product_id = p_whop_product_id AND is_active = TRUE;
  
  IF v_plan_info IS NULL THEN
    RETURN jsonb_build_object(
      'success', false, 
      'error', 'Unknown Whop product ID: ' || p_whop_product_id,
      'error_code', 'UNKNOWN_PRODUCT',
      'user_id', v_user_id,
      'lookup_method', v_lookup_method
    );
  END IF;
  
  -- Calculate subscription end date
  v_subscription_ends_at := CASE 
    WHEN COALESCE(v_plan_info.trial_days, 0) > 0 THEN NOW() + (v_plan_info.trial_days || ' days')::INTERVAL
    WHEN v_plan_info.billing_interval = 'monthly' THEN NOW() + INTERVAL '1 month' 
    ELSE NOW() + INTERVAL '1 year' 
  END;
  
  -- Calculate max trades (-1 means unlimited)
  v_max_trades := CASE 
    WHEN v_plan_info.max_trades = -1 THEN 999999 
    ELSE v_plan_info.max_trades 
  END;
  
  -- Get old plan for logging
  SELECT account_type INTO v_old_plan FROM profiles WHERE id = v_user_id;
  
  -- ========================================
  -- STEP 4: Update User Profile
  -- ========================================
  
  UPDATE profiles SET
    -- Subscription info
    account_type = v_plan_info.finotaur_plan,
    subscription_status = 'active',
    subscription_interval = v_plan_info.billing_interval,
    subscription_started_at = COALESCE(subscription_started_at, NOW()),
    subscription_expires_at = v_subscription_ends_at,
    subscription_cancel_at_period_end = FALSE,
    pending_downgrade_plan = NULL,
    cancellation_reason = NULL,
    -- Whop identifiers
    whop_user_id = p_whop_user_id,
    whop_membership_id = p_whop_membership_id,
    whop_product_id = p_whop_product_id,
    whop_customer_email = p_user_email,
    -- Payment info
    payment_provider = 'whop',
    -- Trade limits
    max_trades = v_max_trades,
    current_month_trades_count = 0,
    billing_cycle_start = CURRENT_DATE,
    -- Timestamp
    updated_at = NOW()
  WHERE id = v_user_id;
  
  -- ========================================
  -- STEP 5: Log Subscription Event
  -- ========================================
  
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    v_user_id,
    'payment_succeeded',
    COALESCE(v_old_plan, 'free'),
    v_plan_info.finotaur_plan,
    jsonb_build_object(
      'whop_membership_id', p_whop_membership_id,
      'whop_product_id', p_whop_product_id,
      'whop_user_id', p_whop_user_id,
      'lookup_method', v_lookup_method,
      'retries_needed', v_retry_count,
      'finotaur_user_id_provided', p_finotaur_user_id IS NOT NULL,
      'price_usd', v_plan_info.price_usd
    )
  );
  
  -- ========================================
  -- STEP 6: Process Affiliate if Provided
  -- ========================================
  
  IF p_affiliate_code IS NOT NULL AND p_affiliate_code != '' THEN
    -- Find affiliate by code or coupon
    SELECT id INTO v_affiliate_id FROM affiliates
    WHERE (UPPER(affiliate_code) = UPPER(p_affiliate_code) OR UPPER(coupon_code) = UPPER(p_affiliate_code)) 
      AND status = 'active';
    
    IF v_affiliate_id IS NOT NULL THEN
      -- Check for existing referral
      SELECT id INTO v_referral_id FROM affiliate_referrals WHERE referred_user_id = v_user_id;
      
      IF v_referral_id IS NOT NULL THEN
        -- Update existing referral
        UPDATE affiliate_referrals SET
          whop_membership_id = p_whop_membership_id,
          whop_user_id = p_whop_user_id,
          whop_product_id = p_whop_product_id,
          subscription_plan = v_plan_info.finotaur_plan,
          subscription_type = v_plan_info.billing_interval,
          subscription_price_usd = v_plan_info.price_usd,
          subscription_started_at = NOW(),
          coupon_code_used = p_affiliate_code,
          updated_at = NOW()
        WHERE id = v_referral_id;
      ELSE
        -- Create new referral
        INSERT INTO affiliate_referrals (
          affiliate_id, referred_user_id, referred_user_email, click_id, 
          signup_date, signup_plan, coupon_code_used,
          whop_membership_id, whop_user_id, whop_product_id, 
          subscription_plan, subscription_type, subscription_price_usd, 
          subscription_started_at, status, commission_eligible
        ) VALUES (
          v_affiliate_id, v_user_id, p_user_email, p_click_id, 
          NOW(), v_plan_info.finotaur_plan, p_affiliate_code,
          p_whop_membership_id, p_whop_user_id, p_whop_product_id, 
          v_plan_info.finotaur_plan, v_plan_info.billing_interval, v_plan_info.price_usd, 
          NOW(), 'pending', TRUE
        )
        RETURNING id INTO v_referral_id;
        
        -- Update affiliate stats
        UPDATE affiliates SET 
          total_signups = COALESCE(total_signups, 0) + 1, 
          last_activity_at = NOW(), 
          updated_at = NOW()
        WHERE id = v_affiliate_id;
        
        -- Log activity
        INSERT INTO affiliate_activity_log (affiliate_id, activity_type, description, metadata, is_system_action)
        VALUES (v_affiliate_id, 'new_signup', 
          'New signup via Whop: ' || p_user_email || ' (' || v_plan_info.finotaur_plan || ')',
          jsonb_build_object(
            'user_email', p_user_email, 
            'plan', v_plan_info.finotaur_plan, 
            'interval', v_plan_info.billing_interval,
            'price_usd', v_plan_info.price_usd,
            'coupon_code', p_affiliate_code
          ), 
          TRUE
        );
      END IF;
    END IF;
  END IF;
  
  -- ========================================
  -- STEP 7: Return Success Result
  -- ========================================
  
  RETURN jsonb_build_object(
    'success', true, 
    'user_id', v_user_id, 
    'email', p_user_email,
    'plan', v_plan_info.finotaur_plan,
    'interval', v_plan_info.billing_interval, 
    'price_usd', v_plan_info.price_usd,
    'expires_at', v_subscription_ends_at,
    'max_trades', v_max_trades,
    'lookup_method', v_lookup_method,
    'retries_needed', v_retry_count,
    'affiliate_id', v_affiliate_id, 
    'referral_id', v_referral_id,
    'old_plan', v_old_plan
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object(
    'success', false, 
    'error', SQLERRM,
    'sqlstate', SQLSTATE,
    'email', p_user_email,
    'finotaur_user_id', p_finotaur_user_id,
    'lookup_method', v_lookup_method,
    'retries', v_retry_count
  );
END;
$$;


ALTER FUNCTION "public"."activate_whop_subscription"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_finotaur_user_id" "text", "p_affiliate_code" "text", "p_click_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."add_purchased_credits"("p_user_id" "uuid", "p_pack_type" "text", "p_credits" integer, "p_price_usd" numeric, "p_payment_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_new_total INTEGER;
BEGIN
  -- Update purchased credits
  UPDATE profiles 
  SET credits_purchased = COALESCE(credits_purchased, 0) + p_credits
  WHERE id = p_user_id
  RETURNING credits_purchased INTO v_new_total;
  
  -- Log purchase
  INSERT INTO credit_purchases (
    user_id, pack_type, credits_amount, price_usd, payment_id
  ) VALUES (
    p_user_id, p_pack_type, p_credits, p_price_usd, p_payment_id
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'credits_added', p_credits,
    'purchased_total', v_new_total
  );
END;
$$;


ALTER FUNCTION "public"."add_purchased_credits"("p_user_id" "uuid", "p_pack_type" "text", "p_credits" integer, "p_price_usd" numeric, "p_payment_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_count_users"("p_filters" "jsonb" DEFAULT '{}'::"jsonb") RETURNS integer
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_is_admin BOOLEAN;
  v_count INTEGER;
  v_query TEXT;
  v_where_clauses TEXT[] := ARRAY[]::TEXT[];
  v_search TEXT;
  v_account_type TEXT;
  v_subscription_status TEXT;
  v_newsletter_status TEXT;
  v_top_secret_status TEXT;
  v_platform_plan TEXT;
BEGIN
  -- Check if user is admin
  SELECT p.role IN ('admin', 'super_admin') AND COALESCE(p.is_banned, false) = false
  INTO v_is_admin
  FROM public.profiles p
  WHERE p.id = auth.uid();

  IF NOT COALESCE(v_is_admin, false) THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  -- Extract filters
  v_search := p_filters->>'search';
  v_account_type := p_filters->>'account_type';
  v_subscription_status := p_filters->>'subscription_status';
  v_newsletter_status := p_filters->>'newsletter_status';
  v_top_secret_status := p_filters->>'top_secret_status';
  v_platform_plan := p_filters->>'platform_plan';

  -- Build WHERE clauses (same logic as admin_list_users)
  IF v_search IS NOT NULL AND v_search != '' THEN
    v_where_clauses := array_append(v_where_clauses, 
      format('(email ILIKE %L OR display_name ILIKE %L)', '%' || v_search || '%', '%' || v_search || '%'));
  END IF;

  IF v_account_type IS NOT NULL AND v_account_type != 'all' THEN
    IF v_account_type = 'free' THEN
      v_where_clauses := array_append(v_where_clauses, '(account_type IS NULL OR account_type = ''free'')');
    ELSE
      v_where_clauses := array_append(v_where_clauses, format('account_type = %L', v_account_type));
    END IF;
  END IF;

  IF v_subscription_status IS NOT NULL AND v_subscription_status != 'all' THEN
    v_where_clauses := array_append(v_where_clauses, format('subscription_status = %L', v_subscription_status));
  END IF;

  IF v_newsletter_status IS NOT NULL AND v_newsletter_status != 'all' THEN
    IF v_newsletter_status = 'inactive' THEN
      v_where_clauses := array_append(v_where_clauses, '(newsletter_status IS NULL OR newsletter_status = ''inactive'')');
    ELSE
      v_where_clauses := array_append(v_where_clauses, format('newsletter_status = %L', v_newsletter_status));
    END IF;
  END IF;

  IF v_top_secret_status IS NOT NULL AND v_top_secret_status != 'all' THEN
    IF v_top_secret_status = 'inactive' THEN
      v_where_clauses := array_append(v_where_clauses, '(top_secret_status IS NULL OR top_secret_status = ''inactive'')');
    ELSE
      v_where_clauses := array_append(v_where_clauses, format('top_secret_status = %L', v_top_secret_status));
    END IF;
  END IF;

  IF v_platform_plan IS NOT NULL AND v_platform_plan != 'all' THEN
    IF v_platform_plan = 'free' THEN
      v_where_clauses := array_append(v_where_clauses, '(platform_plan IS NULL OR platform_plan = ''free'')');
    ELSE
      v_where_clauses := array_append(v_where_clauses, format('platform_plan = %L', v_platform_plan));
    END IF;
  END IF;

  -- Build query
  v_query := 'SELECT COUNT(*) FROM public.profiles p WHERE p.deleted_at IS NULL';

  IF array_length(v_where_clauses, 1) > 0 THEN
    v_query := v_query || ' AND ' || array_to_string(v_where_clauses, ' AND ');
  END IF;

  EXECUTE v_query INTO v_count;
  
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."admin_count_users"("p_filters" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_force_ism_regenerate"("p_month" "text", "p_admin_id" "text", "p_reason" "text") RETURNS boolean
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF p_reason IS NULL OR LENGTH(p_reason) < 5 THEN
    RAISE EXCEPTION 'Override reason must be at least 5 characters';
  END IF;
  
  INSERT INTO ism_report_tracking (
    report_month,
    status,
    ism_data_available,
    is_admin_override,
    admin_id,
    override_reason
  ) VALUES (
    p_month,
    'ism_available',
    true,
    true,
    p_admin_id,
    p_reason
  )
  ON CONFLICT (report_month) DO UPDATE SET
    status = 'ism_available',
    is_admin_override = true,
    admin_id = EXCLUDED.admin_id,
    override_reason = EXCLUDED.override_reason,
    updated_at = NOW();
  
  RETURN true;
END;
$$;


ALTER FUNCTION "public"."admin_force_ism_regenerate"("p_month" "text", "p_admin_id" "text", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_get_broker_stats"() RETURNS json
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;

  RETURN (
    SELECT json_build_object(
      'total_connections', COUNT(*),
      'active_connections', COUNT(*) FILTER (WHERE status = 'connected'),
      'failed_connections', COUNT(*) FILTER (WHERE status = 'error'),
      'pending_connections', COUNT(*) FILTER (WHERE status = 'pending'),
      'by_broker', (
        SELECT COALESCE(json_object_agg(broker, count), '{}'::json)
        FROM (
          SELECT broker, COUNT(*) as count
          FROM public.broker_connections
          GROUP BY broker
        ) broker_counts
      ),
      'recent_syncs', (
        SELECT COALESCE(json_agg(
          json_build_object(
            'user_id', bc.user_id,
            'broker', bc.broker,
            'last_sync_at', bc.last_sync_at,
            'status', bc.status
          )
        ), '[]'::json)
        FROM (
          SELECT user_id, broker, last_sync_at, status
          FROM public.broker_connections
          WHERE last_sync_at IS NOT NULL
          ORDER BY last_sync_at DESC
          LIMIT 10
        ) bc
      ),
      'generated_at', NOW()
    )
    FROM public.broker_connections
  );
END;
$$;


ALTER FUNCTION "public"."admin_get_broker_stats"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_get_broker_stats"() IS 'v8.5.10: Platform-wide broker connection statistics. Admin only.';



