CREATE OR REPLACE FUNCTION "public"."admin_get_deleted_users"() RETURNS TABLE("user_id" "uuid", "email" "text", "display_name" "text", "deleted_at" timestamp with time zone, "deleted_by_email" "text", "ban_reason" "text", "days_since_deletion" integer, "can_restore" boolean, "total_trades" bigint, "total_strategies" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  -- בדיקה: רק אדמין
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  RETURN QUERY
  SELECT 
    p.id as user_id,
    p.email,
    COALESCE(p.display_name, split_part(p.email, '@', 1)) as display_name,
    p.deleted_at,
    deleter.email as deleted_by_email,
    p.ban_reason,
    EXTRACT(DAY FROM (NOW() - p.deleted_at))::INTEGER as days_since_deletion,
    (p.deleted_at > NOW() - INTERVAL '30 days') as can_restore,
    (SELECT COUNT(*) FROM public.trades WHERE user_id = p.id) as total_trades,
    (SELECT COUNT(*) FROM public.strategies WHERE user_id = p.id) as total_strategies
  FROM public.profiles p
  LEFT JOIN public.profiles deleter ON deleter.id = p.deleted_by
  WHERE p.deleted_at IS NOT NULL
  ORDER BY p.deleted_at DESC;
END;
$$;


ALTER FUNCTION "public"."admin_get_deleted_users"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_get_deleted_users"() IS 'v8.4.5: Returns list of soft deleted users with restore eligibility. Admin only.';



CREATE OR REPLACE FUNCTION "public"."admin_get_limits_overview"() RETURNS TABLE("user_id" "uuid", "email" "text", "display_name" "text", "plan" "text", "lifetime_trades" integer, "monthly_trades" integer, "max_limit" integer, "usage_percent" numeric, "can_add" boolean, "last_trade_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized: Admin access required';
  END IF;

  RETURN QUERY
  SELECT 
    p.id as user_id,
    p.email,
    p.display_name,
    p.account_type as plan,
    COALESCE(p.trade_count, 0)::INTEGER as lifetime_trades,
    COALESCE(p.current_month_trades_count, 0)::INTEGER as monthly_trades,
    COALESCE(p.max_trades, public.get_trade_limit(p.account_type))::INTEGER as max_limit,
    CASE 
      WHEN COALESCE(p.max_trades, 25) = 0 THEN 0
      ELSE 
        ROUND((COALESCE(p.current_month_trades_count, 0)::NUMERIC / COALESCE(p.max_trades, 25)) * 100, 1)
    END as usage_percent,
    public.can_create_trade(p.id) as can_add,
    (SELECT MAX(t.open_at) FROM public.trades t WHERE t.user_id = p.id) as last_trade_at
  FROM public.profiles p
  WHERE p.deleted_at IS NULL
  ORDER BY 
    CASE p.account_type
      WHEN 'free' THEN p.trade_count
      ELSE p.current_month_trades_count
    END DESC
  LIMIT 100;
END;
$$;


ALTER FUNCTION "public"."admin_get_limits_overview"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_get_limits_overview"() IS 'v8.5.10: Returns overview of all users trade limits with usage percentage. Admin only.';



