CREATE OR REPLACE FUNCTION "public"."admin_get_stats"() RETURNS TABLE("total_users" bigint, "active_users" bigint, "new_users_today" bigint, "new_users_this_week" bigint, "new_users_this_month" bigint, "free_users" bigint, "basic_users" bigint, "premium_users" bigint, "trial_users" bigint, "newsletter_users" bigint, "top_secret_users" bigint, "basic_monthly_users" bigint, "basic_yearly_users" bigint, "premium_monthly_users" bigint, "premium_yearly_users" bigint, "estimated_monthly_revenue" numeric, "estimated_yearly_revenue" numeric, "total_trades" bigint, "trades_this_week" bigint, "trades_this_month" bigint, "average_trades_per_user" numeric, "daily_active_users" bigint, "weekly_active_users" bigint, "monthly_active_users" bigint, "free_to_paying_conversion_rate" numeric, "trial_to_paying_conversion_rate" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_now TIMESTAMPTZ := NOW();
  v_today DATE := CURRENT_DATE;
  v_week_ago DATE := CURRENT_DATE - INTERVAL '7 days';
  v_month_ago DATE := CURRENT_DATE - INTERVAL '30 days';
  
  -- Counts
  v_total_users BIGINT;
  v_total_registered BIGINT;  -- All registered users (for conversion rate)
  v_whop_verified BIGINT;     -- Users who paid via Whop
  v_free_users BIGINT;
  v_basic_users BIGINT;
  v_premium_users BIGINT;
  v_trial_users BIGINT;
BEGIN
  -- Check if user is admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles pf
    WHERE pf.id = auth.uid() 
    AND pf.role IN ('admin', 'super_admin')
  ) THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  -- ============================================
  -- 🔥 TOTAL USERS = All registered users
  -- ============================================
  SELECT COUNT(*) INTO v_total_registered
  FROM profiles 
  WHERE deleted_at IS NULL 
    AND (is_banned = FALSE OR is_banned IS NULL);

  -- ============================================
  -- 🔥 WHOP VERIFIED = Users who ACTUALLY PAID in last 30 days
  -- (Not just has membership ID, but real payment > $0)
  -- ============================================
  SELECT COUNT(DISTINCT p.id) INTO v_whop_verified
  FROM profiles p
  INNER JOIN payment_history ph ON ph.user_id = p.id
  WHERE p.deleted_at IS NULL 
    AND (p.is_banned = FALSE OR p.is_banned IS NULL)
    AND p.whop_membership_id IS NOT NULL
    AND ph.status = 'completed'
    AND ph.amount > 0
    AND ph.created_at >= v_now - INTERVAL '30 days';

  -- ============================================
  -- 🔥 FREE USERS = Registered but no Whop payment
  -- ============================================
  SELECT COUNT(*) INTO v_free_users
  FROM profiles 
  WHERE deleted_at IS NULL 
    AND (is_banned = FALSE OR is_banned IS NULL)
    AND (whop_membership_id IS NULL);

  -- ============================================
  -- 🔥 BASIC USERS = Whop verified + basic plan
  -- ============================================
  SELECT COUNT(*) INTO v_basic_users
  FROM profiles 
  WHERE deleted_at IS NULL 
    AND whop_membership_id IS NOT NULL
    AND account_type = 'basic'
    AND (is_in_trial = FALSE OR is_in_trial IS NULL OR subscription_started_at <= v_now - INTERVAL '14 days');

  -- ============================================
  -- 🔥 PREMIUM USERS = Whop verified + premium plan
  -- ============================================
  SELECT COUNT(*) INTO v_premium_users
  FROM profiles 
  WHERE deleted_at IS NULL 
    AND whop_membership_id IS NOT NULL
    AND account_type = 'premium';

  -- ============================================
  -- 🔥 TRIAL USERS = Whop verified + in trial period
  -- ============================================
  SELECT COUNT(*) INTO v_trial_users
  FROM profiles 
  WHERE deleted_at IS NULL 
    AND whop_membership_id IS NOT NULL
    AND account_type = 'basic'
    AND is_in_trial = TRUE
    AND subscription_started_at > v_now - INTERVAL '14 days';

  -- ============================================
  -- RETURN ALL STATS
  -- ============================================
  RETURN QUERY
  SELECT
    -- Total users (all registered)
    v_total_registered,
    
    -- Active users (logged in within 30 days)
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND last_login_at >= v_month_ago::timestamptz)::BIGINT,
    
    -- New users today
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND created_at >= v_today::timestamptz)::BIGINT,
    
    -- New users this week
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND created_at >= v_week_ago::timestamptz)::BIGINT,
    
    -- New users this month
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND created_at >= v_month_ago::timestamptz)::BIGINT,
    
    -- 🔥 FREE USERS (no Whop payment)
    v_free_users,
    
    -- 🔥 BASIC USERS (Whop verified, paid)
    v_basic_users,
    
    -- 🔥 PREMIUM USERS (Whop verified)
    v_premium_users,
    
    -- 🔥 TRIAL USERS (Whop verified, in trial)
    v_trial_users,
    
    -- 🔥 NEWSLETTER USERS (Whop verified)
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND newsletter_whop_membership_id IS NOT NULL
     AND newsletter_status IN ('active', 'trial'))::BIGINT,
    
    -- 🔥 TOP SECRET USERS (Whop verified)
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND top_secret_whop_membership_id IS NOT NULL
     AND top_secret_status = 'active')::BIGINT,
    
    -- 🔥 BASIC MONTHLY (Whop verified)
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND whop_membership_id IS NOT NULL
     AND account_type = 'basic'
     AND (subscription_interval = 'monthly' OR subscription_interval IS NULL)
     AND (is_in_trial = FALSE OR is_in_trial IS NULL OR subscription_started_at <= v_now - INTERVAL '14 days'))::BIGINT,
    
    -- 🔥 BASIC YEARLY (Whop verified)
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND whop_membership_id IS NOT NULL
     AND account_type = 'basic'
     AND subscription_interval = 'yearly')::BIGINT,
    
    -- 🔥 PREMIUM MONTHLY (Whop verified)
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND whop_membership_id IS NOT NULL
     AND account_type = 'premium'
     AND (subscription_interval = 'monthly' OR subscription_interval IS NULL))::BIGINT,
    
    -- 🔥 PREMIUM YEARLY (Whop verified)
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND whop_membership_id IS NOT NULL
     AND account_type = 'premium'
     AND subscription_interval = 'yearly')::BIGINT,
    
    -- 🔥 ESTIMATED MONTHLY REVENUE (Whop verified only)
    (SELECT COALESCE(SUM(
      CASE 
        -- Basic Monthly (paid, not trial)
        WHEN account_type = 'basic' 
          AND whop_membership_id IS NOT NULL
          AND (subscription_interval = 'monthly' OR subscription_interval IS NULL)
          AND (is_in_trial = FALSE OR is_in_trial IS NULL OR subscription_started_at <= v_now - INTERVAL '14 days')
          THEN 19.99
        -- Basic Yearly (monthly equivalent)
        WHEN account_type = 'basic' 
          AND whop_membership_id IS NOT NULL
          AND subscription_interval = 'yearly' 
          THEN 149.00 / 12
        -- Premium Monthly
        WHEN account_type = 'premium' 
          AND whop_membership_id IS NOT NULL
          AND (subscription_interval = 'monthly' OR subscription_interval IS NULL)
          THEN 39.99
        -- Premium Yearly (monthly equivalent)
        WHEN account_type = 'premium' 
          AND whop_membership_id IS NOT NULL
          AND subscription_interval = 'yearly' 
          THEN 299.00 / 12
        ELSE 0
      END
    ), 0)
    FROM profiles 
    WHERE deleted_at IS NULL)::NUMERIC,
    
    -- 🔥 ESTIMATED YEARLY REVENUE
    (SELECT COALESCE(SUM(
      CASE 
        WHEN account_type = 'basic' 
          AND whop_membership_id IS NOT NULL
          AND (subscription_interval = 'monthly' OR subscription_interval IS NULL)
          AND (is_in_trial = FALSE OR is_in_trial IS NULL OR subscription_started_at <= v_now - INTERVAL '14 days')
          THEN 19.99 * 12
        WHEN account_type = 'basic' 
          AND whop_membership_id IS NOT NULL
          AND subscription_interval = 'yearly' 
          THEN 149.00
        WHEN account_type = 'premium' 
          AND whop_membership_id IS NOT NULL
          AND (subscription_interval = 'monthly' OR subscription_interval IS NULL)
          THEN 39.99 * 12
        WHEN account_type = 'premium' 
          AND whop_membership_id IS NOT NULL
          AND subscription_interval = 'yearly' 
          THEN 299.00
        ELSE 0
      END
    ), 0)
    FROM profiles 
    WHERE deleted_at IS NULL)::NUMERIC,
    
    -- Total trades
    (SELECT COALESCE(SUM(trade_count), 0) FROM profiles WHERE deleted_at IS NULL)::BIGINT,
    
    -- Trades this week (from trades table if exists, otherwise estimate)
    (SELECT COUNT(*) FROM trades WHERE created_at >= v_week_ago::timestamptz)::BIGINT,
    
    -- Trades this month
    (SELECT COUNT(*) FROM trades WHERE created_at >= v_month_ago::timestamptz)::BIGINT,
    
    -- Average trades per user
    CASE WHEN v_total_registered > 0 
      THEN (SELECT COALESCE(AVG(trade_count), 0) FROM profiles WHERE deleted_at IS NULL)::NUMERIC
      ELSE 0 
    END,
    
    -- Daily active users
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND last_login_at >= v_today::timestamptz)::BIGINT,
    
    -- Weekly active users
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND last_login_at >= v_week_ago::timestamptz)::BIGINT,
    
    -- Monthly active users
    (SELECT COUNT(*) FROM profiles 
     WHERE deleted_at IS NULL 
     AND last_login_at >= v_month_ago::timestamptz)::BIGINT,
    
    -- 🔥 FREE TO PAYING CONVERSION RATE
    -- (Whop verified users / Total registered users) * 100
    CASE WHEN v_total_registered > 0 
      THEN ROUND((v_whop_verified::NUMERIC / v_total_registered::NUMERIC) * 100, 2)
      ELSE 0 
    END,
    
    -- 🔥 TRIAL TO PAYING CONVERSION RATE
    -- Calculate from users who completed trial
    CASE WHEN v_trial_users + v_basic_users + v_premium_users > 0 
      THEN ROUND(((v_basic_users + v_premium_users)::NUMERIC / 
                  (v_trial_users + v_basic_users + v_premium_users)::NUMERIC) * 100, 2)
      ELSE 0 
    END;

END;
$_$;


