CREATE OR REPLACE FUNCTION "public"."admin_get_subscription_health"() RETURNS TABLE("user_id" "uuid", "email" "text", "display_name" "text", "account_type" "text", "subscription_interval" "text", "subscription_status" "text", "subscription_expires_at" timestamp with time zone, "subscription_cancel_at_period_end" boolean, "cancellation_requested_at" timestamp with time zone, "cancellation_effective_date" "date", "days_remaining" integer, "health_status" "text", "last_payment_date" timestamp with time zone, "last_payment_amount" numeric, "lifetime_value" numeric, "renewal_count" bigint, "current_period_start" timestamp with time zone, "auto_renew_enabled" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Check if user is admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles pf
    WHERE pf.id = auth.uid() 
    AND pf.role IN ('admin', 'super_admin')
  ) THEN
