CREATE OR REPLACE FUNCTION "public"."admin_get_users"("p_page" integer DEFAULT 1, "p_per_page" integer DEFAULT 50, "p_search" "text" DEFAULT NULL::"text", "p_account_type" "text" DEFAULT NULL::"text", "p_role" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "email" "text", "display_name" "text", "account_type" "text", "role" "text", "is_banned" boolean, "trade_count" integer, "created_at" timestamp with time zone, "last_login" timestamp with time zone, "total_count" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total BIGINT;
BEGIN
  -- Verify admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin')
      AND COALESCE(is_banned, FALSE) = FALSE
  ) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;
  
  v_offset := (p_page - 1) * p_per_page;
  
  -- Get total count
  SELECT COUNT(*) INTO v_total
  FROM public.profiles p
  WHERE 
    (p_search IS NULL OR p.email ILIKE '%' || p_search || '%' OR p.display_name ILIKE '%' || p_search || '%')
    AND (p_account_type IS NULL OR p.account_type = p_account_type)
    AND (p_role IS NULL OR p.role = p_role);
  
  RETURN QUERY
  SELECT 
    p.id,
    p.email,
    p.display_name,
    p.account_type,
    p.role,
    COALESCE(p.is_banned, FALSE),
    COALESCE(p.trade_count, 0),
    p.created_at,
    p.last_login_at,
    v_total
  FROM public.profiles p
  WHERE 
    (p_search IS NULL OR p.email ILIKE '%' || p_search || '%' OR p.display_name ILIKE '%' || p_search || '%')
    AND (p_account_type IS NULL OR p.account_type = p_account_type)
    AND (p_role IS NULL OR p.role = p_role)
  ORDER BY p.created_at DESC
  LIMIT p_per_page
  OFFSET v_offset;
END;
$$;


ALTER FUNCTION "public"."admin_get_users"("p_page" integer, "p_per_page" integer, "p_search" "text", "p_account_type" "text", "p_role" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_get_users"("p_page" integer, "p_per_page" integer, "p_search" "text", "p_account_type" "text", "p_role" "text") IS 'v8.5.9: Paginated user list for admin panel';



CREATE OR REPLACE FUNCTION "public"."admin_grant_access"("p_user_id" "uuid", "p_product" "text", "p_plan" "text", "p_duration_days" integer DEFAULT 30) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id    UUID;
  v_expires_at  TIMESTAMPTZ;
  v_user_exists BOOLEAN;
  v_full_plan   TEXT;
BEGIN
  v_admin_id := auth.uid();

  -- Check admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = v_admin_id
      AND role IN ('admin', 'super_admin')
      AND COALESCE(is_banned, FALSE) = FALSE
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'Access denied: Admin only');
  END IF;

  -- Check user exists
  SELECT EXISTS (SELECT 1 FROM public.profiles WHERE id = p_user_id)
  INTO v_user_exists;

  IF NOT v_user_exists THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  -- Validate plan
  IF p_plan NOT IN ('core', 'finotaur', 'enterprise') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid plan: must be core, finotaur, or enterprise');
  END IF;

  -- Build full plan name (matching webhook convention)
  v_full_plan  := 'platform_' || p_plan;
  v_expires_at := NOW() + (p_duration_days || ' days')::INTERVAL;

  -- Update profile (platform fields)
  UPDATE public.profiles
  SET
    platform_plan                   = v_full_plan,
    platform_subscription_status    = 'active',
    platform_subscription_started_at = NOW(),
    platform_subscription_expires_at = v_expires_at,
    platform_payment_provider       = 'admin_granted',
    platform_is_in_trial            = FALSE,
    platform_cancel_at_period_end   = FALSE,
    updated_at                      = NOW(),

    -- 🔥 Core: Journal Basic included
    account_type = CASE
      WHEN p_plan = 'core' THEN 'basic'
      WHEN p_plan IN ('finotaur', 'enterprise') THEN 'premium'
      ELSE account_type
    END,
    max_trades = CASE
      WHEN p_plan = 'core' THEN 25
      WHEN p_plan IN ('finotaur', 'enterprise') THEN 999999
      ELSE max_trades
    END,
    subscription_status = CASE
      WHEN p_plan IN ('core', 'finotaur', 'enterprise') THEN 'active'
      ELSE subscription_status
    END,
    subscription_started_at = CASE
      WHEN p_plan IN ('core', 'finotaur', 'enterprise') THEN NOW()
      ELSE subscription_started_at
    END,
    subscription_expires_at = CASE
      WHEN p_plan IN ('core', 'finotaur', 'enterprise') THEN v_expires_at
      ELSE subscription_expires_at
    END,
    is_in_trial = CASE
      WHEN p_plan IN ('core', 'finotaur', 'enterprise') THEN FALSE
      ELSE is_in_trial
    END,
    platform_bundle_journal_granted = CASE
      WHEN p_plan IN ('core', 'finotaur', 'enterprise') THEN TRUE
      ELSE platform_bundle_journal_granted
    END,

    -- 🔥 Finotaur/Enterprise: War Zone Newsletter included
    newsletter_enabled = CASE
      WHEN p_plan IN ('finotaur', 'enterprise') THEN TRUE
      ELSE newsletter_enabled
    END,
    newsletter_status = CASE
      WHEN p_plan IN ('finotaur', 'enterprise') THEN 'active'
      ELSE newsletter_status
    END,
    newsletter_paid = CASE
      WHEN p_plan IN ('finotaur', 'enterprise') THEN TRUE
      ELSE newsletter_paid
    END,
    platform_bundle_newsletter_granted = CASE
      WHEN p_plan IN ('finotaur', 'enterprise') THEN TRUE
      ELSE platform_bundle_newsletter_granted
    END,

    -- 🔥 Finotaur/Enterprise: Top Secret included
    top_secret_enabled = CASE
      WHEN p_plan IN ('finotaur', 'enterprise') THEN TRUE
      ELSE top_secret_enabled
    END,
    top_secret_status = CASE
      WHEN p_plan IN ('finotaur', 'enterprise') THEN 'active'
      ELSE top_secret_status
    END,
    top_secret_interval = CASE
      WHEN p_plan IN ('finotaur', 'enterprise') THEN 'monthly'
      ELSE top_secret_interval
    END,

    -- 🔥 Enterprise: AI Portfolio included
    enterprise_ai_portfolio_enabled = CASE
      WHEN p_plan = 'enterprise' THEN TRUE
      ELSE enterprise_ai_portfolio_enabled
    END
  WHERE id = p_user_id;

  -- Log action
  PERFORM public.log_admin_action(
    'ADMIN_GRANT_PLATFORM_ACCESS',
    'user',
    p_user_id,
    jsonb_build_object(
      'product',       p_product,
      'plan',          v_full_plan,
      'duration_days', p_duration_days,
      'expires_at',    v_expires_at
    )
  );

  RETURN jsonb_build_object(
    'success',    true,
    'plan',       v_full_plan,
    'expires_at', v_expires_at,
    'message',    'Platform ' || p_plan || ' granted for ' || p_duration_days || ' days'
  );

EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."admin_grant_access"("p_user_id" "uuid", "p_product" "text", "p_plan" "text", "p_duration_days" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_grant_access"("p_user_id" "uuid", "p_product" "text", "p_plan" "text", "p_duration_days" integer) IS 'Admin grants platform access directly in DB (no Whop). Called by SiteDashboard Grant Access dialog.';



CREATE OR REPLACE FUNCTION "public"."admin_impersonate_user"("p_target_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_target_user RECORD;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  SELECT 
    id,
    email,
    display_name,
    account_type,
    role
  INTO v_target_user
  FROM public.profiles
  WHERE id = p_target_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  PERFORM public.log_admin_action(
    'IMPERSONATE_USER',
    'profile',
    p_target_user_id,
    jsonb_build_object(
      'target_email', v_target_user.email,
      'target_role', v_target_user.role
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'user', jsonb_build_object(
      'id', v_target_user.id,
      'email', v_target_user.email,
      'display_name', v_target_user.display_name,
      'account_type', v_target_user.account_type,
      'role', v_target_user.role
    )
  );
END;
$$;


ALTER FUNCTION "public"."admin_impersonate_user"("p_target_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_impersonate_user"("p_target_user_id" "uuid") IS 'v8.5.9: Allows admin to impersonate a user for support purposes';



CREATE OR REPLACE FUNCTION "public"."admin_list_users"("p_filters" "jsonb" DEFAULT '{}'::"jsonb", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0, "p_sort_by" "text" DEFAULT 'created_at'::"text", "p_sort_order" "text" DEFAULT 'DESC'::"text") RETURNS TABLE("id" "uuid", "email" "text", "display_name" "text", "created_at" timestamp with time zone, "account_type" "text", "subscription_status" "text", "whop_membership_id" "text", "is_in_trial" boolean, "trial_ends_at" timestamp with time zone, "subscription_cancel_at_period_end" boolean, "subscription_started_at" timestamp with time zone, "total_pnl" numeric, "initial_portfolio" numeric, "current_portfolio" numeric, "risk_mode" "text", "risk_percentage" numeric, "newsletter_status" "text", "newsletter_whop_membership_id" "text", "newsletter_enabled" boolean, "newsletter_paid" boolean, "newsletter_trial_ends_at" timestamp with time zone, "newsletter_cancel_at_period_end" boolean, "newsletter_expires_at" timestamp with time zone, "top_secret_status" "text", "top_secret_whop_membership_id" "text", "top_secret_enabled" boolean, "top_secret_is_in_trial" boolean, "top_secret_trial_ends_at" timestamp with time zone, "top_secret_cancel_at_period_end" boolean, "top_secret_started_at" timestamp with time zone, "top_secret_expires_at" timestamp with time zone, "platform_plan" "text", "platform_subscription_status" "text", "platform_is_in_trial" boolean, "platform_trial_ends_at" timestamp with time zone, "platform_cancel_at_period_end" boolean, "last_login_at" timestamp with time zone, "trade_count" integer, "subscription_interval" "text", "subscription_expires_at" timestamp with time zone, "role" "text", "is_banned" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_is_admin BOOLEAN;
  v_query TEXT;
  v_where_clauses TEXT[] := ARRAY[]::TEXT[];
  v_search TEXT;
  v_account_type TEXT;
  v_subscription_status TEXT;
  v_newsletter_status TEXT;
  v_top_secret_status TEXT;
  v_platform_plan TEXT;
  v_is_banned BOOLEAN;
  v_has_active_subscription BOOLEAN;
BEGIN
  -- Check if user is admin
  SELECT p.role IN ('admin', 'super_admin') AND COALESCE(p.is_banned, false) = false
  INTO v_is_admin
  FROM public.profiles p
  WHERE p.id = auth.uid();

  IF NOT COALESCE(v_is_admin, false) THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  -- Extract filters from JSONB
  v_search := p_filters->>'search';
  v_account_type := p_filters->>'account_type';
  v_subscription_status := p_filters->>'subscription_status';
  v_newsletter_status := p_filters->>'newsletter_status';
  v_top_secret_status := p_filters->>'top_secret_status';
  v_platform_plan := p_filters->>'platform_plan';
  v_is_banned := (p_filters->>'is_banned')::BOOLEAN;
  v_has_active_subscription := (p_filters->>'has_active_subscription')::BOOLEAN;

  -- Build WHERE clauses
  IF v_search IS NOT NULL AND v_search != '' THEN
    v_where_clauses := array_append(v_where_clauses, 
      format('(email ILIKE %L OR display_name ILIKE %L)', '%' || v_search || '%', '%' || v_search || '%'));
  END IF;

  IF v_account_type IS NOT NULL AND v_account_type != 'all' THEN
    IF v_account_type = 'free' THEN
      v_where_clauses := array_append(v_where_clauses, '(account_type IS NULL OR account_type = ''free'')');
    ELSE
      v_where_clauses := array_append(v_where_clauses, format('account_type = %L', v_account_type));
    END IF;
  END IF;

  IF v_subscription_status IS NOT NULL AND v_subscription_status != 'all' THEN
    v_where_clauses := array_append(v_where_clauses, format('subscription_status = %L', v_subscription_status));
  END IF;

  IF v_newsletter_status IS NOT NULL AND v_newsletter_status != 'all' THEN
    IF v_newsletter_status = 'inactive' THEN
      v_where_clauses := array_append(v_where_clauses, '(newsletter_status IS NULL OR newsletter_status = ''inactive'')');
    ELSE
      v_where_clauses := array_append(v_where_clauses, format('newsletter_status = %L', v_newsletter_status));
    END IF;
  END IF;

  IF v_top_secret_status IS NOT NULL AND v_top_secret_status != 'all' THEN
    IF v_top_secret_status = 'inactive' THEN
      v_where_clauses := array_append(v_where_clauses, '(top_secret_status IS NULL OR top_secret_status = ''inactive'')');
    ELSE
      v_where_clauses := array_append(v_where_clauses, format('top_secret_status = %L', v_top_secret_status));
    END IF;
  END IF;

  IF v_platform_plan IS NOT NULL AND v_platform_plan != 'all' THEN
    IF v_platform_plan = 'free' THEN
      v_where_clauses := array_append(v_where_clauses, '(platform_plan IS NULL OR platform_plan = ''free'')');
    ELSE
      v_where_clauses := array_append(v_where_clauses, format('platform_plan = %L', v_platform_plan));
    END IF;
  END IF;

  IF v_is_banned IS NOT NULL THEN
    v_where_clauses := array_append(v_where_clauses, format('is_banned = %L', v_is_banned));
  END IF;

  IF v_has_active_subscription = true THEN
    v_where_clauses := array_append(v_where_clauses, 
      '(whop_membership_id IS NOT NULL OR newsletter_whop_membership_id IS NOT NULL OR top_secret_whop_membership_id IS NOT NULL)');
  END IF;

  -- Build the final query
  v_query := '
    SELECT 
      p.id,
      p.email::TEXT,
      p.display_name::TEXT,
      p.created_at,
      p.account_type::TEXT,
      p.subscription_status::TEXT,
      p.whop_membership_id::TEXT,
      -- Journal Trial fields
      COALESCE(p.is_in_trial, false) AS is_in_trial,
      p.trial_ends_at,
      COALESCE(p.subscription_cancel_at_period_end, false) AS subscription_cancel_at_period_end,
      p.subscription_started_at,
      -- Financial Info
      COALESCE(p.total_pnl, 0) AS total_pnl,
      COALESCE(p.initial_portfolio, 10000) AS initial_portfolio,
      COALESCE(p.current_portfolio, 10000) AS current_portfolio,
      -- Risk Settings
      COALESCE(p.risk_mode, ''percentage'')::TEXT AS risk_mode,
      COALESCE(p.risk_percentage, 1)::NUMERIC AS risk_percentage,
      -- Newsletter fields
      p.newsletter_status::TEXT,
      p.newsletter_whop_membership_id::TEXT,
      p.newsletter_enabled,
      COALESCE(p.newsletter_paid, false) AS newsletter_paid,
      p.newsletter_trial_ends_at,
      COALESCE(p.newsletter_cancel_at_period_end, false) AS newsletter_cancel_at_period_end,
      p.newsletter_expires_at,
      -- Top Secret fields
      p.top_secret_status::TEXT,
      p.top_secret_whop_membership_id::TEXT,
      p.top_secret_enabled,
      COALESCE(p.top_secret_is_in_trial, false) AS top_secret_is_in_trial,
      p.top_secret_trial_ends_at,
      COALESCE(p.top_secret_cancel_at_period_end, false) AS top_secret_cancel_at_period_end,
      p.top_secret_started_at,
      p.top_secret_expires_at,
      -- Platform fields
      p.platform_plan::TEXT,
      p.platform_subscription_status::TEXT,
      COALESCE(p.platform_is_in_trial, false) AS platform_is_in_trial,
      p.platform_trial_ends_at,
      COALESCE(p.platform_cancel_at_period_end, false) AS platform_cancel_at_period_end,
      -- Common fields
      p.last_login_at,
      COALESCE(p.trade_count, 0) AS trade_count,
      p.subscription_interval::TEXT,
      p.subscription_expires_at,
      p.role::TEXT,
      COALESCE(p.is_banned, false) AS is_banned
    FROM public.profiles p
    WHERE p.deleted_at IS NULL';

  -- Add WHERE clauses if any
  IF array_length(v_where_clauses, 1) > 0 THEN
    v_query := v_query || ' AND ' || array_to_string(v_where_clauses, ' AND ');
  END IF;

  -- Add ORDER BY (sanitize sort column)
  IF p_sort_by NOT IN ('created_at', 'email', 'last_login_at', 'trade_count', 'display_name') THEN
    p_sort_by := 'created_at';
  END IF;
  
  IF UPPER(p_sort_order) NOT IN ('ASC', 'DESC') THEN
    p_sort_order := 'DESC';
  END IF;

  v_query := v_query || format(' ORDER BY %I %s NULLS LAST', p_sort_by, UPPER(p_sort_order));

  -- Add LIMIT and OFFSET
  v_query := v_query || format(' LIMIT %s OFFSET %s', p_limit, p_offset);

  -- Execute and return
  RETURN QUERY EXECUTE v_query;
END;
$$;


ALTER FUNCTION "public"."admin_list_users"("p_filters" "jsonb", "p_limit" integer, "p_offset" integer, "p_sort_by" "text", "p_sort_order" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reset_trade_count"("target_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID;
  v_old_count INTEGER;
  v_user_email TEXT;
BEGIN
  v_admin_id := auth.uid();
  
  IF NOT public.is_admin() THEN
    RETURN jsonb_build_object('success', false, 'error', 'Unauthorized: Admin access required');
  END IF;

  -- Get old count and email for logging
  SELECT current_month_trades_count, email 
  INTO v_old_count, v_user_email
  FROM public.profiles 
  WHERE id = target_user_id;
  
  IF v_old_count IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  -- Reset the counter
  UPDATE public.profiles
  SET 
    current_month_trades_count = 0,
    billing_cycle_start = CURRENT_DATE,
    updated_at = NOW()
  WHERE id = target_user_id;
  
  -- Log admin action
  PERFORM public.log_admin_action(
    'RESET_TRADE_COUNT',
    'profile',
    target_user_id,
    jsonb_build_object(
      'old_count', v_old_count, 
      'reset_date', CURRENT_DATE,
      'user_email', v_user_email
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'message', 'Trade count reset successfully',
    'data', jsonb_build_object(
      'user_id', target_user_id,
      'user_email', v_user_email,
      'old_count', v_old_count,
      'new_count', 0
    )
  );
END;
$$;


ALTER FUNCTION "public"."admin_reset_trade_count"("target_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_reset_trade_count"("target_user_id" "uuid") IS 'v8.5.10: Resets monthly trade count for a user. Admin only. Logs action.';



CREATE OR REPLACE FUNCTION "public"."admin_restore_user"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_user_email TEXT;
  v_restored_trades INTEGER;
  v_restored_strategies INTEGER;
BEGIN
  -- בדיקה: רק אדמין יכול לשחזר
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  -- בדיקה: המשתמש קיים ונמחק
  SELECT email INTO v_user_email
  FROM public.profiles
  WHERE id = p_user_id AND deleted_at IS NOT NULL;
  
  IF v_user_email IS NULL THEN
    RAISE EXCEPTION 'User not found or not deleted: %', p_user_id;
  END IF;
  
  -- שחזור המשתמש
  UPDATE public.profiles
  SET 
    deleted_at = NULL,
    deleted_by = NULL,
    is_banned = FALSE,
    ban_reason = NULL,
    banned_at = NULL,
    banned_by = NULL,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- שחזור הטרייד
  UPDATE public.trades
  SET 
    deleted_at = NULL,
    deleted_by = NULL
  WHERE user_id = p_user_id
    AND deleted_at IS NOT NULL;
  
  GET DIAGNOSTICS v_restored_trades = ROW_COUNT;
  
  -- שחזור האסטרטגיות
  UPDATE public.strategies
  SET deleted_at = NULL
  WHERE user_id = p_user_id
    AND deleted_at IS NOT NULL;
  
  GET DIAGNOSTICS v_restored_strategies = ROW_COUNT;
  
  -- רישום ב-audit log
  PERFORM public.log_admin_action(
    'RESTORE_USER',
    p_user_id,
    'user',
    p_user_id,
    jsonb_build_object(
      'email', v_user_email,
      'restored_trades', v_restored_trades,
      'restored_strategies', v_restored_strategies,
      'restored_by', auth.uid(),
      'restored_at', NOW()
    )
  );
  
  RAISE NOTICE '✅ User % restored successfully', v_user_email;
  
  RETURN jsonb_build_object(
    'success', TRUE,
    'message', 'User restored successfully',
    'data', jsonb_build_object(
      'user_id', p_user_id,
      'email', v_user_email,
      'restored_trades', v_restored_trades,
      'restored_strategies', v_restored_strategies
    )
  );
  
EXCEPTION 
  WHEN OTHERS THEN
    RAISE WARNING 'Error in restore: %', SQLERRM;
    RETURN jsonb_build_object(
      'success', FALSE,
      'error', SQLERRM
    );
END;
$$;


ALTER FUNCTION "public"."admin_restore_user"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_restore_user"("p_user_id" "uuid") IS 'v8.4.5: Restores soft deleted user and all their data. Admin only.';



CREATE OR REPLACE FUNCTION "public"."admin_soft_delete_user"("p_user_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_email TEXT;
  v_user_name TEXT;
  v_affected_trades INTEGER;
  v_affected_strategies INTEGER;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  IF EXISTS(
    SELECT 1 FROM public.profiles 
    WHERE id = p_user_id AND role = 'super_admin'
  ) THEN
    RAISE EXCEPTION 'Cannot delete super admin users';
  END IF;
  
  SELECT email, display_name INTO v_user_email, v_user_name
  FROM public.profiles
  WHERE id = p_user_id;
  
  IF v_user_email IS NULL THEN
    RAISE EXCEPTION 'User not found: %', p_user_id;
  END IF;
  
  SELECT COUNT(*) INTO v_affected_trades
  FROM public.trades
  WHERE user_id = p_user_id AND deleted_at IS NULL;
  
  SELECT COUNT(*) INTO v_affected_strategies
  FROM public.strategies
  WHERE user_id = p_user_id AND deleted_at IS NULL;
  
  UPDATE public.profiles
  SET 
    deleted_at = NOW(),
    deleted_by = auth.uid(),
    is_banned = TRUE,
    ban_reason = COALESCE(p_reason, 'Admin deleted user'),
    banned_at = NOW(),
    banned_by = auth.uid(),
    updated_at = NOW()
  WHERE id = p_user_id;
  
  UPDATE public.trades
  SET 
    deleted_at = NOW(),
    deleted_by = auth.uid()
  WHERE user_id = p_user_id
    AND deleted_at IS NULL;
  
  UPDATE public.strategies
  SET deleted_at = NOW()
  WHERE user_id = p_user_id
    AND deleted_at IS NULL;
  
  PERFORM public.log_admin_action(
    'SOFT_DELETE_USER',
    'user',
    p_user_id,
    jsonb_build_object(
      'email', v_user_email,
      'display_name', v_user_name,
      'reason', p_reason,
      'affected_trades', v_affected_trades,
      'affected_strategies', v_affected_strategies,
      'deleted_by', auth.uid(),
      'deleted_at', NOW()
    )
  );
  
  RETURN jsonb_build_object(
    'success', TRUE,
    'message', 'User soft deleted successfully',
    'data', jsonb_build_object(
      'user_id', p_user_id,
      'email', v_user_email,
      'display_name', v_user_name,
      'affected_trades', v_affected_trades,
      'affected_strategies', v_affected_strategies,
      'can_restore', TRUE
    )
  );
  
EXCEPTION 
  WHEN OTHERS THEN
    RETURN jsonb_build_object(
      'success', FALSE,
      'error', SQLERRM
    );
END;
$$;


ALTER FUNCTION "public"."admin_soft_delete_user"("p_user_id" "uuid", "p_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_soft_delete_user"("p_user_id" "uuid", "p_reason" "text") IS 'v9.4.2: Soft deletes a user and all their data. Admin only.';



CREATE OR REPLACE FUNCTION "public"."admin_toggle_ban"("p_user_id" "uuid", "p_is_banned" boolean, "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID;
  v_old_status BOOLEAN;
BEGIN
  v_admin_id := auth.uid();
  
  -- Check admin permission (admin OR super_admin)
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = v_admin_id
      AND role IN ('admin', 'super_admin')
      AND COALESCE(is_banned, FALSE) = FALSE
  ) THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;

  -- Get current status
  SELECT is_banned INTO v_old_status
  FROM public.profiles
  WHERE id = p_user_id;
  
  IF v_old_status IS NULL THEN
    RETURN jsonb_build_object('success', FALSE, 'error', 'User not found');
  END IF;

  -- Set ban status explicitly (not toggle)
  UPDATE public.profiles
  SET 
    is_banned = p_is_banned,
    ban_reason = CASE WHEN p_is_banned THEN p_reason ELSE NULL END,
    banned_at = CASE WHEN p_is_banned THEN NOW() ELSE NULL END,
    banned_by = CASE WHEN p_is_banned THEN v_admin_id ELSE NULL END,
    updated_at = NOW()
  WHERE id = p_user_id;

  -- Log admin action
  PERFORM log_admin_action(
    CASE WHEN p_is_banned THEN 'BAN_USER' ELSE 'UNBAN_USER' END,
    'user', 
    p_user_id, 
    jsonb_build_object(
      'reason', p_reason,
      'previous_status', v_old_status,
      'new_status', p_is_banned
    )
  );

  RETURN jsonb_build_object(
    'success', TRUE,
    'message', CASE WHEN p_is_banned THEN 'User banned' ELSE 'User unbanned' END
  );

EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('success', FALSE, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."admin_toggle_ban"("p_user_id" "uuid", "p_is_banned" boolean, "p_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_toggle_ban"("p_user_id" "uuid", "p_is_banned" boolean, "p_reason" "text") IS 'v10.0.0: Ban/unban user with explicit status. Admin only. Returns JSONB.';



CREATE OR REPLACE FUNCTION "public"."admin_update_subscription"("p_user_id" "uuid", "p_account_type" "text", "p_subscription_interval" "text", "p_subscription_status" "text", "p_subscription_expires_at" timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID;
  v_admin_role TEXT;
  v_max_trades INTEGER;
  v_old_account_type TEXT;
BEGIN
  -- Verify authentication
  v_admin_id := auth.uid();
  
  IF v_admin_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authenticated');
  END IF;
  
  -- Verify admin role
  SELECT role INTO v_admin_role FROM public.profiles WHERE id = v_admin_id;
  
  IF v_admin_role NOT IN ('admin', 'super_admin') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Insufficient permissions');
  END IF;
  
  -- Validate account type
  -- Validate account type - ❌ FREE בוטל
IF p_account_type NOT IN ('basic', 'premium', 'trial') THEN
  RETURN jsonb_build_object('success', false, 'error', 'Invalid account type: ' || p_account_type);
END IF;

  -- Validate subscription interval (only required for non-free)
  IF p_account_type != 'free' AND p_subscription_interval NOT IN ('monthly', 'yearly') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid subscription interval: ' || p_subscription_interval);
  END IF;

  -- Validate subscription status
  IF p_subscription_status NOT IN ('trial', 'active', 'expired', 'cancelled') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid subscription status: ' || p_subscription_status);
  END IF;
  
  -- Get old account type for logging
  SELECT account_type INTO v_old_account_type 
  FROM public.profiles WHERE id = p_user_id;
  
  IF v_old_account_type IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  -- Use get_trade_limit() function if it exists, otherwise fallback
  BEGIN
    v_max_trades := public.get_trade_limit(p_account_type);
  EXCEPTION WHEN undefined_function THEN
    -- Fallback if function doesn't exist
  -- Calculate max_trades
  v_max_trades := CASE p_account_type
    WHEN 'basic' THEN 25
    WHEN 'premium' THEN 999999
    WHEN 'admin' THEN 999999
    WHEN 'vip' THEN 999999
    -- ❌ FREE בוטל
    -- WHEN 'free' THEN 0
    ELSE 25                     -- ✅ Default = basic
  END;
  END;
  
  -- Update profile (uses subscription_expires_at - FIXED!)
  UPDATE public.profiles
  SET 
    account_type = p_account_type,
    subscription_interval = CASE 
      WHEN p_account_type = 'free' THEN NULL 
      ELSE p_subscription_interval 
    END,
    subscription_status = p_subscription_status,
    subscription_expires_at = p_subscription_expires_at,  -- ✅ CORRECT column name
    max_trades = v_max_trades,
    -- Reset counters when upgrading from free
    current_month_trades_count = CASE 
      WHEN v_old_account_type = 'free' AND p_account_type IN ('basic', 'trial', 'premium') THEN 0 
      ELSE current_month_trades_count 
    END,
    billing_cycle_start = CASE 
      WHEN v_old_account_type = 'free' AND p_account_type IN ('basic', 'trial', 'premium') THEN CURRENT_DATE 
      ELSE billing_cycle_start 
    END,
    subscription_started_at = CASE
      WHEN v_old_account_type = 'free' AND p_account_type IN ('basic', 'trial', 'premium') THEN NOW()
      ELSE subscription_started_at
    END,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- Log admin action
  BEGIN
    PERFORM log_admin_action(
      'UPDATE_SUBSCRIPTION',
      'subscription', 
      p_user_id,
      jsonb_build_object(
        'old_account_type', v_old_account_type,
        'new_account_type', p_account_type,
        'subscription_interval', p_subscription_interval,
        'subscription_status', p_subscription_status,
        'expires_at', p_subscription_expires_at,
        'max_trades', v_max_trades
      )
    );
  EXCEPTION 
    WHEN OTHERS THEN
      -- Don't fail the update if logging fails
      RAISE WARNING 'Failed to log admin action: %', SQLERRM;
  END;
  
  RETURN jsonb_build_object(
    'success', true, 
    'message', 'Subscription updated successfully',
    'data', jsonb_build_object(
      'user_id', p_user_id,
      'old_account_type', v_old_account_type,
      'new_account_type', p_account_type,
      'max_trades', v_max_trades,
      'expires_at', p_subscription_expires_at
    )
  );
  
EXCEPTION 
  WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."admin_update_subscription"("p_user_id" "uuid", "p_account_type" "text", "p_subscription_interval" "text", "p_subscription_status" "text", "p_subscription_expires_at" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_update_subscription"("p_user_id" "uuid", "p_account_type" "text", "p_subscription_interval" "text", "p_subscription_status" "text", "p_subscription_expires_at" timestamp with time zone) IS 'v9.4.2-SYNCED: Returns JSONB with success/error. Uses subscription_expires_at. Uses get_trade_limit() with fallback.';



CREATE OR REPLACE FUNCTION "public"."admin_update_user_account"("p_user_id" "uuid", "p_account_type" "text", "p_reason" "text" DEFAULT 'Admin update'::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_max_trades INTEGER;
BEGIN
  -- Verify admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin')
      AND COALESCE(is_banned, FALSE) = FALSE
  ) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;
  
  -- Calculate max_trades
  v_max_trades := CASE p_account_type
    WHEN 'free' THEN 10
    WHEN 'basic' THEN 25
    WHEN 'premium' THEN 999999
    WHEN 'trial' THEN 25
    ELSE 10
  END;
  
  UPDATE public.profiles
  SET 
    account_type = p_account_type,
    max_trades = v_max_trades,
    payment_provider = CASE 
      WHEN p_account_type = 'free' THEN NULL 
      ELSE 'admin_granted' 
    END,
    current_month_trades_count = CASE
      WHEN p_account_type != 'free' THEN 0
      ELSE current_month_trades_count
    END,
    billing_cycle_start = CASE
      WHEN p_account_type != 'free' THEN CURRENT_DATE
      ELSE billing_cycle_start
    END,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- Log action
  PERFORM public.log_admin_action(
    'update_account_type',
    'user',
    p_user_id,
    jsonb_build_object(
      'new_type', p_account_type,
      'reason', p_reason
    )
  );
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."admin_update_user_account"("p_user_id" "uuid", "p_account_type" "text", "p_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."admin_update_user_account"("p_user_id" "uuid", "p_account_type" "text", "p_reason" "text") IS 'v8.5.9: Admin function to change user account type';



CREATE OR REPLACE FUNCTION "public"."apply_platform_bundle"("p_user_id" "uuid", "p_platform_plan" "text", "p_newsletter_choice" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_journal_benefit TEXT;
  v_newsletter_benefit TEXT;
  v_current_journal TEXT;
  v_journal_was_paid BOOLEAN;
BEGIN
  SELECT benefit_value INTO v_journal_benefit
  FROM platform_bundle_benefits
  WHERE platform_plan = p_platform_plan 
    AND benefit_type = 'journal_plan'
    AND is_active = TRUE;
  
  SELECT benefit_value INTO v_newsletter_benefit
  FROM platform_bundle_benefits
  WHERE platform_plan = p_platform_plan 
    AND benefit_type IN ('newsletter_included', 'newsletter_choice')
    AND is_active = TRUE;
  
  SELECT account_type, (payment_provider IS NOT NULL) 
  INTO v_current_journal, v_journal_was_paid
  FROM profiles WHERE id = p_user_id;
  
  -- Apply Journal benefit
  IF v_journal_benefit IS NOT NULL THEN
    IF v_current_journal IN ('free', 'trial', 'basic') OR v_current_journal IS NULL THEN
      UPDATE profiles SET
        account_type = v_journal_benefit,
        subscription_status = 'active',
        max_trades = CASE WHEN v_journal_benefit = 'premium' THEN 999999 ELSE 25 END,
        platform_bundle_journal_granted = TRUE,
        subscription_started_at = COALESCE(subscription_started_at, NOW()),
        updated_at = NOW()
      WHERE id = p_user_id;
      
      INSERT INTO platform_subscription_events (user_id, event_type, old_plan, new_plan, metadata)
      VALUES (p_user_id, 'bundle_applied', v_current_journal, v_journal_benefit,
        jsonb_build_object('benefit_type', 'journal', 'granted_plan', v_journal_benefit));
    END IF;
  END IF;
  
  -- Apply Newsletter benefit
  IF v_newsletter_benefit IS NOT NULL THEN
    IF v_newsletter_benefit = 'true' OR p_newsletter_choice = 'included' THEN
      UPDATE profiles SET
        newsletter_paid = TRUE,
        newsletter_status = 'active',
        newsletter_started_at = COALESCE(newsletter_started_at, NOW()),
        platform_bundle_newsletter_granted = TRUE,
        platform_bundle_newsletter_choice = COALESCE(p_newsletter_choice, 'included'),
        updated_at = NOW()
      WHERE id = p_user_id;
    END IF;
  END IF;
  
  RETURN jsonb_build_object(
    'success', true,
    'journal_granted', v_journal_benefit,
    'newsletter_choice', p_newsletter_choice,
    'newsletter_granted', (v_newsletter_benefit = 'true' OR p_newsletter_choice = 'included')
  );
END;
$$;


ALTER FUNCTION "public"."apply_platform_bundle"("p_user_id" "uuid", "p_platform_plan" "text", "p_newsletter_choice" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_affiliate_application"("p_application_id" "uuid", "p_approved_by" "uuid", "p_custom_code" "text" DEFAULT NULL::"text", "p_admin_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  app_record RECORD;
  v_affiliate_id UUID;
  v_code TEXT;
  v_use_code TEXT;
BEGIN
  -- Get application
  SELECT * INTO app_record FROM affiliate_applications WHERE id = p_application_id;
  
  IF app_record IS NULL THEN
    RAISE EXCEPTION 'Application not found';
  END IF;
  
  IF app_record.status != 'pending' AND app_record.status != 'under_review' THEN
    RAISE EXCEPTION 'Application is not pending. Current status: %', app_record.status;
  END IF;
  
  -- ✅ Priority: admin override > applicant requested_code > full_name fallback
  v_use_code := COALESCE(
    NULLIF(TRIM(p_custom_code), ''),
    NULLIF(TRIM(app_record.requested_code), ''),
    NULL
  );
  
  -- Generate code
  v_code := generate_affiliate_code(
    v_use_code,
    app_record.full_name
  );
  
  -- Create affiliate account
  INSERT INTO affiliates (
    user_id,
    application_id,
    display_name,
    email,
    phone,
    country,
    affiliate_code,
    coupon_code,
    status,
    current_tier,
    discount_tier,
    affiliate_type,
    commission_enabled
  ) VALUES (
    app_record.user_id,
    p_application_id,
    app_record.full_name,
    app_record.email,
    app_record.phone,
    app_record.country,
    v_code,
    v_code,
    'active',
    'tier_1',
    'standard',
    'regular',
    TRUE
  )
  RETURNING id INTO v_affiliate_id;
  
  -- Update application status
  UPDATE affiliate_applications
  SET 
    status = 'approved',
    reviewed_by = p_approved_by,
    reviewed_at = NOW(),
    admin_notes = COALESCE(p_admin_notes, admin_notes)
  WHERE id = p_application_id;
  
  -- Log activity
  INSERT INTO affiliate_activity_log (affiliate_id, activity_type, description, triggered_by, is_system_action)
  VALUES (v_affiliate_id, 'application_approved', 'Affiliate application approved. Code: ' || v_code, p_approved_by, FALSE);
  
  RETURN v_affiliate_id;
END;
$$;


ALTER FUNCTION "public"."approve_affiliate_application"("p_application_id" "uuid", "p_approved_by" "uuid", "p_custom_code" "text", "p_admin_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."archive_soft_deleted_users"() RETURNS TABLE("archived_count" integer, "archived_user_ids" "uuid"[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_archived_users UUID[];
  v_user RECORD;
  v_count INTEGER := 0;
BEGIN
  RAISE NOTICE '🔄 Starting archive process...';
  
  FOR v_user IN 
    SELECT * FROM public.profiles
    WHERE deleted_at IS NOT NULL
      AND deleted_at < NOW() - INTERVAL '30 days'
    ORDER BY deleted_at ASC
    LIMIT 1000
  LOOP
    BEGIN
      INSERT INTO public.profiles_archive SELECT v_user.*;
      DELETE FROM public.profiles WHERE id = v_user.id;
      v_archived_users := array_append(v_archived_users, v_user.id);
      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING '❌ Failed to archive user %: %', v_user.id, SQLERRM;
      CONTINUE;
    END;
  END LOOP;
  
  RAISE NOTICE '✅ Archived % users', v_count;
  RETURN QUERY SELECT v_count, v_archived_users;
END;
$$;


ALTER FUNCTION "public"."archive_soft_deleted_users"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_convert_company_to_ticker"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_ticker TEXT;
BEGIN
    -- If ticker looks like a company name (more than 5 characters), try to convert
    IF LENGTH(NEW.ticker) > 5 THEN
        -- Try to find matching ticker
        SELECT ctm.ticker INTO v_ticker
        FROM company_ticker_mapping ctm
        WHERE LOWER(NEW.ticker) = LOWER(ctm.company_name)
           OR LOWER(NEW.ticker) = ANY(SELECT LOWER(unnest(ctm.aliases)))
        LIMIT 1;
        
        -- If found, use the ticker instead
        IF v_ticker IS NOT NULL THEN
            RAISE NOTICE '[AutoConvert] Converting "%" to "%"', NEW.ticker, v_ticker;
            NEW.ticker := v_ticker;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_convert_company_to_ticker"() OWNER TO "postgres";


