CREATE OR REPLACE FUNCTION "public"."ban_user"("p_user_id" "uuid", "p_reason" "text" DEFAULT 'Violation of terms'::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Only admins can ban
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin')
  ) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;
  
  -- Cannot ban admins
  IF EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = p_user_id
      AND role IN ('admin', 'super_admin')
  ) THEN
    RAISE EXCEPTION 'Cannot ban admin users';
  END IF;
  
  UPDATE public.profiles
  SET 
    is_banned = TRUE,
    banned_at = NOW(),
    ban_reason = p_reason,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- Log action
  PERFORM public.log_admin_action(
    'ban_user',
    'user',
    p_user_id,
    jsonb_build_object('reason', p_reason)
  );
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."ban_user"("p_user_id" "uuid", "p_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."ban_user"("p_user_id" "uuid", "p_reason" "text") IS 'v8.5.9: Ban user (admin only, cannot ban other admins)';



CREATE OR REPLACE FUNCTION "public"."bulk_insert_trades"("p_trades" "jsonb") RETURNS TABLE("inserted_count" integer, "skipped_count" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_inserted INTEGER := 0;
    v_skipped INTEGER := 0;
    v_trade JSONB;
BEGIN
    FOR v_trade IN SELECT * FROM jsonb_array_elements(p_trades)
    LOOP
        BEGIN
            INSERT INTO trades (
                user_id, symbol, asset_class, side, quantity,
                entry_price, exit_price, stop_price, fees, fees_mode,
                open_at, close_at, pnl, broker, external_id,
                multiplier, import_source, broker_connection_id,
                broker_account_id, broker_trade_id, synced_at, raw_data
            ) VALUES (
                (v_trade->>'user_id')::UUID,
                v_trade->>'symbol',
                v_trade->>'asset_class',
                v_trade->>'side',
                (v_trade->>'quantity')::NUMERIC,
                (v_trade->>'entry_price')::NUMERIC,
                (v_trade->>'exit_price')::NUMERIC,
                (v_trade->>'stop_price')::NUMERIC,
                COALESCE((v_trade->>'fees')::NUMERIC, 0),
                COALESCE(v_trade->>'fees_mode', 'auto'),
                (v_trade->>'open_at')::TIMESTAMPTZ,
                (v_trade->>'close_at')::TIMESTAMPTZ,
                (v_trade->>'pnl')::NUMERIC,
                v_trade->>'broker',
                v_trade->>'external_id',
                (v_trade->>'multiplier')::NUMERIC,
                v_trade->>'import_source',
                (v_trade->>'broker_connection_id')::UUID,
                (v_trade->>'broker_account_id')::UUID,
                v_trade->>'broker_trade_id',
                COALESCE((v_trade->>'synced_at')::TIMESTAMPTZ, NOW()),
                v_trade->'raw_data'
            );
            v_inserted := v_inserted + 1;
        EXCEPTION WHEN unique_violation THEN
            v_skipped := v_skipped + 1;
        END;
    END LOOP;
    
    RETURN QUERY SELECT v_inserted, v_skipped;
END;
$$;


ALTER FUNCTION "public"."bulk_insert_trades"("p_trades" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bulk_lookup_tickers"("p_symbols" "text"[]) RETURNS TABLE("symbol" "text", "name" "text", "multiplier" numeric, "asset_class" "text", "found" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  WITH input_symbols AS (
    SELECT UPPER(TRIM(unnest(p_symbols))) as input_symbol
  )
  SELECT 
    i.input_symbol as symbol,
    t.name,
    COALESCE(t.multiplier, public.get_asset_multiplier(i.input_symbol)) as multiplier,
    t.asset_class,
    (t.symbol IS NOT NULL) as found
  FROM input_symbols i
  LEFT JOIN public.ticker_symbols t 
    ON t.symbol = i.input_symbol 
    AND t.is_active = TRUE;
END;
$$;


ALTER FUNCTION "public"."bulk_lookup_tickers"("p_symbols" "text"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."bulk_lookup_tickers"("p_symbols" "text"[]) IS 'v8.5.9: Batch lookup for multiple ticker symbols';



CREATE OR REPLACE FUNCTION "public"."bulk_update_published_reports_target"("p_ids" "uuid"[], "p_target_group" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_user_id UUID;
    v_is_admin BOOLEAN;
    v_updated_count INTEGER;
BEGIN
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Not authenticated');
    END IF;

    SELECT is_admin_user(v_user_id) INTO v_is_admin;
    IF NOT COALESCE(v_is_admin, false) THEN
        RETURN jsonb_build_object('success', false, 'error', 'Admin access required');
    END IF;

    IF p_target_group NOT IN ('all', 'top_secret', 'newsletter', 'trading_journal') THEN
        RETURN jsonb_build_object('success', false, 'error', 'Invalid target group');
    END IF;

    UPDATE published_reports
    SET 
        target_group = p_target_group,
        updated_at = NOW()
    WHERE id = ANY(p_ids);

    GET DIAGNOSTICS v_updated_count = ROW_COUNT;

    RETURN jsonb_build_object(
        'success', true,
        'updated_count', v_updated_count,
        'target_group', p_target_group
    );
END;
$$;


ALTER FUNCTION "public"."bulk_update_published_reports_target"("p_ids" "uuid"[], "p_target_group" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_affiliate_tier"("qualified_count" integer) RETURNS "public"."affiliate_tier"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF qualified_count >= 75 THEN
    RETURN 'tier_3';
  ELSIF qualified_count >= 20 THEN
    RETURN 'tier_2';
  ELSE
    RETURN 'tier_1';
  END IF;
END;
$$;


