CREATE OR REPLACE FUNCTION "public"."calculate_discounted_price"("p_code" "text", "p_plan" "text", "p_original_price" numeric) RETURNS TABLE("final_price" numeric, "discount_applied" numeric, "discount_description" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $_$
DECLARE
  v_validation RECORD;
  v_final_price NUMERIC;
  v_discount NUMERIC;
  v_description TEXT;
BEGIN
  -- Validate the code
  SELECT * INTO v_validation FROM validate_coupon_code(p_code, p_plan, NULL);
  
  IF NOT v_validation.is_valid THEN
    -- Return original price if code is invalid
    RETURN QUERY SELECT p_original_price, 0::NUMERIC, 'Invalid code'::TEXT;
    RETURN;
  END IF;
  
  -- Calculate based on discount type
  IF v_validation.code_type = 'affiliate' THEN
    -- Affiliate code: percentage discount
    v_discount := p_original_price * (v_validation.discount_percent / 100);
    v_final_price := p_original_price - v_discount;
    v_description := v_validation.discount_percent || '% affiliate discount';
    
  ELSIF v_validation.discount_type = 'percentage' THEN
    -- Percentage coupon
    v_discount := p_original_price * (v_validation.discount_percent / 100);
    v_final_price := p_original_price - v_discount;
    v_description := v_validation.discount_percent || '% off';
    
  ELSIF v_validation.discount_type = 'fixed_amount' THEN
    -- Fixed amount off
    v_discount := LEAST(v_validation.discount_amount_usd, p_original_price);
    v_final_price := p_original_price - v_discount;
    v_description := '$' || v_validation.discount_amount_usd || ' off';
    
  ELSIF v_validation.discount_type = 'fixed_price' THEN
    -- Fixed price for this plan
    IF v_validation.fixed_price_usd IS NOT NULL THEN
      v_final_price := v_validation.fixed_price_usd;
      v_discount := p_original_price - v_final_price;
      v_description := 'Special price: $' || v_final_price;
    ELSE
      -- No fixed price for this plan, return original
      v_final_price := p_original_price;
      v_discount := 0;
      v_description := 'Coupon not valid for this plan';
    END IF;
  ELSE
    v_final_price := p_original_price;
    v_discount := 0;
    v_description := 'Unknown discount type';
  END IF;
  
  -- Ensure final price is not negative
  v_final_price := GREATEST(v_final_price, 0);
  
  RETURN QUERY SELECT v_final_price, v_discount, v_description;
END;
$_$;


ALTER FUNCTION "public"."calculate_discounted_price"("p_code" "text", "p_plan" "text", "p_original_price" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_monthly_commissions"("for_month" "date") RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  ref_record RECORD;
  commission_rate NUMERIC(5,4);
  commission_amount NUMERIC(10,2);
  month_num INTEGER;
  commissions_created INTEGER := 0;
BEGIN
  FOR ref_record IN 
    SELECT ar.*, a.current_tier, a.id as aff_id, a.commission_enabled, a.affiliate_type
    FROM affiliate_referrals ar
    JOIN affiliates a ON ar.affiliate_id = a.id
    WHERE ar.status = 'qualified'
      AND ar.commission_eligible = TRUE
      AND ar.subscription_cancelled_at IS NULL
      AND ar.commission_end_date > for_month
      AND a.commission_enabled = TRUE
      AND a.affiliate_type = 'regular'
  LOOP
    -- Calculate which month this is
    month_num := EXTRACT(MONTH FROM AGE(for_month, ref_record.commission_start_date))::INTEGER + 1;
    
    -- Cap at 12 months
    IF month_num > 12 THEN
      CONTINUE;
    END IF;
    
    -- Determine commission rate - flat 10% for all plans
    IF ref_record.subscription_type = 'annual' THEN
      IF month_num > 1 THEN
        CONTINUE;
      END IF;
      commission_rate := 0.1000;
    ELSE
      commission_rate := 0.1000;
    END IF;
    
    commission_amount := ref_record.subscription_price_usd * commission_rate;
    
    -- Insert commission
    INSERT INTO affiliate_commissions (
      affiliate_id,
      referral_id,
      commission_type,
      commission_month,
      base_amount_usd,
      commission_rate,
      commission_amount_usd,
      tier_at_time,
      month_number,
      status
    ) VALUES (
      ref_record.affiliate_id,
      ref_record.id,
      CASE WHEN ref_record.subscription_type = 'annual' THEN 'annual_upfront' ELSE 'monthly_recurring' END,
      for_month,
      ref_record.subscription_price_usd,
      commission_rate,
      commission_amount,
      ref_record.current_tier,
      month_num,
      'pending'
    )
    ON CONFLICT (referral_id, commission_month) DO NOTHING;
    
    IF FOUND THEN
      commissions_created := commissions_created + 1;
      
      -- Update affiliate totals
      UPDATE affiliates 
      SET 
        total_pending_usd = total_pending_usd + commission_amount,
        total_earnings_usd = total_earnings_usd + commission_amount
      WHERE id = ref_record.affiliate_id;
      
      -- Update months commissioned
      UPDATE affiliate_referrals 
      SET months_commissioned = month_num
      WHERE id = ref_record.id;
    END IF;
  END LOOP;
  
  RETURN commissions_created;
END;
$$;


ALTER FUNCTION "public"."calculate_monthly_commissions"("for_month" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_prorated_upgrade"("p_user_id" "uuid", "p_new_plan" "text", "p_new_interval" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_current_profile RECORD;
  v_days_remaining INTEGER;
  v_days_in_period INTEGER;
  v_old_daily_rate NUMERIC;
  v_new_daily_rate NUMERIC;
  v_old_price NUMERIC;
  v_new_price NUMERIC;
  v_unused_credit NUMERIC;
  v_prorated_amount NUMERIC;
  v_discount NUMERIC;
BEGIN
  SELECT 
    account_type,
    subscription_interval,
    subscription_expires_at,
    subscription_started_at
  INTO v_current_profile
  FROM public.profiles
  WHERE id = p_user_id;
  
  IF v_current_profile.account_type = 'free' THEN
    v_new_price := public.get_current_price(p_new_plan, p_new_interval);
    
    RETURN jsonb_build_object(
      'is_new_subscription', true,
      'amount_to_charge', v_new_price,
      'prorated', false,
      'new_plan', p_new_plan,
      'new_interval', p_new_interval
    );
  END IF;
  
  IF (p_new_plan = 'basic' AND v_current_profile.account_type = 'premium') THEN
    RETURN jsonb_build_object(
      'error', 'Downgrade not supported mid-cycle. Cancel and resubscribe at end of period.',
      'is_downgrade', true
    );
  END IF;
  
  v_days_remaining := EXTRACT(DAY FROM (v_current_profile.subscription_expires_at - NOW()));
  
  IF v_days_remaining <= 0 THEN
    v_new_price := public.get_current_price(p_new_plan, p_new_interval);
    
    RETURN jsonb_build_object(
      'is_new_subscription', true,
      'amount_to_charge', v_new_price,
      'prorated', false,
      'reason', 'Previous subscription expired'
    );
  END IF;
  
  v_days_in_period := EXTRACT(DAY FROM (
    v_current_profile.subscription_expires_at - v_current_profile.subscription_started_at
  ));
  
  v_old_price := public.get_current_price(
    v_current_profile.account_type,
    v_current_profile.subscription_interval
  );
  
  v_new_price := public.get_current_price(p_new_plan, p_new_interval);
  
  v_old_daily_rate := v_old_price / NULLIF(v_days_in_period, 0);
  v_new_daily_rate := v_new_price / CASE p_new_interval
    WHEN 'monthly' THEN 30
    WHEN 'yearly' THEN 365
  END;
  
  v_unused_credit := v_old_daily_rate * v_days_remaining;
  v_prorated_amount := v_new_daily_rate * v_days_remaining;
  v_discount := v_unused_credit;
  
  RETURN jsonb_build_object(
    'is_upgrade', true,
    'prorated', true,
    'old_plan', v_current_profile.account_type,
    'new_plan', p_new_plan,
    'old_interval', v_current_profile.subscription_interval,
    'new_interval', p_new_interval,
    'days_remaining', v_days_remaining,
    'old_price', ROUND(v_old_price, 2),
    'new_price', ROUND(v_new_price, 2),
    'unused_credit', ROUND(v_unused_credit, 2),
    'prorated_charge_for_remaining_days', ROUND(v_prorated_amount, 2),
    'discount_applied', ROUND(v_discount, 2),
    'amount_to_charge', ROUND(v_new_price - v_discount + v_prorated_amount, 2)
  );
END;
$$;


ALTER FUNCTION "public"."calculate_prorated_upgrade"("p_user_id" "uuid", "p_new_plan" "text", "p_new_interval" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."calculate_prorated_upgrade"("p_user_id" "uuid", "p_new_plan" "text", "p_new_interval" "text") IS 'v8.5.9: SMART PRORATION: Calculates exact charge for mid-cycle upgrades with credit from unused days';



CREATE OR REPLACE FUNCTION "public"."calculate_sub_affiliate_commissions"("for_month" "date") RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  parent_record RECORD;
  child_commission_total NUMERIC(12,2);
  layer2_commission NUMERIC(10,2);
  commissions_created INTEGER := 0;
BEGIN
  FOR parent_record IN 
    SELECT a.*
    FROM affiliates a
    WHERE a.can_recruit_sub_affiliates = TRUE
      AND a.status = 'active'
      AND a.commission_enabled = TRUE
      AND a.affiliate_type = 'regular'
      AND EXISTS (SELECT 1 FROM affiliates sub WHERE sub.parent_affiliate_id = a.id)
  LOOP
    -- Sum sub-affiliate commissions for the month
    SELECT COALESCE(SUM(c.commission_amount_usd), 0) INTO child_commission_total
    FROM affiliate_commissions c
    JOIN affiliates sub ON c.affiliate_id = sub.id
    WHERE sub.parent_affiliate_id = parent_record.id
      AND c.commission_month = for_month
      AND c.status IN ('pending', 'confirmed');
    
    IF child_commission_total > 0 THEN
      layer2_commission := child_commission_total * 0.05;
      
      INSERT INTO affiliate_commissions (
        affiliate_id,
        commission_type,
        commission_month,
        base_amount_usd,
        commission_rate,
        commission_amount_usd,
        tier_at_time,
        status
      ) VALUES (
        parent_record.id,
        'sub_affiliate',
        for_month,
        child_commission_total,
        0.0500,
        layer2_commission,
        parent_record.current_tier,
        'pending'
      );
      
      commissions_created := commissions_created + 1;
      
      -- Update parent affiliate totals
      UPDATE affiliates 
      SET 
        total_sub_affiliate_earnings_usd = total_sub_affiliate_earnings_usd + layer2_commission,
        total_pending_usd = total_pending_usd + layer2_commission,
        total_earnings_usd = total_earnings_usd + layer2_commission
      WHERE id = parent_record.id;
    END IF;
  END LOOP;
  
  RETURN commissions_created;
END;
$$;


ALTER FUNCTION "public"."calculate_sub_affiliate_commissions"("for_month" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_create_trade"("p_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_account_type         TEXT;
  v_role                 TEXT;
  v_subscription_status  TEXT;
  v_is_in_trial          BOOLEAN;
  v_trial_ends_at        TIMESTAMPTZ;
  v_subscription_expires TIMESTAMPTZ;
  v_max_trades           INTEGER;
  v_monthly_count        INTEGER;
  v_lifetime_trades      BIGINT;
  v_platform_plan        TEXT := NULL;
  v_platform_status      TEXT := NULL;
  v_has_platform_cols    BOOLEAN;
BEGIN
  -- ✅ Check if platform columns exist (added by WHOP_DB)
  SELECT EXISTS (
    SELECT 1 FROM information_schema.columns 
    WHERE table_schema = 'public' 
      AND table_name = 'profiles' 
      AND column_name = 'platform_plan'
  ) INTO v_has_platform_cols;

  SELECT 
    account_type, role, subscription_status,
    is_in_trial, trial_ends_at, subscription_expires_at,
    max_trades, current_month_trades_count
  INTO 
    v_account_type, v_role, v_subscription_status,
    v_is_in_trial, v_trial_ends_at, v_subscription_expires,
    v_max_trades, v_monthly_count
  FROM public.profiles
  WHERE id = p_user_id;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  SELECT COUNT(*) INTO v_lifetime_trades
  FROM public.trades
  WHERE user_id = p_user_id AND deleted_at IS NULL;

  IF v_has_platform_cols THEN
    EXECUTE format(
      'SELECT platform_plan, platform_subscription_status FROM public.profiles WHERE id = %L',
      p_user_id
    ) INTO v_platform_plan, v_platform_status;
  END IF;

  -- Admins = unlimited
  IF v_role IN ('admin', 'super_admin') THEN
    RETURN TRUE;
  END IF;

  -- Premium/VIP/Beta/Admin/Trial = unlimited
  IF v_account_type IN ('premium', 'admin', 'vip', 'beta', 'trial') THEN
    RETURN TRUE;
  END IF;

  -- Platform Finotaur/Enterprise = unlimited
  IF v_platform_plan IN ('finotaur', 'platform_finotaur', 'enterprise', 'platform_enterprise')
     AND v_platform_status IN ('active', 'trial', 'trialing') THEN
    RETURN TRUE;
  END IF;

  -- Platform Core = 50/month
  IF v_platform_plan IN ('core', 'platform_core')
     AND v_platform_status IN ('active', 'trial', 'trialing') THEN
    RETURN COALESCE(v_monthly_count, 0) < 50;
  END IF;

  -- Free / platform_free / NULL = 15 lifetime
  IF v_account_type IN ('free', 'platform_free') OR v_account_type IS NULL THEN
    RETURN COALESCE(v_lifetime_trades, 0) < 15;
  END IF;

  -- Basic
  IF v_account_type = 'basic' THEN
    IF (v_subscription_status = 'trial' OR COALESCE(v_is_in_trial, FALSE))
       AND v_trial_ends_at IS NOT NULL
       AND v_trial_ends_at < NOW() THEN
      RETURN FALSE;
    END IF;
    IF v_subscription_status = 'expired' THEN
      RETURN FALSE;
    END IF;
    IF v_subscription_status = 'cancelled'
       AND (v_subscription_expires IS NULL
            OR v_subscription_expires < NOW()) THEN
      RETURN FALSE;
    END IF;
    RETURN COALESCE(v_monthly_count, 0) < COALESCE(v_max_trades, 25);
  END IF;

  RETURN FALSE;
END;
$$;


ALTER FUNCTION "public"."can_create_trade"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."can_create_trade"("p_user_id" "uuid") IS 'v10.1.0-SAFE: עובד גם לפני WHOP_DB. platform_plan נבדק דינמית. FREE=15 lifetime, BASIC=25/month, PREMIUM=unlimited.';



CREATE OR REPLACE FUNCTION "public"."can_user_use_coupon"("p_coupon_id" "uuid", "p_user_id" "uuid", "p_plan" "text" DEFAULT NULL::"text") RETURNS TABLE("can_use" boolean, "reason" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_coupon RECORD;
  v_user_usage_count INTEGER;
  v_user_has_paid_before BOOLEAN;
  v_is_new_user BOOLEAN;
BEGIN
  -- Get coupon details
  SELECT * INTO v_coupon FROM admin_coupons WHERE id = p_coupon_id;
  
  IF v_coupon IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Coupon not found'::TEXT;
    RETURN;
  END IF;
  
  -- Check if coupon is active
  IF NOT v_coupon.is_active THEN
    RETURN QUERY SELECT FALSE, 'Coupon is not active'::TEXT;
    RETURN;
  END IF;
  
  -- Check validity dates
  IF v_coupon.valid_from IS NOT NULL AND v_coupon.valid_from > NOW() THEN
    RETURN QUERY SELECT FALSE, 'Coupon is not yet valid'::TEXT;
    RETURN;
  END IF;
  
  IF v_coupon.valid_until IS NOT NULL AND v_coupon.valid_until < NOW() THEN
    RETURN QUERY SELECT FALSE, 'Coupon has expired'::TEXT;
    RETURN;
  END IF;
  
  -- Check max uses (global)
  IF v_coupon.max_uses IS NOT NULL AND v_coupon.current_uses >= v_coupon.max_uses THEN
    RETURN QUERY SELECT FALSE, 'Coupon usage limit reached'::TEXT;
    RETURN;
  END IF;
  
  -- Check max uses per user
  IF v_coupon.max_uses_per_user IS NOT NULL THEN
    SELECT COUNT(*) INTO v_user_usage_count
    FROM coupon_usage_log
    WHERE coupon_id = p_coupon_id AND user_id = p_user_id;
    
    IF v_user_usage_count >= v_coupon.max_uses_per_user THEN
      RETURN QUERY SELECT FALSE, 'You have already used this coupon the maximum number of times'::TEXT;
      RETURN;
    END IF;
  END IF;
  
  -- Check single use per user (for single_use_per_user duration type)
  IF v_coupon.duration_type = 'single_use_per_user' THEN
    IF EXISTS (SELECT 1 FROM coupon_usage_log WHERE coupon_id = p_coupon_id AND user_id = p_user_id) THEN
      RETURN QUERY SELECT FALSE, 'You have already used this coupon'::TEXT;
      RETURN;
    END IF;
  END IF;
  
  -- Check first payment only
  IF v_coupon.first_time_only OR v_coupon.duration_type = 'first_payment_only' THEN
    SELECT EXISTS (
      SELECT 1 FROM affiliate_referrals 
      WHERE referred_user_id = p_user_id 
      AND first_payment_date IS NOT NULL
    ) INTO v_user_has_paid_before;
    
    IF v_user_has_paid_before THEN
      RETURN QUERY SELECT FALSE, 'This coupon is only for first-time payments'::TEXT;
      RETURN;
    END IF;
  END IF;
  
  -- Check new users only
  IF v_coupon.new_users_only THEN
    -- User is considered "new" if account was created in the last 7 days
    SELECT EXISTS (
      SELECT 1 FROM auth.users 
      WHERE id = p_user_id 
      AND created_at > NOW() - INTERVAL '7 days'
    ) INTO v_is_new_user;
    
    IF NOT v_is_new_user THEN
      RETURN QUERY SELECT FALSE, 'This coupon is only for new users'::TEXT;
      RETURN;
    END IF;
  END IF;
  
  -- Check applicable plans
  IF v_coupon.applicable_plans IS NOT NULL AND p_plan IS NOT NULL THEN
    IF NOT (p_plan = ANY(v_coupon.applicable_plans)) THEN
      RETURN QUERY SELECT FALSE, 'This coupon is not valid for the selected plan'::TEXT;
      RETURN;
    END IF;
  END IF;
  
  -- All checks passed
  RETURN QUERY SELECT TRUE, 'Coupon is valid'::TEXT;
END;
$$;


ALTER FUNCTION "public"."can_user_use_coupon"("p_coupon_id" "uuid", "p_user_id" "uuid", "p_plan" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_newsletter_subscription"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_profile RECORD;
  v_membership_id TEXT;
BEGIN
  SELECT 
    newsletter_status,
    newsletter_whop_membership_id,
    newsletter_expires_at
  INTO v_profile
  FROM profiles 
  WHERE id = p_user_id;
  
  IF v_profile IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  IF v_profile.newsletter_status NOT IN ('active', 'trial') THEN
    RETURN jsonb_build_object('success', false, 'error', 'No active subscription to cancel');
  END IF;
  
  v_membership_id := v_profile.newsletter_whop_membership_id;
  
  UPDATE profiles SET
    newsletter_cancel_at_period_end = TRUE,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, scheduled_at, metadata
  ) VALUES (
    p_user_id, 
    'cancel_scheduled', 
    'newsletter', 
    'none',
    v_profile.newsletter_expires_at,
    jsonb_build_object(
      'whop_membership_id', v_membership_id,
      'cancelled_by', 'user',
      'subscription_type', 'newsletter'
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'message', 'Subscription will be cancelled at period end',
    'membership_id', v_membership_id,
    'access_until', v_profile.newsletter_expires_at
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."cancel_newsletter_subscription"("p_user_id" "uuid") OWNER TO "postgres";


