      'cancelled_by', 'user',
      'subscription_type', 'newsletter'
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'message', 'Newsletter subscription will be cancelled at period end',
    'membership_id', v_profile.newsletter_whop_membership_id,
    'access_until', v_profile.newsletter_expires_at
  );
  
EXCEPTION WHEN OTHERS THEN
