CREATE OR REPLACE FUNCTION "public"."cancel_platform_subscription"("p_whop_membership_id" "text", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_current_plan TEXT;
  v_expires_at TIMESTAMPTZ;
BEGIN
  SELECT id, platform_plan, platform_subscription_expires_at 
  INTO v_user_id, v_current_plan, v_expires_at
  FROM profiles WHERE platform_whop_membership_id = p_whop_membership_id;
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Membership not found');
  END IF;
  
  UPDATE profiles SET
    platform_subscription_status = 'cancelled',
    platform_cancel_at_period_end = TRUE,
    platform_cancelled_at = NOW(),
    updated_at = NOW()
  WHERE id = v_user_id;
  
  INSERT INTO platform_subscription_events (user_id, event_type, new_plan, reason, metadata)
  VALUES (v_user_id, 'cancelled', v_current_plan, p_reason,
    jsonb_build_object('effective_date', v_expires_at, 'cancel_at_period_end', true));
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'plan', v_current_plan,
    'effective_date', v_expires_at
  );
END;
$$;


ALTER FUNCTION "public"."cancel_platform_subscription"("p_whop_membership_id" "text", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_subscription"("p_user_id" "uuid", "p_reason" "text" DEFAULT NULL::"text", "p_immediate" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_profile RECORD;
  v_effective_date TIMESTAMPTZ;
  v_days_remaining INTEGER;
BEGIN
  SELECT * INTO v_profile
  FROM public.profiles
  WHERE id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  IF v_profile.account_type = 'free' THEN
    RETURN jsonb_build_object('success', false, 'error', 'No active subscription');
  END IF;
  
  IF p_immediate THEN
  v_effective_date := NOW();
  
  UPDATE public.profiles
  SET 
    previous_account_type = account_type,
    subscription_status = 'expired',
    subscription_interval = NULL,
    payment_provider = NULL,
    subscription_expires_at = NOW(),
    subscription_cancel_at_period_end = FALSE,
    cancellation_reason = p_reason,
    cancellation_requested_at = NOW(),
    cancellation_effective_date = NOW(),
    updated_at = NOW()
  WHERE id = p_user_id;
  ELSE
    -- Graceful cancellation - cancel at period end
    v_effective_date := COALESCE(v_profile.subscription_expires_at, NOW());
    
UPDATE public.profiles
    SET 
      previous_account_type = v_profile.account_type,
      subscription_status = 'cancelled',
      subscription_cancel_at_period_end = TRUE,
      cancellation_reason = p_reason,
      cancellation_requested_at = NOW(),
      cancellation_effective_date = v_effective_date,
      updated_at = NOW()
    WHERE id = p_user_id;
  END IF;
  
  -- Log to subscription_changes
  INSERT INTO public.subscription_changes (
    user_id, change_type, from_plan, to_plan, effective_date, reason
  ) VALUES (
    p_user_id, 'cancel', v_profile.account_type, 'free', v_effective_date, p_reason
  );
  
  v_days_remaining := GREATEST(0, EXTRACT(DAY FROM (v_effective_date - NOW()))::INTEGER);
  
  RETURN jsonb_build_object(
    'success', true,
    'message', CASE 
      WHEN p_immediate THEN 'Subscription cancelled immediately'
      ELSE format('Subscription will cancel on %s', v_effective_date::DATE)
    END,
    'data', jsonb_build_object(
      'effective_date', v_effective_date,
      'days_remaining', v_days_remaining,
      'immediate', p_immediate
    )
  );
END;
$$;


ALTER FUNCTION "public"."cancel_subscription"("p_user_id" "uuid", "p_reason" "text", "p_immediate" boolean) OWNER TO "postgres";


