  RETURN jsonb_build_object(
    'success', true,
    'message', 'Subscription will be cancelled at period end',
    'membership_id', v_membership_id,
    'access_until', v_profile.top_secret_expires_at
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."cancel_top_secret_subscription"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_top_secret_subscription_rpc"("p_user_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_profile RECORD;
BEGIN
  SELECT 
    top_secret_status,
    top_secret_whop_membership_id,
    top_secret_expires_at,
    top_secret_cancel_at_period_end
  INTO v_profile
  FROM profiles 
  WHERE id = p_user_id;
  
  IF v_profile IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  IF v_profile.top_secret_status != 'active' THEN
    RETURN jsonb_build_object('success', false, 'error', 'No active Top Secret subscription to cancel');
  END IF;
  
  IF COALESCE(v_profile.top_secret_cancel_at_period_end, FALSE) THEN
    RETURN jsonb_build_object(
      'success', false, 
      'error', 'Top Secret is already scheduled for cancellation',
      'expiresAt', v_profile.top_secret_expires_at
    );
  END IF;
  
  UPDATE profiles SET
    top_secret_cancel_at_period_end = TRUE,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, scheduled_at, reason, metadata
  ) VALUES (
    p_user_id, 'cancel_scheduled', 'top_secret', 'none',
    v_profile.top_secret_expires_at, p_reason,
    jsonb_build_object(
      'whop_membership_id', v_profile.top_secret_whop_membership_id,
      'cancelled_by', 'user',
      'subscription_type', 'top_secret'
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'message', 'Top Secret subscription will be cancelled at period end',
    'membership_id', v_profile.top_secret_whop_membership_id,
    'access_until', v_profile.top_secret_expires_at
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."cancel_top_secret_subscription_rpc"("p_user_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_affiliate_cron_health"() RETURNS TABLE("job_name" "text", "last_run" timestamp with time zone, "status" "text")
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    j.jobname::TEXT,
    (SELECT MAX(end_time) FROM cron.job_run_details WHERE jobid = j.jobid),
    CASE 
      WHEN (SELECT MAX(end_time) FROM cron.job_run_details WHERE jobid = j.jobid) > NOW() - INTERVAL '25 hours'
      THEN 'healthy'
      ELSE 'stale'
    END
  FROM cron.job j
  WHERE j.jobname LIKE 'affiliate_%';
END;
$$;


ALTER FUNCTION "public"."check_affiliate_cron_health"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_ai_usage"("p_user_id" "uuid") RETURNS TABLE("questions_today" integer, "limit_reached" boolean, "tier" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_tier TEXT;
  v_limit INT;
  v_count INT;
BEGIN
  -- Get user's tier
  SELECT COALESCE(profiles.tier, 'FREE') INTO v_tier
  FROM profiles WHERE id = p_user_id;
  
  -- Set limit based on tier
  v_limit := CASE v_tier
    WHEN 'PREMIUM' THEN 999999  -- Unlimited
    WHEN 'BASIC' THEN 20
    ELSE 5  -- FREE
  END;
  
  -- Get today's count
  SELECT COALESCE(questions_count, 0) INTO v_count
  FROM ai_usage
  WHERE user_id = p_user_id AND date = CURRENT_DATE;
  
  IF v_count IS NULL THEN
    v_count := 0;
  END IF;
  
  RETURN QUERY SELECT v_count, v_count >= v_limit, v_tier;
END;
$$;


ALTER FUNCTION "public"."check_ai_usage"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_ai_usage"("p_user_id" "uuid") IS 'Simple check if user has reached their daily AI question limit';



CREATE OR REPLACE FUNCTION "public"."check_ai_usage_limit"("p_user_id" "uuid") RETURNS TABLE("questions_today" integer, "tokens_today" integer, "daily_limit" integer, "limit_reached" boolean, "user_tier" "text", "remaining_questions" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_tier TEXT;
  v_limit INTEGER;
  v_count INTEGER;
  v_tokens INTEGER;
BEGIN
  -- Get user's tier from profiles
  SELECT COALESCE(tier, 'FREE') INTO v_tier
  FROM profiles WHERE id = p_user_id;
  
  -- Set limit based on tier
  v_limit := CASE v_tier
    WHEN 'PREMIUM' THEN 999999  -- Effectively unlimited
    WHEN 'BASIC' THEN 20
    ELSE 5  -- FREE tier
  END;
  
  -- Get today's usage
  SELECT 
    COALESCE(questions_count, 0),
    COALESCE(tokens_used, 0)
  INTO v_count, v_tokens
  FROM ai_usage
  WHERE user_id = p_user_id AND date = CURRENT_DATE;
  
  -- Handle case where no usage record exists
  IF v_count IS NULL THEN
    v_count := 0;
    v_tokens := 0;
  END IF;
  
  RETURN QUERY SELECT 
    v_count,
    v_tokens,
    v_limit,
    v_count >= v_limit,
    v_tier,
    GREATEST(0, v_limit - v_count);
END;
$$;


ALTER FUNCTION "public"."check_ai_usage_limit"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_ai_usage_limit"("p_user_id" "uuid") IS 'Checks if user has reached their daily AI question limit based on tier';



CREATE OR REPLACE FUNCTION "public"."check_expired_subscriptions"() RETURNS TABLE("user_id" "uuid", "old_plan" "text", "email" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH expired_users AS (
    SELECT DISTINCT sp.user_id
    FROM public.subscription_periods sp
    WHERE sp.period_end < NOW()
      AND sp.auto_renew = FALSE
      AND NOT EXISTS (
        SELECT 1 FROM public.subscription_periods sp2
        WHERE sp2.user_id = sp.user_id AND sp2.period_end > NOW()
      )
  )
UPDATE public.profiles p
SET 
  previous_account_type = account_type,
  subscription_status = 'expired',
  subscription_interval = NULL,
  updated_at = NOW()
FROM expired_users eu
WHERE p.id = eu.user_id 
  AND p.role NOT IN ('admin', 'super_admin')
RETURNING p.id, p.account_type, p.email;
END;
$$;


ALTER FUNCTION "public"."check_expired_subscriptions"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_expired_subscriptions"() IS 'v8.5.10: Checks and downgrades expired subscriptions to free plan';



CREATE OR REPLACE FUNCTION "public"."check_expired_top_secret_trials"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_expired_count INTEGER := 0;
  v_user RECORD;
BEGIN
  FOR v_user IN
    SELECT id, email, top_secret_trial_ends_at
    FROM profiles
    WHERE top_secret_is_in_trial = TRUE
      AND top_secret_trial_ends_at < NOW()
      AND top_secret_whop_membership_id IS NULL
  LOOP
    UPDATE profiles SET
      top_secret_is_in_trial = FALSE,
      top_secret_enabled = FALSE,
      top_secret_status = 'inactive',
      updated_at = NOW()
    WHERE id = v_user.id;

    INSERT INTO subscription_events (user_id, event_type, old_plan, metadata)
    VALUES (v_user.id, 'trial_expired', 'top_secret',
      jsonb_build_object('trial_ended_at', v_user.top_secret_trial_ends_at));

    v_expired_count := v_expired_count + 1;
  END LOOP;

  RETURN v_expired_count;
END;
$$;


ALTER FUNCTION "public"."check_expired_top_secret_trials"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_ism_report_status"("p_month" "text") RETURNS TABLE("report_month" "text", "status" "text", "can_generate" boolean, "reason" "text", "existing_report_id" "text", "ism_available" boolean, "last_check" timestamp with time zone)
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COALESCE(t.report_month, p_month),
    COALESCE(t.status, 'pending_ism'),
    CASE 
      WHEN t.status = 'report_generated' AND NOT COALESCE(t.is_admin_override, false) THEN false
      WHEN t.status = 'generating' THEN false
      ELSE true
    END,
    CASE 
      WHEN t.status = 'report_generated' THEN 'Report already exists for this month'
      WHEN t.status = 'generating' THEN 'Generation in progress'
      ELSE 'Ready to generate'
    END,
    t.report_id,
    COALESCE(t.ism_data_available, false),
    t.last_ism_check
  FROM ism_report_tracking t
  WHERE t.report_month = p_month
  
  UNION ALL
  
  SELECT 
    p_month,
    'pending_ism',
    true,
    'No tracking record - ready to generate',
    NULL,
    false,
    NULL
  WHERE NOT EXISTS (SELECT 1 FROM ism_report_tracking WHERE ism_report_tracking.report_month = p_month);
END;
$$;


ALTER FUNCTION "public"."check_ism_report_status"("p_month" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_platform_trial_eligibility"("p_user_id" "uuid", "p_plan" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_trial_used_at TIMESTAMPTZ;
  v_current_plan TEXT;
  v_plan_info RECORD;
BEGIN
  IF p_plan = 'pro' THEN
    SELECT platform_pro_trial_used_at, platform_plan 
    INTO v_trial_used_at, v_current_plan
    FROM profiles WHERE id = p_user_id;
  ELSIF p_plan = 'core' THEN
    SELECT platform_core_trial_used_at, platform_plan 
    INTO v_trial_used_at, v_current_plan
    FROM profiles WHERE id = p_user_id;
  ELSE
    RETURN jsonb_build_object('eligible', false, 'reason', 'Invalid plan');
  END IF;
  
  SELECT trial_days, trial_once_only INTO v_plan_info
  FROM platform_plan_mapping
  WHERE finotaur_plan = p_plan AND is_active = TRUE
  LIMIT 1;
  
  IF v_plan_info IS NULL THEN
    RETURN jsonb_build_object('eligible', false, 'reason', 'Plan not found');
  END IF;
  
  IF v_plan_info.trial_days = 0 THEN
    RETURN jsonb_build_object('eligible', false, 'reason', 'Plan has no trial');
  END IF;
  
  IF v_plan_info.trial_once_only AND v_trial_used_at IS NOT NULL THEN
    RETURN jsonb_build_object(
      'eligible', false, 
      'reason', 'Trial already used',
      'used_at', v_trial_used_at
    );
  END IF;
  
  RETURN jsonb_build_object(
    'eligible', true,
    'trial_days', v_plan_info.trial_days,
    'once_only', v_plan_info.trial_once_only,
    'current_plan', v_current_plan
  );
END;
$$;


ALTER FUNCTION "public"."check_platform_trial_eligibility"("p_user_id" "uuid", "p_plan" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_rate_limit"("p_endpoint" "text", "p_max_requests" integer DEFAULT 100, "p_window_minutes" integer DEFAULT 1) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_count INTEGER;
  v_user_id UUID;
BEGIN
  v_user_id := auth.uid();
  
  IF v_user_id IS NULL THEN
    RETURN FALSE;
  END IF;
  
  -- Count requests in time window
  SELECT COUNT(*) INTO v_count
  FROM public.api_rate_limits
  WHERE user_id = v_user_id
    AND endpoint = p_endpoint
    AND window_start > NOW() - (p_window_minutes || ' minutes')::INTERVAL;
  
  -- Exceeded limit?
  IF v_count >= p_max_requests THEN
    RETURN FALSE;
  END IF;
  
  -- Log request
  INSERT INTO public.api_rate_limits (user_id, endpoint)
  VALUES (v_user_id, p_endpoint);
  
  -- Cleanup old entries (async)
  DELETE FROM public.api_rate_limits
  WHERE window_start < NOW() - INTERVAL '1 hour';
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."check_rate_limit"("p_endpoint" "text", "p_max_requests" integer, "p_window_minutes" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_rate_limit"("p_endpoint" "text", "p_max_requests" integer, "p_window_minutes" integer) IS 'Rate limiting: default 100 requests/minute. Returns FALSE if exceeded.';



CREATE OR REPLACE FUNCTION "public"."check_referral_trial_status"("p_referral_id" "uuid") RETURNS TABLE("is_in_trial" boolean, "trial_ends_at" timestamp with time zone, "days_remaining" integer, "has_paid" boolean, "can_qualify" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_referral RECORD;
  v_user_profile RECORD;
BEGIN
  -- Get referral info
  SELECT * INTO v_referral FROM affiliate_referrals WHERE id = p_referral_id;
  
  IF v_referral IS NULL THEN
    RETURN QUERY SELECT FALSE, NULL::TIMESTAMPTZ, 0, FALSE, FALSE;
    RETURN;
  END IF;
  
  -- Get user profile
  SELECT * INTO v_user_profile FROM profiles WHERE id = v_referral.referred_user_id;
  
  IF v_user_profile IS NULL THEN
    RETURN QUERY SELECT FALSE, NULL::TIMESTAMPTZ, 0, FALSE, FALSE;
    RETURN;
  END IF;
  
  RETURN QUERY SELECT 
    COALESCE(v_user_profile.is_in_trial, FALSE),
    v_user_profile.trial_ends_at,
    CASE 
      WHEN v_user_profile.trial_ends_at IS NOT NULL 
      THEN EXTRACT(DAY FROM (v_user_profile.trial_ends_at - NOW()))::INTEGER
      ELSE 0
    END,
    v_referral.first_payment_date IS NOT NULL,
    -- Can qualify only after trial ends AND payment received AND 7 more days
    v_referral.first_payment_date IS NOT NULL 
    AND (v_referral.first_payment_date + INTERVAL '7 days') <= NOW()
    AND v_referral.subscription_cancelled_at IS NULL;
END;
$$;


ALTER FUNCTION "public"."check_referral_trial_status"("p_referral_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_subscription_status"("p_user_id" "uuid") RETURNS TABLE("is_active" boolean, "account_type" "text", "days_remaining" integer, "should_downgrade" boolean, "subscription_status" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_profile RECORD;
BEGIN
  SELECT 
    p.account_type,
    p.subscription_expires_at,  -- ✅ FIXED: was subscription_end_date
    p.subscription_status,
    p.subscription_cancel_at_period_end
  INTO v_profile
  FROM public.profiles p
  WHERE p.id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'free'::TEXT, 0, FALSE, 'none'::TEXT;
    RETURN;
  END IF;
  
  RETURN QUERY SELECT
    v_profile.account_type != 'free',
    v_profile.account_type,
    CASE 
      WHEN v_profile.subscription_expires_at IS NOT NULL 
      THEN GREATEST(0, EXTRACT(DAY FROM (v_profile.subscription_expires_at - NOW()))::INTEGER)
      ELSE NULL::INTEGER
    END,
    (v_profile.subscription_expires_at IS NOT NULL 
      AND v_profile.subscription_expires_at < NOW()
      AND v_profile.account_type != 'free'),
    COALESCE(v_profile.subscription_status, 'none')::TEXT;
END;
$$;


ALTER FUNCTION "public"."check_subscription_status"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_subscription_status"("p_user_id" "uuid") IS 'v9.4.2-SYNCED: Uses subscription_expires_at (not subscription_end_date)';



CREATE OR REPLACE FUNCTION "public"."check_system_health"() RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_result JSONB;
  v_db_size NUMERIC;
  v_max_connections INTEGER;
  v_current_connections INTEGER;
  v_rls_count INTEGER;
  v_function_count INTEGER;
  v_matview_count INTEGER;
  v_total_users BIGINT;
  v_total_trades BIGINT;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  -- Get database size in GB
  SELECT pg_database_size(current_database())::NUMERIC / 1073741824 INTO v_db_size;
  
  -- Get connection info
  SELECT setting::INTEGER INTO v_max_connections 
  FROM pg_settings WHERE name = 'max_connections';
  
  SELECT COUNT(*)::INTEGER INTO v_current_connections 
  FROM pg_stat_activity;
  
  -- Get RLS enabled tables count
  SELECT COUNT(*) INTO v_rls_count 
  FROM pg_tables 
  WHERE schemaname = 'public' AND rowsecurity = true;
  
  -- Get function count
  SELECT COUNT(*) INTO v_function_count 
  FROM pg_proc p 
  JOIN pg_namespace n ON p.pronamespace = n.oid 
  WHERE n.nspname = 'public';
  
  -- Get materialized view count
  SELECT COUNT(*) INTO v_matview_count 
  FROM pg_matviews 
  WHERE schemaname = 'public';
  
  -- Get user and trade counts
  SELECT COUNT(*) INTO v_total_users FROM public.profiles WHERE deleted_at IS NULL;
  SELECT COUNT(*) INTO v_total_trades FROM public.trades WHERE deleted_at IS NULL;
  
  v_result := jsonb_build_object(
    'database', jsonb_build_object(
      'status', CASE 
        WHEN v_db_size < 8 THEN 'healthy' 
        WHEN v_db_size < 9 THEN 'warning' 
        ELSE 'critical' 
      END,
      'size_gb', ROUND(v_db_size, 4),
      'max_size_gb', 10
    ),
    'connections', jsonb_build_object(
      'status', CASE 
        WHEN v_current_connections < (v_max_connections * 0.7) THEN 'healthy' 
        WHEN v_current_connections < (v_max_connections * 0.9) THEN 'warning' 
        ELSE 'critical' 
      END,
      'current', v_current_connections,
      'max', v_max_connections,
      'usage_percent', ROUND((v_current_connections::NUMERIC / v_max_connections * 100), 1)
    ),
    'rls', jsonb_build_object(
      'status', 'healthy',
      'enabled_tables', v_rls_count
    ),
    'functions', jsonb_build_object(
      'status', 'healthy',
      'total', v_function_count
    ),
    'materialized_views', jsonb_build_object(
      'status', 'healthy',
      'total', v_matview_count
    ),
    'data', jsonb_build_object(
      'total_users', v_total_users,
      'total_trades', v_total_trades
    ),
    'checked_at', NOW()
  );
  
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."check_system_health"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_system_health"() IS 'v8.5.10: Comprehensive system health check for admin dashboard.';



CREATE OR REPLACE FUNCTION "public"."check_usage_warning"("target_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  profile_record RECORD;
  usage_percentage NUMERIC;
  trades_used INTEGER;
BEGIN
  SELECT 
    max_trades,
    current_month_trades_count,
    trade_count,
    account_type,
    last_warning_shown_at
  INTO profile_record
  FROM public.profiles
  WHERE id = target_user_id;
  
  -- Premium users never get warnings
  IF profile_record.account_type = 'premium' THEN
    RETURN FALSE;
  END IF;
  
  -- Handle NULL/zero max_trades
  IF profile_record.max_trades IS NULL OR profile_record.max_trades = 0 THEN
    RETURN FALSE;
  END IF;
  
  -- FREE uses lifetime count, others use monthly
  IF profile_record.account_type = 'free' THEN
    trades_used := COALESCE(profile_record.trade_count, 0);
  ELSE
    trades_used := COALESCE(profile_record.current_month_trades_count, 0);
  END IF;
  
  usage_percentage := (trades_used::NUMERIC / profile_record.max_trades::NUMERIC) * 100;
  
  -- Show warning at 80%, max once per 24 hours
  IF usage_percentage >= 80 AND 
     (profile_record.last_warning_shown_at IS NULL OR 
      profile_record.last_warning_shown_at < NOW() - INTERVAL '24 hours') THEN
    RETURN TRUE;
  END IF;
  
  RETURN FALSE;
END;
$$;


ALTER FUNCTION "public"."check_usage_warning"("target_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_usage_warning"("target_user_id" "uuid") IS 'v8.5.10: Returns TRUE if user should see 80% usage warning. Max once per 24h.';



