CREATE OR REPLACE FUNCTION "public"."cleanup_old_embeddings"("p_report_type" "text", "p_keep_count" integer DEFAULT 12) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_deleted INTEGER;
BEGIN
  WITH reports_to_keep AS (
    SELECT DISTINCT report_id
    FROM report_embeddings
    WHERE report_type = p_report_type
    ORDER BY report_date DESC
    LIMIT p_keep_count
  ),
  deleted AS (
    DELETE FROM report_embeddings
    WHERE report_type = p_report_type
      AND report_id NOT IN (SELECT report_id FROM reports_to_keep)
    RETURNING id
  )
  SELECT COUNT(*) INTO v_deleted FROM deleted;
  
  RETURN v_deleted;
END;
$$;


