CREATE OR REPLACE FUNCTION "public"."cleanup_old_price_history"() RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_deleted INTEGER;
BEGIN
  DELETE FROM pick_price_history
  WHERE pick_tracking_id IN (
    SELECT id FROM pick_tracking 
    WHERE status NOT IN ('active', 'hit_target_1')
    AND closed_at < NOW() - INTERVAL '90 days'
  );
  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$$;


