CREATE OR REPLACE FUNCTION "public"."cleanup_old_sync_logs"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    deleted_count INT;
BEGIN
    WITH logs_to_keep AS (
        SELECT id
        FROM (
            SELECT id, 
                   ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY created_at DESC) as rn
            FROM public.snaptrade_sync_log
        ) ranked
        WHERE rn <= 100
    )
    DELETE FROM public.snaptrade_sync_log
    WHERE id NOT IN (SELECT id FROM logs_to_keep);
    
    GET DIAGNOSTICS deleted_count = ROW_COUNT;
    RETURN deleted_count;
END;
$$;


