CREATE OR REPLACE FUNCTION "public"."cleanup_old_updates"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  UPDATE system_updates 
  SET is_active = false
  WHERE created_at < NOW() - INTERVAL '30 days'
    AND is_active = true
    AND is_pinned = false;
END;
$$;


ALTER FUNCTION "public"."cleanup_old_updates"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cleanup_top5_old_data"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  DELETE FROM top5_scans WHERE scan_date < NOW() - INTERVAL '30 days';
  DELETE FROM earnings_reports WHERE processed_at < NOW() - INTERVAL '365 days';
END;
$$;


