CREATE OR REPLACE FUNCTION "public"."close_tradingview_trade"("p_user_id" "uuid", "p_symbol" "text", "p_side" "text", "p_exit_price" numeric) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_trade_id UUID;
  v_entry_price NUMERIC;
  v_outcome TEXT;
BEGIN
  -- Find the most recent open trade matching criteria (with lock)
  SELECT id, entry_price
  INTO v_trade_id, v_entry_price
  FROM public.trades
  WHERE user_id = p_user_id
    AND symbol = p_symbol
    AND side = p_side
    AND exit_price IS NULL
    AND deleted_at IS NULL
  ORDER BY open_at DESC
  LIMIT 1
  FOR UPDATE SKIP LOCKED;

  IF v_trade_id IS NULL THEN
    RAISE EXCEPTION 'No open trade found for symbol % side %', p_symbol, p_side;
  END IF;

  -- Determine outcome
  IF (p_exit_price > v_entry_price AND p_side = 'LONG') OR
     (p_exit_price < v_entry_price AND p_side = 'SHORT') THEN
    v_outcome := 'WIN';
  ELSIF (p_exit_price < v_entry_price AND p_side = 'LONG') OR
        (p_exit_price > v_entry_price AND p_side = 'SHORT') THEN
    v_outcome := 'LOSS';
  ELSE
    v_outcome := 'BE';
  END IF;

  -- Update the trade (unified trigger will calculate PnL)
  UPDATE public.trades
  SET 
    exit_price = p_exit_price,
    outcome = v_outcome,
    close_at = NOW(),
    updated_at = NOW()
  WHERE id = v_trade_id;

  RETURN v_trade_id;
END;
$$;


ALTER FUNCTION "public"."close_tradingview_trade"("p_user_id" "uuid", "p_symbol" "text", "p_side" "text", "p_exit_price" numeric) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."close_tradingview_trade"("p_user_id" "uuid", "p_symbol" "text", "p_side" "text", "p_exit_price" numeric) IS 'v8.5.10: Atomically closes a TradingView trade with proper locking. Trigger calculates PnL.';



CREATE OR REPLACE FUNCTION "public"."complete_ism_generation"("p_month" "text", "p_report_id" "text" DEFAULT NULL::"text", "p_success" boolean DEFAULT true, "p_error_message" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE ism_report_tracking SET
    status = CASE WHEN p_success THEN 'report_generated' ELSE 'error' END,
    report_id = COALESCE(p_report_id, report_id),
    latest_report_id = COALESCE(p_report_id, latest_report_id),
    generation_completed_at = NOW(),
    report_generated_at = CASE WHEN p_success THEN NOW() ELSE NULL END,
    error_message = p_error_message,
    error_count = CASE WHEN p_success THEN 0 ELSE error_count + 1 END,
    updated_at = NOW()
  WHERE report_month = p_month;
END;
$$;


ALTER FUNCTION "public"."complete_ism_generation"("p_month" "text", "p_report_id" "text", "p_success" boolean, "p_error_message" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complete_sync_operation"("p_log_id" "uuid", "p_status" character varying, "p_records_fetched" integer DEFAULT 0, "p_records_created" integer DEFAULT 0, "p_records_updated" integer DEFAULT 0, "p_records_skipped" integer DEFAULT 0, "p_records_failed" integer DEFAULT 0, "p_error_message" "text" DEFAULT NULL::"text", "p_sync_details" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_started_at TIMESTAMPTZ;
    v_duration INTEGER;
    v_connection_id UUID;
BEGIN
    SELECT started_at, connection_id INTO v_started_at, v_connection_id 
    FROM broker_sync_logs WHERE id = p_log_id;
    
    v_duration := EXTRACT(MILLISECONDS FROM (NOW() - v_started_at))::INTEGER;
    
    UPDATE broker_sync_logs
    SET 
        status = p_status,
        records_fetched = p_records_fetched,
        records_created = p_records_created,
        records_updated = p_records_updated,
        records_skipped = p_records_skipped,
        records_failed = p_records_failed,
        error_message = p_error_message,
        sync_details = p_sync_details,
        completed_at = NOW(),
        duration_ms = v_duration
    WHERE id = p_log_id;
    
    -- Update last sync on connection
    UPDATE broker_connections
    SET 
        last_sync_at = NOW(),
        last_successful_sync_at = CASE WHEN p_status = 'completed' THEN NOW() ELSE last_successful_sync_at END,
        last_error = CASE WHEN p_status = 'failed' THEN p_error_message ELSE last_error END,
        last_error_at = CASE WHEN p_status = 'failed' THEN NOW() ELSE last_error_at END,
        error_count = CASE WHEN p_status = 'failed' THEN COALESCE(error_count, 0) + 1 ELSE 0 END
    WHERE id = v_connection_id;
END;
$$;


ALTER FUNCTION "public"."complete_sync_operation"("p_log_id" "uuid", "p_status" character varying, "p_records_fetched" integer, "p_records_created" integer, "p_records_updated" integer, "p_records_skipped" integer, "p_records_failed" integer, "p_error_message" "text", "p_sync_details" "jsonb") OWNER TO "postgres";


