CREATE OR REPLACE FUNCTION "public"."count_pending_snaptrade_trades"("p_user_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
    last_sync_record RECORD;
    imported_count INT;
BEGIN
    SELECT * INTO last_sync_record
    FROM snaptrade_sync_log
    WHERE user_id = p_user_id
    AND status = 'running'
    ORDER BY sync_started_at DESC
    LIMIT 1;
    
    IF last_sync_record IS NULL THEN
        RETURN 0;
    END IF;
    
    SELECT COUNT(*) INTO imported_count
    FROM trades
    WHERE user_id = p_user_id
    AND import_source = 'snaptrade'
    AND imported_at >= last_sync_record.sync_started_at;
    
    RETURN imported_count;
END;
$$;


ALTER FUNCTION "public"."count_pending_snaptrade_trades"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."count_pending_snaptrade_trades"("p_user_id" "uuid") IS 'v8.5.0: Counts trades from current running sync';



CREATE OR REPLACE FUNCTION "public"."create_admin_affiliate"("p_admin_user_id" "uuid", "p_display_name" "text" DEFAULT 'Admin'::"text", "p_affiliate_code" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_affiliate_id UUID;
  v_code TEXT;
  v_email TEXT;
BEGIN
  -- Check if user is admin
  IF NOT EXISTS (SELECT 1 FROM profiles WHERE id = p_admin_user_id AND role IN ('admin', 'super_admin')) THEN
    RAISE EXCEPTION 'User is not an admin';
  END IF;
  
  -- Check if already has affiliate account
  IF EXISTS (SELECT 1 FROM affiliates WHERE user_id = p_admin_user_id) THEN
    SELECT id INTO v_affiliate_id FROM affiliates WHERE user_id = p_admin_user_id;
    RETURN v_affiliate_id;
  END IF;
  
  -- Get email
  SELECT email INTO v_email FROM auth.users WHERE id = p_admin_user_id;
  
  -- Generate code
  v_code := generate_affiliate_code(p_affiliate_code, p_display_name);
  
  -- Create admin affiliate
  INSERT INTO affiliates (
    user_id,
    display_name,
    email,
    affiliate_code,
    coupon_code,
    status,
    current_tier,
    discount_tier,
    affiliate_type,
    commission_enabled
  ) VALUES (
    p_admin_user_id,
    p_display_name,
    v_email,
    v_code,
    v_code,
    'active',
    'tier_3',
    'vip',
    'admin',
    FALSE  -- Admin affiliates don't earn commissions
  )
  RETURNING id INTO v_affiliate_id;
  
  RETURN v_affiliate_id;
END;
$$;


ALTER FUNCTION "public"."create_admin_affiliate"("p_admin_user_id" "uuid", "p_display_name" "text", "p_affiliate_code" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_admin_coupon"("p_code" "text", "p_name" "text", "p_discount_type" "public"."coupon_discount_type", "p_discount_percent" numeric DEFAULT NULL::numeric, "p_discount_amount_usd" numeric DEFAULT NULL::numeric, "p_plan_prices" "jsonb" DEFAULT NULL::"jsonb", "p_description" "text" DEFAULT NULL::"text", "p_duration_type" "public"."coupon_duration_type" DEFAULT 'unlimited'::"public"."coupon_duration_type", "p_valid_from" timestamp with time zone DEFAULT "now"(), "p_valid_until" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_max_uses" integer DEFAULT NULL::integer, "p_max_uses_per_user" integer DEFAULT NULL::integer, "p_min_purchase_amount" numeric DEFAULT NULL::numeric, "p_applicable_plans" "text"[] DEFAULT NULL::"text"[], "p_first_time_only" boolean DEFAULT false, "p_new_users_only" boolean DEFAULT false, "p_stackable_with_affiliate" boolean DEFAULT false, "p_priority" integer DEFAULT 0) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_coupon_id UUID;
  v_clean_code TEXT;
  v_plan TEXT;
  v_price NUMERIC;
BEGIN
  -- Check admin permission
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Only admins can create coupons';
  END IF;
  
  -- Clean and uppercase the code
  v_clean_code := UPPER(REGEXP_REPLACE(p_code, '[^A-Z0-9]', '', 'g'));
  
  -- Check code availability
  IF NOT is_affiliate_code_available(v_clean_code) THEN
    RAISE EXCEPTION 'Code "%" already exists', v_clean_code;
  END IF;
  
  -- Validate params based on discount type
  IF p_discount_type = 'percentage' THEN
    IF p_discount_percent IS NULL OR p_discount_percent <= 0 OR p_discount_percent > 100 THEN
      RAISE EXCEPTION 'Percentage discount requires discount_percent between 0 and 100';
    END IF;
  ELSIF p_discount_type = 'fixed_amount' THEN
    IF p_discount_amount_usd IS NULL OR p_discount_amount_usd <= 0 THEN
      RAISE EXCEPTION 'Fixed amount discount requires discount_amount_usd > 0';
    END IF;
  ELSIF p_discount_type = 'fixed_price' THEN
    IF p_plan_prices IS NULL OR p_plan_prices = '{}'::JSONB THEN
      RAISE EXCEPTION 'Fixed price discount requires plan_prices';
    END IF;
  END IF;
  
  -- Create coupon
  INSERT INTO admin_coupons (
    code,
    name,
    description,
    discount_type,
    discount_percent,
    discount_amount_usd,
    duration_type,
    valid_from,
    valid_until,
    max_uses,
    max_uses_per_user,
    min_purchase_amount,
    applicable_plans,
    first_time_only,
    new_users_only,
    stackable_with_affiliate,
    priority,
    created_by
  ) VALUES (
    v_clean_code,
    p_name,
    p_description,
    p_discount_type,
    CASE WHEN p_discount_type = 'percentage' THEN p_discount_percent ELSE NULL END,
    CASE WHEN p_discount_type = 'fixed_amount' THEN p_discount_amount_usd ELSE NULL END,
    p_duration_type,
    p_valid_from,
    p_valid_until,
    p_max_uses,
    p_max_uses_per_user,
    p_min_purchase_amount,
    p_applicable_plans,
    p_first_time_only,
    p_new_users_only,
    p_stackable_with_affiliate,
    p_priority,
    auth.uid()
  )
  RETURNING id INTO v_coupon_id;
  
  -- Insert fixed prices if provided
  IF p_discount_type = 'fixed_price' AND p_plan_prices IS NOT NULL THEN
    FOR v_plan, v_price IN SELECT * FROM jsonb_each_text(p_plan_prices)
    LOOP
      INSERT INTO admin_coupon_plan_prices (coupon_id, plan_name, fixed_price_usd)
      VALUES (v_coupon_id, v_plan, v_price::NUMERIC);
    END LOOP;
  END IF;
  
  RETURN v_coupon_id;
END;
$$;


ALTER FUNCTION "public"."create_admin_coupon"("p_code" "text", "p_name" "text", "p_discount_type" "public"."coupon_discount_type", "p_discount_percent" numeric, "p_discount_amount_usd" numeric, "p_plan_prices" "jsonb", "p_description" "text", "p_duration_type" "public"."coupon_duration_type", "p_valid_from" timestamp with time zone, "p_valid_until" timestamp with time zone, "p_max_uses" integer, "p_max_uses_per_user" integer, "p_min_purchase_amount" numeric, "p_applicable_plans" "text"[], "p_first_time_only" boolean, "p_new_users_only" boolean, "p_stackable_with_affiliate" boolean, "p_priority" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."deactivate_admin_coupon"("p_coupon_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Only admins can deactivate coupons';
  END IF;
  
  UPDATE admin_coupons
  SET 
    is_active = FALSE,
    valid_until = NOW(),
    updated_by = auth.uid(),
    updated_at = NOW()
  WHERE id = p_coupon_id;
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."deactivate_admin_coupon"("p_coupon_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."deactivate_bundle_subscription"("p_whop_membership_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_user_email TEXT;
  v_previous_status TEXT;
  v_newsletter_paused BOOLEAN;
  v_top_secret_paused BOOLEAN;
BEGIN
  SELECT id, email, bundle_status, newsletter_paused_for_bundle, top_secret_paused_for_bundle
  INTO v_user_id, v_user_email, v_previous_status, v_newsletter_paused, v_top_secret_paused
  FROM profiles WHERE bundle_whop_membership_id = p_whop_membership_id;
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found for bundle membership: ' || p_whop_membership_id);
  END IF;
  
  UPDATE profiles SET
    bundle_enabled = FALSE, bundle_status = 'cancelled', bundle_cancel_at_period_end = FALSE,
    newsletter_enabled = FALSE, newsletter_status = 'cancelled',
    top_secret_enabled = FALSE, top_secret_status = 'cancelled',
    updated_at = NOW()
  WHERE id = v_user_id;
  
  INSERT INTO subscription_events (user_id, event_type, old_plan, new_plan, processed_at, metadata)
  VALUES (v_user_id, 'bundle_deactivated', COALESCE(v_previous_status, 'active'), 'none', NOW(),
    jsonb_build_object('whop_membership_id', p_whop_membership_id, 'previous_status', v_previous_status, 'newsletter_was_paused', v_newsletter_paused, 'top_secret_was_paused', v_top_secret_paused));
  
  RETURN jsonb_build_object('success', true, 'user_id', v_user_id, 'email', v_user_email, 'previous_status', v_previous_status, 'new_status', 'cancelled', 'newsletter_was_paused', v_newsletter_paused, 'top_secret_was_paused', v_top_secret_paused);
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'sqlstate', SQLSTATE);
END;
$$;


ALTER FUNCTION "public"."deactivate_bundle_subscription"("p_whop_membership_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."deactivate_newsletter_subscription"("p_whop_membership_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
