CREATE OR REPLACE FUNCTION "public"."deactivate_platform_subscription"("p_whop_membership_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_email TEXT;
  v_old_plan TEXT;
BEGIN
  SELECT id, email, platform_plan INTO v_user_id, v_email, v_old_plan
  FROM profiles WHERE platform_whop_membership_id = p_whop_membership_id;
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Membership not found');
  END IF;
  
  -- Remove bundle first
  PERFORM remove_platform_bundle(v_user_id);
  
  UPDATE profiles SET
    platform_plan = 'free',
    platform_subscription_status = 'expired',
    platform_cancelled_at = NOW(),
    platform_cancel_at_period_end = FALSE,
    platform_is_in_trial = FALSE,
    platform_trial_ends_at = NULL,
    updated_at = NOW()
  WHERE id = v_user_id;
  
  INSERT INTO platform_subscription_events (user_id, event_type, old_plan, new_plan, metadata)
  VALUES (v_user_id, 'expired', v_old_plan, 'free', jsonb_build_object('whop_membership_id', p_whop_membership_id));
  
  RETURN jsonb_build_object('success', true, 'user_id', v_user_id, 'old_plan', v_old_plan);
END;
$$;


