CREATE OR REPLACE FUNCTION "public"."downgrade_expired_subscriptions"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_count INTEGER := 0;
BEGIN
  UPDATE public.profiles
  SET 
    account_type = 'free',
    max_trades = 10,
    subscription_id = NULL,
    updated_at = NOW()
  WHERE 
    account_type != 'free'
    AND subscription_end_date IS NOT NULL
    AND subscription_end_date < NOW()
    AND (subscription_cancel_at_period_end = TRUE OR subscription_end_date < NOW() - INTERVAL '3 days');
  
  GET DIAGNOSTICS v_count = ROW_COUNT;
  
  RETURN v_count;
END;
$$;


