CREATE OR REPLACE FUNCTION "public"."end_impersonation_session"("p_session_token" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_session RECORD;
BEGIN
  -- Get session details
  SELECT admin_id, impersonated_user_id, is_active, admin_email
  INTO v_session
  FROM public.admin_impersonation_sessions
  WHERE session_token = p_session_token;
  
  IF v_session.admin_id IS NULL THEN
    RAISE WARNING 'Session not found: %', LEFT(p_session_token, 8) || '...';
    RETURN FALSE;
  END IF;
  
  -- Verify caller is the admin who started the session
  IF v_session.admin_id != auth.uid() THEN
    RAISE EXCEPTION 'Unauthorized: Only the admin who started impersonation can end it';
  END IF;
  
  -- End the session
  UPDATE public.admin_impersonation_sessions
  SET 
    is_active = FALSE,
    last_activity_at = NOW()
  WHERE session_token = p_session_token;
  
  -- Log the action
  PERFORM public.log_admin_action(
    'END_IMPERSONATION',
    'impersonation_session',
    v_session.impersonated_user_id,
    jsonb_build_object(
      'session_token_prefix', LEFT(p_session_token, 8) || '...',
      'ended_at', NOW()
    )
  );
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."end_impersonation_session"("p_session_token" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."end_impersonation_session"("p_session_token" "text") IS 'v8.5.10: Ends an active impersonation session. Only starting admin can end it.';



