CREATE OR REPLACE FUNCTION "public"."get_admin_stats"() RETURNS TABLE("total_users" bigint, "free_users" bigint, "basic_users" bigint, "premium_users" bigint, "trial_users" bigint, "total_trades" bigint, "trades_today" bigint, "active_subscriptions" bigint, "expired_subscriptions" bigint, "total_revenue" numeric, "revenue_this_month" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  RETURN QUERY
  SELECT 
    (SELECT COUNT(*) FROM public.profiles)::BIGINT as total_users,
    (SELECT COUNT(*) FROM public.profiles WHERE account_type = 'free')::BIGINT as free_users,
    (SELECT COUNT(*) FROM public.profiles WHERE account_type = 'basic')::BIGINT as basic_users,
    (SELECT COUNT(*) FROM public.profiles WHERE account_type = 'premium')::BIGINT as premium_users,
    (SELECT COUNT(*) FROM public.profiles WHERE account_type = 'trial')::BIGINT as trial_users,
    (SELECT COUNT(*) FROM public.trades)::BIGINT as total_trades,
    (SELECT COUNT(*) FROM public.trades WHERE DATE(created_at) = CURRENT_DATE)::BIGINT as trades_today,
    (SELECT COUNT(*) FROM public.profiles WHERE subscription_status = 'active')::BIGINT as active_subscriptions,
    (SELECT COUNT(*) FROM public.profiles WHERE subscription_status = 'expired')::BIGINT as expired_subscriptions,
    (SELECT COALESCE(SUM(amount), 0) FROM public.payment_history WHERE status = 'completed')::NUMERIC as total_revenue,
    (SELECT COALESCE(SUM(amount), 0) FROM public.payment_history 
     WHERE status = 'completed' AND DATE_TRUNC('month', created_at) = DATE_TRUNC('month', NOW()))::NUMERIC as revenue_this_month;
END;
$$;


