CREATE OR REPLACE FUNCTION "public"."get_affiliate_referrals_with_trial_info"("p_affiliate_id" "uuid") RETURNS TABLE("referral_id" "uuid", "referred_user_email" "text", "signup_date" timestamp with time zone, "status" "public"."referral_status", "is_in_trial" boolean, "trial_ends_at" timestamp with time zone, "days_until_trial_ends" integer, "first_payment_date" timestamp with time zone, "days_until_qualification" integer, "verification_end" timestamp with time zone, "subscription_plan" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    ar.id,
    ar.referred_user_email,
    ar.signup_date,
    ar.status,
    COALESCE(p.is_in_trial, FALSE),
    p.trial_ends_at,
    CASE 
      WHEN p.trial_ends_at IS NOT NULL AND p.trial_ends_at > NOW()
      THEN EXTRACT(DAY FROM (p.trial_ends_at - NOW()))::INTEGER
      ELSE 0
    END,
    ar.first_payment_date,
    CASE 
      WHEN ar.verification_end IS NOT NULL AND ar.verification_end > NOW()
      THEN EXTRACT(DAY FROM (ar.verification_end - NOW()))::INTEGER
      ELSE 0
    END,
    ar.verification_end,
    ar.subscription_plan
  FROM affiliate_referrals ar
  JOIN profiles p ON ar.referred_user_id = p.id
  WHERE ar.affiliate_id = p_affiliate_id
  ORDER BY ar.signup_date DESC;
END;
$$;


