CREATE OR REPLACE FUNCTION "public"."get_ai_action_info"("p_action_name" "text", "p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_action RECORD;
  v_plan TEXT := 'free';
  v_daily_cap INTEGER;
  v_daily_usage INTEGER := 0;
BEGIN
  SELECT * INTO v_action
  FROM ai_actions_config
  WHERE action_name = p_action_name AND is_active = TRUE;
  
  IF v_action IS NULL THEN
    RETURN jsonb_build_object('error', 'Action not found');
  END IF;

  IF p_user_id IS NOT NULL THEN
    SELECT COALESCE(platform_plan, 'free') INTO v_plan
    FROM profiles WHERE id = p_user_id;
    
    SELECT COALESCE(SUM(usage_count), 0) INTO v_daily_usage
    FROM ai_daily_usage
    WHERE user_id = p_user_id 
      AND usage_date = CURRENT_DATE
      AND action_name = p_action_name;
  END IF;

  v_daily_cap := CASE v_plan
    WHEN 'pro' THEN v_action.daily_cap_pro
    WHEN 'core' THEN v_action.daily_cap_core
    ELSE v_action.daily_cap_free
  END;

  RETURN jsonb_build_object(
    'action_name', v_action.action_name,
    'action_type', v_action.action_type,
    'base_cost', v_action.base_cost,
    'category', v_action.category,
    'display_name', v_action.display_name,
    'description', v_action.description,
    'plan_required', v_action.plan_required,
    'daily_cap', v_daily_cap,
    'daily_usage', v_daily_usage,
    'is_available', (v_action.plan_required IS NULL OR 
      (v_action.plan_required = 'core' AND v_plan IN ('core', 'pro')) OR
      (v_action.plan_required = 'pro' AND v_plan = 'pro'))
  );
END;
$$;


ALTER FUNCTION "public"."get_ai_action_info"("p_action_name" "text", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_announcement_recipients"("p_filters" "jsonb") RETURNS TABLE("email" "text", "display_name" "text", "account_type" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_conditions TEXT[] := ARRAY[]::TEXT[];
BEGIN
  -- Journal conditions
  IF (p_filters->>'journal_all')::boolean THEN
    v_conditions := array_append(v_conditions, 
      '(account_type IS NOT NULL AND account_type != ''FREE'')');
  ELSE
    IF (p_filters->>'journal_premium')::boolean THEN
      v_conditions := array_append(v_conditions, 'account_type = ''PREMIUM''');
    END IF;
    IF (p_filters->>'journal_basic')::boolean THEN
      v_conditions := array_append(v_conditions, 'account_type = ''BASIC''');
    END IF;
    IF (p_filters->>'journal_free')::boolean THEN
      v_conditions := array_append(v_conditions, '(account_type IS NULL OR account_type = ''FREE'')');
    END IF;
    IF (p_filters->>'journal_trial')::boolean THEN
      v_conditions := array_append(v_conditions, 'subscription_status = ''trialing''');
    END IF;
  END IF;

  -- Newsletter conditions
  IF (p_filters->>'newsletter_all')::boolean THEN
    v_conditions := array_append(v_conditions, '(newsletter_enabled = true OR newsletter_paid = true)');
  ELSE
    IF (p_filters->>'newsletter_paid')::boolean THEN
      v_conditions := array_append(v_conditions, 'newsletter_paid = true');
    END IF;
    IF (p_filters->>'newsletter_trial')::boolean THEN
      v_conditions := array_append(v_conditions, '(newsletter_enabled = true AND newsletter_paid = false)');
    END IF;
  END IF;

  -- Top Secret conditions
  IF (p_filters->>'topsecret_all')::boolean THEN
    v_conditions := array_append(v_conditions, 'top_secret_enabled = true');
  ELSE
    IF (p_filters->>'topsecret_paid')::boolean THEN
      v_conditions := array_append(v_conditions, '(top_secret_enabled = true AND subscription_status = ''active'')');
    END IF;
    IF (p_filters->>'topsecret_trial')::boolean THEN
      v_conditions := array_append(v_conditions, '(top_secret_enabled = true AND subscription_status = ''trialing'')');
    END IF;
  END IF;

  -- Special groups
  IF (p_filters->>'all_users')::boolean THEN
    v_conditions := array_append(v_conditions, '1=1');
  END IF;
  IF (p_filters->>'all_paying')::boolean THEN
    v_conditions := array_append(v_conditions, 
      '(subscription_status = ''active'' OR newsletter_paid = true OR top_secret_enabled = true)');
  END IF;
  IF (p_filters->>'all_trials')::boolean THEN
    v_conditions := array_append(v_conditions, 
      '(subscription_status = ''trialing'' OR is_in_trial = true)');
  END IF;
  IF (p_filters->>'cancelled_winback')::boolean THEN
    v_conditions := array_append(v_conditions, 
      'subscription_status IN (''canceled'', ''cancelled'', ''expired'')');
  END IF;
  IF (p_filters->>'active_this_week')::boolean THEN
    v_conditions := array_append(v_conditions, 'last_login_at > NOW() - INTERVAL ''7 days''');
  END IF;
  IF (p_filters->>'inactive_30_days')::boolean THEN
    v_conditions := array_append(v_conditions, '(last_login_at < NOW() - INTERVAL ''30 days'' OR last_login_at IS NULL)');
  END IF;

  -- If no conditions, return empty
  IF array_length(v_conditions, 1) IS NULL THEN
    RETURN;
  END IF;

  -- Execute dynamic query
  RETURN QUERY EXECUTE format(
    'SELECT email, display_name, account_type 
     FROM profiles 
     WHERE (is_banned IS NULL OR is_banned = false) 
       AND email IS NOT NULL 
       AND role NOT IN (''admin'', ''super_admin'')
       AND (%s)',
    array_to_string(v_conditions, ' OR ')
  );
END;
$$;


ALTER FUNCTION "public"."get_announcement_recipients"("p_filters" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_asset_class_performance"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("asset_class" "text", "total_trades" bigint, "win_rate" numeric, "total_pnl" numeric, "avg_pnl" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  RETURN QUERY
  SELECT 
    COALESCE(t.asset_class, 'unknown') as asset_class,
    COUNT(*)::BIGINT as total_trades,
    ROUND((COUNT(*) FILTER (WHERE t.outcome = 'WIN')::NUMERIC / NULLIF(COUNT(*), 0)) * 100, 2) as win_rate,
    COALESCE(SUM(t.pnl), 0) as total_pnl,
    COALESCE(ROUND(AVG(t.pnl), 2), 0) as avg_pnl
  FROM public.trades t
  WHERE t.user_id = v_user_id
    AND t.outcome IN ('WIN', 'LOSS', 'BE')
    AND t.deleted_at IS NULL
  GROUP BY COALESCE(t.asset_class, 'unknown')
  ORDER BY total_pnl DESC;
END;
$$;


