CREATE OR REPLACE FUNCTION "public"."get_bundle_status"("p_user_id" "uuid") RETURNS TABLE("bundle_enabled" boolean, "bundle_status" "text", "bundle_interval" "text", "bundle_whop_membership_id" "text", "bundle_started_at" timestamp with time zone, "bundle_expires_at" timestamp with time zone, "bundle_trial_ends_at" timestamp with time zone, "bundle_cancel_at_period_end" boolean, "bundle_is_in_trial" boolean, "days_until_expiry" integer, "days_until_trial_ends" integer, "is_active" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COALESCE(p.bundle_enabled, FALSE), COALESCE(p.bundle_status, 'inactive'), p.bundle_interval, p.bundle_whop_membership_id,
    p.bundle_started_at, p.bundle_expires_at, p.bundle_trial_ends_at,
    COALESCE(p.bundle_cancel_at_period_end, FALSE), COALESCE(p.bundle_is_in_trial, FALSE),
    CASE WHEN p.bundle_expires_at IS NOT NULL THEN GREATEST(0, EXTRACT(DAY FROM p.bundle_expires_at - NOW())::INTEGER) ELSE NULL END,
    CASE WHEN p.bundle_trial_ends_at IS NOT NULL THEN GREATEST(0, EXTRACT(DAY FROM p.bundle_trial_ends_at - NOW())::INTEGER) ELSE NULL END,
    COALESCE(p.bundle_enabled, FALSE) = TRUE AND COALESCE(p.bundle_status, 'inactive') IN ('active', 'trial')
  FROM profiles p WHERE p.id = p_user_id;
END;
$$;


