CREATE OR REPLACE FUNCTION "public"."get_cancellation_feedbacks"("p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0, "p_plan_filter" "text" DEFAULT NULL::"text", "p_unprocessed_only" boolean DEFAULT false) RETURNS TABLE("id" "uuid", "user_id" "uuid", "email" "text", "plan_cancelled" "text", "subscription_type" "text", "subscription_duration_days" integer, "reason_id" "text", "reason_label" "text", "feedback_text" "text", "whop_membership_id" "text", "processed" boolean, "admin_notes" "text", "processed_by" "uuid", "processed_at" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_caller_role TEXT;
BEGIN
  -- Check admin access
  SELECT role INTO v_caller_role 
  FROM profiles 
  WHERE profiles.id = auth.uid();

  IF v_caller_role IS NULL OR v_caller_role NOT IN ('admin', 'super_admin') THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  RETURN QUERY
  SELECT 
    scf.id,
    scf.user_id,
    scf.email,
    scf.plan_cancelled,
    scf.subscription_type,
    scf.subscription_duration_days,
    scf.reason_id,
    scf.reason_label,
    scf.feedback_text,
    scf.whop_membership_id,
    scf.processed,
    scf.admin_notes,
    scf.processed_by,
    scf.processed_at,
    scf.created_at
  FROM subscription_cancellation_feedback scf
  WHERE (p_plan_filter IS NULL OR scf.plan_cancelled = p_plan_filter)
    AND (NOT p_unprocessed_only OR scf.processed = FALSE)
  ORDER BY scf.created_at DESC
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;


