CREATE OR REPLACE FUNCTION "public"."get_cancellation_stats"("p_days" integer DEFAULT 30) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_caller_role TEXT;
  v_result JSONB;
  v_start_date TIMESTAMPTZ;
BEGIN
  -- Check admin access
  SELECT role INTO v_caller_role 
  FROM profiles 
  WHERE profiles.id = auth.uid();

  IF v_caller_role IS NULL OR v_caller_role NOT IN ('admin', 'super_admin') THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  v_start_date := NOW() - (p_days || ' days')::INTERVAL;

  SELECT jsonb_build_object(
    'period_days', p_days,
    'start_date', v_start_date,
    'end_date', NOW(),
    
    -- Total cancellations
    'total_cancellations', (
      SELECT COUNT(*) 
      FROM subscription_cancellation_feedback 
      WHERE created_at >= v_start_date
    ),
    
    -- By reason
    'by_reason', (
      SELECT COALESCE(jsonb_agg(
        jsonb_build_object(
          'reason_id', reason_id,
          'reason_label', reason_label,
          'count', cnt,
          'percentage', ROUND((cnt::NUMERIC / NULLIF(total, 0)) * 100, 1)
        )
        ORDER BY cnt DESC
      ), '[]'::jsonb)
      FROM (
        SELECT 
          reason_id,
          MAX(reason_label) as reason_label,
          COUNT(*) as cnt,
          SUM(COUNT(*)) OVER() as total
        FROM subscription_cancellation_feedback
        WHERE created_at >= v_start_date
        GROUP BY reason_id
      ) r
    ),
    
    -- By plan
    'by_plan', (
      SELECT COALESCE(jsonb_agg(
        jsonb_build_object(
          'plan', plan_cancelled,
          'count', cnt,
          'percentage', ROUND((cnt::NUMERIC / NULLIF(total, 0)) * 100, 1)
        )
        ORDER BY cnt DESC
      ), '[]'::jsonb)
      FROM (
        SELECT 
          plan_cancelled,
          COUNT(*) as cnt,
          SUM(COUNT(*)) OVER() as total
        FROM subscription_cancellation_feedback
        WHERE created_at >= v_start_date
        GROUP BY plan_cancelled
      ) p
    ),
    
    -- By duration bucket
    'by_duration', (
      SELECT COALESCE(jsonb_agg(
        jsonb_build_object(
          'bucket', bucket,
          'count', cnt,
          'percentage', ROUND((cnt::NUMERIC / NULLIF(total, 0)) * 100, 1)
        )
        ORDER BY bucket_order
      ), '[]'::jsonb)
      FROM (
        SELECT 
          CASE 
            WHEN subscription_duration_days IS NULL THEN 'Unknown'
            WHEN subscription_duration_days < 7 THEN '< 1 week'
            WHEN subscription_duration_days < 30 THEN '1-4 weeks'
            WHEN subscription_duration_days < 90 THEN '1-3 months'
            WHEN subscription_duration_days < 180 THEN '3-6 months'
            WHEN subscription_duration_days < 365 THEN '6-12 months'
            ELSE '1+ year'
          END as bucket,
          CASE 
            WHEN subscription_duration_days IS NULL THEN 99
            WHEN subscription_duration_days < 7 THEN 1
            WHEN subscription_duration_days < 30 THEN 2
            WHEN subscription_duration_days < 90 THEN 3
            WHEN subscription_duration_days < 180 THEN 4
            WHEN subscription_duration_days < 365 THEN 5
            ELSE 6
          END as bucket_order,
          COUNT(*) as cnt,
          SUM(COUNT(*)) OVER() as total
        FROM subscription_cancellation_feedback
        WHERE created_at >= v_start_date
        GROUP BY 1, 2
      ) d
    ),
    
    -- Average subscription duration
    'avg_subscription_days', (
      SELECT ROUND(AVG(subscription_duration_days), 1)
      FROM subscription_cancellation_feedback
      WHERE created_at >= v_start_date
        AND subscription_duration_days IS NOT NULL
    ),
    
    -- Feedbacks with text
    'feedbacks_with_text', (
      SELECT COUNT(*)
      FROM subscription_cancellation_feedback
      WHERE created_at >= v_start_date
        AND feedback_text IS NOT NULL
        AND feedback_text != ''
    ),
    
    -- Recent feedbacks with text (for review)
    'recent_feedbacks', (
      SELECT COALESCE(jsonb_agg(
        jsonb_build_object(
          'id', id,
          'email', email,
          'plan', plan_cancelled,
          'reason', reason_label,
          'feedback', feedback_text,
          'duration_days', subscription_duration_days,
          'created_at', created_at,
          'processed', processed
        )
        ORDER BY created_at DESC
      ), '[]'::jsonb)
      FROM (
        SELECT *
        FROM subscription_cancellation_feedback
        WHERE created_at >= v_start_date
          AND feedback_text IS NOT NULL
          AND feedback_text != ''
        ORDER BY created_at DESC
        LIMIT 10
      ) f
    )
    
  ) INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."get_cancellation_stats"("p_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_churn_stats"("p_days" integer DEFAULT 30) RETURNS TABLE("total_churned" bigint, "trading_journal_churned" bigint, "newsletter_churned" bigint, "top_secret_churned" bigint)
