CREATE OR REPLACE FUNCTION "public"."get_comprehensive_subscription_stats"() RETURNS json
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_result JSON;
  v_now TIMESTAMPTZ := NOW();
  v_today DATE := CURRENT_DATE;
  v_week_ago TIMESTAMPTZ := NOW() - INTERVAL '7 days';
  v_month_ago TIMESTAMPTZ := NOW() - INTERVAL '30 days';
BEGIN
  -- Check if user is admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles pf
    WHERE pf.id = auth.uid()
    AND pf.role IN ('admin', 'super_admin')
    AND COALESCE(pf.is_banned, false) = false
  ) THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  SELECT json_build_object(
    'generated_at', v_now,

    -- ===== OVERALL =====
    'overall', json_build_object(
      'total_users', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL),
      'active_today', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND last_login_at >= v_today::TIMESTAMPTZ),
      'active_this_week', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND last_login_at >= v_week_ago),
      'active_this_month', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND last_login_at >= v_month_ago),
      'new_users_today', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND created_at >= v_today::TIMESTAMPTZ),
      'new_users_this_week', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND created_at >= v_week_ago),
      'new_users_this_month', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND created_at >= v_month_ago)
    ),

    -- ===== JOURNAL =====
    'journal', json_build_object(
      'basic', json_build_object(
        'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic'),
        'monthly', json_build_object(
          'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic' AND subscription_interval = 'monthly'),
          'in_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic' AND subscription_interval = 'monthly' AND COALESCE(is_in_trial, false) = true),
          'paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic' AND subscription_interval = 'monthly' AND COALESCE(is_in_trial, false) = false AND whop_membership_id IS NOT NULL)
        ),
        'yearly', json_build_object(
          'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic' AND subscription_interval = 'yearly'),
          'in_trial', 0,
          'paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic' AND subscription_interval = 'yearly' AND whop_membership_id IS NOT NULL)
        ),
        'pending_cancellation', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic' AND subscription_status = 'cancelled')
      ),
      'premium', json_build_object(
        'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium'),
        'monthly', json_build_object(
          'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium' AND subscription_interval = 'monthly'),
          'in_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium' AND subscription_interval = 'monthly' AND COALESCE(is_in_trial, false) = true),
          'paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium' AND subscription_interval = 'monthly' AND COALESCE(is_in_trial, false) = false AND whop_membership_id IS NOT NULL)
        ),
        'yearly', json_build_object(
          'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium' AND subscription_interval = 'yearly'),
          'in_trial', 0,
          'paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium' AND subscription_interval = 'yearly' AND whop_membership_id IS NOT NULL)
        ),
        'pending_cancellation', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium' AND subscription_status = 'cancelled')
      ),
      'free', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND (account_type IS NULL OR account_type = 'free')),
      'legacy_no_whop', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type IS NOT NULL AND account_type != 'free' AND whop_membership_id IS NULL),
      'total_subscribers', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type IS NOT NULL AND account_type != 'free' AND whop_membership_id IS NOT NULL),
      'total_in_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND (subscription_status = 'trial' OR COALESCE(is_in_trial, false) = true)),
      'total_paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND whop_membership_id IS NOT NULL AND COALESCE(is_in_trial, false) = false AND subscription_status = 'active')
    ),

    -- ===== NEWSLETTER (WAR ZONE) =====
    'newsletter', json_build_object(
      'total_subscribers', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND (newsletter_status = 'active' OR newsletter_whop_membership_id IS NOT NULL)),
      'monthly', json_build_object(
        'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND newsletter_status = 'active'),
        'in_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND newsletter_status = 'trial'),
        'paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND newsletter_whop_membership_id IS NOT NULL AND newsletter_status = 'active'),
        'top_secret_discount', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND COALESCE(newsletter_enabled, false) = true AND COALESCE(top_secret_enabled, false) = true)
      ),
      'yearly', json_build_object(
        'total', 0,
        'paid', 0
      ),
      'cancelled', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND newsletter_status = 'cancelled'),
      'pending_cancellation', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND COALESCE(newsletter_cancel_at_period_end, false) = true AND newsletter_status = 'active')
    ),

    -- ===== TOP SECRET =====
    'top_secret', json_build_object(
      'total_subscribers', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND (top_secret_status = 'active' OR top_secret_whop_membership_id IS NOT NULL)),
      'monthly', json_build_object(
        'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_status = 'active'),
        'in_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_status = 'trial'),
        'paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_whop_membership_id IS NOT NULL AND top_secret_status = 'active')
      ),
      'yearly', json_build_object(
        'total', 0,
        'in_trial', 0,
        'paid', 0
      ),
      'journey', json_build_object(
        'in_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_status = 'trial'),
        'month_1', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_status = 'active' AND top_secret_started_at >= NOW() - INTERVAL '30 days'),
        'month_2', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_status = 'active' AND top_secret_started_at < NOW() - INTERVAL '30 days' AND top_secret_started_at >= NOW() - INTERVAL '60 days'),
        'month_3_plus', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_status = 'active' AND top_secret_started_at < NOW() - INTERVAL '60 days')
      ),
      'cancelled', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_status = 'cancelled'),
      'pending_cancellation', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND COALESCE(top_secret_cancel_at_period_end, false) = true AND top_secret_status = 'active')
    ),

    -- ===== PLATFORM =====
    'platform', json_build_object(
      'total_subscribers', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan IS NOT NULL AND platform_plan != 'free'),
      'free', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND (platform_plan IS NULL OR platform_plan = 'free')),
      'core', json_build_object(
        'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'core'),
        'monthly', json_build_object(
          'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'core'),
          'in_trial', 0,
          'paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'core' AND platform_subscription_status = 'active')
        ),
        'yearly', json_build_object('total', 0, 'paid', 0)
      ),
      'finotaur', json_build_object(
        'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'finotaur'),
        'monthly', json_build_object(
          'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'finotaur'),
          'in_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'finotaur' AND COALESCE(platform_is_in_trial, false) = true),
          'paid', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'finotaur' AND platform_subscription_status = 'active')
        ),
        'yearly', json_build_object('total', 0, 'paid', 0),
        'trial_eligible', 0
      ),
      'enterprise', json_build_object(
        'total', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'enterprise')
      ),
      'pending_cancellation', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND COALESCE(platform_cancel_at_period_end, false) = true)
    ),

    -- ===== REVENUE (MRR) =====
    'revenue', json_build_object(
      'journal_mrr', ROUND((
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic' AND whop_membership_id IS NOT NULL AND COALESCE(is_in_trial, false) = false AND subscription_interval = 'monthly') * 19.99 +
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'basic' AND whop_membership_id IS NOT NULL AND subscription_interval = 'yearly') * 12.42 +
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium' AND whop_membership_id IS NOT NULL AND COALESCE(is_in_trial, false) = false AND subscription_interval = 'monthly') * 39.99 +
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND account_type = 'premium' AND whop_membership_id IS NOT NULL AND subscription_interval = 'yearly') * 24.92
      )::NUMERIC, 2),
      'newsletter_mrr', ROUND((
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND newsletter_whop_membership_id IS NOT NULL AND newsletter_status = 'active' AND COALESCE(top_secret_enabled, false) = false) * 69.99 +
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND newsletter_whop_membership_id IS NOT NULL AND newsletter_status = 'active' AND COALESCE(top_secret_enabled, false) = true) * 30
      )::NUMERIC, 2),
      'top_secret_mrr', ROUND((
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_whop_membership_id IS NOT NULL AND top_secret_status = 'active' AND COALESCE(newsletter_enabled, false) = false) * 89.99 +
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_whop_membership_id IS NOT NULL AND top_secret_status = 'active' AND COALESCE(newsletter_enabled, false) = true) * 50
      )::NUMERIC, 2),
      'platform_mrr', ROUND((
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'core' AND platform_subscription_status = 'active') * 59 +
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'finotaur' AND platform_subscription_status = 'active') * 109 +
        (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND platform_plan = 'enterprise' AND platform_subscription_status = 'active') * 500
      )::NUMERIC, 2)
    ),

    -- ===== TRIALS =====
    'trials', json_build_object(
      'total_in_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND (COALESCE(is_in_trial, false) = true OR subscription_status = 'trial' OR newsletter_status = 'trial' OR COALESCE(platform_is_in_trial, false) = true)),
      'journal_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND (subscription_status = 'trial' OR COALESCE(is_in_trial, false) = true)),
      'newsletter_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND newsletter_status = 'trial'),
      'top_secret_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND top_secret_status = 'trial'),
      'platform_trial', (SELECT COUNT(*) FROM public.profiles WHERE deleted_at IS NULL AND COALESCE(platform_is_in_trial, false) = true)
    )
  ) INTO v_result;

  RETURN v_result;
END;
$$;


