CREATE OR REPLACE FUNCTION "public"."get_conversation_with_messages"("p_conversation_id" "uuid", "p_user_id" "uuid") RETURNS TABLE("conversation" "jsonb", "messages" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    to_jsonb(c.*) as conversation,
    COALESCE(
      jsonb_agg(
        to_jsonb(m.*) ORDER BY m.created_at ASC
      ) FILTER (WHERE m.id IS NOT NULL),
      '[]'::jsonb
    ) as messages
  FROM ai_conversations c
  LEFT JOIN ai_messages m ON m.conversation_id = c.id
  WHERE c.id = p_conversation_id AND c.user_id = p_user_id
  GROUP BY c.id;
END;
$$;


ALTER FUNCTION "public"."get_conversation_with_messages"("p_conversation_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_conversation_with_messages"("p_conversation_id" "uuid", "p_user_id" "uuid") IS 'Gets a conversation with all its messages for a user';



