CREATE OR REPLACE FUNCTION "public"."get_credits_status"("p_user_id" "uuid") RETURNS TABLE("credits_balance" integer, "credits_purchased" integer, "credits_rollover" integer, "credits_total" integer, "credits_heavy_today" integer, "credits_heavy_limit" integer, "soft_cap_active" boolean, "plan" "text", "monthly_allocation" integer, "reset_date" "date")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COALESCE(p.credits_balance, 30)::INTEGER,
    COALESCE(p.credits_purchased, 0)::INTEGER,
    COALESCE(p.credits_rollover, 0)::INTEGER,
    (COALESCE(p.credits_balance, 30) + COALESCE(p.credits_purchased, 0) + COALESCE(p.credits_rollover, 0))::INTEGER,
    CASE WHEN p.credits_heavy_reset_date < CURRENT_DATE THEN 0 ELSE COALESCE(p.credits_heavy_today, 0) END::INTEGER,
    CASE COALESCE(p.platform_plan, 'free')
      WHEN 'pro' THEN 8
      WHEN 'core' THEN 3
      ELSE 0
    END::INTEGER,
    CASE WHEN p.credits_heavy_reset_date < CURRENT_DATE THEN FALSE 
         ELSE COALESCE(p.credits_heavy_today, 0) >= CASE COALESCE(p.platform_plan, 'free')
           WHEN 'pro' THEN 8
           WHEN 'core' THEN 3
           ELSE 0
         END
    END::BOOLEAN,
    COALESCE(p.platform_plan, 'free')::TEXT,
    CASE COALESCE(p.platform_plan, 'free')
      WHEN 'pro' THEN 1500
      WHEN 'core' THEN 600
      ELSE 30
    END::INTEGER,
    (DATE_TRUNC('month', COALESCE(p.credits_reset_at, NOW())) + INTERVAL '1 month')::DATE
  FROM profiles p
  WHERE p.id = p_user_id;
END;
$$;


ALTER FUNCTION "public"."get_credits_status"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_current_plan_prices"() RETURNS TABLE("plan_name" "text", "original_price" numeric, "current_price" numeric, "sale_name" "text", "discount_percent" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_default_prices JSONB;
  v_active_sale RECORD;
BEGIN
  -- Get default prices
  SELECT config_value INTO v_default_prices
  FROM affiliate_config
  WHERE config_key = 'default_plan_prices';
  
  -- Check for active global sale
  SELECT * INTO v_active_sale
  FROM admin_global_pricing
  WHERE is_active = TRUE
    AND (valid_from IS NULL OR valid_from <= NOW())
    AND (valid_until IS NULL OR valid_until > NOW())
  ORDER BY created_at DESC
  LIMIT 1;
  
  -- Return prices for each plan
  RETURN QUERY
  SELECT 
    'monthly'::TEXT,
    (v_default_prices->>'monthly')::NUMERIC,
    CASE 
      WHEN v_active_sale IS NOT NULL AND v_active_sale.monthly_price_usd IS NOT NULL 
        THEN v_active_sale.monthly_price_usd
      WHEN v_active_sale IS NOT NULL AND v_active_sale.discount_percent IS NOT NULL 
        THEN (v_default_prices->>'monthly')::NUMERIC * (1 - v_active_sale.discount_percent / 100)
      ELSE (v_default_prices->>'monthly')::NUMERIC
    END,
    COALESCE(v_active_sale.sale_name, NULL),
    COALESCE(v_active_sale.discount_percent, NULL);
  
  RETURN QUERY
  SELECT 
    'yearly'::TEXT,
    (v_default_prices->>'yearly')::NUMERIC,
    CASE 
      WHEN v_active_sale IS NOT NULL AND v_active_sale.yearly_price_usd IS NOT NULL 
        THEN v_active_sale.yearly_price_usd
      WHEN v_active_sale IS NOT NULL AND v_active_sale.discount_percent IS NOT NULL 
        THEN (v_default_prices->>'yearly')::NUMERIC * (1 - v_active_sale.discount_percent / 100)
      ELSE (v_default_prices->>'yearly')::NUMERIC
    END,
    COALESCE(v_active_sale.sale_name, NULL),
    COALESCE(v_active_sale.discount_percent, NULL);
  
  RETURN QUERY
  SELECT 
    'lifetime'::TEXT,
    (v_default_prices->>'lifetime')::NUMERIC,
    CASE 
      WHEN v_active_sale IS NOT NULL AND v_active_sale.lifetime_price_usd IS NOT NULL 
        THEN v_active_sale.lifetime_price_usd
      WHEN v_active_sale IS NOT NULL AND v_active_sale.discount_percent IS NOT NULL 
        THEN (v_default_prices->>'lifetime')::NUMERIC * (1 - v_active_sale.discount_percent / 100)
      ELSE (v_default_prices->>'lifetime')::NUMERIC
    END,
    COALESCE(v_active_sale.sale_name, NULL),
    COALESCE(v_active_sale.discount_percent, NULL);
END;
$$;


ALTER FUNCTION "public"."get_current_plan_prices"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_current_price"("p_plan" "text", "p_interval" "text") RETURNS numeric
    LANGUAGE "plpgsql" STABLE
    AS $$
BEGIN
  RETURN CASE
    WHEN p_plan = 'basic' AND p_interval = 'monthly' THEN 19.99
    WHEN p_plan = 'basic' AND p_interval = 'yearly' THEN 149.00
    WHEN p_plan = 'premium' AND p_interval = 'monthly' THEN 39.99
    WHEN p_plan = 'premium' AND p_interval = 'yearly' THEN 299.00
    ELSE 0
  END;
END;
$$;


