CREATE OR REPLACE FUNCTION "public"."get_daily_pnl"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_days" integer DEFAULT 30) RETURNS TABLE("trade_date" "date", "trades_count" bigint, "pnl" numeric, "cumulative_pnl" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  RETURN QUERY
  WITH daily AS (
    SELECT 
      close_at::DATE as trade_date,
      COUNT(*) as trades_count,
      SUM(pnl) as pnl
    FROM public.trades
    WHERE user_id = v_user_id
      AND outcome IN ('WIN', 'LOSS', 'BE')
      AND deleted_at IS NULL
      AND close_at >= CURRENT_DATE - p_days
    GROUP BY close_at::DATE
  )
  SELECT 
    d.trade_date,
    d.trades_count,
    d.pnl,
    SUM(d.pnl) OVER (ORDER BY d.trade_date) as cumulative_pnl
  FROM daily d
  ORDER BY d.trade_date;
END;
$$;


ALTER FUNCTION "public"."get_daily_pnl"("p_user_id" "uuid", "p_days" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_daily_pnl"("p_user_id" "uuid", "p_days" integer) IS 'v8.5.9: Daily P&L with cumulative for equity curve';



CREATE OR REPLACE FUNCTION "public"."get_database_size"() RETURNS TABLE("total_size_mb" numeric, "total_size_gb" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  RETURN QUERY
  SELECT 
    ROUND(pg_database_size(current_database())::NUMERIC / 1048576, 2) as total_size_mb,
    ROUND(pg_database_size(current_database())::NUMERIC / 1073741824, 4) as total_size_gb;
END;
$$;


