CREATE OR REPLACE FUNCTION "public"."get_equity_curve"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_start_date" "date" DEFAULT NULL::"date") RETURNS TABLE("trade_date" timestamp with time zone, "trade_id" "uuid", "pnl" numeric, "cumulative_pnl" numeric, "equity" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_initial_portfolio NUMERIC;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  SELECT initial_portfolio INTO v_initial_portfolio
  FROM public.profiles
  WHERE id = v_user_id;
  
  v_initial_portfolio := COALESCE(v_initial_portfolio, 10000);
  
  RETURN QUERY
  SELECT 
    t.close_at as trade_date,
    t.id as trade_id,
    t.pnl,
    SUM(t.pnl) OVER (ORDER BY t.close_at, t.id) as cumulative_pnl,
    v_initial_portfolio + SUM(t.pnl) OVER (ORDER BY t.close_at, t.id) as equity
  FROM public.trades t
  WHERE t.user_id = v_user_id
    AND t.outcome IN ('WIN', 'LOSS', 'BE')
    AND t.deleted_at IS NULL
    AND (p_start_date IS NULL OR t.close_at::DATE >= p_start_date)
  ORDER BY t.close_at, t.id;
END;
$$;


ALTER FUNCTION "public"."get_equity_curve"("p_user_id" "uuid", "p_start_date" "date") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_equity_curve"("p_user_id" "uuid", "p_start_date" "date") IS 'v8.5.9: Equity curve data for charting';



CREATE OR REPLACE FUNCTION "public"."get_existing_trade_external_ids"("p_user_id" "uuid", "p_broker" character varying, "p_external_ids" "text"[]) RETURNS TABLE("external_id" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT t.external_id
    FROM trades t
    WHERE t.user_id = p_user_id
    AND t.broker = p_broker
    AND t.external_id = ANY(p_external_ids);
END;
$$;


