CREATE OR REPLACE FUNCTION "public"."get_finotaur_plan_from_whop"("p_whop_product_id" "text") RETURNS TABLE("finotaur_plan" "text", "billing_interval" "text", "price_usd" numeric, "max_trades" integer, "display_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    wpm.finotaur_plan, 
    wpm.billing_interval, 
    wpm.price_usd, 
    CASE WHEN wpm.max_trades = -1 THEN 999999 ELSE wpm.max_trades END as max_trades,
    wpm.display_name
  FROM whop_plan_mapping wpm
  WHERE wpm.whop_product_id = p_whop_product_id 
    AND wpm.is_active = TRUE;
END;
$$;


