CREATE OR REPLACE FUNCTION "public"."get_instrument_by_symbol"("p_symbol" character varying, "p_exchange" character varying DEFAULT NULL::character varying) RETURNS "public"."instrument_definitions"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_instrument instrument_definitions;
BEGIN
    IF p_exchange IS NOT NULL THEN
        SELECT * INTO v_instrument
        FROM instrument_definitions
        WHERE symbol = p_symbol AND exchange = p_exchange AND is_active = true;
    ELSE
        SELECT * INTO v_instrument
        FROM instrument_definitions
        WHERE symbol = p_symbol AND is_active = true
        LIMIT 1;
    END IF;
    
    RETURN v_instrument;
END;
$$;


