CREATE OR REPLACE FUNCTION "public"."get_ism_insights"("p_report_month" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_month TEXT;
    v_result JSONB;
BEGIN
    -- Use latest month if not specified
    v_month := COALESCE(p_report_month, (SELECT MAX(report_month) FROM ism_economic_environment));
    
    SELECT jsonb_build_object(
        'report_month', v_month,
        'economic_environment', (
            SELECT row_to_json(e.*)
            FROM ism_economic_environment e
            WHERE e.report_month = v_month
        ),
        'sector_outlook', (
            SELECT jsonb_agg(row_to_json(s.*) ORDER BY s.display_order)
            FROM ism_sector_outlook s
            WHERE s.report_month = v_month
        ),
        'stock_tailwinds', (
            SELECT jsonb_agg(row_to_json(t.*) ORDER BY t.is_top_pick DESC, t.display_order)
            FROM ism_stock_tailwinds t
            WHERE t.report_month = v_month
        )
    ) INTO v_result;
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."get_ism_insights"("p_report_month" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_ism_macro_for_stock_analyzer"("p_sector" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_result JSONB;
  v_report_month TEXT;
  v_ism_data JSONB;
  v_macro_snapshot JSONB;
  v_exec_summary JSONB;
  v_sector_ranking JSONB;
  v_quotes JSONB;
  v_trade_ideas JSONB;
BEGIN
  -- 1. Latest ISM report headline data
  SELECT report_month, ism_data, macro_snapshot, executive_summary
  INTO v_report_month, v_ism_data, v_macro_snapshot, v_exec_summary
  FROM ism_reports
  WHERE ism_data IS NOT NULL
  ORDER BY report_month DESC
  LIMIT 1;

  -- 2. Sector ranking from ism_sector_analysis
  SELECT jsonb_build_object(
    'rank', rank,
    'impact_score', impact_score,
    'direction', direction,
    'reasoning', reasoning,
    'key_driver', key_driver,
    'ism_signal', ism_signal,
    'trend', trend,
    'report_month', report_month
  ) INTO v_sector_ranking
  FROM ism_sector_analysis
  WHERE sector_name ILIKE '%' || p_sector || '%'
  ORDER BY report_month DESC
  LIMIT 1;

  -- 2b. Fallback to ism_sector_rankings if sector_analysis empty
  IF v_sector_ranking IS NULL THEN
    SELECT jsonb_build_object(
      'rank', rank,
      'impact_score', impact_score,
      'direction', direction,
      'reasoning', reasoning,
      'quote_support', quote_support,
      'report_month', report_month
    ) INTO v_sector_ranking
    FROM ism_sector_rankings
    WHERE sector_name ILIKE '%' || p_sector || '%'
    ORDER BY report_month DESC
    LIMIT 1;
  END IF;

  -- 3. Executive quotes related to sector
  SELECT COALESCE(jsonb_agg(q_row), '[]'::jsonb)
  INTO v_quotes
  FROM (
    SELECT jsonb_build_object(
      'industry', industry,
      'comment', comment,
      'sentiment', sentiment
    ) AS q_row
    FROM ism_quotes
    WHERE industry ILIKE '%' || p_sector || '%'
       OR industry ILIKE '%' || split_part(p_sector, ' ', 1) || '%'
    ORDER BY created_at DESC
    LIMIT 3
  ) sub;

  -- 4. Trade ideas for sector
  SELECT COALESCE(jsonb_agg(t_row), '[]'::jsonb)
  INTO v_trade_ideas
  FROM (
    SELECT jsonb_build_object(
      'title', title,
      'direction', direction,
      'thesis', thesis,
      'conviction', conviction
    ) AS t_row
    FROM ism_trade_ideas
    WHERE sector ILIKE '%' || p_sector || '%'
    ORDER BY report_month DESC
    LIMIT 2
  ) sub;

  -- Build final result
  v_result := jsonb_build_object(
    'reportMonth', v_report_month,
    'headline', v_ism_data,
    'macroSnapshot', v_macro_snapshot,
    'executiveSummary', v_exec_summary,
    'sectorRanking', v_sector_ranking,
    'relevantQuotes', v_quotes,
    'tradeIdeas', v_trade_ideas
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."get_ism_macro_for_stock_analyzer"("p_sector" "text") OWNER TO "postgres";


