CREATE OR REPLACE FUNCTION "public"."get_ism_sector_context"("p_sector" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_context JSONB;
BEGIN
  SELECT jsonb_build_object(
    'sector', p_sector,
    'latest_ranking', (
      SELECT jsonb_build_object(
        'rank', rank,
        'impact_score', impact_score,
        'direction', direction,
        'reasoning', reasoning,
        'report_month', report_month
      )
      FROM ism_sector_analysis
      WHERE sector_name ILIKE '%' || p_sector || '%'
      ORDER BY report_month DESC
      LIMIT 1
    ),
    'trade_ideas', (
      SELECT jsonb_agg(jsonb_build_object(
        'title', title,
        'thesis', thesis,
        'conviction', conviction,
        'etf', etf
      ))
      FROM (
        SELECT title, thesis, conviction, etf
        FROM ism_trade_ideas
        WHERE sector ILIKE '%' || p_sector || '%'
        ORDER BY report_month DESC
        LIMIT 2
      ) sub
    )
  ) INTO v_context;
  
  RETURN COALESCE(v_context, '{}'::jsonb);
END;
$$;


