CREATE OR REPLACE FUNCTION "public"."get_monthly_performance"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_months" integer DEFAULT 12) RETURNS TABLE("month_year" "text", "total_trades" bigint, "winning_trades" bigint, "losing_trades" bigint, "win_rate" numeric, "total_pnl" numeric, "cumulative_pnl" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  RETURN QUERY
  WITH monthly_stats AS (
    SELECT 
      TO_CHAR(DATE_TRUNC('month', t.open_at), 'YYYY-MM') as month_year,
      COUNT(*)::BIGINT as total_trades,
      COUNT(*) FILTER (WHERE t.outcome = 'WIN')::BIGINT as winning_trades,
      COUNT(*) FILTER (WHERE t.outcome = 'LOSS')::BIGINT as losing_trades,
      ROUND((COUNT(*) FILTER (WHERE t.outcome = 'WIN') * 100.0 / NULLIF(COUNT(*), 0)), 2) as win_rate,
      COALESCE(SUM(t.pnl), 0) as total_pnl
    FROM public.trades t
    WHERE t.user_id = v_user_id
      AND t.open_at >= NOW() - (p_months || ' months')::INTERVAL
      AND t.outcome IN ('WIN', 'LOSS', 'BE')
    GROUP BY DATE_TRUNC('month', t.open_at)
    ORDER BY DATE_TRUNC('month', t.open_at) ASC
  )
  SELECT 
    ms.month_year,
    ms.total_trades,
    ms.winning_trades,
    ms.losing_trades,
    ms.win_rate,
    ms.total_pnl,
    SUM(ms.total_pnl) OVER (ORDER BY ms.month_year) as cumulative_pnl
  FROM monthly_stats ms;
END;
$$;


ALTER FUNCTION "public"."get_monthly_performance"("p_user_id" "uuid", "p_months" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_monthly_performance"("p_user_id" "uuid", "p_months" integer) IS 'v8.5.9: Returns monthly performance with cumulative P&L';



CREATE OR REPLACE FUNCTION "public"."get_monthly_summary"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_months" integer DEFAULT 12) RETURNS TABLE("month_year" "text", "month_start" "date", "total_trades" bigint, "win_rate" numeric, "total_pnl" numeric, "avg_pnl" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  RETURN QUERY
  SELECT 
    TO_CHAR(DATE_TRUNC('month', t.close_at), 'Mon YYYY') as month_year,
    DATE_TRUNC('month', t.close_at)::DATE as month_start,
    COUNT(*)::BIGINT as total_trades,
    ROUND((COUNT(*) FILTER (WHERE t.outcome = 'WIN')::NUMERIC / NULLIF(COUNT(*), 0)) * 100, 2) as win_rate,
    COALESCE(SUM(t.pnl), 0) as total_pnl,
    COALESCE(ROUND(AVG(t.pnl), 2), 0) as avg_pnl
  FROM public.trades t
  WHERE t.user_id = v_user_id
    AND t.outcome IN ('WIN', 'LOSS', 'BE')
    AND t.deleted_at IS NULL
    AND t.close_at >= DATE_TRUNC('month', CURRENT_DATE) - (p_months || ' months')::INTERVAL
  GROUP BY DATE_TRUNC('month', t.close_at)
  ORDER BY month_start DESC;
END;
$$;


ALTER FUNCTION "public"."get_monthly_summary"("p_user_id" "uuid", "p_months" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_monthly_summary"("p_user_id" "uuid", "p_months" integer) IS 'v8.5.9: Monthly performance summary';



