CREATE OR REPLACE FUNCTION "public"."get_newsletter_config"() RETURNS TABLE("config_key" "text", "config_value" "jsonb", "description" "text", "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM profiles 
    WHERE profiles.id = auth.uid() 
    AND profiles.role IN ('admin', 'super_admin')
  ) THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  RETURN QUERY
  SELECT 
    nc.config_key, 
    nc.config_value, 
    nc.description,
    nc.updated_at
  FROM newsletter_config nc
  ORDER BY nc.config_key;
END;
$$;


