CREATE OR REPLACE FUNCTION "public"."get_newsletter_users"() RETURNS TABLE("id" "uuid", "email" "text", "display_name" "text", "account_type" "text", "newsletter_enabled" boolean, "newsletter_status" "text", "newsletter_started_at" timestamp with time zone, "newsletter_expires_at" timestamp with time zone, "newsletter_trial_ends_at" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_caller_role TEXT;
BEGIN
  -- Get caller's role (returns NULL if not found)
  SELECT role INTO v_caller_role 
  FROM profiles 
  WHERE profiles.id = auth.uid();

  -- Allow if: admin/super_admin OR service_role OR no auth context (edge function)
  IF v_caller_role IS NOT NULL AND v_caller_role NOT IN ('admin', 'super_admin') THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  RETURN QUERY
  SELECT 
    p.id,
    p.email::TEXT,
COALESCE(p.display_name, split_part(p.email, '@', 1))::TEXT as display_name,
    COALESCE(p.account_type, 'free')::TEXT as account_type,
    COALESCE(p.newsletter_enabled, FALSE)::BOOLEAN as newsletter_enabled,
    COALESCE(p.newsletter_status, 'inactive')::TEXT as newsletter_status,
    p.newsletter_started_at,
    p.newsletter_expires_at,
    p.newsletter_trial_ends_at,
    p.created_at
  FROM profiles p
  WHERE p.email IS NOT NULL
  ORDER BY 
    CASE COALESCE(p.newsletter_status, 'inactive')
      WHEN 'active' THEN 1 
      WHEN 'trial' THEN 2 
      WHEN 'cancelled' THEN 3
      ELSE 4 
    END,
    p.created_at DESC;
END;
$$;


ALTER FUNCTION "public"."get_newsletter_users"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_next_trading_day"("from_date" "date") RETURNS "date"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  next_date DATE := from_date + 1;
  max_iterations INTEGER := 14;
  iteration INTEGER := 0;
BEGIN
  WHILE iteration < max_iterations LOOP
    IF EXTRACT(DOW FROM next_date) IN (0, 6) THEN
      next_date := next_date + 1;
      iteration := iteration + 1;
      CONTINUE;
    END IF;
    
    IF EXISTS (SELECT 1 FROM us_market_holidays WHERE date = next_date AND type = 'full_close') THEN
      next_date := next_date + 1;
      iteration := iteration + 1;
      CONTINUE;
    END IF;
    
    RETURN next_date;
  END LOOP;
  
  RETURN from_date + 1;
END;
$$;


