CREATE OR REPLACE FUNCTION "public"."get_performance_by_strategy"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("strategy_id" "uuid", "strategy_name" "text", "total_trades" bigint, "winning_trades" bigint, "losing_trades" bigint, "win_rate" numeric, "total_pnl" numeric, "avg_pnl" numeric, "profit_factor" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  RETURN QUERY
  SELECT 
    t.strategy_id,
    COALESCE(s.name, 'No Strategy') as strategy_name,
    COUNT(*)::BIGINT as total_trades,
    COUNT(*) FILTER (WHERE t.outcome = 'WIN')::BIGINT as winning_trades,
    COUNT(*) FILTER (WHERE t.outcome = 'LOSS')::BIGINT as losing_trades,
    ROUND((COUNT(*) FILTER (WHERE t.outcome = 'WIN') * 100.0 / NULLIF(COUNT(*), 0)), 2) as win_rate,
    COALESCE(SUM(t.pnl), 0) as total_pnl,
    ROUND(AVG(t.pnl), 2) as avg_pnl,
    ROUND(
      SUM(t.pnl) FILTER (WHERE t.outcome = 'WIN') / 
      NULLIF(ABS(SUM(t.pnl) FILTER (WHERE t.outcome = 'LOSS')), 0),
      2
    ) as profit_factor
  FROM public.trades t
  LEFT JOIN public.strategies s ON s.id = t.strategy_id
  WHERE t.user_id = v_user_id
    AND t.outcome IN ('WIN', 'LOSS', 'BE')
  GROUP BY t.strategy_id, s.name
  ORDER BY total_pnl DESC;
END;
$$;


ALTER FUNCTION "public"."get_performance_by_strategy"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_performance_by_strategy"("p_user_id" "uuid") IS 'v8.5.9: Returns performance statistics grouped by strategy';



CREATE OR REPLACE FUNCTION "public"."get_performance_by_symbol"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("symbol" "text", "total_trades" bigint, "winning_trades" bigint, "losing_trades" bigint, "win_rate" numeric, "total_pnl" numeric, "avg_pnl" numeric, "best_trade" numeric, "worst_trade" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  RETURN QUERY
  SELECT 
    t.symbol,
    COUNT(*)::BIGINT as total_trades,
    COUNT(*) FILTER (WHERE t.outcome = 'WIN')::BIGINT as winning_trades,
    COUNT(*) FILTER (WHERE t.outcome = 'LOSS')::BIGINT as losing_trades,
    ROUND((COUNT(*) FILTER (WHERE t.outcome = 'WIN') * 100.0 / NULLIF(COUNT(*), 0)), 2) as win_rate,
    COALESCE(SUM(t.pnl), 0) as total_pnl,
    ROUND(AVG(t.pnl), 2) as avg_pnl,
    COALESCE(MAX(t.pnl), 0) as best_trade,
    COALESCE(MIN(t.pnl), 0) as worst_trade
  FROM public.trades t
  WHERE t.user_id = v_user_id
    AND t.outcome IN ('WIN', 'LOSS', 'BE')
  GROUP BY t.symbol
  ORDER BY total_pnl DESC;
END;
$$;


ALTER FUNCTION "public"."get_performance_by_symbol"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_performance_by_symbol"("p_user_id" "uuid") IS 'v8.5.9: Returns performance statistics grouped by symbol';



CREATE OR REPLACE FUNCTION "public"."get_performance_summary"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS TABLE("total_trades" bigint, "winning_trades" bigint, "losing_trades" bigint, "breakeven_trades" bigint, "win_rate" numeric, "total_pnl" numeric, "avg_win" numeric, "avg_loss" numeric, "largest_win" numeric, "largest_loss" numeric, "profit_factor" numeric, "avg_rr" numeric, "expectancy" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_gross_profit NUMERIC;
  v_gross_loss NUMERIC;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  -- Security check
  IF v_user_id != auth.uid() AND NOT public.is_admin() THEN
    RAISE EXCEPTION 'Access denied';
  END IF;
  
  RETURN QUERY
  WITH trade_stats AS (
    SELECT 
      COUNT(*) as total,
      COUNT(*) FILTER (WHERE outcome = 'WIN') as wins,
      COUNT(*) FILTER (WHERE outcome = 'LOSS') as losses,
      COUNT(*) FILTER (WHERE outcome = 'BE') as be,
      SUM(pnl) as total_pnl,
      AVG(pnl) FILTER (WHERE outcome = 'WIN') as avg_win,
      AVG(pnl) FILTER (WHERE outcome = 'LOSS') as avg_loss,
      MAX(pnl) as largest_win,
      MIN(pnl) as largest_loss,
      SUM(pnl) FILTER (WHERE pnl > 0) as gross_profit,
      ABS(SUM(pnl) FILTER (WHERE pnl < 0)) as gross_loss,
      AVG(rr) as avg_rr
    FROM public.trades
    WHERE user_id = v_user_id
      AND outcome IN ('WIN', 'LOSS', 'BE')
      AND deleted_at IS NULL
      AND (p_start_date IS NULL OR open_at::DATE >= p_start_date)
      AND (p_end_date IS NULL OR open_at::DATE <= p_end_date)
  )
  SELECT 
    ts.total,
    ts.wins,
    ts.losses,
    ts.be,
    CASE WHEN ts.total > 0 THEN ROUND((ts.wins::NUMERIC / ts.total) * 100, 2) ELSE 0 END,
    COALESCE(ts.total_pnl, 0),
    COALESCE(ROUND(ts.avg_win, 2), 0),
    COALESCE(ROUND(ts.avg_loss, 2), 0),
    COALESCE(ts.largest_win, 0),
    COALESCE(ts.largest_loss, 0),
    CASE WHEN ts.gross_loss > 0 THEN ROUND(ts.gross_profit / ts.gross_loss, 2) ELSE 0 END,
    COALESCE(ROUND(ts.avg_rr, 2), 0),
    CASE WHEN ts.total > 0 THEN ROUND(ts.total_pnl / ts.total, 2) ELSE 0 END
  FROM trade_stats ts;
END;
$$;


ALTER FUNCTION "public"."get_performance_summary"("p_user_id" "uuid", "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_performance_summary"("p_user_id" "uuid", "p_start_date" "date", "p_end_date" "date") IS 'v8.5.9: Comprehensive trading performance metrics';



CREATE OR REPLACE FUNCTION "public"."get_platform_stats"() RETURNS json
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  stats JSON;
  v_basic_monthly INTEGER;
  v_basic_yearly INTEGER;
  v_premium_monthly INTEGER;
  v_premium_yearly INTEGER;
  v_monthly_revenue NUMERIC;
  v_yearly_revenue NUMERIC;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;

  -- Count subscribers by plan and interval
  SELECT COUNT(*) INTO v_basic_monthly
  FROM public.profiles 
  WHERE account_type = 'basic' AND subscription_interval = 'monthly';
  
  SELECT COUNT(*) INTO v_basic_yearly
  FROM public.profiles 
  WHERE account_type = 'basic' AND subscription_interval = 'yearly';
  
  SELECT COUNT(*) INTO v_premium_monthly
  FROM public.profiles 
  WHERE account_type = 'premium' AND subscription_interval = 'monthly';
  
  SELECT COUNT(*) INTO v_premium_yearly
  FROM public.profiles 
  WHERE account_type = 'premium' AND subscription_interval = 'yearly';

  -- Calculate revenue (prices: basic monthly=$19.99, yearly=$149; premium monthly=$39.99, yearly=$299)
  v_monthly_revenue := 
    (v_basic_monthly * 19.99) + 
    (v_basic_yearly * 12.42) +   -- 149/12 = 12.42
    (v_premium_monthly * 39.99) + 
    (v_premium_yearly * 24.92);  -- 299/12 = 24.92
    
  v_yearly_revenue := v_monthly_revenue * 12;

  -- Build comprehensive stats object
  SELECT json_build_object(
    'total_users', (SELECT COUNT(*) FROM public.profiles),
    'active_users', (SELECT COUNT(*) FROM public.profiles WHERE last_login_at > NOW() - INTERVAL '30 days'),
    'free_users', (SELECT COUNT(*) FROM public.profiles WHERE account_type = 'free'),
    'basic_users', (SELECT COUNT(*) FROM public.profiles WHERE account_type = 'basic'),
    'premium_users', (SELECT COUNT(*) FROM public.profiles WHERE account_type = 'premium'),
    'trial_users', (SELECT COUNT(*) FROM public.profiles WHERE subscription_status = 'trial'),
    'banned_users', (SELECT COUNT(*) FROM public.profiles WHERE is_banned = true),
    'basic_monthly_subscribers', v_basic_monthly,
    'basic_yearly_subscribers', v_basic_yearly,
    'premium_monthly_subscribers', v_premium_monthly,
    'premium_yearly_subscribers', v_premium_yearly,
    'estimated_monthly_revenue', ROUND(v_monthly_revenue, 2),
    'estimated_yearly_revenue', ROUND(v_yearly_revenue, 2),
    'total_trades', (SELECT COUNT(*) FROM public.trades WHERE deleted_at IS NULL),
    'trades_today', (SELECT COUNT(*) FROM public.trades WHERE created_at::date = CURRENT_DATE AND deleted_at IS NULL),
    'trades_this_week', (SELECT COUNT(*) FROM public.trades WHERE created_at > NOW() - INTERVAL '7 days' AND deleted_at IS NULL),
    'trades_this_month', (SELECT COUNT(*) FROM public.trades WHERE DATE_TRUNC('month', created_at) = DATE_TRUNC('month', CURRENT_DATE) AND deleted_at IS NULL),
    'total_strategies', (SELECT COUNT(*) FROM public.strategies WHERE deleted_at IS NULL),
    'new_users_today', (SELECT COUNT(*) FROM public.profiles WHERE created_at::date = CURRENT_DATE),
    'new_users_this_week', (SELECT COUNT(*) FROM public.profiles WHERE created_at > NOW() - INTERVAL '7 days'),
    'new_users_this_month', (SELECT COUNT(*) FROM public.profiles WHERE DATE_TRUNC('month', created_at) = DATE_TRUNC('month', CURRENT_DATE)),
    'generated_at', NOW()
  ) INTO stats;

  RETURN stats;
END;
$_$;


ALTER FUNCTION "public"."get_platform_stats"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_platform_stats"() IS 'v8.5.10: Returns comprehensive platform statistics including users, trades, and revenue estimates. Admin only.';



CREATE OR REPLACE FUNCTION "public"."get_platform_subscription_status"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_result JSONB;
  v_profile RECORD;
  v_trial_days_remaining INTEGER;
  v_days_until_expiry INTEGER;
BEGIN
  SELECT 
    platform_plan,
    platform_subscription_status,
    platform_billing_interval,
    platform_subscription_started_at,
    platform_subscription_expires_at,
    platform_trial_ends_at,
    platform_is_in_trial,
    platform_cancel_at_period_end,
    platform_cancelled_at,
    platform_pro_trial_used_at,
    platform_core_trial_used_at,
    platform_whop_membership_id,
    platform_bundle_journal_granted,
    platform_bundle_newsletter_granted,
    platform_bundle_newsletter_choice
  INTO v_profile
  FROM profiles
  WHERE id = p_user_id;
  
  IF v_profile IS NULL THEN
    RETURN jsonb_build_object('plan', 'free', 'status', 'inactive');
  END IF;
  
  -- Calculate trial days remaining
  IF v_profile.platform_is_in_trial AND v_profile.platform_trial_ends_at IS NOT NULL THEN
    v_trial_days_remaining := GREATEST(0, 
      EXTRACT(DAY FROM (v_profile.platform_trial_ends_at - NOW()))::INTEGER
    );
  END IF;
  
  -- Calculate days until expiry
  IF v_profile.platform_subscription_expires_at IS NOT NULL THEN
    v_days_until_expiry := GREATEST(0,
      EXTRACT(DAY FROM (v_profile.platform_subscription_expires_at - NOW()))::INTEGER
    );
  END IF;
  
  RETURN jsonb_build_object(
    'plan', COALESCE(v_profile.platform_plan, 'free'),
    'status', COALESCE(v_profile.platform_subscription_status, 'inactive'),
    'billing_interval', v_profile.platform_billing_interval,
    'started_at', v_profile.platform_subscription_started_at,
    'expires_at', v_profile.platform_subscription_expires_at,
    'days_until_expiry', v_days_until_expiry,
    'is_in_trial', COALESCE(v_profile.platform_is_in_trial, false),
    'trial_ends_at', v_profile.platform_trial_ends_at,
    'trial_days_remaining', v_trial_days_remaining,
    'cancel_at_period_end', COALESCE(v_profile.platform_cancel_at_period_end, false),
    'cancelled_at', v_profile.platform_cancelled_at,
    'pro_trial_eligible', (v_profile.platform_pro_trial_used_at IS NULL),
    'core_trial_eligible', (v_profile.platform_core_trial_used_at IS NULL),
    'whop_membership_id', v_profile.platform_whop_membership_id,
    'bundle', jsonb_build_object(
      'journal_granted', COALESCE(v_profile.platform_bundle_journal_granted, false),
      'newsletter_granted', COALESCE(v_profile.platform_bundle_newsletter_granted, false),
      'newsletter_choice', v_profile.platform_bundle_newsletter_choice
    )
  );
END;
$$;


