CREATE OR REPLACE FUNCTION "public"."get_published_reports_for_user"("p_user_id" "uuid", "p_limit" integer DEFAULT 100, "p_is_tester" boolean DEFAULT false) RETURNS TABLE("id" "uuid", "report_type" "text", "original_report_id" "text", "title" "text", "subtitle" "text", "ticker" "text", "company_name" "text", "sector" "text", "report_month" "text", "markdown_content" "text", "html_content" "text", "qa_score" integer, "pdf_url" "text", "pdf_storage_path" "text", "highlights" "text"[], "key_metric_label" "text", "key_metric_value" "text", "key_insights_count" integer, "is_featured" boolean, "is_pinned" boolean, "published_at" timestamp with time zone, "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "visibility" "text", "market_regime" "text", "pmi_value" numeric, "target_group" "text", "likes_count" bigint, "comments_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_user_profile RECORD;
BEGIN
    -- Get user profile for admin check
    SELECT 
        role, top_secret_enabled, newsletter_enabled, newsletter_paid, account_type
    INTO v_user_profile
    FROM public.profiles
    WHERE profiles.id = p_user_id;

    RETURN QUERY
    SELECT 
        pr.id,
        pr.report_type,
        pr.original_report_id,
        pr.title,
        pr.subtitle,
        pr.ticker,
        pr.company_name,
        pr.sector,
        pr.report_month,
        pr.markdown_content,
        pr.html_content,
        pr.qa_score,
        pr.pdf_url,
        pr.pdf_storage_path,
        pr.highlights,
        pr.key_metric_label,
        pr.key_metric_value,
        pr.key_insights_count,
        pr.is_featured,
        pr.is_pinned,
        pr.published_at,
        pr.created_at,
        pr.updated_at,
        pr.visibility,
        pr.market_regime,
        pr.pmi_value,
        pr.target_group,
        COALESCE((SELECT COUNT(*) FROM report_likes rl WHERE rl.report_id = pr.id), 0)::BIGINT as likes_count,
        0::BIGINT as comments_count
    FROM public.published_reports pr
    WHERE 
        -- Visibility filtering
        CASE 
          -- Testers see ALL reports (including test)
          WHEN p_is_tester = TRUE THEN TRUE
          -- Admins see ALL reports
          WHEN v_user_profile.role IN ('admin', 'super_admin') THEN TRUE
          -- Regular users see only live reports
          ELSE (
            pr.visibility = 'live'
          )
        END
        -- Target group filtering (for non-admins)
        AND (
            v_user_profile.role IN ('admin', 'super_admin')
            OR pr.target_group = 'all'
            OR (pr.target_group = 'top_secret' AND v_user_profile.top_secret_enabled = true)
            OR (pr.target_group = 'newsletter' AND (v_user_profile.newsletter_enabled = true OR v_user_profile.newsletter_paid = true))
            OR (pr.target_group = 'trading_journal' AND v_user_profile.account_type IN ('basic', 'premium', 'pro'))
        )
    ORDER BY 
        pr.is_pinned DESC NULLS LAST,
        pr.is_featured DESC NULLS LAST,
        pr.published_at DESC
    LIMIT p_limit;
END;
$$;


ALTER FUNCTION "public"."get_published_reports_for_user"("p_user_id" "uuid", "p_limit" integer, "p_is_tester" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_published_reports_for_user"("p_user_id" "uuid", "p_limit" integer, "p_is_tester" boolean) IS 'Get published reports for a user with visibility filtering.
- Regular users (p_is_tester=false): See only live reports
- Testers (p_is_tester=true): See ALL reports including test
- Admins: See ALL reports regardless of p_is_tester
v1.2: Simplified to use only live visibility';



CREATE OR REPLACE FUNCTION "public"."get_published_reports_stats"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_stats JSONB;
    v_this_month DATE;
    v_last_month DATE;
BEGIN
    v_this_month := DATE_TRUNC('month', NOW());
    v_last_month := DATE_TRUNC('month', NOW() - INTERVAL '1 month');

    SELECT jsonb_build_object(
        'total', COUNT(*),
        'this_month', COUNT(*) FILTER (WHERE published_at >= v_this_month),
        'last_month', COUNT(*) FILTER (WHERE published_at >= v_last_month AND published_at < v_this_month),
        'by_type', jsonb_build_object(
            'ism', COUNT(*) FILTER (WHERE report_type = 'ism'),
            'company', COUNT(*) FILTER (WHERE report_type = 'company'),
            'crypto', COUNT(*) FILTER (WHERE report_type = 'crypto'),
            'weekly', COUNT(*) FILTER (WHERE report_type = 'weekly')
        ),
        'by_target', jsonb_build_object(
            'all', COUNT(*) FILTER (WHERE target_group = 'all'),
            'top_secret', COUNT(*) FILTER (WHERE target_group = 'top_secret'),
            'newsletter', COUNT(*) FILTER (WHERE target_group = 'newsletter'),
            'trading_journal', COUNT(*) FILTER (WHERE target_group = 'trading_journal')
        ),
        'featured_count', COUNT(*) FILTER (WHERE is_featured = true),
        'pinned_count', COUNT(*) FILTER (WHERE is_pinned = true),
        'email_sent_count', COUNT(*) FILTER (WHERE email_sent = true),
        'total_emails_sent', COALESCE(SUM(email_recipient_count), 0),
        'avg_qa_score', ROUND(AVG(qa_score)::NUMERIC, 1)
    ) INTO v_stats
    FROM published_reports;

    RETURN v_stats;
END;
$$;


ALTER FUNCTION "public"."get_published_reports_stats"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_remaining_trades"("p_user_id" "uuid") RETURNS TABLE("remaining" integer, "used" integer, "max_trades" integer, "account_type" "text", "can_create" boolean, "is_in_trial" boolean, "trial_days_remaining" integer, "needs_subscription" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_profile RECORD;
  v_is_free BOOLEAN;
BEGIN
  SELECT 
    p.account_type,
    p.max_trades,
    p.current_month_trades_count,
    p.trade_count,
    p.subscription_status,
    p.is_in_trial,
    p.trial_ends_at,
    p.role
  INTO v_profile
  FROM public.profiles p
  WHERE p.id = p_user_id;
  
  -- User not found - return free defaults
  IF NOT FOUND THEN
    RETURN QUERY SELECT 
      15::INTEGER, 0::INTEGER, 15::INTEGER,
      'free'::TEXT, FALSE::BOOLEAN, FALSE::BOOLEAN,
      0::INTEGER, TRUE::BOOLEAN;
    RETURN;
  END IF;
  
  -- Admin/Premium/VIP/Beta = unlimited
  IF v_profile.role IN ('admin', 'super_admin') OR 
     v_profile.account_type IN ('premium', 'admin', 'vip', 'beta') THEN
    RETURN QUERY SELECT 
      999999::INTEGER,
      COALESCE(v_profile.current_month_trades_count, 0)::INTEGER,
      999999::INTEGER,
      v_profile.account_type::TEXT,
      TRUE::BOOLEAN,
      COALESCE(v_profile.is_in_trial, FALSE)::BOOLEAN,
      0::INTEGER,
      FALSE::BOOLEAN;
    RETURN;
  END IF;
  
  -- FREE users: lifetime trade_count (never resets)
  v_is_free := v_profile.account_type IN ('free', 'platform_free') 
    OR v_profile.account_type IS NULL;
  
  IF v_is_free THEN
    RETURN QUERY SELECT 
      GREATEST(0, 15 - COALESCE(v_profile.trade_count, 0))::INTEGER,
      COALESCE(v_profile.trade_count, 0)::INTEGER,
      15::INTEGER,
      COALESCE(v_profile.account_type, 'free')::TEXT,
      (COALESCE(v_profile.trade_count, 0) < 15)::BOOLEAN,
      FALSE::BOOLEAN,
      0::INTEGER,
      FALSE::BOOLEAN;
    RETURN;
  END IF;
  
  -- Basic/Trial: monthly current_month_trades_count
  RETURN QUERY SELECT
    GREATEST(0, COALESCE(v_profile.max_trades, 25) - COALESCE(v_profile.current_month_trades_count, 0))::INTEGER,
    COALESCE(v_profile.current_month_trades_count, 0)::INTEGER,
    COALESCE(v_profile.max_trades, 25)::INTEGER,
    v_profile.account_type::TEXT,
    public.can_create_trade(p_user_id)::BOOLEAN,
    COALESCE(v_profile.is_in_trial, FALSE)::BOOLEAN,
    CASE WHEN v_profile.trial_ends_at IS NOT NULL AND v_profile.trial_ends_at > NOW()
      THEN EXTRACT(DAY FROM (v_profile.trial_ends_at - NOW()))::INTEGER
      ELSE 0 END::INTEGER,
    (v_profile.subscription_status IS NULL OR 
     v_profile.subscription_status IN ('expired', 'cancelled'))::BOOLEAN;
END;
$$;


ALTER FUNCTION "public"."get_remaining_trades"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_remaining_trades"("p_user_id" "uuid") IS 'v10.3.0-CANONICAL: Single source of truth. FREE uses trade_count (lifetime, never resets). BASIC uses current_month_trades_count (monthly). Returns needs_subscription flag.';



CREATE OR REPLACE FUNCTION "public"."get_revenue_analytics"("p_days" integer DEFAULT 30) RETURNS TABLE("date" "date", "basic_monthly_count" integer, "basic_yearly_count" integer, "premium_monthly_count" integer, "premium_yearly_count" integer, "daily_revenue" numeric, "cumulative_revenue" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_start_date DATE;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;

  -- Limit to reasonable range
  IF p_days > 365 THEN
    p_days := 365;
  END IF;

  v_start_date := CURRENT_DATE - p_days;

  RETURN QUERY
  WITH RECURSIVE date_series AS (
    SELECT v_start_date as date
    UNION ALL
    SELECT (date + 1)::DATE FROM date_series WHERE date < CURRENT_DATE
  ),
  daily_stats AS (
    SELECT 
      ds.date,
      COUNT(*) FILTER (WHERE p.account_type = 'basic' AND p.subscription_interval = 'monthly') as basic_monthly,
      COUNT(*) FILTER (WHERE p.account_type = 'basic' AND p.subscription_interval = 'yearly') as basic_yearly,
      COUNT(*) FILTER (WHERE p.account_type = 'premium' AND p.subscription_interval = 'monthly') as premium_monthly,
      COUNT(*) FILTER (WHERE p.account_type = 'premium' AND p.subscription_interval = 'yearly') as premium_yearly
    FROM date_series ds
    LEFT JOIN public.profiles p ON p.subscription_started_at::DATE <= ds.date 
      AND (p.subscription_expires_at IS NULL OR p.subscription_expires_at::DATE >= ds.date)
      AND p.account_type IN ('basic', 'premium')
    GROUP BY ds.date
  )
  SELECT 
    ds.date,
    ds.basic_monthly::INTEGER,
    ds.basic_yearly::INTEGER,
    ds.premium_monthly::INTEGER,
    ds.premium_yearly::INTEGER,
    ROUND(((ds.basic_monthly * 19.99) + (ds.basic_yearly * 12.42) + 
     (ds.premium_monthly * 39.99) + (ds.premium_yearly * 24.92))::NUMERIC, 2) as daily_revenue,
    ROUND(SUM((ds.basic_monthly * 19.99) + (ds.basic_yearly * 12.42) +
        (ds.premium_monthly * 39.99) + (ds.premium_yearly * 24.92)) 
    OVER (ORDER BY ds.date)::NUMERIC, 2) as cumulative_revenue
  FROM daily_stats ds
  ORDER BY ds.date;
END;
$$;


ALTER FUNCTION "public"."get_revenue_analytics"("p_days" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_revenue_analytics"("p_days" integer) IS 'v8.5.10: Returns daily revenue analytics for specified number of days. Admin only.';



CREATE OR REPLACE FUNCTION "public"."get_revenue_stats"() RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_stats JSONB;
  v_journal_mrr NUMERIC;
  v_newsletter_mrr NUMERIC;
  v_top_secret_mrr NUMERIC;
  v_platform_mrr NUMERIC;
  v_total_mrr NUMERIC;
BEGIN
  v_stats := get_comprehensive_subscription_stats()->'revenue';
  
  v_journal_mrr := COALESCE((v_stats->>'journal_mrr')::NUMERIC, 0);
  v_newsletter_mrr := COALESCE((v_stats->>'newsletter_mrr')::NUMERIC, 0);
  v_top_secret_mrr := COALESCE((v_stats->>'top_secret_mrr')::NUMERIC, 0);
  v_platform_mrr := COALESCE((v_stats->>'platform_mrr')::NUMERIC, 0);
  v_total_mrr := v_journal_mrr + v_newsletter_mrr + v_top_secret_mrr + v_platform_mrr;
  
  RETURN jsonb_build_object(
    'journal_mrr', ROUND(v_journal_mrr, 2),
    'newsletter_mrr', ROUND(v_newsletter_mrr, 2),
    'top_secret_mrr', ROUND(v_top_secret_mrr, 2),
    'platform_mrr', ROUND(v_platform_mrr, 2),
    'total_mrr', ROUND(v_total_mrr, 2),
    'total_arr', ROUND(v_total_mrr * 12, 2)
  );
END;
$$;


ALTER FUNCTION "public"."get_revenue_stats"() OWNER TO "postgres";


