CREATE OR REPLACE FUNCTION "public"."get_significant_insider_buys"("p_min_value" numeric DEFAULT 100000, "p_days_back" integer DEFAULT 30) RETURNS TABLE("ticker" character varying, "insider_name" character varying, "insider_title" character varying, "shares" bigint, "total_value" numeric, "transaction_date" "date", "filed_date" "date")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    i.ticker,
    i.insider_name,
    i.insider_title,
    i.shares,
    i.total_value,
    i.transaction_date,
    i.filed_date
  FROM insider_transactions i
  WHERE i.transaction_type = 'P'
    AND i.total_value >= p_min_value
    AND i.transaction_date >= CURRENT_DATE - p_days_back
