CREATE OR REPLACE FUNCTION "public"."get_slow_queries"("limit_count" integer DEFAULT 10) RETURNS TABLE("query" "text", "mean_time_ms" numeric, "calls" bigint, "total_time_ms" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  -- Check if pg_stat_statements extension is available
  IF NOT EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_stat_statements') THEN
    RAISE EXCEPTION 'pg_stat_statements extension is not enabled';
  END IF;
  
  RETURN QUERY
  SELECT 
    pss.query::TEXT,
    ROUND(pss.mean_exec_time::NUMERIC, 2) as mean_time_ms,
    pss.calls::BIGINT,
    ROUND(pss.total_exec_time::NUMERIC, 2) as total_time_ms
  FROM pg_stat_statements pss
  WHERE pss.query NOT LIKE '%pg_stat_statements%'
  ORDER BY pss.mean_exec_time DESC
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION "public"."get_slow_queries"("limit_count" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_slow_queries"("limit_count" integer) IS 'v8.5.10: Get slowest queries for performance monitoring. Requires pg_stat_statements extension. (admin only)';



CREATE OR REPLACE FUNCTION "public"."get_snaptrade_import_stats"("p_user_id" "uuid", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS TABLE("total_imported" bigint, "by_symbol" "jsonb", "by_side" "jsonb", "by_account" "jsonb", "date_range" "jsonb")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_start_date DATE;
  v_end_date DATE;
  v_total BIGINT;
  v_by_symbol JSONB;
  v_by_side JSONB;
  v_by_account JSONB;
BEGIN
  -- Set default date range (last 30 days)
  v_start_date := COALESCE(p_start_date, CURRENT_DATE - INTERVAL '30 days');
  v_end_date := COALESCE(p_end_date, CURRENT_DATE);
  
  -- Calculate total count
  SELECT COUNT(*) INTO v_total
  FROM trades
  WHERE user_id = p_user_id
    AND import_source = 'snaptrade'
    AND imported_at::DATE BETWEEN v_start_date AND v_end_date
    AND deleted_at IS NULL;
  
  -- Aggregate by symbol (SEPARATE QUERY)
  SELECT COALESCE(jsonb_object_agg(symbol, cnt), '{}'::jsonb)
  INTO v_by_symbol
  FROM (
    SELECT symbol, COUNT(*) as cnt
    FROM trades
    WHERE user_id = p_user_id
      AND import_source = 'snaptrade'
      AND imported_at::DATE BETWEEN v_start_date AND v_end_date
      AND deleted_at IS NULL
    GROUP BY symbol
    ORDER BY cnt DESC
  ) symbol_stats;
  
  -- Aggregate by side (SEPARATE QUERY)
  SELECT COALESCE(jsonb_object_agg(side, cnt), '{}'::jsonb)
  INTO v_by_side
  FROM (
    SELECT side, COUNT(*) as cnt
    FROM trades
    WHERE user_id = p_user_id
      AND import_source = 'snaptrade'
      AND imported_at::DATE BETWEEN v_start_date AND v_end_date
      AND deleted_at IS NULL
    GROUP BY side
  ) side_stats;
  
  -- Aggregate by account (SEPARATE QUERY)
  SELECT COALESCE(jsonb_object_agg(account_id, cnt), '{}'::jsonb)
  INTO v_by_account
  FROM (
    SELECT COALESCE(snaptrade_account_id::TEXT, 'unknown') as account_id, COUNT(*) as cnt
    FROM trades
    WHERE user_id = p_user_id
      AND import_source = 'snaptrade'
      AND imported_at::DATE BETWEEN v_start_date AND v_end_date
      AND deleted_at IS NULL
    GROUP BY snaptrade_account_id
  ) account_stats;
  
  -- Return all results
  RETURN QUERY SELECT 
    COALESCE(v_total, 0::BIGINT),
    COALESCE(v_by_symbol, '{}'::jsonb),
    COALESCE(v_by_side, '{}'::jsonb),
    COALESCE(v_by_account, '{}'::jsonb),
    jsonb_build_object(
      'start_date', v_start_date,
      'end_date', v_end_date,
      'days', (v_end_date - v_start_date)::INTEGER
    );
END;
$$;


ALTER FUNCTION "public"."get_snaptrade_import_stats"("p_user_id" "uuid", "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_snaptrade_import_stats"("p_user_id" "uuid", "p_start_date" "date", "p_end_date" "date") IS 'v8.5.10: Get detailed import statistics with fixed aggregation.';



CREATE OR REPLACE FUNCTION "public"."get_strategy_performance"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_strategy_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("strategy_id" "uuid", "strategy_name" "text", "total_trades" bigint, "win_rate" numeric, "total_pnl" numeric, "avg_pnl" numeric, "profit_factor" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  RETURN QUERY
  SELECT 
    s.id as strategy_id,
    s.name as strategy_name,
    COUNT(t.id)::BIGINT as total_trades,
    CASE 
      WHEN COUNT(t.id) > 0 
      THEN ROUND((COUNT(*) FILTER (WHERE t.outcome = 'WIN')::NUMERIC / COUNT(t.id)) * 100, 2) 
      ELSE 0 
    END as win_rate,
    COALESCE(SUM(t.pnl), 0) as total_pnl,
    COALESCE(ROUND(AVG(t.pnl), 2), 0) as avg_pnl,
    CASE 
      WHEN ABS(SUM(t.pnl) FILTER (WHERE t.pnl < 0)) > 0 
      THEN ROUND(SUM(t.pnl) FILTER (WHERE t.pnl > 0) / ABS(SUM(t.pnl) FILTER (WHERE t.pnl < 0)), 2)
      ELSE 0 
    END as profit_factor
  FROM public.strategies s
  LEFT JOIN public.trades t ON t.strategy_id = s.id 
    AND t.deleted_at IS NULL 
    AND t.outcome IN ('WIN', 'LOSS', 'BE')
  WHERE s.user_id = v_user_id
    AND (p_strategy_id IS NULL OR s.id = p_strategy_id)
  GROUP BY s.id, s.name
  ORDER BY total_pnl DESC;
END;
$$;


ALTER FUNCTION "public"."get_strategy_performance"("p_user_id" "uuid", "p_strategy_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_strategy_performance"("p_user_id" "uuid", "p_strategy_id" "uuid") IS 'v8.5.9: Strategy-level performance breakdown';



CREATE OR REPLACE FUNCTION "public"."get_subscription_breakdown"() RETURNS TABLE("account_type" "text", "subscription_interval" "text", "user_count" bigint, "percentage" numeric, "monthly_revenue" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;

  RETURN QUERY
  WITH total_users AS (
    SELECT COUNT(*)::NUMERIC as total FROM public.profiles
  ),
  breakdown AS (
    SELECT 
      p.account_type,
      COALESCE(p.subscription_interval, 'none') as subscription_interval,
      COUNT(*) as user_count,
      CASE 
        WHEN p.account_type = 'basic' AND p.subscription_interval = 'monthly' THEN 19.99
        WHEN p.account_type = 'basic' AND p.subscription_interval = 'yearly' THEN 12.42
        WHEN p.account_type = 'premium' AND p.subscription_interval = 'monthly' THEN 39.99
        WHEN p.account_type = 'premium' AND p.subscription_interval = 'yearly' THEN 24.92
        ELSE 0
      END as monthly_price
    FROM public.profiles p
    GROUP BY p.account_type, p.subscription_interval
  )
  SELECT 
    b.account_type,
    b.subscription_interval,
    b.user_count,
    ROUND((b.user_count::NUMERIC / NULLIF(t.total, 0) * 100), 2) as percentage,
    ROUND((b.user_count * b.monthly_price), 2) as monthly_revenue
  FROM breakdown b
  CROSS JOIN total_users t
  ORDER BY b.account_type, b.subscription_interval;
END;
$$;


ALTER FUNCTION "public"."get_subscription_breakdown"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_subscription_breakdown"() IS 'v8.5.10: Returns subscription breakdown with revenue estimates. Admin only.';



