CREATE OR REPLACE FUNCTION "public"."get_system_updates_for_user"("p_user_id" "uuid", "p_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "title" "text", "content" "text", "type" "text", "target_group" "text", "is_active" boolean, "is_pinned" boolean, "metadata" "jsonb", "views_count" integer, "created_at" timestamp with time zone, "expires_at" timestamp with time zone, "is_read" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_user_role TEXT;
  v_user_email TEXT;
  v_account_type TEXT;
  v_top_secret_enabled BOOLEAN;
  v_newsletter_paid BOOLEAN;
BEGIN
  -- Get user info
  SELECT 
    p.role,
    p.email,
    COALESCE(p.account_type, 'free'),
    COALESCE(p.top_secret_enabled, false),
    COALESCE(p.newsletter_paid, false)
  INTO v_user_role, v_user_email, v_account_type, v_top_secret_enabled, v_newsletter_paid
  FROM profiles p
  WHERE p.id = p_user_id;
  
  -- Admin check: role is admin/super_admin OR email is admin email
  IF v_user_role IN ('admin', 'super_admin') OR v_user_email = 'elad2550@gmail.com' THEN
    -- Admins see ALL active updates
    RETURN QUERY
    SELECT 
      su.id,
      su.title,
      su.content,
      su.type,
      su.target_group,
      su.is_active,
      su.is_pinned,
      su.metadata,
      su.views_count,
      su.created_at,
      su.expires_at,
      COALESCE(uur.read_at IS NOT NULL, false) as is_read
    FROM system_updates su
    LEFT JOIN user_update_reads uur ON uur.update_id = su.id AND uur.user_id = p_user_id
    WHERE su.is_active = true
      AND (su.expires_at IS NULL OR su.expires_at > NOW())
    ORDER BY su.is_pinned DESC, su.created_at DESC
    LIMIT p_limit;
  ELSE
    -- Regular users: filter by target_group
    RETURN QUERY
    SELECT 
      su.id,
      su.title,
      su.content,
      su.type,
      su.target_group,
      su.is_active,
      su.is_pinned,
      su.metadata,
      su.views_count,
      su.created_at,
      su.expires_at,
      COALESCE(uur.read_at IS NOT NULL, false) as is_read
    FROM system_updates su
    LEFT JOIN user_update_reads uur ON uur.update_id = su.id AND uur.user_id = p_user_id
    WHERE su.is_active = true
      AND (su.expires_at IS NULL OR su.expires_at > NOW())
      AND (
        su.target_group = 'all'
        OR (su.target_group = 'top_secret' AND v_top_secret_enabled = true)
        OR (su.target_group = 'newsletter' AND v_newsletter_paid = true)
        OR (su.target_group = 'trading_journal' AND v_account_type IN ('basic', 'premium', 'pro'))
      )
    ORDER BY su.is_pinned DESC, su.created_at DESC
    LIMIT p_limit;
  END IF;
END;
$$;


ALTER FUNCTION "public"."get_system_updates_for_user"("p_user_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_table_sizes"() RETURNS TABLE("table_name" "text", "size_mb" numeric, "row_count" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  RETURN QUERY
  SELECT 
    t.table_name::TEXT,
    ROUND(pg_total_relation_size(quote_ident(t.table_schema)||'.'||quote_ident(t.table_name))::NUMERIC / 1048576, 2) as size_mb,
    (xpath('/row/cnt/text()', 
      query_to_xml(format('SELECT COUNT(*) as cnt FROM %I.%I', t.table_schema, t.table_name), 
      false, true, '')))[1]::text::BIGINT as row_count
  FROM information_schema.tables t
  WHERE t.table_schema = 'public'
    AND t.table_type = 'BASE TABLE'
  ORDER BY pg_total_relation_size(quote_ident(t.table_schema)||'.'||quote_ident(t.table_name)) DESC;
END;
$$;


