CREATE OR REPLACE FUNCTION "public"."get_ticker_from_name"("p_company_name" "text") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_ticker TEXT;
BEGIN
    -- Direct match on company_name
    SELECT ticker INTO v_ticker
    FROM company_ticker_mapping
    WHERE LOWER(company_name) = LOWER(p_company_name)
    LIMIT 1;
    
    IF v_ticker IS NOT NULL THEN
        RETURN v_ticker;
    END IF;
    
    -- Match in aliases
    SELECT ticker INTO v_ticker
    FROM company_ticker_mapping
    WHERE LOWER(p_company_name) = ANY(SELECT LOWER(unnest(aliases)))
    LIMIT 1;
    
    IF v_ticker IS NOT NULL THEN
        RETURN v_ticker;
    END IF;
    
    -- Partial match
    SELECT ticker INTO v_ticker
    FROM company_ticker_mapping
    WHERE LOWER(company_name) LIKE '%' || LOWER(p_company_name) || '%'
       OR LOWER(p_company_name) LIKE '%' || LOWER(company_name) || '%'
    LIMIT 1;
    
    RETURN v_ticker;
END;
$$;


