CREATE OR REPLACE FUNCTION "public"."get_top_secret_inclusion_status"() RETURNS TABLE("premium_included" boolean, "basic_included" boolean, "total_recipients" bigint, "top_secret_subscribers" bigint, "premium_recipients" bigint, "basic_recipients" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_premium BOOLEAN;
  v_basic BOOLEAN;
  v_top_secret_subs BIGINT;
  v_premium_users BIGINT;
  v_basic_users BIGINT;
  v_caller_role TEXT;
BEGIN
  SELECT role INTO v_caller_role 
  FROM profiles 
  WHERE profiles.id = auth.uid();

  IF v_caller_role IS NOT NULL AND v_caller_role NOT IN ('admin', 'super_admin') THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  -- Get config from top_secret_config table (NOT newsletter_config!)
  SELECT COALESCE((config_value->>'enabled')::boolean, FALSE) INTO v_premium
  FROM top_secret_config WHERE config_key = 'premium_included';
  v_premium := COALESCE(v_premium, FALSE);
  
  SELECT COALESCE((config_value->>'enabled')::boolean, FALSE) INTO v_basic
  FROM top_secret_config WHERE config_key = 'basic_included';
  v_basic := COALESCE(v_basic, FALSE);

  -- Count Top Secret subscribers (NOT newsletter!)
  SELECT COUNT(*) INTO v_top_secret_subs
  FROM profiles 
  WHERE COALESCE(top_secret_status, 'inactive') = 'active'
    AND email IS NOT NULL;

  -- Count Premium journal users
  SELECT COUNT(*) INTO v_premium_users
  FROM profiles 
  WHERE account_type = 'premium' 
    AND subscription_status = 'active'
    AND email IS NOT NULL;

  -- Count Basic journal users
  SELECT COUNT(*) INTO v_basic_users
  FROM profiles 
  WHERE account_type = 'basic' 
    AND subscription_status = 'active'
    AND email IS NOT NULL;

  RETURN QUERY
  SELECT 
    v_premium as premium_included,
    v_basic as basic_included,
    (v_top_secret_subs + 
     CASE WHEN v_premium THEN v_premium_users ELSE 0 END + 
     CASE WHEN v_basic THEN v_basic_users ELSE 0 END)::BIGINT as total_recipients,
    v_top_secret_subs as top_secret_subscribers,
    CASE WHEN v_premium THEN v_premium_users ELSE 0::BIGINT END as premium_recipients,
    CASE WHEN v_basic THEN v_basic_users ELSE 0::BIGINT END as basic_recipients;
END;
$$;


