CREATE OR REPLACE FUNCTION "public"."get_top_secret_status"("p_user_id" "uuid") RETURNS TABLE("top_secret_enabled" boolean, "top_secret_status" "text", "top_secret_whop_membership_id" "text", "top_secret_started_at" timestamp with time zone, "top_secret_expires_at" timestamp with time zone, "top_secret_interval" "text", "top_secret_cancel_at_period_end" boolean, "days_until_expiry" integer, "is_active" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COALESCE(p.top_secret_enabled, FALSE),
    COALESCE(p.top_secret_status, 'inactive'),
    p.top_secret_whop_membership_id,
    p.top_secret_started_at,
    p.top_secret_expires_at,
    p.top_secret_interval,
    COALESCE(p.top_secret_cancel_at_period_end, FALSE),
    CASE 
      WHEN p.top_secret_expires_at IS NOT NULL 
      THEN GREATEST(0, EXTRACT(DAY FROM p.top_secret_expires_at - NOW())::INTEGER)
      ELSE NULL
    END,
    COALESCE(p.top_secret_enabled, FALSE) = TRUE 
      AND COALESCE(p.top_secret_status, 'inactive') = 'active'
  FROM profiles p
  WHERE p.id = p_user_id;
END;
$$;


ALTER FUNCTION "public"."get_top_secret_status"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_top_secret_users"() RETURNS TABLE("id" "uuid", "email" "text", "display_name" "text", "account_type" "text", "top_secret_enabled" boolean, "top_secret_status" "text", "top_secret_started_at" timestamp with time zone, "top_secret_expires_at" timestamp with time zone, "top_secret_interval" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_caller_role TEXT;
BEGIN
  SELECT role INTO v_caller_role 
  FROM profiles 
  WHERE profiles.id = auth.uid();

  IF v_caller_role IS NOT NULL AND v_caller_role NOT IN ('admin', 'super_admin') THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  RETURN QUERY
  SELECT 
    p.id,
    p.email::TEXT,
    COALESCE(p.display_name, split_part(p.email, '@', 1))::TEXT as display_name,
    COALESCE(p.account_type, 'free')::TEXT as account_type,
    COALESCE(p.top_secret_enabled, FALSE)::BOOLEAN as top_secret_enabled,
    COALESCE(p.top_secret_status, 'inactive')::TEXT as top_secret_status,
    p.top_secret_started_at,
    p.top_secret_expires_at,
    p.top_secret_interval::TEXT,
    p.created_at
  FROM profiles p
  WHERE p.email IS NOT NULL
  ORDER BY 
    CASE COALESCE(p.top_secret_status, 'inactive')
      WHEN 'active' THEN 1 
      WHEN 'cancelled' THEN 2
      ELSE 3 
    END,
    p.created_at DESC;
END;
$$;


ALTER FUNCTION "public"."get_top_secret_users"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_trade_details"("trade_id" "uuid") RETURNS TABLE("id" "uuid", "user_id" "uuid", "symbol" "text", "side" "text", "entry_price" numeric, "exit_price" numeric, "stop_price" numeric, "take_profit_price" numeric, "quantity" numeric, "fees" numeric, "pnl" numeric, "outcome" "text", "multiplier" numeric, "user_risk_r" numeric, "user_reward_r" numeric, "risk_pts" numeric, "reward_pts" numeric, "rr" numeric, "risk_usd" numeric, "reward_usd" numeric, "open_at" timestamp with time zone, "close_at" timestamp with time zone, "strategy_id" "uuid", "strategy_name" "text", "notes" "text", "screenshot_url" "text", "screenshot_exists" boolean, "setup" "text", "mistake" "text", "next_time" "text", "quality_tag" "text", "session" "text", "asset_class" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_trade_user_id UUID;
  v_is_admin BOOLEAN;
BEGIN
  SELECT t.user_id INTO v_trade_user_id
  FROM public.trades t
  WHERE t.id = trade_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Trade not found';
  END IF;
  
  SELECT role IN ('admin', 'super_admin') AND is_banned = FALSE
  INTO v_is_admin
  FROM public.profiles
  WHERE id = auth.uid();
  
  IF v_trade_user_id != auth.uid() AND NOT COALESCE(v_is_admin, FALSE) THEN
    RAISE EXCEPTION 'Access denied: This trade belongs to another user';
  END IF;
  
  IF COALESCE(v_is_admin, FALSE) AND v_trade_user_id != auth.uid() THEN
    PERFORM set_config('app.admin_mode', 'true', true);
  END IF;
  
  RETURN QUERY
  SELECT 
    t.id, t.user_id, t.symbol, t.side,
    t.entry_price, t.exit_price, t.stop_price, t.take_profit_price,
    t.quantity, t.fees, t.pnl, t.outcome,
    t.multiplier, t.user_risk_r, t.user_reward_r,
    t.risk_pts, t.reward_pts, t.rr, t.risk_usd, t.reward_usd,
    t.open_at, t.close_at, t.strategy_id,
    s.name as strategy_name,
    t.notes, t.screenshot_url,
    (t.screenshot_url IS NOT NULL AND t.screenshot_url != '') as screenshot_exists,
    t.setup, t.mistake, t.next_time, t.quality_tag, t.session, t.asset_class,
    t.created_at, t.updated_at
  FROM public.trades t
  LEFT JOIN public.strategies s ON s.id = t.strategy_id
  WHERE t.id = trade_id;
  
  IF COALESCE(v_is_admin, FALSE) THEN
    PERFORM set_config('app.admin_mode', 'false', true);
  END IF;
END;
$$;


