CREATE OR REPLACE FUNCTION "public"."get_trade_limit"("p_account_type" "text") RETURNS integer
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
BEGIN
  RETURN CASE LOWER(COALESCE(p_account_type, 'free'))
    WHEN 'free' THEN 15
    WHEN 'basic' THEN 25
    WHEN 'premium' THEN 999999
    WHEN 'admin' THEN 999999
    WHEN 'vip' THEN 999999
    WHEN 'beta' THEN 999999
    ELSE 15  -- Default = free (15 lifetime)
  END;
END;
$$;


