CREATE OR REPLACE FUNCTION "public"."get_trading_session"("p_timestamp" timestamp with time zone) RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
DECLARE
  v_ny_hour INTEGER;
BEGIN
  v_ny_hour := EXTRACT(HOUR FROM p_timestamp AT TIME ZONE 'America/New_York')::INTEGER;
  
  -- Direct mapping: Asia (6PM-1AM), London (1AM-7AM), NY (7AM-5PM)
  IF (v_ny_hour >= 18 OR v_ny_hour < 1) THEN
    RETURN 'asia';
  ELSIF (v_ny_hour >= 1 AND v_ny_hour < 7) THEN
    RETURN 'london';
  ELSIF (v_ny_hour >= 7 AND v_ny_hour < 17) THEN
    RETURN 'newyork';
  ELSE
    RETURN NULL;
  END IF;
END;
$$;


ALTER FUNCTION "public"."get_trading_session"("p_timestamp" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_trading_session"("p_timestamp" timestamp with time zone) IS 'v8.5.9-FIXED: No table dependency - direct time mapping';



CREATE OR REPLACE FUNCTION "public"."get_unread_updates_count"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  user_group TEXT;
  unread_count INTEGER;
BEGIN
  user_group := get_user_target_group(auth.uid());

  SELECT COUNT(*)::INTEGER INTO unread_count
  FROM system_updates su
  WHERE su.is_active = true
    AND (su.starts_at IS NULL OR su.starts_at <= NOW())
    AND (su.expires_at IS NULL OR su.expires_at > NOW())
    AND (su.target_group = 'all' OR su.target_group = user_group)
    AND NOT EXISTS (
      SELECT 1 FROM user_update_reads ur
      WHERE ur.update_id = su.id AND ur.user_id = auth.uid()
    );

  RETURN unread_count;
END;
$$;


