CREATE OR REPLACE FUNCTION "public"."get_usage_status"("p_user_id" "uuid") RETURNS TABLE("platform_plan" "text", "stock_analysis_today" integer, "stock_analysis_limit" integer, "sector_analysis_month" integer, "sector_analysis_limit" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_plan TEXT;
  v_role TEXT;
BEGIN
  SELECT COALESCE(p.platform_plan, 'free'), p.role 
  INTO v_plan, v_role
  FROM profiles p WHERE p.id = p_user_id;

  -- Admin/super_admin always gets full enterprise access
  IF v_role IN ('admin', 'super_admin') THEN
    v_plan := 'platform_enterprise';
  END IF;

  RETURN QUERY
  SELECT
    v_plan,
    COALESCE((
      SELECT ut.usage_count FROM usage_tracking ut
      WHERE ut.user_id = p_user_id AND ut.feature = 'stock_analysis' AND ut.usage_date = CURRENT_DATE
    ), 0)::INTEGER,
    (CASE v_plan
      WHEN 'free' THEN 3
      WHEN 'platform_core' THEN 5
      WHEN 'platform_finotaur' THEN 7
      WHEN 'platform_enterprise' THEN 999999
      ELSE 3
    END)::INTEGER,
    COALESCE((
      SELECT mut.usage_count FROM monthly_usage_tracking mut
      WHERE mut.user_id = p_user_id AND mut.feature = 'sector_analysis' 
        AND mut.usage_month = DATE_TRUNC('month', CURRENT_DATE)::DATE
    ), 0)::INTEGER,
    (CASE v_plan
      WHEN 'platform_core' THEN 3
      WHEN 'platform_finotaur' THEN 999999
      WHEN 'platform_enterprise' THEN 999999
      ELSE 0
    END)::INTEGER;
END;
$$;


ALTER FUNCTION "public"."get_usage_status"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_user_activity"("p_user_id" "uuid") RETURNS TABLE("user_id" "uuid", "email" "text", "display_name" "text", "account_type" "text", "total_trades" bigint, "trades_this_month" bigint, "last_trade_date" timestamp with time zone, "total_pnl" numeric, "win_rate" numeric, "subscription_status" "text", "subscription_expires_at" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  RETURN QUERY
  SELECT 
    p.id as user_id,
    p.email,
    p.display_name,
    p.account_type,
    COALESCE(p.trade_count, 0)::BIGINT as total_trades,
    COALESCE(p.current_month_trades_count, 0)::BIGINT as trades_this_month,
    (SELECT MAX(created_at) FROM public.trades WHERE trades.user_id = p.id) as last_trade_date,
    COALESCE(p.total_pnl, 0) as total_pnl,
    CASE 
      WHEN COALESCE(p.trade_count, 0) > 0 THEN
        ROUND((SELECT COUNT(*) * 100.0 / NULLIF(p.trade_count, 0) 
               FROM public.trades WHERE trades.user_id = p.id AND outcome = 'WIN'), 2)
      ELSE 0
    END as win_rate,
    p.subscription_status,
    p.subscription_expires_at,
    p.created_at
  FROM public.profiles p
  WHERE p.id = p_user_id;
END;
$$;


ALTER FUNCTION "public"."get_user_activity"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_user_activity"("p_user_id" "uuid") IS 'v8.5.9: Returns detailed activity for a specific user (admin only)';



CREATE OR REPLACE FUNCTION "public"."get_user_available_credits"("p_user_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_purchased_credits INTEGER := 0;
  v_profile_credits INTEGER := 0;
BEGIN
  -- Sum from ai_credits table (active, non-expired)
  SELECT COALESCE(SUM(credits_remaining), 0) INTO v_purchased_credits
  FROM ai_credits
  WHERE user_id = p_user_id 
    AND status = 'active'
    AND (expires_at IS NULL OR expires_at > NOW());
  
  -- Add from profiles table
  SELECT COALESCE(credits_balance, 0) + COALESCE(credits_purchased, 0) + COALESCE(credits_rollover, 0)
  INTO v_profile_credits
  FROM profiles
  WHERE id = p_user_id;
  
  RETURN COALESCE(v_purchased_credits, 0) + COALESCE(v_profile_credits, 0);
END;
$$;


ALTER FUNCTION "public"."get_user_available_credits"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_user_bookmarked_reports"("p_user_id" "uuid") RETURNS TABLE("id" "uuid", "report_type" "text", "title" "text", "subtitle" "text", "pdf_url" "text", "published_at" timestamp with time zone, "bookmarked_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        pr.id,
        pr.report_type,
        pr.title,
        pr.subtitle,
        pr.pdf_url,
        pr.published_at,
        rb.created_at as bookmarked_at
    FROM report_bookmarks rb
    JOIN published_reports pr ON pr.id = rb.report_id
    WHERE rb.user_id = p_user_id
    ORDER BY rb.created_at DESC;
END;
$$;


