CREATE OR REPLACE FUNCTION "public"."get_user_broker_connections"("p_user_id" "uuid") RETURNS TABLE("connection_id" "uuid", "broker_name" character varying, "broker_slug" character varying, "broker_logo" "text", "connection_name" character varying, "environment" character varying, "status" character varying, "accounts_count" bigint, "last_sync_at" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        bc.id as connection_id,
        COALESCE(bd.display_name, bc.broker::VARCHAR) as broker_name,
        COALESCE(bd.slug, bc.broker::VARCHAR) as broker_slug,
        bd.logo_url as broker_logo,
        bc.connection_name,
        bc.environment,
        bc.status,
        COUNT(ba.id) as accounts_count,
        bc.last_sync_at,
        bc.created_at
    FROM broker_connections bc
    LEFT JOIN broker_definitions bd ON bc.broker_id = bd.id
    LEFT JOIN broker_accounts ba ON ba.connection_id = bc.id AND ba.is_active = true
    WHERE bc.user_id = p_user_id
    AND bc.is_active = true
    GROUP BY bc.id, bd.display_name, bd.slug, bd.logo_url
    ORDER BY bc.created_at DESC;
END;
$$;


ALTER FUNCTION "public"."get_user_broker_connections"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_user_detailed_stats"("p_user_id" "uuid") RETURNS json
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  stats JSON;
  v_is_admin BOOLEAN;
BEGIN
  -- 🔒 Strict admin check
  SELECT role IN ('admin', 'super_admin') AND is_banned = FALSE
  INTO v_is_admin
  FROM public.profiles
  WHERE id = auth.uid();

  IF NOT COALESCE(v_is_admin, FALSE) THEN
    RAISE EXCEPTION 'Access denied: Admin access required';
  END IF;

  -- 🔒 Enable admin mode for RLS bypass
  PERFORM set_config('app.admin_mode', 'true', true);

  -- Build detailed stats for the user
  SELECT json_build_object(
    'user_id', p_user_id,
    'total_trades', (SELECT COUNT(*) FROM public.trades WHERE user_id = p_user_id AND deleted_at IS NULL),
    'open_trades', (SELECT COUNT(*) FROM public.trades WHERE user_id = p_user_id AND exit_price IS NULL AND deleted_at IS NULL),
    'closed_trades', (SELECT COUNT(*) FROM public.trades WHERE user_id = p_user_id AND exit_price IS NOT NULL AND deleted_at IS NULL),
    'total_strategies', (SELECT COUNT(*) FROM public.strategies WHERE user_id = p_user_id AND deleted_at IS NULL),
    'win_rate', (
      SELECT CASE WHEN COUNT(*) > 0 THEN 
        ROUND((COUNT(*) FILTER (WHERE outcome = 'WIN')::NUMERIC / COUNT(*)::NUMERIC) * 100, 2)
      ELSE 0 END
      FROM public.trades 
      WHERE user_id = p_user_id AND outcome IN ('WIN', 'LOSS') AND deleted_at IS NULL
    ),
    'total_pnl', (SELECT COALESCE(SUM(pnl), 0) FROM public.trades WHERE user_id = p_user_id AND deleted_at IS NULL),
    'avg_pnl', (SELECT ROUND(COALESCE(AVG(pnl), 0)::NUMERIC, 2) FROM public.trades WHERE user_id = p_user_id AND pnl IS NOT NULL AND deleted_at IS NULL),
    'best_trade', (SELECT MAX(pnl) FROM public.trades WHERE user_id = p_user_id AND deleted_at IS NULL),
    'worst_trade', (SELECT MIN(pnl) FROM public.trades WHERE user_id = p_user_id AND deleted_at IS NULL),
    'first_trade_date', (SELECT MIN(open_at) FROM public.trades WHERE user_id = p_user_id AND deleted_at IS NULL),
    'last_trade_date', (SELECT MAX(open_at) FROM public.trades WHERE user_id = p_user_id AND deleted_at IS NULL),
    'most_traded_symbol', (
      SELECT symbol FROM public.trades WHERE user_id = p_user_id AND deleted_at IS NULL
      GROUP BY symbol ORDER BY COUNT(*) DESC LIMIT 1
    ),
    'favorite_side', (
      SELECT side FROM public.trades WHERE user_id = p_user_id AND deleted_at IS NULL
      GROUP BY side ORDER BY COUNT(*) DESC LIMIT 1
    ),
    'generated_at', NOW()
  ) INTO stats;

  -- 🔒 Disable admin mode
  PERFORM set_config('app.admin_mode', 'false', true);

  RETURN stats;
END;
$$;


ALTER FUNCTION "public"."get_user_detailed_stats"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_user_detailed_stats"("p_user_id" "uuid") IS 'v8.5.10-SECURE: Admin-only function with admin_mode enforcement and strict permission checks.';



CREATE OR REPLACE FUNCTION "public"."get_user_group_counts"() RETURNS TABLE("group_name" "text", "user_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 'all'::TEXT, COUNT(*)::BIGINT 
  FROM profiles 
  WHERE role NOT IN ('admin', 'super_admin')
  
  UNION ALL
  
  SELECT 'trading_journal'::TEXT, COUNT(*)::BIGINT 
  FROM profiles 
  WHERE COALESCE(top_secret_enabled, false) = false
    AND COALESCE(newsletter_enabled, false) = false
    AND COALESCE(newsletter_paid, false) = false
    AND role NOT IN ('admin', 'super_admin')
  
  UNION ALL
  
  SELECT 'newsletter'::TEXT, COUNT(*)::BIGINT 
  FROM profiles 
  WHERE (COALESCE(newsletter_enabled, false) = true OR COALESCE(newsletter_paid, false) = true)
    AND role NOT IN ('admin', 'super_admin')
  
  UNION ALL
  
  SELECT 'top_secret'::TEXT, COUNT(*)::BIGINT 
  FROM profiles 
  WHERE COALESCE(top_secret_enabled, false) = true
    AND role NOT IN ('admin', 'super_admin');
END;
$$;


