CREATE OR REPLACE FUNCTION "public"."get_user_role"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("user_id" "uuid", "role" "text", "is_admin" boolean, "is_super_admin" boolean, "is_banned" boolean, "account_type" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  
  RETURN QUERY
  SELECT 
    p.id,
    p.role,
    p.role IN ('admin', 'super_admin'),
    p.role = 'super_admin',
    COALESCE(p.is_banned, FALSE),
    p.account_type
  FROM public.profiles p
  WHERE p.id = v_user_id;
END;
