CREATE OR REPLACE FUNCTION "public"."get_user_subscription_status"("p_user_id" "uuid") RETURNS TABLE("account_type" "text", "subscription_status" "text", "subscription_interval" "text", "subscription_expires_at" timestamp with time zone, "subscription_started_at" timestamp with time zone, "subscription_cancel_at_period_end" boolean, "pending_downgrade_plan" "text", "cancellation_reason" "text", "is_lifetime" boolean, "max_trades" integer, "current_month_trades_count" integer, "trade_count" integer, "remaining" integer, "used" integer, "plan" "text", "reset_date" "date", "billing_cycle_start" "date", "current_month_active_days" integer, "payment_provider" "text", "whop_user_id" "text", "whop_membership_id" "text", "whop_product_id" "text", "whop_plan_id" "text", "whop_customer_email" "text", "initial_portfolio" numeric, "current_portfolio" numeric, "portfolio_size" numeric, "total_pnl" numeric, "risk_mode" "text", "risk_percentage" numeric, "fixed_risk_amount" numeric, "role" "text", "newsletter_paid" boolean, "newsletter_status" "text", "newsletter_expires_at" timestamp with time zone, "top_secret_enabled" boolean, "top_secret_status" "text", "top_secret_expires_at" timestamp with time zone, "platform_plan" "text", "platform_subscription_status" "text", "platform_billing_interval" "text", "platform_subscription_started_at" timestamp with time zone, "platform_subscription_expires_at" timestamp with time zone, "platform_trial_ends_at" timestamp with time zone, "platform_is_in_trial" boolean, "platform_trial_days_remaining" integer, "platform_cancel_at_period_end" boolean, "platform_cancelled_at" timestamp with time zone, "platform_whop_membership_id" "text", "platform_finotaur_trial_eligible" boolean, "platform_core_trial_eligible" boolean, "platform_bundle_journal_granted" boolean, "platform_bundle_newsletter_granted" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_platform_trial_days_remaining INTEGER;
BEGIN
  -- Calculate Platform trial days remaining
  SELECT 
    CASE 
      WHEN p.platform_is_in_trial AND p.platform_trial_ends_at IS NOT NULL 
      THEN GREATEST(0, EXTRACT(DAY FROM (p.platform_trial_ends_at - NOW()))::INTEGER)
      ELSE NULL
    END
  INTO v_platform_trial_days_remaining
  FROM profiles p
  WHERE p.id = p_user_id;

  RETURN QUERY
  SELECT 
    -- Basic subscription info
    COALESCE(p.account_type, 'free')::TEXT,
    p.subscription_status::TEXT,
    p.subscription_interval::TEXT,
    p.subscription_expires_at,
    p.subscription_started_at,
    COALESCE(p.subscription_cancel_at_period_end, FALSE),
    p.pending_downgrade_plan::TEXT,
    p.cancellation_reason::TEXT,
    COALESCE(p.is_lifetime, FALSE),
    
    -- Trade limits (v8.5.0: FREE=15 lifetime)
    COALESCE(p.max_trades, 15),
    COALESCE(p.current_month_trades_count, 0),
    COALESCE(p.trade_count, 0),
    
    -- Computed trade fields (v8.5.0: default 15 for FREE tier)
    GREATEST(0, COALESCE(p.max_trades, 15) - COALESCE(p.current_month_trades_count, 0))::INTEGER,
    COALESCE(p.current_month_trades_count, 0)::INTEGER,
    COALESCE(p.account_type, 'free')::TEXT,
    (COALESCE(p.billing_cycle_start, DATE_TRUNC('month', NOW())::DATE) + INTERVAL '1 month')::DATE,
    
    -- Billing
    COALESCE(p.billing_cycle_start, DATE_TRUNC('month', NOW())::DATE),
    COALESCE(p.current_month_active_days, 0),
    
    -- Payment provider
    p.payment_provider::TEXT,
    
    -- Whop identifiers (Journal)
    p.whop_user_id::TEXT,
    p.whop_membership_id::TEXT,
    p.whop_product_id::TEXT,
    p.whop_plan_id::TEXT,
    p.whop_customer_email::TEXT,
    
    -- Portfolio & Risk
    COALESCE(p.initial_portfolio, 10000)::NUMERIC,
    COALESCE(p.current_portfolio, 10000)::NUMERIC,
    COALESCE(p.portfolio_size, 10000)::NUMERIC,
    COALESCE(p.total_pnl, 0)::NUMERIC,
    COALESCE(p.risk_mode, 'percentage')::TEXT,
    COALESCE(p.risk_percentage, 1.0)::NUMERIC,
    p.fixed_risk_amount::NUMERIC,
    
    -- User role
    COALESCE(p.role, 'user')::TEXT,
    
    -- Newsletter
    COALESCE(p.newsletter_paid, FALSE),
    COALESCE(p.newsletter_status, 'inactive')::TEXT,
    p.newsletter_expires_at,
    
    -- Top Secret
    COALESCE(p.top_secret_enabled, FALSE),
    COALESCE(p.top_secret_status, 'inactive')::TEXT,
    p.top_secret_expires_at,
    
    -- ═══════════════════════════════════════════
    -- 🔥 PLATFORM FIELDS
    -- ═══════════════════════════════════════════
    COALESCE(p.platform_plan, 'free')::TEXT,
    COALESCE(p.platform_subscription_status, 'inactive')::TEXT,
    p.platform_billing_interval::TEXT,
    p.platform_subscription_started_at,
    p.platform_subscription_expires_at,
    p.platform_trial_ends_at,
    COALESCE(p.platform_is_in_trial, FALSE),
    v_platform_trial_days_remaining,
    COALESCE(p.platform_cancel_at_period_end, FALSE),
    p.platform_cancelled_at,
    p.platform_whop_membership_id::TEXT,
    
    -- Trial eligibility (NULL = eligible, NOT NULL = already used)
    (p.platform_finotaur_trial_used_at IS NULL),
    (p.platform_core_trial_used_at IS NULL),
    
    -- Bundle status
    COALESCE(p.platform_bundle_journal_granted, FALSE),
    COALESCE(p.platform_bundle_newsletter_granted, FALSE)
    
  FROM profiles p
  WHERE p.id = p_user_id;
END;
$$;


ALTER FUNCTION "public"."get_user_subscription_status"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_user_sync_stats"("p_user_id" "uuid") RETURNS TABLE("total_syncs" bigint, "successful_syncs" bigint, "failed_syncs" bigint, "total_trades_imported" bigint, "last_sync_at" timestamp with time zone, "last_sync_status" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*)::BIGINT as total_syncs,
    COUNT(*) FILTER (WHERE status = 'completed')::BIGINT as successful_syncs,
    COUNT(*) FILTER (WHERE status = 'failed')::BIGINT as failed_syncs,
    COALESCE(SUM(trades_imported), 0)::BIGINT as total_trades_imported,
    MAX(sync_completed_at) as last_sync_at,
    (
      SELECT ssl.status FROM snaptrade_sync_log ssl
      WHERE ssl.user_id = p_user_id 
      ORDER BY ssl.created_at DESC 
      LIMIT 1
    )::TEXT as last_sync_status
  FROM snaptrade_sync_log
  WHERE snaptrade_sync_log.user_id = p_user_id;
END;
$$;


ALTER FUNCTION "public"."get_user_sync_stats"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_user_sync_stats"("p_user_id" "uuid") IS 'v8.5.10: Get comprehensive sync statistics for user';



CREATE OR REPLACE FUNCTION "public"."get_user_target_group"("user_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  user_group TEXT;
  is_top_secret BOOLEAN;
  is_newsletter BOOLEAN;
BEGIN
  SELECT 
    COALESCE(top_secret_enabled, false),
    COALESCE(newsletter_enabled, false) OR COALESCE(newsletter_paid, false)
  INTO is_top_secret, is_newsletter
  FROM profiles
  WHERE id = user_id;

  -- Priority: top_secret > newsletter > trading_journal
  IF is_top_secret THEN
    RETURN 'top_secret';
  ELSIF is_newsletter THEN
    RETURN 'newsletter';
  ELSE
    RETURN 'trading_journal';
  END IF;
END;
$$;


ALTER FUNCTION "public"."get_user_target_group"("user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_user_target_group"("user_id" "uuid") IS 'Returns single highest-priority group (backward compatible wrapper)';



CREATE OR REPLACE FUNCTION "public"."get_user_target_groups"("user_id" "uuid") RETURNS "text"[]
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  user_groups text[] := ARRAY['all'];  -- Everyone sees 'all'
  is_top_secret BOOLEAN;
  is_newsletter BOOLEAN;
  has_trading_journal BOOLEAN;
BEGIN
  SELECT 
    COALESCE(top_secret_enabled, false),
    COALESCE(newsletter_enabled, false) OR COALESCE(newsletter_paid, false) OR COALESCE(newsletter_status IN ('active', 'trial'), false),
    COALESCE(subscription_status = 'active' AND account_type IN ('basic', 'premium'), false)
  INTO is_top_secret, is_newsletter, has_trading_journal
  FROM profiles
  WHERE id = user_id;

  -- Add ALL applicable groups (not just one!)
  IF is_top_secret THEN
    user_groups := array_append(user_groups, 'top_secret');
  END IF;
  
  IF is_newsletter THEN
    user_groups := array_append(user_groups, 'newsletter');
  END IF;
  
  IF has_trading_journal THEN
    user_groups := array_append(user_groups, 'trading_journal');
  END IF;

  RETURN user_groups;
END;
$$;


ALTER FUNCTION "public"."get_user_target_groups"("user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_user_target_groups"("user_id" "uuid") IS 'Returns array of all target groups user belongs to (supports multiple subscriptions)';



CREATE OR REPLACE FUNCTION "public"."get_users_by_subscription"("p_product_type" "text", "p_filter" "text" DEFAULT 'all'::"text") RETURNS TABLE("id" "uuid", "email" "text", "display_name" "text", "status" "text", "plan" "text", "billing_interval" "text", "is_in_trial" boolean, "started_at" timestamp with time zone, "expires_at" timestamp with time zone, "created_at" timestamp with time zone, "last_login_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Check if user is admin
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles pf
    WHERE pf.id = auth.uid()
    AND pf.role IN ('admin', 'super_admin')
    AND COALESCE(pf.is_banned, false) = false
  ) THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  -- ===== JOURNAL =====
  IF p_product_type = 'journal' THEN
    IF p_filter = 'free' THEN
      -- Free users: no whop_membership_id and no paid account
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.subscription_status, 'none')::TEXT AS status,
        COALESCE(p.account_type, 'free')::TEXT AS plan,
        p.subscription_interval::TEXT AS billing_interval,
        COALESCE(p.is_in_trial, false) AS is_in_trial,
        p.subscription_started_at AS started_at,
        p.subscription_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL
        AND p.whop_membership_id IS NULL
        AND (p.account_type IS NULL OR p.account_type IN ('basic') AND COALESCE(p.is_in_trial, false) = false AND p.subscription_status != 'active')
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'basic' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.subscription_status, 'none')::TEXT AS status,
        p.account_type::TEXT AS plan,
        p.subscription_interval::TEXT AS billing_interval,
        COALESCE(p.is_in_trial, false) AS is_in_trial,
        p.subscription_started_at AS started_at,
        p.subscription_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.account_type = 'basic'
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'premium' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.subscription_status, 'none')::TEXT AS status,
        p.account_type::TEXT AS plan,
        p.subscription_interval::TEXT AS billing_interval,
        COALESCE(p.is_in_trial, false) AS is_in_trial,
        p.subscription_started_at AS started_at,
        p.subscription_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.account_type = 'premium'
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'trial' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.subscription_status, 'trial')::TEXT AS status,
        COALESCE(p.account_type, 'basic')::TEXT AS plan,
        p.subscription_interval::TEXT AS billing_interval,
        true AS is_in_trial,
        p.subscription_started_at AS started_at,
        p.trial_ends_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL
        AND (p.subscription_status = 'trial' OR COALESCE(p.is_in_trial, false) = true)
      ORDER BY p.created_at DESC;

    ELSE -- 'all'
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.subscription_status, 'none')::TEXT AS status,
        COALESCE(p.account_type, 'free')::TEXT AS plan,
        p.subscription_interval::TEXT AS billing_interval,
        COALESCE(p.is_in_trial, false) AS is_in_trial,
        p.subscription_started_at AS started_at,
        p.subscription_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL
        AND p.account_type IN ('basic', 'premium')
      ORDER BY p.created_at DESC;
    END IF;

  -- ===== NEWSLETTER (WAR ZONE) =====
  ELSIF p_product_type = 'newsletter' THEN
    IF p_filter = 'active' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.newsletter_status, 'inactive')::TEXT AS status,
        'newsletter'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        false AS is_in_trial,
        NULL::TIMESTAMPTZ AS started_at,
        p.newsletter_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.newsletter_status = 'active'
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'trial' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        'trial'::TEXT AS status,
        'newsletter'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        true AS is_in_trial,
        NULL::TIMESTAMPTZ AS started_at,
        p.newsletter_trial_ends_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.newsletter_status = 'trial'
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'cancelled' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        'cancelled'::TEXT AS status,
        'newsletter'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        false AS is_in_trial,
        NULL::TIMESTAMPTZ AS started_at,
        p.newsletter_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.newsletter_status = 'cancelled'
      ORDER BY p.created_at DESC;

    ELSE -- 'all'
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.newsletter_status, 'inactive')::TEXT AS status,
        'newsletter'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        (p.newsletter_status = 'trial') AS is_in_trial,
        NULL::TIMESTAMPTZ AS started_at,
        p.newsletter_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL
        AND (p.newsletter_status IS NOT NULL AND p.newsletter_status != 'inactive')
      ORDER BY p.created_at DESC;
    END IF;

  -- ===== TOP SECRET =====
  ELSIF p_product_type = 'top_secret' THEN
    IF p_filter = 'active' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.top_secret_status, 'inactive')::TEXT AS status,
        'top_secret'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        COALESCE(p.top_secret_is_in_trial, false) AS is_in_trial,
        p.top_secret_started_at AS started_at,
        p.top_secret_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.top_secret_status = 'active'
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'trial' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        'trial'::TEXT AS status,
        'top_secret'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        true AS is_in_trial,
        p.top_secret_started_at AS started_at,
        p.top_secret_trial_ends_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.top_secret_status = 'trial'
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'cancelled' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        'cancelled'::TEXT AS status,
        'top_secret'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        false AS is_in_trial,
        p.top_secret_started_at AS started_at,
        p.top_secret_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.top_secret_status = 'cancelled'
      ORDER BY p.created_at DESC;

    ELSE -- 'all'
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.top_secret_status, 'inactive')::TEXT AS status,
        'top_secret'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        COALESCE(p.top_secret_is_in_trial, false) AS is_in_trial,
        p.top_secret_started_at AS started_at,
        p.top_secret_expires_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL
        AND (p.top_secret_status IS NOT NULL AND p.top_secret_status != 'inactive')
      ORDER BY p.created_at DESC;
    END IF;

  -- ===== PLATFORM =====
  ELSIF p_product_type = 'platform' THEN
    IF p_filter = 'core' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.platform_subscription_status, 'inactive')::TEXT AS status,
        'core'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        COALESCE(p.platform_is_in_trial, false) AS is_in_trial,
        NULL::TIMESTAMPTZ AS started_at,
        p.platform_trial_ends_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.platform_plan = 'core'
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'finotaur' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.platform_subscription_status, 'inactive')::TEXT AS status,
        'finotaur'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        COALESCE(p.platform_is_in_trial, false) AS is_in_trial,
        NULL::TIMESTAMPTZ AS started_at,
        p.platform_trial_ends_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.platform_plan = 'finotaur'
      ORDER BY p.created_at DESC;

    ELSIF p_filter = 'enterprise' THEN
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.platform_subscription_status, 'inactive')::TEXT AS status,
        'enterprise'::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        false AS is_in_trial,
        NULL::TIMESTAMPTZ AS started_at,
        NULL::TIMESTAMPTZ AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL AND p.platform_plan = 'enterprise'
      ORDER BY p.created_at DESC;

    ELSE -- 'all'
      RETURN QUERY
      SELECT
        p.id, p.email, p.display_name,
        COALESCE(p.platform_subscription_status, 'inactive')::TEXT AS status,
        COALESCE(p.platform_plan, 'free')::TEXT AS plan,
        NULL::TEXT AS billing_interval,
        COALESCE(p.platform_is_in_trial, false) AS is_in_trial,
        NULL::TIMESTAMPTZ AS started_at,
        p.platform_trial_ends_at AS expires_at,
        p.created_at,
        p.last_login_at
      FROM public.profiles p
      WHERE p.deleted_at IS NULL
        AND p.platform_plan IS NOT NULL AND p.platform_plan != 'free'
      ORDER BY p.created_at DESC;
    END IF;

  ELSE
    RAISE EXCEPTION 'Unknown product type: %. Valid types: journal, newsletter, top_secret, platform', p_product_type;
  END IF;
END;
$$;


