CREATE OR REPLACE FUNCTION "public"."get_week_holidays"("week_start" "date") RETURNS TABLE("date" "date", "name" character varying, "type" character varying, "close_time" character varying, "day_name" character varying)
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  monday DATE;
  friday DATE;
BEGIN
  monday := week_start - (EXTRACT(DOW FROM week_start)::INTEGER - 1);
  IF EXTRACT(DOW FROM week_start) = 0 THEN
    monday := week_start + 1;
  END IF;
  friday := monday + 4;
  
  RETURN QUERY
  SELECT 
    h.date,
    h.name,
    h.type,
    h.close_time,
    CASE EXTRACT(DOW FROM h.date)
      WHEN 1 THEN 'Monday'
      WHEN 2 THEN 'Tuesday'
      WHEN 3 THEN 'Wednesday'
      WHEN 4 THEN 'Thursday'
      WHEN 5 THEN 'Friday'
    END::VARCHAR as day_name
  FROM us_market_holidays h
  WHERE h.date BETWEEN monday AND friday
  ORDER BY h.date;
END;
$$;


ALTER FUNCTION "public"."get_week_holidays"("week_start" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."grant_beta_access"("p_admin_id" "uuid", "p_target_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_role TEXT;
BEGIN
  -- Check if caller is admin
  SELECT role INTO v_admin_role
  FROM profiles WHERE id = p_admin_id;
  
  IF v_admin_role NOT IN ('admin', 'super_admin') THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Only admins can grant beta access'
    );
  END IF;
  
  -- Update user to beta
  UPDATE profiles
  SET 
    account_type = 'beta',
    subscription_status = 'active',
    max_trades = 999999,
    updated_at = NOW()
  WHERE id = p_target_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'User not found'
    );
  END IF;
  
  RETURN jsonb_build_object(
    'success', true,
    'message', 'Beta access granted',
    'user_id', p_target_user_id
  );
END;
$$;


ALTER FUNCTION "public"."grant_beta_access"("p_admin_id" "uuid", "p_target_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."grant_journal_discount"("p_user_id" "uuid", "p_source" "text" DEFAULT 'top_secret'::"text", "p_percent" integer DEFAULT 25) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_profile RECORD;
BEGIN
  SELECT journal_discount_available, journal_discount_used
  INTO v_profile FROM profiles WHERE id = p_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  IF v_profile.journal_discount_used THEN
    RETURN jsonb_build_object('success', false, 'error', 'Discount already used');
  END IF;

  UPDATE profiles SET
    journal_discount_available = TRUE,
    journal_discount_percent = p_percent,
    journal_discount_source = p_source,
    updated_at = NOW()
  WHERE id = p_user_id;

  RETURN jsonb_build_object('success', true, 'discount_percent', p_percent, 'source', p_source);
END;
$$;


ALTER FUNCTION "public"."grant_journal_discount"("p_user_id" "uuid", "p_source" "text", "p_percent" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_auth_user_login"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Update profiles.last_login_at when auth.users.last_sign_in_at changes
  UPDATE public.profiles
  SET 
    last_login_at = NEW.last_sign_in_at,
    login_count = COALESCE(login_count, 0) + 1,
    updated_at = NOW()
  WHERE id = NEW.id;
  
  RETURN NEW;
END;
$$;


