COMMENT ON FUNCTION "public"."handle_auth_user_login"() IS 'v9.4.4: Syncs last_login_at from auth.users.last_sign_in_at on every login.';



CREATE OR REPLACE FUNCTION "public"."handle_bundle_upgrade_to_yearly"("p_user_id" "uuid", "p_new_whop_membership_id" "text", "p_new_expires_at" timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_user_record RECORD;
  v_now TIMESTAMPTZ := NOW();
BEGIN
  -- Find user
  SELECT id, email, bundle_interval, bundle_status
  INTO v_user_record
  FROM profiles
  WHERE id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'User not found'
    );
  END IF;
  
  -- Update to yearly - clear all trial flags!
  UPDATE profiles
  SET
    -- Bundle fields
    bundle_interval = 'yearly',
    bundle_status = 'active',
    bundle_whop_membership_id = p_new_whop_membership_id,
    bundle_expires_at = p_new_expires_at,
    bundle_is_in_trial = FALSE,
    bundle_trial_ends_at = NULL,
    bundle_cancel_at_period_end = FALSE,
    
    -- Newsletter fields (synced with bundle)
    newsletter_interval = 'yearly',
    newsletter_status = 'active',
    newsletter_expires_at = p_new_expires_at,
    newsletter_is_in_trial = FALSE,
    newsletter_trial_ends_at = NULL,
    newsletter_cancel_at_period_end = FALSE,
    newsletter_paid = TRUE,
    
    -- Top Secret fields (synced with bundle)
    top_secret_interval = 'yearly',
    top_secret_status = 'active',
    top_secret_expires_at = p_new_expires_at,
    top_secret_is_in_trial = FALSE,
    top_secret_trial_ends_at = NULL,
    top_secret_cancel_at_period_end = FALSE,
    top_secret_paid = TRUE,
    
    updated_at = v_now
  WHERE id = p_user_id;
  
  -- Log event
  INSERT INTO subscription_events (
    user_id,
    event_type,
    old_plan,
    new_plan,
    metadata
  ) VALUES (
    p_user_id,
    'bundle_upgraded_to_yearly',
    'bundle_monthly',
    'bundle_yearly',
    jsonb_build_object(
      'new_whop_membership_id', p_new_whop_membership_id,
      'new_expires_at', p_new_expires_at,
      'previous_interval', v_user_record.bundle_interval,
      'previous_status', v_user_record.bundle_status
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', p_user_id,
    'email', v_user_record.email,
    'old_interval', v_user_record.bundle_interval,
    'new_interval', 'yearly'
  );
END;
$$;


ALTER FUNCTION "public"."handle_bundle_upgrade_to_yearly"("p_user_id" "uuid", "p_new_whop_membership_id" "text", "p_new_expires_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_credit_pack_purchase"("p_user_email" "text", "p_whop_product_id" "text", "p_payment_id" "text", "p_amount_paid" numeric) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_pack RECORD;
  v_credits_to_add INTEGER;
  v_new_total INTEGER;
BEGIN
  -- Find user
  SELECT id INTO v_user_id
  FROM profiles
  WHERE LOWER(email) = LOWER(p_user_email);
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  -- Get pack config
  SELECT * INTO v_pack
  FROM credit_pack_config
  WHERE whop_product_id = p_whop_product_id AND is_active = TRUE;
  
  IF v_pack IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Unknown credit pack');
  END IF;

  -- Calculate credits with bonus
  v_credits_to_add := v_pack.credits_amount + FLOOR(v_pack.credits_amount * v_pack.bonus_percent / 100);

  -- Add credits
  UPDATE profiles
  SET credits_purchased = COALESCE(credits_purchased, 0) + v_credits_to_add
  WHERE id = v_user_id
  RETURNING credits_purchased INTO v_new_total;

  -- Log purchase
  INSERT INTO credit_purchases (
    user_id, pack_type, credits_amount, price_usd, payment_id, payment_provider, status
  ) VALUES (
    v_user_id, v_pack.pack_type, v_credits_to_add, p_amount_paid, p_payment_id, 'whop', 'completed'
  );

  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'pack_type', v_pack.pack_type,
    'credits_added', v_credits_to_add,
    'bonus_credits', v_credits_to_add - v_pack.credits_amount,
    'purchased_total', v_new_total
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."handle_credit_pack_purchase"("p_user_email" "text", "p_whop_product_id" "text", "p_payment_id" "text", "p_amount_paid" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.profiles (id, email, display_name, account_type)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(
      NEW.raw_user_meta_data->>'display_name',
      split_part(NEW.email, '@', 1)
    ),
    'free'
  )
  ON CONFLICT (id) DO NOTHING;

  RETURN NEW;

EXCEPTION
  WHEN OTHERS THEN
    RAISE WARNING 'handle_new_user failed for auth.users.id=%: % (SQLSTATE %)',
      NEW.id, SQLERRM, SQLSTATE;
    RETURN NEW;  -- never block signup
END;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."handle_new_user"() IS 'Auto-creates profiles row on auth.users INSERT. Minimal field set (id, email, display_name, account_type=free). Other fields filled by 6 chained triggers on profiles. Never blocks signup on failure.';



CREATE OR REPLACE FUNCTION "public"."handle_newsletter_payment"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_payment_amount" numeric, "p_finotaur_user_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_user_id UUID;
  v_was_in_trial BOOLEAN;
  v_old_status TEXT;
  v_expires_at TIMESTAMPTZ;
  v_trial_ends_at TIMESTAMPTZ;
BEGIN

  -- Find user by multiple methods
  IF p_finotaur_user_id IS NOT NULL AND p_finotaur_user_id != '' THEN
    BEGIN
      SELECT id INTO v_user_id FROM profiles WHERE id = p_finotaur_user_id::UUID;
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END IF;
  
  IF v_user_id IS NULL AND p_whop_membership_id IS NOT NULL THEN
    SELECT id INTO v_user_id FROM profiles WHERE newsletter_whop_membership_id = p_whop_membership_id;
  END IF;
  
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    SELECT id INTO v_user_id FROM profiles WHERE LOWER(email) = LOWER(p_user_email);
  END IF;
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'User not found for payment',
      'lookup_attempted', jsonb_build_object(
        'finotaur_user_id', p_finotaur_user_id,
        'email', p_user_email,
        'membership_id', p_whop_membership_id
      )
    );
  END IF;
  
  -- Get current status and trial info
SELECT 
  newsletter_status, 
  newsletter_status = 'trial',
  newsletter_trial_ends_at
INTO v_old_status, v_was_in_trial, v_trial_ends_at
FROM profiles WHERE id = v_user_id;


IF COALESCE(p_payment_amount, 0) = 0 THEN
  -- $0 payment = trial signup, don't change trial status
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'newsletter_status', COALESCE(v_old_status, 'trial'),
    'message', 'Trial signup - $0 payment, status unchanged',
    'payment_amount', p_payment_amount,
    'is_trial_payment', true
  );
END IF;


v_expires_at := NOW() + INTERVAL '1 month';

UPDATE profiles SET
  newsletter_enabled = TRUE,
  newsletter_status = 'active',
  newsletter_expires_at = v_expires_at,
  newsletter_cancel_at_period_end = FALSE,
  newsletter_paid = TRUE,
  newsletter_paid_at = NOW(),
  updated_at = NOW()
WHERE id = v_user_id;
  
  -- Log event
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    v_user_id,
    CASE WHEN v_was_in_trial THEN 'trial_ended' ELSE 'payment_succeeded' END,
    COALESCE(v_old_status, 'none'), 'newsletter',
    jsonb_build_object(
      'whop_membership_id', p_whop_membership_id,
      'payment_amount', p_payment_amount,
      'was_in_trial', v_was_in_trial,
      'subscription_type', 'newsletter'
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'newsletter_status', 'active',
    'was_in_trial', COALESCE(v_was_in_trial, FALSE),
    'previous_status', v_old_status,
    'expires_at', v_expires_at,
    'payment_amount', p_payment_amount
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'sqlstate', SQLSTATE);
END;
$_$;


ALTER FUNCTION "public"."handle_newsletter_payment"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_payment_amount" numeric, "p_finotaur_user_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_newsletter_payment"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_payment_amount" numeric, "p_finotaur_user_id" "text" DEFAULT NULL::"text", "p_billing_interval" "text" DEFAULT 'monthly'::"text", "p_whop_customer_email" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_user_id UUID;
  v_was_in_trial BOOLEAN;
  v_old_status TEXT;
  v_expires_at TIMESTAMPTZ;
  v_trial_ends_at TIMESTAMPTZ;
  v_whop_email TEXT;
BEGIN
  -- 🔥 NEW: Use whop_customer_email if provided (this is the email user entered at Whop checkout)
  v_whop_email := COALESCE(p_whop_customer_email, p_user_email);

  -- Find user by multiple methods
  -- 🔥 PRIORITY 1: finotaur_user_id (most reliable - passed from frontend)
  IF p_finotaur_user_id IS NOT NULL AND p_finotaur_user_id != '' THEN
    BEGIN
      SELECT id INTO v_user_id FROM profiles WHERE id = p_finotaur_user_id::UUID;
      IF v_user_id IS NOT NULL THEN
        RAISE NOTICE '✅ Found user by finotaur_user_id: %', v_user_id;
      END IF;
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END IF;
  
  -- 🔥 PRIORITY 2: membership_id (for recurring payments)
  IF v_user_id IS NULL AND p_whop_membership_id IS NOT NULL THEN
    SELECT id INTO v_user_id FROM profiles WHERE newsletter_whop_membership_id = p_whop_membership_id;
    IF v_user_id IS NOT NULL THEN
      RAISE NOTICE '✅ Found user by membership_id: %', v_user_id;
    END IF;
  END IF;
  
  -- 🔥 PRIORITY 3: Exact email match (Finotaur registered email)
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    SELECT id INTO v_user_id FROM profiles WHERE LOWER(email) = LOWER(p_user_email);
    IF v_user_id IS NOT NULL THEN
      RAISE NOTICE '✅ Found user by email: %', v_user_id;
    END IF;
  END IF;
  
  -- 🔥 PRIORITY 4: whop_customer_email (returning customer with different Whop email)
  IF v_user_id IS NULL AND v_whop_email IS NOT NULL AND v_whop_email != '' THEN
    SELECT id INTO v_user_id FROM profiles WHERE LOWER(whop_customer_email) = LOWER(v_whop_email);
    IF v_user_id IS NOT NULL THEN
      RAISE NOTICE '✅ Found user by whop_customer_email: %', v_user_id;
    END IF;
  END IF;
  
  -- 🔥 PRIORITY 5: Check pending_checkouts table (user started checkout from Finotaur)
  IF v_user_id IS NULL THEN
    SELECT pc.user_id INTO v_user_id 
    FROM pending_checkouts pc
    WHERE pc.product_type = 'newsletter'
      AND pc.completed_at IS NULL
      AND pc.expires_at > NOW()
      AND (
        -- Match by finotaur_user_id in checkout
        (p_finotaur_user_id IS NOT NULL AND pc.user_id::TEXT = p_finotaur_user_id)
        OR
        -- Match by email (even if different)
        (LOWER(pc.user_email) = LOWER(COALESCE(p_user_email, v_whop_email)))
      )
    ORDER BY pc.created_at DESC
    LIMIT 1;
    
    IF v_user_id IS NOT NULL THEN
      RAISE NOTICE '✅ Found user from pending_checkouts: %', v_user_id;
    END IF;
  END IF;
  
IF v_user_id IS NULL AND p_user_email IS NOT NULL THEN
  DECLARE
    v_email_username TEXT;
    v_similarity REAL;
  BEGIN
    v_email_username := LOWER(SPLIT_PART(p_user_email, '@', 1));
    
    -- Try similar usernames (min 70% similarity)
    SELECT id INTO v_user_id 
    FROM profiles 
    WHERE similarity(LOWER(SPLIT_PART(email, '@', 1)), v_email_username) > 0.7
    ORDER BY similarity(LOWER(SPLIT_PART(email, '@', 1)), v_email_username) DESC
    LIMIT 1;
    
    IF v_user_id IS NOT NULL THEN
      RAISE NOTICE '✅ Found user by fuzzy email match: %', v_user_id;
    END IF;
  END;
END IF;
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'User not found for payment',
      'lookup_attempted', jsonb_build_object(
        'finotaur_user_id', p_finotaur_user_id,
        'email', p_user_email,
        'whop_customer_email', p_whop_customer_email,
        'membership_id', p_whop_membership_id
      )
    );
  END IF;
  
  -- Get current status and trial info
SELECT 
  newsletter_status, 
  newsletter_status = 'trial',
  newsletter_trial_ends_at
INTO v_old_status, v_was_in_trial, v_trial_ends_at
FROM profiles WHERE id = v_user_id;


IF COALESCE(p_payment_amount, 0) = 0 THEN
  -- $0 payment = trial signup, don't change trial status
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'newsletter_status', COALESCE(v_old_status, 'trial'),
    'message', 'Trial signup - $0 payment, status unchanged',
    'payment_amount', p_payment_amount,
    'is_trial_payment', true
  );
END IF;


v_expires_at := CASE 
  WHEN p_billing_interval = 'yearly' THEN NOW() + INTERVAL '1 year'
  ELSE NOW() + INTERVAL '1 month'
END;

UPDATE profiles SET
  newsletter_enabled = TRUE,
  newsletter_status = 'active',
  newsletter_expires_at = v_expires_at,
  newsletter_interval = p_billing_interval,
  newsletter_cancel_at_period_end = FALSE,
  newsletter_paid = TRUE,
  newsletter_paid_at = NOW(),
  newsletter_whop_membership_id = COALESCE(newsletter_whop_membership_id, p_whop_membership_id),
  -- 🔥 CRITICAL: Save the Whop checkout email so we can find this user next time
  whop_customer_email = COALESCE(v_whop_email, whop_customer_email, p_user_email),
  updated_at = NOW()
WHERE id = v_user_id;
  
  -- Log event
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    v_user_id,
    CASE WHEN v_was_in_trial THEN 'trial_ended' ELSE 'payment_succeeded' END,
    COALESCE(v_old_status, 'none'), 'newsletter',
    jsonb_build_object(
      'whop_membership_id', p_whop_membership_id,
      'payment_amount', p_payment_amount,
      'was_in_trial', v_was_in_trial,
      'subscription_type', 'newsletter',
      'billing_interval', p_billing_interval,
      'expires_at', v_expires_at
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'newsletter_status', 'active',
    'was_in_trial', COALESCE(v_was_in_trial, FALSE),
    'previous_status', v_old_status,
    'expires_at', v_expires_at,
    'payment_amount', p_payment_amount,
    'billing_interval', p_billing_interval
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'sqlstate', SQLSTATE);
END;
$_$;


ALTER FUNCTION "public"."handle_newsletter_payment"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_payment_amount" numeric, "p_finotaur_user_id" "text", "p_billing_interval" "text", "p_whop_customer_email" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_newsletter_upgrade_to_yearly"("p_user_id" "uuid", "p_new_whop_membership_id" "text", "p_new_expires_at" timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_old_membership_id TEXT;
  v_old_interval TEXT;
BEGIN
  -- Get current membership info
  SELECT newsletter_whop_membership_id, newsletter_interval 
  INTO v_old_membership_id, v_old_interval
  FROM profiles 
  WHERE id = p_user_id;
  
  -- Update to yearly subscription
  UPDATE profiles SET
    newsletter_interval = 'yearly',
    newsletter_whop_membership_id = p_new_whop_membership_id,
    newsletter_expires_at = p_new_expires_at,
    newsletter_status = 'active',
    newsletter_cancel_at_period_end = FALSE,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- Log the upgrade event
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    p_user_id,
    'upgrade',
    'newsletter_monthly',
    'newsletter_yearly',
    jsonb_build_object(
      'old_membership_id', v_old_membership_id,
      'new_membership_id', p_new_whop_membership_id,
      'old_interval', v_old_interval,
      'new_interval', 'yearly',
      'new_expires_at', p_new_expires_at,
      'upgrade_type', 'monthly_to_yearly'
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', p_user_id,
    'old_interval', v_old_interval,
    'new_interval', 'yearly',
    'new_expires_at', p_new_expires_at
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'sqlstate', SQLSTATE
  );
END;
$$;


ALTER FUNCTION "public"."handle_newsletter_upgrade_to_yearly"("p_user_id" "uuid", "p_new_whop_membership_id" "text", "p_new_expires_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_platform_payment"("p_whop_membership_id" "text", "p_payment_amount" numeric DEFAULT 0, "p_whop_product_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_current_plan TEXT;
  v_billing_interval TEXT;
  v_new_expires TIMESTAMPTZ;
  v_was_in_trial BOOLEAN;
BEGIN
  SELECT id, platform_plan, platform_billing_interval, platform_is_in_trial
  INTO v_user_id, v_current_plan, v_billing_interval, v_was_in_trial
  FROM profiles WHERE platform_whop_membership_id = p_whop_membership_id;
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Membership not found');
  END IF;
  
  v_new_expires := CASE 
    WHEN v_billing_interval = 'monthly' THEN NOW() + INTERVAL '1 month'
    ELSE NOW() + INTERVAL '1 year'
  END;
  
  UPDATE profiles SET
    platform_subscription_status = 'active',
    platform_subscription_expires_at = v_new_expires,
    platform_is_in_trial = FALSE,
    platform_trial_ends_at = NULL,
    platform_cancel_at_period_end = FALSE,
    platform_cancelled_at = NULL,
    updated_at = NOW()
  WHERE id = v_user_id;
  
  INSERT INTO platform_subscription_events (user_id, event_type, new_plan, metadata)
  VALUES (v_user_id, CASE WHEN v_was_in_trial THEN 'trial_converted' ELSE 'renewed' END,
    v_current_plan, jsonb_build_object('payment_amount', p_payment_amount, 'was_in_trial', v_was_in_trial));
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'plan', v_current_plan,
    'new_expires_at', v_new_expires,
    'was_trial_conversion', v_was_in_trial
  );
END;
$$;


ALTER FUNCTION "public"."handle_platform_payment"("p_whop_membership_id" "text", "p_payment_amount" numeric, "p_whop_product_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_top_secret_payment"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_whop_plan_id" "text", "p_payment_amount" numeric, "p_finotaur_user_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_interval TEXT;
  v_expires_at TIMESTAMPTZ;
  v_old_status TEXT;
BEGIN
  -- Determine interval from plan_id
  IF p_whop_plan_id = 'plan_YoeD6wWBxss7Q' THEN
    v_interval := 'yearly';
    v_expires_at := NOW() + INTERVAL '1 year';
  ELSE
    v_interval := 'monthly';
    v_expires_at := NOW() + INTERVAL '1 month';
  END IF;

  -- Find user by multiple methods
  IF p_finotaur_user_id IS NOT NULL AND p_finotaur_user_id != '' THEN
    BEGIN
      SELECT id INTO v_user_id FROM profiles WHERE id = p_finotaur_user_id::UUID;
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END IF;
  
  IF v_user_id IS NULL AND p_whop_membership_id IS NOT NULL THEN
    SELECT id INTO v_user_id FROM profiles WHERE top_secret_whop_membership_id = p_whop_membership_id;
  END IF;
  
  IF v_user_id IS NULL AND p_user_email IS NOT NULL AND p_user_email != '' THEN
    SELECT id INTO v_user_id FROM profiles WHERE LOWER(email) = LOWER(p_user_email);
  END IF;
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'User not found for payment'
    );
  END IF;
  
  -- Get current status
  SELECT top_secret_status INTO v_old_status FROM profiles WHERE id = v_user_id;
  
  -- Update Top Secret fields ONLY
  UPDATE profiles SET
    top_secret_enabled = TRUE,
    top_secret_status = 'active',
    top_secret_expires_at = v_expires_at,
    top_secret_interval = v_interval,
    top_secret_cancel_at_period_end = FALSE,
    updated_at = NOW()
  WHERE id = v_user_id;
  
  -- Log event
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    v_user_id,
    'payment_succeeded',
    COALESCE(v_old_status, 'none'),
    'top_secret',
    jsonb_build_object(
      'whop_membership_id', p_whop_membership_id,
      'payment_amount', p_payment_amount,
      'interval', v_interval,
      'subscription_type', 'top_secret'
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', v_user_id,
    'top_secret_status', 'active',
    'previous_status', v_old_status,
    'expires_at', v_expires_at,
    'interval', v_interval,
    'payment_amount', p_payment_amount
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'sqlstate', SQLSTATE);
END;
$$;


ALTER FUNCTION "public"."handle_top_secret_payment"("p_user_email" "text", "p_whop_user_id" "text", "p_whop_membership_id" "text", "p_whop_product_id" "text", "p_whop_plan_id" "text", "p_payment_amount" numeric, "p_finotaur_user_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_top_secret_upgrade_to_yearly"("p_user_id" "uuid", "p_new_whop_membership_id" "text", "p_new_expires_at" timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_old_membership_id TEXT;
  v_old_interval TEXT;
BEGIN
  -- Get current membership info
  SELECT top_secret_whop_membership_id, top_secret_interval 
  INTO v_old_membership_id, v_old_interval
  FROM profiles 
  WHERE id = p_user_id;
  
  -- Update to yearly subscription
  UPDATE profiles SET
    top_secret_interval = 'yearly',
    top_secret_whop_membership_id = p_new_whop_membership_id,
    top_secret_expires_at = p_new_expires_at,
    top_secret_status = 'active',
    top_secret_cancel_at_period_end = FALSE,
    top_secret_is_in_trial = FALSE,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- Log the upgrade event
  INSERT INTO subscription_events (
    user_id, event_type, old_plan, new_plan, metadata
  ) VALUES (
    p_user_id,
    'upgrade',
    'top_secret_monthly',
    'top_secret_yearly',
    jsonb_build_object(
      'old_membership_id', v_old_membership_id,
      'new_membership_id', p_new_whop_membership_id,
      'old_interval', v_old_interval,
      'new_interval', 'yearly',
      'new_expires_at', p_new_expires_at,
      'upgrade_type', 'monthly_to_yearly'
    )
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', p_user_id,
    'old_interval', v_old_interval,
    'new_interval', 'yearly',
    'new_expires_at', p_new_expires_at
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'sqlstate', SQLSTATE
  );
END;
$$;


ALTER FUNCTION "public"."handle_top_secret_upgrade_to_yearly"("p_user_id" "uuid", "p_new_whop_membership_id" "text", "p_new_expires_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_trade_changes_unified"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $_$
DECLARE
  multiplier NUMERIC;
  price_diff NUMERIC;
  gross_pnl NUMERIC;
  v_account_type TEXT;
  v_old_pnl NUMERIC := 0;
  
  -- 🆕 Variables for R-multiple calculation
  v_portfolio_size NUMERIC;
  v_risk_mode TEXT;
  v_risk_percentage NUMERIC;
  v_fixed_risk_amount NUMERIC;
  v_user_one_r NUMERIC; -- User's 1R
BEGIN
  -- ═══════════════════════════════════════
  -- 🆕 STEP 0: Get user's risk settings WITH DEFAULTS
  -- ═══════════════════════════════════════
  
  SELECT 
    COALESCE(portfolio_size, initial_portfolio, current_portfolio, 10000) as portfolio_size,
    COALESCE(risk_mode, 'percentage') as risk_mode,
    COALESCE(risk_percentage, 1.0) as risk_percentage,
    COALESCE(fixed_risk_amount, 100) as fixed_risk_amount
  INTO 
    v_portfolio_size,
    v_risk_mode,
    v_risk_percentage,
    v_fixed_risk_amount
  FROM public.profiles
  WHERE id = NEW.user_id;
  
  -- 🔥 CRITICAL FIX: Ensure we ALWAYS have valid values
  IF v_portfolio_size IS NULL OR v_portfolio_size <= 0 THEN
    v_portfolio_size := 10000;
  END IF;
  
  IF v_risk_mode IS NULL THEN
    v_risk_mode := 'percentage';
  END IF;
  
  IF v_risk_percentage IS NULL OR v_risk_percentage <= 0 THEN
    v_risk_percentage := 1.0;
  END IF;
  
  -- Calculate user's 1R (NEVER NULL!)
  IF v_risk_mode = 'percentage' THEN
    v_user_one_r := (v_portfolio_size * v_risk_percentage) / 100;
  ELSIF v_risk_mode = 'fixed' AND v_fixed_risk_amount IS NOT NULL AND v_fixed_risk_amount > 0 THEN
    v_user_one_r := v_fixed_risk_amount;
  ELSE
    -- 🔥 FALLBACK: Use 1% of portfolio as default
    v_user_one_r := (v_portfolio_size * 1.0) / 100;
  END IF;
  
  -- 🔥 FINAL SAFETY CHECK: Ensure v_user_one_r is never NULL or zero
  IF v_user_one_r IS NULL OR v_user_one_r <= 0 THEN
    v_user_one_r := 100; -- Absolute fallback: $100
  END IF;
  
  -- ═══════════════════════════════════════
  -- STEP 1: Calculate Multiplier
  -- ═══════════════════════════════════════
  
  IF NEW.multiplier IS NOT NULL AND NEW.multiplier > 0 THEN
    multiplier := NEW.multiplier;
  ELSE
    multiplier := public.get_asset_multiplier(NEW.symbol);
    NEW.multiplier := multiplier;
  END IF;
  
  -- ═══════════════════════════════════════
  -- STEP 2: Calculate Risk & Reward Points
  -- ═══════════════════════════════════════
  
  -- Risk Points (Entry → Stop)
  IF NEW.stop_price IS NOT NULL AND NEW.stop_price > 0 THEN
    NEW.risk_pts := ABS(NEW.entry_price - NEW.stop_price);
  END IF;
  
  -- Reward Points (Entry → Take Profit)
  IF NEW.take_profit_price IS NOT NULL THEN
    NEW.reward_pts := CASE
      WHEN NEW.side = 'LONG' THEN NEW.take_profit_price - NEW.entry_price
      WHEN NEW.side = 'SHORT' THEN NEW.entry_price - NEW.take_profit_price
      ELSE 0
    END;
  END IF;
  
  -- ═══════════════════════════════════════
  -- STEP 3: Calculate Risk & Reward USD
  -- ═══════════════════════════════════════
  
  IF NEW.stop_price IS NOT NULL AND NEW.stop_price > 0 THEN
    -- Risk USD = Points × Quantity × Multiplier + Fees
    NEW.risk_usd := (NEW.risk_pts * NEW.quantity * multiplier) + COALESCE(NEW.fees, 0);
    
    IF NEW.take_profit_price IS NOT NULL THEN
      -- Reward USD = Points × Quantity × Multiplier
      NEW.reward_usd := ABS(NEW.reward_pts * NEW.quantity * multiplier);
    END IF;
  END IF;
  
  -- ═══════════════════════════════════════
  -- STEP 4: Calculate R:R Ratio
  -- ═══════════════════════════════════════
  
  IF NEW.risk_pts IS NOT NULL AND NEW.risk_pts > 0 AND NEW.reward_pts IS NOT NULL THEN
    NEW.rr := ROUND(ABS(NEW.reward_pts / NEW.risk_pts), 2);
  END IF;
  
  -- ═══════════════════════════════════════
  -- 🆕 STEP 5: Calculate user_risk_r & user_reward_r
  -- ═══════════════════════════════════════
  
  IF v_user_one_r IS NOT NULL AND v_user_one_r > 0 THEN
    -- YOU'RE RISKING: X.XXR (for OPEN trades)
    IF NEW.risk_usd IS NOT NULL AND NEW.exit_price IS NULL THEN
      NEW.user_risk_r := ROUND(NEW.risk_usd / v_user_one_r, 2);
    END IF;
    
    -- POTENTIAL REWARD: +X.XXR (for OPEN trades only)
    IF NEW.reward_usd IS NOT NULL AND NEW.exit_price IS NULL THEN
      NEW.user_reward_r := ROUND(NEW.reward_usd / v_user_one_r, 2);
    END IF;
  END IF;
  
  -- ═══════════════════════════════════════
  -- STEP 6: If trade is closed - calculate P&L
  -- ═══════════════════════════════════════
  
  -- 🔥 RISK-ONLY MODE: Check if pnl was provided directly
  IF NEW.input_mode = 'risk-only' THEN
    
    -- If pnl was provided, trade is closed
    IF NEW.pnl IS NOT NULL THEN
      -- Recalculate R values for consistency
      IF NEW.risk_usd IS NOT NULL AND NEW.risk_usd > 0 THEN
        NEW.actual_r := ROUND(NEW.pnl / NEW.risk_usd, 2);
      END IF;
      
      IF v_user_one_r IS NOT NULL AND v_user_one_r > 0 THEN
        NEW.actual_user_r := ROUND(NEW.pnl / v_user_one_r, 2);
      END IF;
      
      -- Set outcome based on pnl
      NEW.outcome := CASE
        WHEN NEW.pnl > 0.01 THEN 'WIN'
        WHEN NEW.pnl < -0.01 THEN 'LOSS'
        ELSE 'BE'
      END;
      
      IF NEW.close_at IS NULL THEN
        NEW.close_at := NOW();
      END IF;
      
      -- Update portfolio for closed risk-only trade
      IF TG_OP = 'UPDATE' AND OLD.pnl IS NOT NULL THEN
        v_old_pnl := COALESCE(OLD.pnl, 0);
      END IF;
      
      UPDATE public.profiles
      SET 
        total_pnl = COALESCE(total_pnl, 0) - v_old_pnl + NEW.pnl,
        current_portfolio = initial_portfolio + (COALESCE(total_pnl, 0) - v_old_pnl + NEW.pnl),
        updated_at = NOW()
      WHERE id = NEW.user_id;
      
    ELSE
      -- Risk-Only without result = OPEN
      NEW.outcome := 'OPEN';
      NEW.actual_r := NULL;
      NEW.actual_user_r := NULL;
    END IF;
    
  -- 🔥 REGULAR MODE: Check exit_price
  ELSIF NEW.exit_price IS NOT NULL AND NEW.exit_price > 0 THEN
    -- Calculate price difference
    IF NEW.side = 'LONG' THEN
      price_diff := NEW.exit_price - NEW.entry_price;
    ELSIF NEW.side = 'SHORT' THEN
      price_diff := NEW.entry_price - NEW.exit_price;
    ELSE
      price_diff := 0;
    END IF;
    
    -- Calculate P&L
    gross_pnl := price_diff * NEW.quantity * multiplier;
    NEW.pnl := gross_pnl - COALESCE(NEW.fees, 0);
    
    -- Calculate actual_user_r (User Rs achieved based on actual P&L)
    IF v_user_one_r IS NOT NULL AND v_user_one_r > 0 THEN
      NEW.actual_user_r := ROUND(NEW.pnl / v_user_one_r, 2);
      -- Clear user_reward_r for closed trades (no longer relevant)
      NEW.user_reward_r := NULL;
    END IF;
    
    -- Calculate actual_r (contract-based R-multiple)
    IF NEW.risk_usd IS NOT NULL AND NEW.risk_usd > 0 THEN
      NEW.actual_r := ROUND(NEW.pnl / NEW.risk_usd, 2);
    END IF;
    
    -- Set outcome
    NEW.outcome := CASE
      WHEN NEW.pnl > 0.01 THEN 'WIN'
      WHEN NEW.pnl < -0.01 THEN 'LOSS'
      ELSE 'BE'
    END;
    
    IF NEW.close_at IS NULL THEN
      NEW.close_at := NOW();
    END IF;
    
    -- Update portfolio
    IF TG_OP = 'UPDATE' AND OLD.exit_price IS NOT NULL THEN
      v_old_pnl := COALESCE(OLD.pnl, 0);
    END IF;
    
    UPDATE public.profiles
    SET 
      total_pnl = COALESCE(total_pnl, 0) - v_old_pnl + NEW.pnl,
      current_portfolio = initial_portfolio + (COALESCE(total_pnl, 0) - v_old_pnl + NEW.pnl),
      updated_at = NOW()
    WHERE id = NEW.user_id;
    
  ELSE
    -- Trade is open (no exit_price and not risk-only with result)
    NEW.outcome := 'OPEN';
    NEW.pnl := NULL;
    NEW.actual_r := NULL;
  END IF;
  -- STEP 7: Increment Trade Count (only on INSERT)
  -- ═══════════════════════════════════════
  
  IF TG_OP = 'INSERT' THEN
    SELECT account_type INTO v_account_type
    FROM public.profiles
    WHERE id = NEW.user_id;
    
    -- 🔥 CRITICAL: platform_free blocked by RLS.
    -- BEFORE trigger runs BEFORE RLS - skip to prevent count inflation on failed inserts.
    IF v_account_type = 'platform_free' THEN
      RETURN NEW;
    END IF;
    
    UPDATE public.profiles
    SET 
      billing_cycle_start = CASE 
        WHEN v_account_type IN ('basic', 'premium', 'trial') THEN
          CASE 
            WHEN billing_cycle_start IS NULL 
              OR billing_cycle_start < DATE_TRUNC('month', CURRENT_DATE)
            THEN DATE_TRUNC('month', CURRENT_DATE)::DATE
            ELSE billing_cycle_start
          END
        ELSE 
          COALESCE(billing_cycle_start, DATE_TRUNC('month', CURRENT_DATE)::DATE)
      END,
      current_month_trades_count = CASE
        WHEN v_account_type IN ('basic', 'premium', 'trial') THEN
          CASE
            WHEN billing_cycle_start IS NULL 
              OR billing_cycle_start < DATE_TRUNC('month', CURRENT_DATE)
            THEN 1
            ELSE COALESCE(current_month_trades_count, 0) + 1
          END
        ELSE 
          COALESCE(current_month_trades_count, 0) + 1
      END,
      trade_count = COALESCE(trade_count, 0) + 1
    WHERE id = NEW.user_id;
  END IF;
  
  RETURN NEW;
END;
$_$;


ALTER FUNCTION "public"."handle_trade_changes_unified"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."handle_trade_changes_unified"() IS '🔥 v8.5.9-FINAL-FIX: R-multiple calculation FIXED - removed actual_user_r column error. 
Now correctly uses user_risk_r for both open and closed trades.
- OPEN trades: user_risk_r = risk in R, user_reward_r = potential reward in R
- CLOSED trades: user_risk_r = actual result in R, user_reward_r = NULL';



CREATE OR REPLACE FUNCTION "public"."handle_updated_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_updated_at"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_whop_newsletter_subscription"("p_user_email" "text", "p_membership_id" "text", "p_action" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_result JSONB;
BEGIN
  SELECT id INTO v_user_id
  FROM profiles
  WHERE LOWER(email) = LOWER(p_user_email)
  LIMIT 1;
  
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  IF p_action = 'subscribe' THEN
    UPDATE profiles
    SET 
      newsletter_paid = true,
      newsletter_paid_at = NOW(),
      newsletter_enabled = true,
      whop_newsletter_membership_id = p_membership_id
    WHERE id = v_user_id;
    
    v_result := jsonb_build_object('success', true, 'action', 'subscribed', 'user_id', v_user_id);
    
  ELSIF p_action = 'unsubscribe' THEN
    UPDATE profiles
    SET 
      newsletter_paid = false,
      whop_newsletter_membership_id = NULL
    WHERE id = v_user_id;
    
    v_result := jsonb_build_object('success', true, 'action', 'unsubscribed', 'user_id', v_user_id);
  ELSE
    v_result := jsonb_build_object('success', false, 'error', 'Invalid action');
  END IF;
  
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."handle_whop_newsletter_subscription"("p_user_email" "text", "p_membership_id" "text", "p_action" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_whop_payment"("p_whop_membership_id" "text", "p_payment_amount" numeric, "p_is_first_payment" boolean DEFAULT false, "p_promo_code" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $_$
DECLARE
  v_user_id UUID;
  v_user_email TEXT;
  v_subscription_type TEXT;
  v_referral RECORD;
  v_affiliate RECORD;
  v_commission_rate NUMERIC;
  v_commission_amount NUMERIC;
  v_referral_id UUID;
  v_commission_type_val commission_type;
BEGIN
  -- Get user info
  SELECT id, email, subscription_interval INTO v_user_id, v_user_email, v_subscription_type
  FROM profiles WHERE whop_membership_id = p_whop_membership_id;
  
  -- Find existing referral
  SELECT ar.*, a.commission_enabled, a.affiliate_type, a.current_tier, a.id as aff_id, a.user_id as aff_user_id
  INTO v_referral
  FROM affiliate_referrals ar
  JOIN affiliates a ON ar.affiliate_id = a.id
  WHERE ar.whop_membership_id = p_whop_membership_id OR ar.referred_user_id = v_user_id;
  
  -- If no referral but promo code provided, try to create one
  IF v_referral IS NULL AND p_promo_code IS NOT NULL AND v_user_id IS NOT NULL THEN
    SELECT * INTO v_affiliate FROM affiliates
    WHERE (UPPER(affiliate_code) = UPPER(p_promo_code) OR UPPER(coupon_code) = UPPER(p_promo_code))
      AND status = 'active' AND commission_enabled = true;
    
    IF v_affiliate IS NOT NULL AND v_affiliate.user_id != v_user_id THEN
      v_commission_rate := get_commission_rate(COALESCE(v_affiliate.current_tier::text, 'tier_1'), COALESCE(v_subscription_type, 'monthly'));
      v_commission_amount := ROUND(p_payment_amount * v_commission_rate, 2);
      v_commission_type_val := CASE WHEN v_subscription_type = 'yearly' THEN 'annual_upfront' ELSE 'monthly_recurring' END;
      
      INSERT INTO affiliate_referrals (
        affiliate_id, referred_user_id, referred_user_email, signup_date, whop_membership_id,
        first_payment_amount_usd, first_payment_date, total_payments_usd, status,
        verification_start, verification_end, commission_eligible, coupon_code_used, subscription_type
      ) VALUES (
        v_affiliate.id, v_user_id, v_user_email, NOW(), p_whop_membership_id,
        p_payment_amount, NOW(), p_payment_amount, 'verification_pending',
        NOW(), NOW() + INTERVAL '7 days',
        TRUE, p_promo_code, v_subscription_type
      ) RETURNING id INTO v_referral_id;
      
      UPDATE affiliates SET total_signups = COALESCE(total_signups, 0) + 1, last_activity_at = NOW() WHERE id = v_affiliate.id;
      
      INSERT INTO affiliate_commissions (
        affiliate_id, referral_id, commission_type, commission_month, base_amount_usd,
        commission_rate, commission_amount_usd, tier_at_time, status, month_number
      ) VALUES (
        v_affiliate.id, v_referral_id, v_commission_type_val, date_trunc('month', NOW())::date,
        p_payment_amount, v_commission_rate, v_commission_amount, v_affiliate.current_tier, 'pending', 1
      );
      
      UPDATE affiliates SET
        total_pending_usd = COALESCE(total_pending_usd, 0) + v_commission_amount,
        total_earnings_usd = COALESCE(total_earnings_usd, 0) + v_commission_amount
      WHERE id = v_affiliate.id;
      
      UPDATE affiliate_referrals SET commission_earned_usd = v_commission_amount WHERE id = v_referral_id;
      
      INSERT INTO affiliate_activity_log (affiliate_id, activity_type, description, metadata, is_system_action)
      VALUES (v_affiliate.id, 'first_payment_received',
        'First payment of $' || p_payment_amount || ' (' || COALESCE(v_subscription_type, 'monthly') || '), commission: $' || v_commission_amount,
        jsonb_build_object('user_email', v_user_email, 'amount', p_payment_amount, 'promo_code', p_promo_code,
          'commission_rate', v_commission_rate, 'commission_amount', v_commission_amount), true);
      
      RETURN jsonb_build_object('success', true, 'message', 'New referral and commission created',
        'referral_id', v_referral_id, 'commission_amount', v_commission_amount, 'commission_rate', v_commission_rate);
    END IF;
  END IF;
  
  IF v_referral IS NULL THEN
    RETURN jsonb_build_object('success', true, 'message', 'No affiliate referral found for this payment');
  END IF;
  
  IF NOT v_referral.commission_enabled OR v_referral.affiliate_type != 'regular' THEN
    RETURN jsonb_build_object('success', true, 'message', 'Affiliate not eligible for commission');
  END IF;
  
  v_commission_rate := get_commission_rate(COALESCE(v_referral.current_tier::text, 'tier_1'), COALESCE(v_subscription_type, 'monthly'));
  v_commission_type_val := CASE WHEN v_subscription_type = 'yearly' THEN 'annual_upfront' ELSE 'monthly_recurring' END;
  
  -- First payment
  IF p_is_first_payment AND v_referral.first_payment_date IS NULL THEN
    v_commission_amount := ROUND(p_payment_amount * v_commission_rate, 2);
    
    UPDATE affiliate_referrals SET
      status = 'verification_pending', first_payment_amount_usd = p_payment_amount, first_payment_date = NOW(),
      verification_start = NOW(), verification_end = NOW() + INTERVAL '7 days',
      total_payments_usd = COALESCE(total_payments_usd, 0) + p_payment_amount,
      subscription_type = v_subscription_type, updated_at = NOW()
    WHERE id = v_referral.id;
    
    INSERT INTO affiliate_commissions (
      affiliate_id, referral_id, commission_type, commission_month, base_amount_usd,
      commission_rate, commission_amount_usd, tier_at_time, status, month_number
    ) VALUES (v_referral.affiliate_id, v_referral.id, v_commission_type_val, date_trunc('month', NOW())::date,
      p_payment_amount, v_commission_rate, v_commission_amount, v_referral.current_tier, 'pending', 1);
    
    UPDATE affiliates SET
      total_pending_usd = COALESCE(total_pending_usd, 0) + v_commission_amount,
      total_earnings_usd = COALESCE(total_earnings_usd, 0) + v_commission_amount, last_activity_at = NOW()
    WHERE id = v_referral.affiliate_id;
    
    UPDATE affiliate_referrals SET commission_earned_usd = COALESCE(commission_earned_usd, 0) + v_commission_amount
    WHERE id = v_referral.id;
    
    INSERT INTO affiliate_activity_log (affiliate_id, activity_type, description, metadata, is_system_action)
    VALUES (v_referral.affiliate_id, 'first_payment_received',
      'First payment of $' || p_payment_amount || ', commission: $' || v_commission_amount,
      jsonb_build_object('amount', p_payment_amount, 'commission', v_commission_amount, 'rate', v_commission_rate), true);
    
    RETURN jsonb_build_object('success', true, 'message', 'First payment recorded, commission created',
      'referral_id', v_referral.id, 'commission_amount', v_commission_amount, 'verification_ends', NOW() + INTERVAL '7 days');
  END IF;
  
  -- Recurring payment for qualified referrals
  IF v_referral.status = 'qualified' AND v_referral.commission_eligible THEN
    UPDATE affiliate_referrals SET total_payments_usd = COALESCE(total_payments_usd, 0) + p_payment_amount, updated_at = NOW()
    WHERE id = v_referral.id;
    
    IF v_subscription_type = 'monthly' AND COALESCE(v_referral.months_commissioned, 0) < 12 THEN
      v_commission_amount := ROUND(p_payment_amount * v_commission_rate, 2);
      
      INSERT INTO affiliate_commissions (
        affiliate_id, referral_id, commission_type, commission_month, base_amount_usd,
        commission_rate, commission_amount_usd, tier_at_time, status, month_number
      ) VALUES (v_referral.affiliate_id, v_referral.id, 'monthly_recurring', date_trunc('month', NOW())::date,
        p_payment_amount, v_commission_rate, v_commission_amount, v_referral.current_tier, 'pending',
        COALESCE(v_referral.months_commissioned, 0) + 1);
      
      UPDATE affiliate_referrals SET
        months_commissioned = COALESCE(months_commissioned, 0) + 1,
        commission_earned_usd = COALESCE(commission_earned_usd, 0) + v_commission_amount
      WHERE id = v_referral.id;
      
      UPDATE affiliates SET
        total_pending_usd = COALESCE(total_pending_usd, 0) + v_commission_amount,
        total_earnings_usd = COALESCE(total_earnings_usd, 0) + v_commission_amount, last_activity_at = NOW()
      WHERE id = v_referral.affiliate_id;
      
      RETURN jsonb_build_object('success', true, 'message', 'Recurring payment and commission recorded',
        'referral_id', v_referral.id, 'commission_amount', v_commission_amount, 'month_number', COALESCE(v_referral.months_commissioned, 0) + 1);
    END IF;
  END IF;
  
  RETURN jsonb_build_object('success', true, 'message', 'Payment recorded', 'referral_id', v_referral.id, 'referral_status', v_referral.status);
END;
$_$;


