CREATE OR REPLACE FUNCTION "public"."has_beta_access"("p_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_role TEXT;
  v_account_type TEXT;
BEGIN
  SELECT role, account_type 
  INTO v_role, v_account_type
  FROM profiles 
  WHERE id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;
  
  -- Beta access granted to: admin, super_admin, vip, beta
  RETURN (
    v_role IN ('admin', 'super_admin') OR
    v_account_type IN ('admin', 'vip', 'beta')
  );
END;
$$;


