CREATE OR REPLACE FUNCTION "public"."impersonate_user"("p_target_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Only super_admin can impersonate
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid()
      AND role = 'super_admin'
      AND COALESCE(is_banned, FALSE) = FALSE
  ) THEN
    RAISE EXCEPTION 'Access denied: Super Admin role required';
  END IF;
  
  -- Verify target exists
  IF NOT EXISTS (SELECT 1 FROM public.profiles WHERE id = p_target_user_id) THEN
    RAISE EXCEPTION 'User not found';
  END IF;
  
  -- Set impersonation config
  PERFORM set_config('app.admin_mode', 'true', true);
  PERFORM set_config('app.impersonated_user', p_target_user_id::text, true);
  
  -- Log action
  PERFORM public.log_admin_action(
    'impersonate',
    'user',
    p_target_user_id,
    jsonb_build_object('admin_id', auth.uid())
  );
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."impersonate_user"("p_target_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."impersonate_user"("p_target_user_id" "uuid") IS 'v8.5.9: Super admin impersonation for support';



