CREATE OR REPLACE FUNCTION "public"."manual_cleanup_old_data"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_rate_limits_deleted INTEGER := 0;
  v_sessions_deactivated INTEGER := 0;
  v_logs_archived INTEGER := 0;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  -- Clean up old rate limits (older than 24 hours)
  DELETE FROM public.api_rate_limits 
  WHERE window_start < NOW() - INTERVAL '24 hours';
  GET DIAGNOSTICS v_rate_limits_deleted = ROW_COUNT;
  
  -- Deactivate expired impersonation sessions
  UPDATE public.admin_impersonation_sessions 
  SET is_active = false 
  WHERE expires_at < NOW() AND is_active = true;
  GET DIAGNOSTICS v_sessions_deactivated = ROW_COUNT;
  
  -- Archive old audit logs (older than 1 year)
  DELETE FROM public.admin_audit_log 
  WHERE created_at < NOW() - INTERVAL '1 year';
  GET DIAGNOSTICS v_logs_archived = ROW_COUNT;
  
  RETURN jsonb_build_object(
    'success', true,
    'rate_limits_deleted', v_rate_limits_deleted,
    'sessions_deactivated', v_sessions_deactivated,
    'logs_archived', v_logs_archived,
    'cleaned_at', NOW()
  );
END;
$$;


ALTER FUNCTION "public"."manual_cleanup_old_data"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."manual_cleanup_old_data"() IS 'v8.5.10: Manual cleanup of old rate limits and expired sessions. Admin only.';



CREATE OR REPLACE FUNCTION "public"."mark_feedback_processed"("p_feedback_id" "uuid", "p_admin_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID;
  v_caller_role TEXT;
BEGIN
  -- Check admin access
  SELECT id, role INTO v_admin_id, v_caller_role
  FROM profiles 
  WHERE profiles.id = auth.uid();

  IF v_caller_role IS NULL OR v_caller_role NOT IN ('admin', 'super_admin') THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  UPDATE subscription_cancellation_feedback
  SET 
    processed = TRUE,
    admin_notes = p_admin_notes,
    processed_by = v_admin_id,
    processed_at = NOW(),
    updated_at = NOW()
  WHERE id = p_feedback_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Feedback not found');
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'feedback_id', p_feedback_id,
    'message', 'Feedback marked as processed'
  );
END;
$$;


ALTER FUNCTION "public"."mark_feedback_processed"("p_feedback_id" "uuid", "p_admin_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_messages_as_read"("p_chat_id" "uuid", "p_sender_type" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE support_messages
  SET is_read = TRUE
  WHERE chat_id = p_chat_id
    AND sender_type != p_sender_type
    AND is_read = FALSE;
    
  IF p_sender_type = 'user' THEN
    UPDATE support_chats
    SET unread_user_count = 0
    WHERE id = p_chat_id;
  ELSE
    UPDATE support_chats
    SET unread_admin_count = 0
    WHERE id = p_chat_id;
  END IF;
END;
