CREATE OR REPLACE FUNCTION "public"."permanent_delete_trade"("p_trade_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Only admins or after 30 days
  IF NOT (public.is_admin() OR 
    EXISTS(
      SELECT 1 FROM public.trades 
      WHERE id = p_trade_id 
        AND user_id = auth.uid()
        AND deleted_at < NOW() - INTERVAL '30 days'
    )
  ) THEN
    RAISE EXCEPTION 'Cannot permanently delete yet. Wait 30 days or contact admin.';
  END IF;
  
  DELETE FROM public.trades
  WHERE id = p_trade_id
    AND (user_id = auth.uid() OR public.is_admin());
  
  RETURN FOUND;
END;
$$;


