CREATE OR REPLACE FUNCTION "public"."process_expired_subscriptions"() RETURNS TABLE("downgraded_count" integer, "downgraded_emails" "text"[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_count INTEGER := 0;
  v_emails TEXT[] := ARRAY[]::TEXT[];
  v_user RECORD;
BEGIN
  FOR v_user IN
    SELECT 
      p.id,
      p.email,
      p.account_type
    FROM public.profiles p
    WHERE p.subscription_expires_at < NOW()  -- ✅ FIXED: was subscription_end_date
      AND p.account_type IN ('basic', 'premium', 'trial')
      AND p.subscription_status IN ('active', 'cancelled')
      AND p.role NOT IN ('admin', 'super_admin')
    ORDER BY p.subscription_expires_at ASC
    LIMIT 1000
  LOOP
UPDATE public.profiles
SET 
  previous_account_type = v_user.account_type,
  -- ❌ לא משנים ל-free
  -- account_type = 'free',
  -- max_trades = 0,
  subscription_status = 'expired',   -- ✅ רק משנים סטטוס
  subscription_interval = NULL,
  subscription_cancel_at_period_end = FALSE,
  payment_provider = NULL,
  updated_at = NOW()
WHERE id = v_user.id;
    
    -- Log the change
    INSERT INTO public.subscription_changes (
      user_id, change_type, from_plan, to_plan, effective_date
    ) VALUES (
      v_user.id, 'expire', v_user.account_type, 'free', NOW()
    );
    
    v_emails := array_append(v_emails, v_user.email);
    v_count := v_count + 1;
  END LOOP;
  
  RETURN QUERY SELECT v_count, v_emails;
END;
$$;


ALTER FUNCTION "public"."process_expired_subscriptions"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."process_expired_subscriptions"() IS 'v9.4.2-SYNCED: CRON job - downgrades expired subscriptions. Uses subscription_expires_at.';



CREATE OR REPLACE FUNCTION "public"."process_expired_trials"() RETURNS TABLE("processed_count" integer, "processed_user_ids" "uuid"[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count INTEGER := 0;
  v_user_ids UUID[] := ARRAY[]::UUID[];
  v_user RECORD;
BEGIN
  RAISE NOTICE '🔄 Processing expired trials...';
  
  FOR v_user IN 
    SELECT id, email
    FROM public.profiles
    WHERE (subscription_status = 'trial' OR is_in_trial = TRUE)
      AND trial_ends_at IS NOT NULL
      AND trial_ends_at < NOW()
      AND subscription_status != 'expired'
  LOOP
    UPDATE public.profiles
    SET 
      subscription_status = 'expired',
      is_in_trial = FALSE,
      updated_at = NOW()
    WHERE id = v_user.id;
    
    v_user_ids := array_append(v_user_ids, v_user.id);
    v_count := v_count + 1;
    
    RAISE NOTICE '  → Expired trial for user: %', v_user.email;
  END LOOP;
  
  RAISE NOTICE '✅ Processed % expired trials', v_count;
  
  RETURN QUERY SELECT v_count, v_user_ids;
END;
$$;


ALTER FUNCTION "public"."process_expired_trials"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."process_expired_trials"() IS 'Processes expired trials. Sets subscription_status=expired but keeps account_type=basic.';



CREATE OR REPLACE FUNCTION "public"."process_payout"("payout_uuid" "uuid", "transaction_ref" "text", "processed_by_user" "uuid") RETURNS boolean
    LANGUAGE "plpgsql"
    AS $_$
DECLARE
  payout_record RECORD;
BEGIN
  SELECT * INTO payout_record FROM affiliate_payouts WHERE id = payout_uuid;
  
  IF payout_record IS NULL OR payout_record.status != 'pending' THEN
    RETURN FALSE;
  END IF;
  
  -- Update payout status
  UPDATE affiliate_payouts
  SET 
    status = 'completed',
    transaction_id = transaction_ref,
    processed_by = processed_by_user,
    processed_at = NOW(),
    completed_at = NOW()
  WHERE id = payout_uuid;
  
  -- Mark commissions as paid
  UPDATE affiliate_commissions
  SET 
    status = 'paid',
    payout_id = payout_uuid,
    paid_at = NOW()
  WHERE affiliate_id = payout_record.affiliate_id
    AND status = 'confirmed'
    AND payout_id IS NULL;
  
  -- Mark bonuses as paid
  UPDATE affiliate_bonuses
  SET 
    status = 'paid',
    payout_id = payout_uuid,
    paid_at = NOW()
  WHERE affiliate_id = payout_record.affiliate_id
    AND status = 'pending'
    AND payout_id IS NULL;
  
  -- Update affiliate totals
  UPDATE affiliates
  SET 
    total_paid_usd = total_paid_usd + payout_record.total_amount_usd,
    total_pending_usd = total_pending_usd - payout_record.total_amount_usd
  WHERE id = payout_record.affiliate_id;
  
  -- Log activity
  INSERT INTO affiliate_activity_log (affiliate_id, activity_type, description, related_payout_id, triggered_by, is_system_action)
  VALUES (
    payout_record.affiliate_id,
    'payout_completed',
    'Payout of $' || payout_record.total_amount_usd || ' completed. Transaction: ' || transaction_ref,
    payout_uuid,
    processed_by_user,
    FALSE
  );
  
  RETURN TRUE;
END;
$_$;


ALTER FUNCTION "public"."process_payout"("payout_uuid" "uuid", "transaction_ref" "text", "processed_by_user" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_pending_verifications"() RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  ref_record RECORD;
  processed INTEGER := 0;
BEGIN
  FOR ref_record IN 
    SELECT *
    FROM affiliate_referrals
    WHERE status = 'verification_pending'
      AND verification_end IS NOT NULL
      AND verification_end <= NOW()
  LOOP
    IF ref_record.subscription_cancelled_at IS NULL THEN
      -- Verification passed
      UPDATE affiliate_referrals
      SET 
        status = 'qualified',
        qualified_at = NOW(),
        commission_eligible = TRUE,
        commission_start_date = NOW(),
        commission_end_date = NOW() + INTERVAL '12 months'
      WHERE id = ref_record.id;
      
      INSERT INTO affiliate_activity_log (
        affiliate_id, 
        activity_type, 
        description, 
        related_referral_id,
        is_system_action
      )
      VALUES (
        ref_record.affiliate_id,
        'referral_qualified',
        'Referral qualified after 7-day verification period. Commission eligible.',
        ref_record.id,
        TRUE
      );
      
      processed := processed + 1;
    ELSE
      -- Verification failed
      UPDATE affiliate_referrals
      SET 
        status = 'verification_failed',
        notes = COALESCE(notes, '') || ' Refund/cancellation during 7-day verification period.'
      WHERE id = ref_record.id;
      
      INSERT INTO affiliate_activity_log (
        affiliate_id, 
        activity_type, 
        description, 
        related_referral_id,
        is_system_action
      )
      VALUES (
        ref_record.affiliate_id,
        'verification_failed',
        'Verification failed - refund or cancellation during 7-day period.',
        ref_record.id,
        TRUE
      );
    END IF;
  END LOOP;
  
  RETURN processed;
END;
$$;


ALTER FUNCTION "public"."process_pending_verifications"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_subscription_upgrade"("p_user_id" "uuid", "p_new_plan" "text", "p_new_interval" "text", "p_payplus_transaction_id" "text", "p_amount_paid" numeric) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_proration_calc JSONB;
  v_old_profile RECORD;
  v_new_expires_at TIMESTAMPTZ;
  v_result JSONB;
BEGIN
  IF p_new_plan NOT IN ('basic', 'premium') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid plan');
  END IF;
  
  IF p_new_interval NOT IN ('monthly', 'yearly') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid interval');
  END IF;
  
  SELECT * INTO v_old_profile
  FROM public.profiles
  WHERE id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  v_proration_calc := public.calculate_prorated_upgrade(p_user_id, p_new_plan, p_new_interval);
  
  IF v_proration_calc->>'error' IS NOT NULL THEN
    RETURN jsonb_build_object('success', false, 'error', v_proration_calc->>'error');
  END IF;
  
  v_new_expires_at := CASE p_new_interval
    WHEN 'monthly' THEN NOW() + INTERVAL '1 month'
    WHEN 'yearly' THEN NOW() + INTERVAL '1 year'
  END;
  
  UPDATE public.profiles
  SET 
    previous_account_type = v_old_profile.account_type,
    account_type = p_new_plan,
    subscription_interval = p_new_interval,
    subscription_status = 'active',
    payment_provider = 'payplus',
    subscription_started_at = NOW(),
    subscription_expires_at = v_new_expires_at,
    max_trades = public.get_trade_limit(p_new_plan),
    billing_cycle_start = CURRENT_DATE,
    current_month_trades_count = 0,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  INSERT INTO public.payment_history (
    user_id, amount, currency, status, plan, payplus_transaction_id, created_at
  ) VALUES (
    p_user_id, p_amount_paid, 'USD', 'completed', p_new_plan, p_payplus_transaction_id, NOW()
  );
  
  v_result := jsonb_build_object(
    'success', true,
    'message', format('Upgraded to %s (%s) successfully!', p_new_plan, p_new_interval),
    'data', jsonb_build_object(
      'new_plan', p_new_plan,
      'new_interval', p_new_interval,
      'expires_at', v_new_expires_at,
      'amount_paid', p_amount_paid
    )
  );
  
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."process_subscription_upgrade"("p_user_id" "uuid", "p_new_plan" "text", "p_new_interval" "text", "p_payplus_transaction_id" "text", "p_amount_paid" numeric) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."process_subscription_upgrade"("p_user_id" "uuid", "p_new_plan" "text", "p_new_interval" "text", "p_payplus_transaction_id" "text", "p_amount_paid" numeric) IS 'v8.5.9: SMART UPGRADE: Handles mid-cycle upgrades with automatic proration calculation';



CREATE OR REPLACE FUNCTION "public"."process_subscription_webhook"("p_user_id" "uuid", "p_account_type" "text", "p_payment_provider" "text", "p_subscription_id" "text" DEFAULT NULL::"text", "p_period_end" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_max_trades INTEGER;
BEGIN
  -- Calculate max_trades based on account type
  v_max_trades := CASE p_account_type
    WHEN 'free' THEN 10
    WHEN 'basic' THEN 25
    WHEN 'premium' THEN 999999
    WHEN 'trial' THEN 25
    ELSE 10
  END;
  
  -- Update profile
  UPDATE public.profiles
  SET 
    account_type = p_account_type,
    payment_provider = p_payment_provider,
    subscription_id = COALESCE(p_subscription_id, subscription_id),
    subscription_end_date = COALESCE(p_period_end, subscription_end_date),
    max_trades = v_max_trades,
    -- Reset monthly count on upgrade
    current_month_trades_count = CASE 
      WHEN p_account_type != 'free' THEN 0 
      ELSE current_month_trades_count 
    END,
    billing_cycle_start = CASE
      WHEN p_account_type != 'free' THEN CURRENT_DATE
      ELSE billing_cycle_start
    END,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."process_subscription_webhook"("p_user_id" "uuid", "p_account_type" "text", "p_payment_provider" "text", "p_subscription_id" "text", "p_period_end" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."process_subscription_webhook"("p_user_id" "uuid", "p_account_type" "text", "p_payment_provider" "text", "p_subscription_id" "text", "p_period_end" timestamp with time zone) IS 'v8.5.9: Webhook handler for subscription changes (service_role only)';



