CREATE OR REPLACE FUNCTION "public"."reconcile_affiliate_stats"() RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  aff_record RECORD;
  v_clicks INTEGER;
  v_signups INTEGER;
  v_qualified INTEGER;
  v_active INTEGER;
  v_pending NUMERIC;
  v_paid NUMERIC;
  v_bonuses NUMERIC;
  v_sub_earnings NUMERIC;
  reconciled INTEGER := 0;
BEGIN
  FOR aff_record IN SELECT id FROM affiliates
  LOOP
    -- Count clicks
    SELECT COUNT(*) INTO v_clicks FROM affiliate_clicks WHERE affiliate_id = aff_record.id;
    
    -- Count signups
    SELECT COUNT(*) INTO v_signups FROM affiliate_referrals WHERE affiliate_id = aff_record.id;
    
    -- Count qualified referrals
    SELECT COUNT(*) INTO v_qualified 
    FROM affiliate_referrals 
    WHERE affiliate_id = aff_record.id AND status = 'qualified';
    
    -- Count active customers
    SELECT COUNT(*) INTO v_active 
    FROM affiliate_referrals 
    WHERE affiliate_id = aff_record.id 
      AND status = 'qualified' 
      AND subscription_cancelled_at IS NULL;
    
    -- Sum pending commissions
    SELECT COALESCE(SUM(commission_amount_usd), 0) INTO v_pending
    FROM affiliate_commissions 
    WHERE affiliate_id = aff_record.id AND status IN ('pending', 'confirmed');
    
    -- Sum paid commissions
    SELECT COALESCE(SUM(commission_amount_usd), 0) INTO v_paid
    FROM affiliate_commissions 
    WHERE affiliate_id = aff_record.id AND status = 'paid';
    
    -- Sum bonuses
    SELECT COALESCE(SUM(bonus_amount_usd), 0) INTO v_bonuses
    FROM affiliate_bonuses 
    WHERE affiliate_id = aff_record.id AND status = 'paid';
    
    -- Sum sub-affiliate earnings
    SELECT COALESCE(SUM(commission_amount_usd), 0) INTO v_sub_earnings
    FROM affiliate_commissions 
    WHERE affiliate_id = aff_record.id AND commission_type = 'sub_affiliate';
    
    -- Update affiliate stats
    UPDATE affiliates SET
      total_clicks = v_clicks,
      total_signups = v_signups,
      total_qualified_referrals = v_qualified,
      total_active_customers = v_active,
      total_pending_usd = v_pending,
      total_paid_usd = v_paid,
      total_bonuses_usd = v_bonuses,
      total_sub_affiliate_earnings_usd = v_sub_earnings,
      total_earnings_usd = v_pending + v_paid
    WHERE id = aff_record.id;
    
    reconciled := reconciled + 1;
  END LOOP;
  
  RETURN reconciled;
END;
$$;


ALTER FUNCTION "public"."reconcile_affiliate_stats"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_affiliate_click"("p_affiliate_code" "text", "p_ip_address" "inet" DEFAULT NULL::"inet", "p_user_agent" "text" DEFAULT NULL::"text", "p_referrer_url" "text" DEFAULT NULL::"text", "p_landing_page" "text" DEFAULT NULL::"text", "p_utm_source" "text" DEFAULT NULL::"text", "p_utm_medium" "text" DEFAULT NULL::"text", "p_utm_campaign" "text" DEFAULT NULL::"text", "p_utm_content" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  aff_id UUID;
  new_click_id UUID;
  v_ip_hash VARCHAR(64);
BEGIN
  -- Get affiliate ID
  SELECT id INTO aff_id 
  FROM affiliates 
  WHERE (affiliate_code = UPPER(p_affiliate_code) OR coupon_code = UPPER(p_affiliate_code))
    AND status = 'active';
  
  IF aff_id IS NULL THEN
    RETURN NULL;
  END IF;
  
  -- Create IP hash for privacy
  IF p_ip_address IS NOT NULL THEN
    v_ip_hash := encode(sha256(p_ip_address::TEXT::bytea), 'hex');
  END IF;
  
  -- Insert click record
  INSERT INTO affiliate_clicks (
    affiliate_id,
    ip_hash,
    ip_address,
    user_agent,
    referrer_url,
    landing_page,
    utm_source,
    utm_medium,
    utm_campaign,
    utm_content
  ) VALUES (
    aff_id,
    v_ip_hash,
    p_ip_address,
    p_user_agent,
    p_referrer_url,
    p_landing_page,
    p_utm_source,
    p_utm_medium,
    p_utm_campaign,
    p_utm_content
  )
  RETURNING id INTO new_click_id;
  
  -- Increment clicks counter atomically
  PERFORM increment_affiliate_clicks(aff_id);
  
  RETURN new_click_id;
END;
$$;


ALTER FUNCTION "public"."record_affiliate_click"("p_affiliate_code" "text", "p_ip_address" "inet", "p_user_agent" "text", "p_referrer_url" "text", "p_landing_page" "text", "p_utm_source" "text", "p_utm_medium" "text", "p_utm_campaign" "text", "p_utm_content" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_affiliate_click"("p_affiliate_code" "text", "p_ip_hash" "text" DEFAULT NULL::"text", "p_user_agent" "text" DEFAULT NULL::"text", "p_referrer_url" "text" DEFAULT NULL::"text", "p_landing_page" "text" DEFAULT NULL::"text", "p_utm_source" "text" DEFAULT NULL::"text", "p_utm_medium" "text" DEFAULT NULL::"text", "p_utm_campaign" "text" DEFAULT NULL::"text", "p_utm_content" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_affiliate_id UUID;
  v_click_id UUID;
BEGIN
  -- Find affiliate
  SELECT id INTO v_affiliate_id
  FROM affiliates
  WHERE (UPPER(affiliate_code) = UPPER(p_affiliate_code) OR UPPER(coupon_code) = UPPER(p_affiliate_code))
    AND status = 'active';
  
  IF v_affiliate_id IS NULL THEN
    RETURN NULL;
  END IF;
  
  -- Insert click
  INSERT INTO affiliate_clicks (
    affiliate_id, ip_hash, user_agent, referrer_url, landing_page,
    utm_source, utm_medium, utm_campaign, utm_content
  ) VALUES (
    v_affiliate_id, p_ip_hash, p_user_agent, p_referrer_url, p_landing_page,
    p_utm_source, p_utm_medium, p_utm_campaign, p_utm_content
  )
  RETURNING id INTO v_click_id;
  
  -- Update affiliate stats
  UPDATE affiliates SET 
    total_clicks = COALESCE(total_clicks, 0) + 1,
    last_activity_at = NOW()
  WHERE id = v_affiliate_id;
  
  RETURN v_click_id;
END;
$$;


