CREATE OR REPLACE FUNCTION "public"."record_referral_first_payment"("p_referral_id" "uuid", "p_payment_amount" numeric, "p_subscription_plan" "text" DEFAULT NULL::"text", "p_subscription_type" "text" DEFAULT 'monthly'::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $_$
DECLARE
  ref_record RECORD;
BEGIN
  SELECT * INTO ref_record FROM affiliate_referrals WHERE id = p_referral_id;
  
  IF ref_record IS NULL THEN
    RAISE EXCEPTION 'Referral not found';
  END IF;
  
  IF ref_record.status != 'pending' THEN
    RAISE EXCEPTION 'Referral is not in pending status. Current status: %', ref_record.status;
  END IF;
  
  -- Start 7-day verification period
  UPDATE affiliate_referrals
  SET 
    status = 'verification_pending',
    first_payment_amount_usd = p_payment_amount,
    first_payment_date = NOW(),
    verification_start = NOW(),
    verification_end = NOW() + INTERVAL '21 days',
    subscription_plan = COALESCE(p_subscription_plan, subscription_plan),
    subscription_type = COALESCE(p_subscription_type, subscription_type),
    subscription_price_usd = p_payment_amount,
    subscription_started_at = NOW()
  WHERE id = p_referral_id;
  
  -- Log activity
  INSERT INTO affiliate_activity_log (
    affiliate_id, 
    activity_type, 
    description, 
    related_referral_id,
    metadata,
    is_system_action
  )
  VALUES (
    ref_record.affiliate_id,
 'first_payment_received',
    'First payment of $' || p_payment_amount || ' received. 21-day verification period started (14 trial + 7 post-payment).',
    p_referral_id,
    jsonb_build_object(
'payment_amount', p_payment_amount,
      'subscription_plan', p_subscription_plan,
      'subscription_type', p_subscription_type,
      'verification_ends', NOW() + INTERVAL '21 days'
    ),
    TRUE
  );
  
  -- Record coupon usage if applicable
  IF ref_record.coupon_id_used IS NOT NULL THEN
    INSERT INTO coupon_usage_log (coupon_id, user_id, plan_purchased, amount_paid_usd, discount_applied_usd)
    VALUES (ref_record.coupon_id_used, ref_record.referred_user_id, p_subscription_plan, p_payment_amount, ref_record.discount_amount_usd)
    ON CONFLICT (coupon_id, user_id) DO NOTHING;
    
    -- Increment coupon usage
    PERFORM increment_admin_coupon_usage(ref_record.coupon_id_used);
  END IF;
  
  RETURN TRUE;
END;
$_$;


ALTER FUNCTION "public"."record_referral_first_payment"("p_referral_id" "uuid", "p_payment_amount" numeric, "p_subscription_plan" "text", "p_subscription_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."refresh_all_materialized_views"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_refreshed INTEGER := 0;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized - Admin access required';
  END IF;
  
  -- Refresh each view with error handling
  BEGIN
    REFRESH MATERIALIZED VIEW CONCURRENTLY public.webhook_stats;
    v_refreshed := v_refreshed + 1;
  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'Failed to refresh webhook_stats: %', SQLERRM;
  END;
  
  BEGIN
    REFRESH MATERIALIZED VIEW CONCURRENTLY public.strategy_stats_view;
    v_refreshed := v_refreshed + 1;
  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'Failed to refresh strategy_stats_view: %', SQLERRM;
  END;
  
  RETURN format('Refreshed %s materialized views at %s', v_refreshed, NOW()::TEXT);
END;
$$;


