CREATE OR REPLACE FUNCTION "public"."remove_platform_bundle"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_journal_was_granted BOOLEAN;
  v_newsletter_was_granted BOOLEAN;
  v_has_paid_journal BOOLEAN;
  v_has_paid_newsletter BOOLEAN;
BEGIN
  SELECT 
    platform_bundle_journal_granted,
    platform_bundle_newsletter_granted,
    (whop_membership_id IS NOT NULL AND NOT platform_bundle_journal_granted),
    (newsletter_whop_membership_id IS NOT NULL AND NOT platform_bundle_newsletter_granted)
  INTO v_journal_was_granted, v_newsletter_was_granted, v_has_paid_journal, v_has_paid_newsletter
  FROM profiles WHERE id = p_user_id;
  
  IF v_journal_was_granted AND NOT v_has_paid_journal THEN
    UPDATE profiles SET
      account_type = 'NULL',
      subscription_status = 'expired',
      max_trades = 0,
      platform_bundle_journal_granted = FALSE,
      updated_at = NOW()
    WHERE id = p_user_id;
    
    INSERT INTO platform_subscription_events (user_id, event_type, metadata)
    VALUES (p_user_id, 'bundle_removed', jsonb_build_object('benefit_type', 'journal'));
  END IF;
  
  IF v_newsletter_was_granted AND NOT v_has_paid_newsletter THEN
    UPDATE profiles SET
      newsletter_paid = FALSE,
      newsletter_status = 'inactive',
      platform_bundle_newsletter_granted = FALSE,
      updated_at = NOW()
    WHERE id = p_user_id;
  END IF;
  
  UPDATE profiles SET platform_bundle_newsletter_choice = NULL WHERE id = p_user_id;
  
  RETURN jsonb_build_object(
    'success', true,
    'journal_removed', v_journal_was_granted AND NOT v_has_paid_journal,
    'newsletter_removed', v_newsletter_was_granted AND NOT v_has_paid_newsletter
  );
END;
$$;


ALTER FUNCTION "public"."remove_platform_bundle"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rename_admin_coupon"("p_coupon_id" "uuid", "p_new_code" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_clean_code TEXT;
BEGIN
  -- Check admin permission
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Only admins can rename coupons';
  END IF;
  
  v_clean_code := UPPER(REGEXP_REPLACE(p_new_code, '[^A-Z0-9]', '', 'g'));
  
  -- Check if code exists in affiliates
  IF EXISTS (SELECT 1 FROM affiliates WHERE affiliate_code = v_clean_code OR coupon_code = v_clean_code) THEN
    RAISE EXCEPTION 'Code already exists as affiliate code';
  END IF;
  
  -- Check if code exists in other admin coupons
  IF EXISTS (SELECT 1 FROM admin_coupons WHERE code = v_clean_code AND id != p_coupon_id) THEN
    RAISE EXCEPTION 'Code already exists as admin coupon';
  END IF;
  
  UPDATE admin_coupons
  SET 
    code = v_clean_code,
    updated_by = auth.uid(),
    updated_at = NOW()
  WHERE id = p_coupon_id;
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."rename_admin_coupon"("p_coupon_id" "uuid", "p_new_code" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."renew_subscription"("p_user_id" "uuid", "p_payplus_transaction_id" "text", "p_amount" numeric) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_profile RECORD;
  v_new_period_end TIMESTAMPTZ;
BEGIN
  SELECT * INTO v_profile
  FROM public.profiles
  WHERE id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  v_new_period_end := CASE v_profile.subscription_interval
    WHEN 'monthly' THEN v_profile.subscription_expires_at + INTERVAL '1 month'
    WHEN 'yearly' THEN v_profile.subscription_expires_at + INTERVAL '1 year'
    ELSE NOW() + INTERVAL '1 month'
  END;
  
  UPDATE public.profiles
  SET 
    subscription_expires_at = v_new_period_end,
    subscription_status = 'active',
    updated_at = NOW()
  WHERE id = p_user_id;
  
  INSERT INTO public.payment_history (
    user_id, amount, currency, status, plan, payplus_transaction_id, created_at
  ) VALUES (
    p_user_id, p_amount, 'USD', 'completed', v_profile.account_type, p_payplus_transaction_id, NOW()
  );
  
  RETURN jsonb_build_object(
    'success', true,
    'message', 'Subscription renewed successfully',
    'data', jsonb_build_object(
      'plan', v_profile.account_type,
      'interval', v_profile.subscription_interval,
      'new_period_end', v_new_period_end,
      'transaction_id', p_payplus_transaction_id
    )
  );
END;
$$;


ALTER FUNCTION "public"."renew_subscription"("p_user_id" "uuid", "p_payplus_transaction_id" "text", "p_amount" numeric) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."renew_subscription"("p_user_id" "uuid", "p_payplus_transaction_id" "text", "p_amount" numeric) IS 'v8.5.9: AUTO-RENEWAL: Handles automatic subscription renewals from PayPlus webhooks';



CREATE OR REPLACE FUNCTION "public"."reset_monthly_credits"() RETURNS TABLE("users_reset" integer, "pro_rollovers" integer, "daily_records_cleaned" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_users_reset INTEGER := 0;
  v_pro_rollovers INTEGER := 0;
  v_cleaned INTEGER := 0;
BEGIN
  -- PRO users: rollover up to 500 credits
  WITH pro_rollover AS (
    UPDATE profiles
    SET 
      credits_rollover = LEAST(500, COALESCE(credits_balance, 0) + COALESCE(credits_rollover, 0)),
      credits_balance = 1500,
      credits_reset_at = NOW()
    WHERE platform_plan = 'pro'
      AND credits_reset_at < DATE_TRUNC('month', NOW())
    RETURNING id
  )
  SELECT COUNT(*) INTO v_pro_rollovers FROM pro_rollover;

  -- CORE users
  WITH core_reset AS (
    UPDATE profiles
    SET 
      credits_balance = 600,
      credits_rollover = 0,
      credits_reset_at = NOW()
    WHERE platform_plan = 'core'
      AND credits_reset_at < DATE_TRUNC('month', NOW())
    RETURNING id
  )
  SELECT COUNT(*) INTO v_users_reset FROM core_reset;

  -- FREE users
  WITH free_reset AS (
    UPDATE profiles
    SET 
      credits_balance = 30,
      credits_rollover = 0,
      credits_reset_at = NOW()
    WHERE (platform_plan IS NULL OR platform_plan = 'free')
      AND credits_reset_at < DATE_TRUNC('month', NOW())
    RETURNING id
  )
  SELECT v_users_reset + COUNT(*) INTO v_users_reset FROM free_reset;

  -- Clean old daily usage records (keep 30 days)
  DELETE FROM ai_daily_usage WHERE usage_date < CURRENT_DATE - INTERVAL '30 days';
  GET DIAGNOSTICS v_cleaned = ROW_COUNT;

  RETURN QUERY SELECT v_users_reset + v_pro_rollovers, v_pro_rollovers, v_cleaned;
END;
$$;


ALTER FUNCTION "public"."reset_monthly_credits"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reset_monthly_trade_counts"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  reset_count INTEGER;
BEGIN
  WITH reset_users AS (
    UPDATE public.profiles
    SET 
      current_month_trades_count = 0,
      billing_cycle_start = CURRENT_DATE,
      updated_at = NOW()
    WHERE billing_cycle_start < CURRENT_DATE - INTERVAL '1 month'
      AND account_type IN ('basic', 'trial', 'premium')  -- ✅ Only reset paid plans
    RETURNING id
  )
  SELECT COUNT(*) INTO reset_count FROM reset_users;
  
  RETURN reset_count;
END;
$$;


