CREATE OR REPLACE FUNCTION "public"."resubscribe_newsletter"("p_user_id" "uuid") RETURNS TABLE("success" boolean, "message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_account_type TEXT;
  v_email TEXT;
BEGIN
  SELECT account_type, email INTO v_account_type, v_email
  FROM profiles WHERE id = p_user_id;

  IF v_account_type IS NULL THEN
    RETURN QUERY SELECT false, 'User not found'::TEXT;
    RETURN;
  END IF;

  IF v_account_type != 'premium' THEN
    RETURN QUERY SELECT false, 'Only premium users can subscribe'::TEXT;
    RETURN;
  END IF;

  UPDATE profiles
  SET newsletter_enabled = true, newsletter_unsubscribed_at = NULL
  WHERE id = p_user_id;

  INSERT INTO newsletter_unsubscribe_log (user_id, email, action)
  VALUES (p_user_id, v_email, 'resubscribe');

  RETURN QUERY SELECT true, 'Successfully resubscribed'::TEXT;
END;
$$;


