CREATE OR REPLACE FUNCTION "public"."revoke_beta_access"("p_admin_id" "uuid", "p_target_user_id" "uuid", "p_new_account_type" "text" DEFAULT 'basic'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_role TEXT;
BEGIN
  SELECT role INTO v_admin_role
  FROM profiles WHERE id = p_admin_id;
  
  IF v_admin_role NOT IN ('admin', 'super_admin') THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Only admins can revoke beta access'
    );
  END IF;
  
  UPDATE profiles
  SET 
    account_type = p_new_account_type,
    max_trades = CASE 
      WHEN p_new_account_type = 'basic' THEN 25
      WHEN p_new_account_type = 'premium' THEN 999999
      ELSE 25 
    END,
    updated_at = NOW()
  WHERE id = p_target_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'User not found'
    );
  END IF;
  
  RETURN jsonb_build_object(
    'success', true,
    'message', 'Beta access revoked',
    'user_id', p_target_user_id,
    'new_account_type', p_new_account_type
  );
END;
$$;


ALTER FUNCTION "public"."revoke_beta_access"("p_admin_id" "uuid", "p_target_user_id" "uuid", "p_new_account_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rls_check_admin"() RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_role TEXT;
  v_banned BOOLEAN;
BEGIN
  -- Direct query - SECURITY DEFINER means this runs as postgres user
  -- which bypasses RLS
  SELECT role, COALESCE(is_banned, false)
  INTO v_role, v_banned
  FROM public.profiles
  WHERE id = auth.uid();
  
  -- Not found = not admin
  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;
  
  -- Banned = not admin
  IF v_banned THEN
    RETURN FALSE;
  END IF;
  
  -- Check role
  RETURN v_role IN ('admin', 'super_admin');
END;
$$;


ALTER FUNCTION "public"."rls_check_admin"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."rls_check_admin"() IS 'v9.4.3: SECURITY DEFINER function that checks admin status. Bypasses RLS to prevent infinite recursion in policies.';



