CREATE OR REPLACE FUNCTION "public"."save_cancellation_feedback"("p_user_id" "uuid", "p_reason_id" "text", "p_reason_label" "text", "p_feedback_text" "text" DEFAULT NULL::"text", "p_plan_cancelled" "text" DEFAULT NULL::"text", "p_subscription_type" "text" DEFAULT NULL::"text", "p_whop_membership_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_email TEXT;
  v_plan TEXT;
  v_sub_type TEXT;
  v_membership_id TEXT;
  v_started_at TIMESTAMPTZ;
  v_duration_days INTEGER;
  v_feedback_id UUID;
BEGIN
  -- Get user info from profile
  SELECT 
    email,
    COALESCE(p_plan_cancelled, account_type),
    COALESCE(p_subscription_type, subscription_interval),
    COALESCE(p_whop_membership_id, whop_membership_id),
    subscription_started_at
  INTO v_email, v_plan, v_sub_type, v_membership_id, v_started_at
  FROM profiles
  WHERE id = p_user_id;
  
  IF v_email IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  -- Calculate subscription duration
  IF v_started_at IS NOT NULL THEN
    v_duration_days := EXTRACT(DAY FROM NOW() - v_started_at)::INTEGER;
  END IF;
  
  -- Insert feedback
  INSERT INTO subscription_cancellation_feedback (
    user_id,
    email,
    plan_cancelled,
    subscription_type,
    subscription_duration_days,
    reason_id,
    reason_label,
    feedback_text,
    whop_membership_id
  ) VALUES (
    p_user_id,
    v_email,
    COALESCE(v_plan, 'unknown'),
    v_sub_type,
    v_duration_days,
    p_reason_id,
    p_reason_label,
    NULLIF(TRIM(p_feedback_text), ''),
    v_membership_id
  )
  RETURNING id INTO v_feedback_id;
  
  RETURN jsonb_build_object(
    'success', true,
    'feedback_id', v_feedback_id,
    'message', 'Feedback saved successfully'
  );
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'sqlstate', SQLSTATE
  );
END;
$$;


ALTER FUNCTION "public"."save_cancellation_feedback"("p_user_id" "uuid", "p_reason_id" "text", "p_reason_label" "text", "p_feedback_text" "text", "p_plan_cancelled" "text", "p_subscription_type" "text", "p_whop_membership_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."schedule_company_reports_from_ism"("p_ism_report_month" "text", "p_count" integer DEFAULT 2) RETURNS TABLE("ticker" "text", "sector" "text", "scheduled" boolean)
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  RETURN QUERY
  WITH top_tickers AS (
    SELECT 
      ts.ticker,
      ts.sector_name as sector,
      ts.conviction
    FROM ism_ticker_selections ts
    WHERE ts.report_month = p_ism_report_month
      AND ts.selection_type = 'overweight'
    ORDER BY 
      CASE ts.conviction 
        WHEN 'high' THEN 1 
        WHEN 'medium' THEN 2 
        ELSE 3 
      END
    LIMIT p_count
  ),
  inserted AS (
    INSERT INTO ism_auto_company_reports (ticker, sector, ism_report_month, conviction, status)
    SELECT 
      tt.ticker,
      tt.sector,
      p_ism_report_month,
      tt.conviction,
      'pending'
    FROM top_tickers tt
    WHERE NOT EXISTS (
      SELECT 1 FROM ism_auto_company_reports iar
      WHERE iar.ticker = tt.ticker 
        AND iar.ism_report_month = p_ism_report_month
    )
    RETURNING ticker, sector
  )
  SELECT 
    tt.ticker::TEXT,
    tt.sector::TEXT,
    EXISTS (SELECT 1 FROM inserted i WHERE i.ticker = tt.ticker) as scheduled
  FROM top_tickers tt;
END;
$$;


ALTER FUNCTION "public"."schedule_company_reports_from_ism"("p_ism_report_month" "text", "p_count" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_embeddings"("query_embedding" "public"."vector", "match_count" integer DEFAULT 5, "filter_report_type" "text" DEFAULT NULL::"text", "filter_min_date" "date" DEFAULT NULL::"date") RETURNS TABLE("id" "uuid", "report_id" "text", "report_type" "text", "report_date" "date", "chunk_text" "text", "metadata" "jsonb", "similarity" double precision)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    e.id,
    e.report_id,
    e.report_type,
    e.report_date,
    e.chunk_text,
    e.metadata,
    (1 - (e.embedding <=> query_embedding))::FLOAT as similarity
  FROM report_embeddings e
  WHERE 
    (filter_report_type IS NULL OR e.report_type = filter_report_type)
    AND (filter_min_date IS NULL OR e.report_date >= filter_min_date)
  ORDER BY e.embedding <=> query_embedding
  LIMIT match_count;
END;
$$;


ALTER FUNCTION "public"."search_embeddings"("query_embedding" "public"."vector", "match_count" integer, "filter_report_type" "text", "filter_min_date" "date") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."search_embeddings"("query_embedding" "public"."vector", "match_count" integer, "filter_report_type" "text", "filter_min_date" "date") IS 'Simple search for similar report chunks using cosine similarity';



CREATE OR REPLACE FUNCTION "public"."search_report_embeddings"("query_embedding" "public"."vector", "match_count" integer DEFAULT 5, "filter_report_type" "text" DEFAULT NULL::"text", "filter_section" "text" DEFAULT NULL::"text", "filter_ticker" "text" DEFAULT NULL::"text", "filter_min_date" "date" DEFAULT NULL::"date", "similarity_threshold" double precision DEFAULT 0.7) RETURNS TABLE("id" "uuid", "report_id" "text", "report_type" "text", "report_date" "date", "chunk_index" integer, "chunk_text" "text", "metadata" "jsonb", "pdf_url" "text", "similarity" double precision)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    e.id,
    e.report_id,
    e.report_type,
    e.report_date,
    e.chunk_index,
    e.chunk_text,
    e.metadata,
    e.pdf_url,
    (1 - (e.embedding <=> query_embedding))::FLOAT as similarity
  FROM report_embeddings e
  WHERE 
    -- Type filter
    (filter_report_type IS NULL OR e.report_type = filter_report_type)
    -- Section filter (from metadata)
    AND (filter_section IS NULL OR e.metadata->>'section' = filter_section)
    -- Ticker filter (from metadata)
    AND (filter_ticker IS NULL OR e.metadata->>'ticker' = filter_ticker)
    -- Date filter
    AND (filter_min_date IS NULL OR e.report_date >= filter_min_date)
    -- Similarity threshold
    AND (1 - (e.embedding <=> query_embedding)) >= similarity_threshold
  ORDER BY e.embedding <=> query_embedding
  LIMIT match_count;
END;
$$;


ALTER FUNCTION "public"."search_report_embeddings"("query_embedding" "public"."vector", "match_count" integer, "filter_report_type" "text", "filter_section" "text", "filter_ticker" "text", "filter_min_date" "date", "similarity_threshold" double precision) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."search_report_embeddings"("query_embedding" "public"."vector", "match_count" integer, "filter_report_type" "text", "filter_section" "text", "filter_ticker" "text", "filter_min_date" "date", "similarity_threshold" double precision) IS 'Searches for similar report chunks using cosine similarity with advanced filters';



CREATE OR REPLACE FUNCTION "public"."search_ticker_symbols"("p_query" "text", "p_asset_class" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20) RETURNS TABLE("symbol" "text", "name" "text", "asset_class" "text", "exchange" "text", "multiplier" numeric, "popularity_rank" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    t.symbol,
    t.name,
    t.asset_class,
    t.exchange,
    t.multiplier,
    t.popularity_rank
  FROM public.ticker_symbols t
  WHERE 
    t.is_active = TRUE
    AND (p_asset_class IS NULL OR t.asset_class = p_asset_class)
    AND (
      t.symbol ILIKE p_query || '%'
      OR t.name ILIKE '%' || p_query || '%'
    )
  ORDER BY 
    t.popularity_rank ASC,
    CASE WHEN t.symbol ILIKE p_query THEN 0 ELSE 1 END,
    t.symbol
  LIMIT LEAST(p_limit, 100);
END;
$$;


ALTER FUNCTION "public"."search_ticker_symbols"("p_query" "text", "p_asset_class" "text", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."search_ticker_symbols"("p_query" "text", "p_asset_class" "text", "p_limit" integer) IS 'v9.4.2-SYNCED: Single version with 3 params (query, asset_class, limit)';



CREATE OR REPLACE FUNCTION "public"."search_tickers_by_asset_class"("p_asset_class" "text", "search_text" "text" DEFAULT NULL::"text", "limit_count" integer DEFAULT 20) RETURNS TABLE("symbol" "text", "name" "text", "asset_class" "text", "multiplier" numeric, "exchange" "text", "popularity_rank" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  p_asset_class := LOWER(TRIM(p_asset_class));
  search_text := UPPER(TRIM(COALESCE(search_text, '')));
  
  RETURN QUERY
  SELECT 
    t.symbol,
    t.name,
    t.asset_class,
    t.multiplier,
    t.exchange,
    t.popularity_rank
  FROM public.ticker_symbols t
  WHERE 
    t.is_active = TRUE
    AND t.asset_class = p_asset_class
    AND (
      search_text = '' 
      OR t.symbol LIKE search_text || '%'
      OR t.name ILIKE '%' || search_text || '%'
    )
  ORDER BY 
    t.popularity_rank ASC,
    t.symbol ASC
  LIMIT LEAST(limit_count, 100);
END;
$$;


