COMMENT ON FUNCTION "public"."search_tickers_by_asset_class"("p_asset_class" "text", "search_text" "text", "limit_count" integer) IS 'v8.5.9: Search tickers filtered by asset class';



CREATE OR REPLACE FUNCTION "public"."search_trades"("search_query" "text", "target_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "symbol" "text", "notes" "text", "setup" "text", "rank" real)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_is_admin BOOLEAN;
BEGIN
  v_user_id := COALESCE(target_user_id, auth.uid());
  
  SELECT role IN ('admin', 'super_admin') AND is_banned = FALSE
  INTO v_is_admin
  FROM public.profiles
  WHERE id = auth.uid();
  
  IF NOT COALESCE(v_is_admin, FALSE) AND v_user_id != auth.uid() THEN
    RAISE EXCEPTION 'Access denied: You can only search your own trades';
  END IF;
  
  IF COALESCE(v_is_admin, FALSE) AND v_user_id != auth.uid() THEN
    PERFORM set_config('app.admin_mode', 'true', true);
  END IF;
  
  RETURN QUERY
  SELECT 
    t.id,
    t.symbol,
    t.notes,
    t.setup,
    ts_rank(t.notes_search_vector, plainto_tsquery('english', search_query)) as rank
  FROM public.trades t
  WHERE 
    t.user_id = v_user_id
    AND t.notes_search_vector @@ plainto_tsquery('english', search_query)
  ORDER BY rank DESC
  LIMIT 50;
  
  IF COALESCE(v_is_admin, FALSE) THEN
    PERFORM set_config('app.admin_mode', 'false', true);
  END IF;
END;
$$;


ALTER FUNCTION "public"."search_trades"("search_query" "text", "target_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."search_trades"("search_query" "text", "target_user_id" "uuid") IS 'v8.5.9-SECURE: Search trades with mandatory user isolation. Admins can view others via admin_mode.';



CREATE OR REPLACE FUNCTION "public"."send_support_email_trigger"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  request_id bigint;
  payload jsonb;
  function_url text := 'https://xsgbtptkueabylkxibly.supabase.co/functions/v1/send-support-email';
  -- 🔑 REPLACE THIS WITH YOUR ACTUAL SERVICE_ROLE_KEY!
  -- Get it from: Supabase Dashboard → Project Settings → API → service_role (secret)
  service_key text := 'YOUR_SERVICE_ROLE_KEY_HERE';
BEGIN
  -- Build the payload based on operation type
  IF TG_OP = 'INSERT' THEN
    payload := jsonb_build_object(
      'type', 'INSERT',
      'table', 'support_tickets',
      'schema', 'public',
      'record', to_jsonb(NEW)
    );
    
    RAISE LOG 'Support email trigger: NEW ticket created (ID: %)', NEW.id;
    
  ELSIF TG_OP = 'UPDATE' THEN
    payload := jsonb_build_object(
      'type', 'UPDATE',
      'table', 'support_tickets',
      'schema', 'public',
      'record', to_jsonb(NEW),
      'old_record', to_jsonb(OLD)
    );
    
    RAISE LOG 'Support email trigger: Ticket UPDATED (ID: %)', NEW.id;
  END IF;

  -- Send HTTP POST request using pg_net
  SELECT INTO request_id net.http_post(
    url := function_url,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'Authorization', 'Bearer ' || service_key
    ),
    body := payload
  );

  RAISE LOG 'Email trigger request sent: request_id=%', request_id;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Log error but don't fail the transaction
  RAISE WARNING 'Failed to send email trigger: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."send_support_email_trigger"() OWNER TO "postgres";


