CREATE OR REPLACE FUNCTION "public"."set_global_sale"("p_sale_name" "text", "p_description" "text" DEFAULT NULL::"text", "p_monthly_price" numeric DEFAULT NULL::numeric, "p_yearly_price" numeric DEFAULT NULL::numeric, "p_lifetime_price" numeric DEFAULT NULL::numeric, "p_discount_percent" numeric DEFAULT NULL::numeric, "p_valid_from" timestamp with time zone DEFAULT "now"(), "p_valid_until" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_sale_id UUID;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Only admins can set global sales';
  END IF;
  
  -- Deactivate any existing active sales
  UPDATE admin_global_pricing SET is_active = FALSE WHERE is_active = TRUE;
  
  -- Create new sale
  INSERT INTO admin_global_pricing (
    sale_name,
    description,
    monthly_price_usd,
    yearly_price_usd,
    lifetime_price_usd,
    discount_percent,
    is_active,
    valid_from,
    valid_until,
    created_by
  ) VALUES (
    p_sale_name,
    p_description,
    p_monthly_price,
    p_yearly_price,
    p_lifetime_price,
    p_discount_percent,
    TRUE,
    p_valid_from,
    p_valid_until,
    auth.uid()
  )
  RETURNING id INTO v_sale_id;
  
  -- Update config to indicate sale is active
  UPDATE affiliate_config 
  SET config_value = '{"active": true}'::JSONB, updated_at = NOW()
  WHERE config_key = 'global_sale_active';
  
  RETURN v_sale_id;
END;
$$;


ALTER FUNCTION "public"."set_global_sale"("p_sale_name" "text", "p_description" "text", "p_monthly_price" numeric, "p_yearly_price" numeric, "p_lifetime_price" numeric, "p_discount_percent" numeric, "p_valid_from" timestamp with time zone, "p_valid_until" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."set_imported_at_timestamp"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    -- Only set imported_at for non-manual trades if not already set
    IF NEW.import_source != 'manual' AND NEW.imported_at IS NULL THEN
        NEW.imported_at = NOW();
    END IF;
    
    -- If import_source is 'snaptrade', ensure we have required fields
    IF NEW.import_source = 'snaptrade' AND NEW.snaptrade_activity_id IS NULL THEN
        RAISE EXCEPTION 'snaptrade_activity_id is required for import_source = snaptrade';
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."set_imported_at_timestamp"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."set_imported_at_timestamp"() IS 'v8.5.0: Auto-sets imported_at for non-manual trades and validates SnapTrade imports';



