CREATE OR REPLACE FUNCTION "public"."should_generate_daily_report"("check_date" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("should_generate" boolean, "reason" character varying, "next_trading_day" "date", "is_early_close" boolean, "early_close_time" character varying)
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  day_of_week INTEGER;
  holiday_rec RECORD;
BEGIN
  day_of_week := EXTRACT(DOW FROM check_date);
  
  IF day_of_week IN (0, 6) THEN
    RETURN QUERY SELECT 
      FALSE, 
      'Weekend'::VARCHAR, 
      get_next_trading_day(check_date),
      FALSE,
      NULL::VARCHAR;
    RETURN;
  END IF;
  
  SELECT * INTO holiday_rec 
  FROM us_market_holidays 
  WHERE date = check_date AND type = 'full_close';
  
  IF FOUND THEN
    RETURN QUERY SELECT 
      FALSE, 
      holiday_rec.name::VARCHAR, 
      get_next_trading_day(check_date),
      FALSE,
      NULL::VARCHAR;
    RETURN;
  END IF;
  
  SELECT * INTO holiday_rec 
  FROM us_market_holidays 
  WHERE date = check_date AND type = 'early_close';
  
  IF FOUND THEN
    RETURN QUERY SELECT 
      TRUE, 
      holiday_rec.name::VARCHAR, 
      NULL::DATE,
      TRUE,
      holiday_rec.close_time::VARCHAR;
    RETURN;
  END IF;
  
  RETURN QUERY SELECT 
    TRUE, 
    NULL::VARCHAR, 
    NULL::DATE,
    FALSE,
    NULL::VARCHAR;
END;
$$;


ALTER FUNCTION "public"."should_generate_daily_report"("check_date" "date") OWNER TO "postgres";


