CREATE OR REPLACE FUNCTION "public"."spend_credits"("p_user_id" "uuid", "p_action_name" "text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_profile RECORD;
  v_action RECORD;
  v_actual_cost INTEGER;
  v_multiplier NUMERIC := 1.0;
  v_was_soft_cap BOOLEAN := FALSE;
  v_daily_cap INTEGER;
  v_daily_usage INTEGER := 0;
  v_credits_before INTEGER;
  v_credits_after INTEGER;
  v_source TEXT := 'monthly';
BEGIN
  -- ========================================
  -- STEP 1: Get Action Config
  -- ========================================
  SELECT * INTO v_action
  FROM ai_actions_config
  WHERE action_name = p_action_name AND is_active = TRUE;
  
  IF v_action IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Unknown action: ' || p_action_name);
  END IF;

  -- ========================================
  -- STEP 2: Get User Profile
  -- ========================================
  SELECT 
    COALESCE(platform_plan, 'free') as platform_plan,
    COALESCE(credits_balance, 30) as credits_balance,
    COALESCE(credits_purchased, 0) as credits_purchased,
    COALESCE(credits_rollover, 0) as credits_rollover,
    COALESCE(role, 'user') as user_role
  INTO v_profile
  FROM profiles
  WHERE id = p_user_id;
  
  IF v_profile IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  -- ========================================
  -- STEP 2.5: ADMIN UNLIMITED ACCESS
  -- ========================================
  IF v_profile.user_role IN ('admin', 'super_admin', 'owner') THEN
    -- Log action but don't charge
    INSERT INTO ai_daily_usage (user_id, usage_date, action_name, usage_count, credits_spent)
    VALUES (p_user_id, CURRENT_DATE, p_action_name, 1, 0)
    ON CONFLICT (user_id, usage_date, action_name) DO UPDATE SET
      usage_count = ai_daily_usage.usage_count + 1,
      updated_at = NOW();
    
    RETURN jsonb_build_object(
      'success', true,
      'credits_spent', 0,
      'credits_remaining', 999999,
      'was_soft_cap', false,
      'multiplier', 1.0,
      'source', 'admin_unlimited',
      'action_type', v_action.action_type,
      'daily_usage', 0,
      'daily_cap', NULL,
      'is_admin', true
    );
  END IF;

  -- ========================================
  -- STEP 3: Check Plan Requirement
  -- ========================================
  IF v_action.plan_required IS NOT NULL THEN
    IF v_profile.platform_plan = 'free' THEN
      RETURN jsonb_build_object(
        'success', false,
        'error', 'This action requires ' || UPPER(v_action.plan_required) || ' plan',
        'requires_upgrade', true,
        'plan_required', v_action.plan_required
      );
    END IF;
    
    IF v_action.plan_required = 'pro' AND v_profile.platform_plan = 'core' THEN
      RETURN jsonb_build_object(
        'success', false,
        'error', 'This action requires PRO plan',
        'requires_upgrade', true,
        'plan_required', 'pro'
      );
    END IF;
  END IF;

  -- ========================================
  -- STEP 4: Get Daily Cap for User's Plan
  -- ========================================
  v_daily_cap := CASE v_profile.platform_plan
    WHEN 'pro' THEN v_action.daily_cap_pro
    WHEN 'core' THEN v_action.daily_cap_core
    ELSE v_action.daily_cap_free
  END;

  -- ========================================
  -- STEP 5: Check Daily Usage
  -- ========================================
  SELECT COALESCE(SUM(usage_count), 0) INTO v_daily_usage
  FROM ai_daily_usage
  WHERE user_id = p_user_id 
    AND usage_date = CURRENT_DATE
    AND action_name = p_action_name;

  -- Check if over daily cap (soft cap = x2 cost)
  IF v_daily_cap IS NOT NULL AND v_daily_usage >= v_daily_cap THEN
    IF v_action.action_type = 'heavy' THEN
      v_multiplier := 2.0;
      v_was_soft_cap := TRUE;
    ELSE
      -- For light/medium, just warn but allow
      v_was_soft_cap := TRUE;
    END IF;
  END IF;

  -- ========================================
  -- STEP 6: Calculate Cost
  -- ========================================
  v_actual_cost := CEIL(v_action.base_cost * v_multiplier)::INTEGER;
  
  -- Light actions are always free
  IF v_action.action_type = 'light' THEN
    v_actual_cost := 0;
  END IF;

  v_credits_before := v_profile.credits_balance + v_profile.credits_purchased + v_profile.credits_rollover;

  -- ========================================
  -- STEP 7: Check Balance (if cost > 0)
  -- ========================================
  IF v_actual_cost > 0 AND v_credits_before < v_actual_cost THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Insufficient credits',
      'credits_needed', v_actual_cost,
      'credits_available', v_credits_before,
      'can_purchase', true
    );
  END IF;

  -- ========================================
  -- STEP 8: Deduct Credits
  -- ========================================
  IF v_actual_cost > 0 THEN
    IF v_profile.credits_balance >= v_actual_cost THEN
      UPDATE profiles SET credits_balance = credits_balance - v_actual_cost WHERE id = p_user_id;
      v_source := 'monthly';
    ELSIF v_profile.credits_balance + v_profile.credits_rollover >= v_actual_cost THEN
      UPDATE profiles SET 
        credits_rollover = credits_rollover - (v_actual_cost - credits_balance),
        credits_balance = 0
      WHERE id = p_user_id;
      v_source := 'rollover';
    ELSE
      UPDATE profiles SET 
        credits_purchased = credits_purchased - (v_actual_cost - credits_balance - credits_rollover),
        credits_rollover = 0,
        credits_balance = 0
      WHERE id = p_user_id;
      v_source := 'purchased';
    END IF;
  END IF;

  v_credits_after := v_credits_before - v_actual_cost;

  -- ========================================
  -- STEP 9: Update Daily Usage
  -- ========================================
  INSERT INTO ai_daily_usage (user_id, usage_date, action_name, usage_count, credits_spent)
  VALUES (p_user_id, CURRENT_DATE, p_action_name, 1, v_actual_cost)
  ON CONFLICT (user_id, usage_date, action_name) DO UPDATE SET
    usage_count = ai_daily_usage.usage_count + 1,
    credits_spent = ai_daily_usage.credits_spent + v_actual_cost,
    updated_at = NOW();

  -- ========================================
  -- STEP 10: Log Transaction
  -- ========================================
  INSERT INTO credit_transactions (
    user_id, action_type, action_name, credits_spent,
    credits_before, credits_after, was_soft_cap_exceeded,
    multiplier, metadata
  ) VALUES (
    p_user_id, v_action.action_type, p_action_name, v_actual_cost,
    v_credits_before, v_credits_after, v_was_soft_cap,
    v_multiplier, p_metadata || jsonb_build_object(
      'source', v_source,
      'daily_usage', v_daily_usage + 1,
      'daily_cap', v_daily_cap,
      'category', v_action.category
    )
  );

  -- ========================================
  -- STEP 11: Return Result
  -- ========================================
  RETURN jsonb_build_object(
    'success', true,
    'credits_spent', v_actual_cost,
    'credits_remaining', v_credits_after,
    'was_soft_cap', v_was_soft_cap,
    'multiplier', v_multiplier,
    'source', v_source,
    'action_type', v_action.action_type,
    'daily_usage', v_daily_usage + 1,
    'daily_cap', v_daily_cap
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'sqlstate', SQLSTATE);
END;
$$;


ALTER FUNCTION "public"."spend_credits"("p_user_id" "uuid", "p_action_name" "text", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."start_impersonation_session_v1"("p_user_id" "uuid", "p_admin_email" "text") RETURNS TABLE("access_token" "text", "refresh_token" "text", "user_data" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_admin_id UUID;
  v_session_token TEXT;
  v_impersonated_user RECORD;
BEGIN
  -- Verify admin by email
  SELECT id INTO v_admin_id
  FROM public.profiles
  WHERE email = p_admin_email
    AND role IN ('admin', 'super_admin')
    AND is_banned = FALSE;
  
  IF v_admin_id IS NULL THEN
    RAISE EXCEPTION 'Unauthorized: Must be admin. Email % not found or not admin.', p_admin_email;
  END IF;
  
  -- Get target user info
  SELECT 
    p.id,
    p.email,
    p.display_name,
    p.role,
    p.account_type
  INTO v_impersonated_user
  FROM public.profiles p
  WHERE p.id = p_user_id;
  
  IF v_impersonated_user.id IS NULL THEN
    RAISE EXCEPTION 'User not found: %', p_user_id;
  END IF;
  
  -- Cannot impersonate other admins
  IF v_impersonated_user.role IN ('admin', 'super_admin') THEN
    RAISE EXCEPTION 'Cannot impersonate other admins';
  END IF;
  
  -- Generate secure session token
  v_session_token := encode(extensions.gen_random_bytes(32), 'hex');
  
  -- Create impersonation session record
  INSERT INTO public.admin_impersonation_sessions (
    admin_id,
    impersonated_user_id,
    session_token,
    expires_at,
    impersonated_user_email,
    impersonated_user_name,
    admin_email,
    is_active
  ) VALUES (
    v_admin_id,
    p_user_id,
    v_session_token,
    NOW() + INTERVAL '2 hours',
    v_impersonated_user.email,
    COALESCE(v_impersonated_user.display_name, v_impersonated_user.email),
    p_admin_email,
    TRUE
  );
  
  -- Log action with CORRECT admin_id
  BEGIN
    PERFORM public.log_admin_action(
      'START_IMPERSONATION',
      'impersonation_session',
      p_user_id,
      jsonb_build_object(
        'admin_id', v_admin_id,
        'impersonated_email', v_impersonated_user.email,
        'impersonated_name', v_impersonated_user.display_name,
        'session_token_prefix', LEFT(v_session_token, 8) || '...'
      )
    );
  EXCEPTION 
    WHEN undefined_function THEN
      RAISE WARNING 'log_admin_action function not found';
    WHEN OTHERS THEN
      RAISE WARNING 'Failed to log impersonation action: %', SQLERRM;
  END;
  
  -- Return session data for UI
  RETURN QUERY SELECT
    v_session_token::TEXT as access_token,
    v_session_token::TEXT as refresh_token,
    jsonb_build_object(
      'id', v_impersonated_user.id,
      'email', v_impersonated_user.email,
      'display_name', COALESCE(v_impersonated_user.display_name, v_impersonated_user.email),
      'role', v_impersonated_user.role,
      'account_type', v_impersonated_user.account_type,
      'impersonated', TRUE,
      'impersonated_by', p_admin_email,
      'session_expires_at', NOW() + INTERVAL '2 hours'
    ) as user_data;
END;
$$;


ALTER FUNCTION "public"."start_impersonation_session_v1"("p_user_id" "uuid", "p_admin_email" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."start_impersonation_session_v1"("p_user_id" "uuid", "p_admin_email" "text") IS 'v8.5.10: Allows admins to impersonate users. Admin_id correctly logged.';



CREATE OR REPLACE FUNCTION "public"."start_ism_generation"("p_month" "text", "p_admin_id" "text" DEFAULT NULL::"text", "p_is_override" boolean DEFAULT false, "p_override_reason" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_current_status TEXT;
BEGIN
  SELECT status INTO v_current_status
  FROM ism_report_tracking
  WHERE report_month = p_month;
  
  IF v_current_status = 'generating' THEN
    RETURN false;
  END IF;
  
  IF v_current_status = 'report_generated' AND NOT p_is_override THEN
    RETURN false;
  END IF;
  
  INSERT INTO ism_report_tracking (
    report_month, 
    status, 
    generation_started_at,
    is_admin_override,
    admin_id,
    override_reason,
    ism_data_available
  )
  VALUES (
    p_month,
    'generating',
    NOW(),
    p_is_override,
    p_admin_id,
    p_override_reason,
    true
  )
  ON CONFLICT (report_month) DO UPDATE SET
    status = 'generating',
    generation_started_at = NOW(),
    is_admin_override = COALESCE(p_is_override, ism_report_tracking.is_admin_override),
    admin_id = COALESCE(p_admin_id, ism_report_tracking.admin_id),
    override_reason = COALESCE(p_override_reason, ism_report_tracking.override_reason),
    error_message = NULL,
    updated_at = NOW();
  
  RETURN true;
END;
$$;


ALTER FUNCTION "public"."start_ism_generation"("p_month" "text", "p_admin_id" "text", "p_is_override" boolean, "p_override_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."start_top_secret_trial"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_profile RECORD;
  v_trial_end TIMESTAMPTZ;
BEGIN
  SELECT top_secret_trial_used, top_secret_is_in_trial, top_secret_enabled
  INTO v_profile FROM profiles WHERE id = p_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  IF v_profile.top_secret_trial_used THEN
    RETURN jsonb_build_object('success', false, 'error', 'Trial already used');
  END IF;

  IF v_profile.top_secret_enabled THEN
    RETURN jsonb_build_object('success', false, 'error', 'Already subscribed to Top Secret');
  END IF;

  v_trial_end := NOW() + INTERVAL '14 days';

  UPDATE profiles SET
    top_secret_is_in_trial = TRUE,
    top_secret_trial_used = TRUE,
    top_secret_trial_start_date = NOW(),
    top_secret_trial_ends_at = v_trial_end,
    top_secret_enabled = TRUE,
    top_secret_status = 'active',
    top_secret_started_at = NOW(),
    top_secret_expires_at = v_trial_end,
    journal_discount_available = TRUE,
    journal_discount_source = 'top_secret',
    updated_at = NOW()
  WHERE id = p_user_id;

  INSERT INTO subscription_events (user_id, event_type, new_plan, metadata)
  VALUES (p_user_id, 'trial_started', 'top_secret',
    jsonb_build_object('trial_days', 14, 'trial_ends_at', v_trial_end, 'source', 'post_signup'));

  RETURN jsonb_build_object('success', true, 'trial_ends_at', v_trial_end, 'journal_discount_enabled', true);
END;
$$;


ALTER FUNCTION "public"."start_top_secret_trial"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."start_trial"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_trial_used BOOLEAN;
BEGIN
  -- Check if user already used trial
  SELECT trial_used INTO v_trial_used
  FROM public.profiles
  WHERE id = p_user_id;
  
  IF v_trial_used = TRUE THEN
    RETURN jsonb_build_object(
      'success', FALSE,
      'error', 'Trial already used. Each user gets one trial only.',
      'code', 'TRIAL_ALREADY_USED'
    );
  END IF;
  
  -- Start trial
  UPDATE public.profiles
  SET 
    account_type = 'basic',
    subscription_status = 'trial',
    is_in_trial = TRUE,
    trial_ends_at = NOW() + INTERVAL '14 days',
    trial_used = TRUE,  -- Mark as used immediately!
    max_trades = 25,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  RETURN jsonb_build_object(
    'success', TRUE,
    'message', 'Trial started successfully',
    'trial_ends_at', NOW() + INTERVAL '14 days',
    'max_trades', 25
  );
END;
$$;


ALTER FUNCTION "public"."start_trial"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."start_trial"("p_user_id" "uuid") IS 'Starts 14-day trial for user. Prevents abuse - each user gets ONE trial only.';



CREATE OR REPLACE FUNCTION "public"."start_trial"("p_user_id" "uuid", "p_trial_days" integer DEFAULT 7) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_profile RECORD;
BEGIN
  SELECT account_type, trial_used INTO v_profile
  FROM public.profiles
  WHERE id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;
  
  -- Check if trial already used
  IF COALESCE(v_profile.trial_used, FALSE) THEN
    RAISE EXCEPTION 'Trial already used';
  END IF;
  
  -- Only free users can start trial
  IF v_profile.account_type != 'free' THEN
    RAISE EXCEPTION 'Only free users can start trial';
  END IF;
  
  UPDATE public.profiles
  SET 
    account_type = 'trial',
    trial_used = TRUE,
    trial_start_date = NOW(),
    subscription_end_date = NOW() + (p_trial_days || ' days')::INTERVAL,
    max_trades = 25,
    current_month_trades_count = 0,
    billing_cycle_start = CURRENT_DATE,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."start_trial"("p_user_id" "uuid", "p_trial_days" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."start_trial"("p_user_id" "uuid", "p_trial_days" integer) IS 'v8.5.9: Starts trial period (default 7 days, can only use once)';



CREATE OR REPLACE FUNCTION "public"."suspend_affiliate"("p_affiliate_id" "uuid", "p_suspended_by" "uuid", "p_reason" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  UPDATE affiliates
  SET 
    status = 'suspended',
    suspended_at = NOW(),
    suspension_reason = p_reason
  WHERE id = p_affiliate_id
    AND status = 'active';
  
  IF FOUND THEN
    INSERT INTO affiliate_activity_log (affiliate_id, activity_type, description, triggered_by, is_system_action)
    VALUES (p_affiliate_id, 'affiliate_suspended', 'Affiliate suspended. Reason: ' || p_reason, p_suspended_by, FALSE);
  END IF;
  
  RETURN FOUND;
END;
$$;


