CREATE OR REPLACE FUNCTION "public"."sync_published_reports_content"() RETURNS TABLE("report_type" "text", "synced_count" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_ism_count INTEGER := 0;
    v_company_count INTEGER := 0;
    v_crypto_count INTEGER := 0;
BEGIN
    -- Sync ISM
    UPDATE published_reports pr
    SET 
        markdown_content = ir.markdown_content,
        html_content = ir.html_content,
        updated_at = NOW()
    FROM ism_reports ir
    WHERE pr.original_report_id = ir.id
    AND pr.report_type = 'ism'
    AND ir.markdown_content IS NOT NULL
    AND (pr.markdown_content IS NULL OR pr.markdown_content = '');
    GET DIAGNOSTICS v_ism_count = ROW_COUNT;
    
    -- Sync Company
    UPDATE published_reports pr
    SET 
        markdown_content = cr.markdown_content,
        html_content = cr.html_content,
        updated_at = NOW()
    FROM company_reports cr
    WHERE pr.original_report_id = cr.id
    AND pr.report_type = 'company'
    AND cr.markdown_content IS NOT NULL
    AND (pr.markdown_content IS NULL OR pr.markdown_content = '');
    GET DIAGNOSTICS v_company_count = ROW_COUNT;
    
    -- Sync Crypto
    UPDATE published_reports pr
    SET 
        markdown_content = cr.markdown_content,
        html_content = cr.html_content,
        updated_at = NOW()
    FROM crypto_reports cr
    WHERE pr.original_report_id = cr.id::TEXT
    AND pr.report_type = 'crypto'
    AND cr.markdown_content IS NOT NULL
    AND (pr.markdown_content IS NULL OR pr.markdown_content = '');
    GET DIAGNOSTICS v_crypto_count = ROW_COUNT;
    
    RETURN QUERY VALUES 
        ('ism'::TEXT, v_ism_count),
        ('company'::TEXT, v_company_count),
        ('crypto'::TEXT, v_crypto_count);
END;
$$;


