CREATE OR REPLACE FUNCTION "public"."sync_tier_from_account_type"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  NEW.tier := COALESCE(
    CASE 
      WHEN NEW.account_type IS NULL THEN 'free'
      WHEN NEW.account_type = '' THEN 'free'
      ELSE LOWER(NEW.account_type)
    END,
    'free'
  );
  RETURN NEW;
END;
$$;


