CREATE OR REPLACE FUNCTION "public"."sync_trade_count_for_user"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_monthly_count INTEGER;
  v_total_count INTEGER;
  v_billing_start DATE;
BEGIN
  -- Get billing start
  SELECT COALESCE(billing_cycle_start, DATE_TRUNC('month', NOW())::DATE)
  INTO v_billing_start
  FROM public.profiles WHERE id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'User not found');
  END IF;
  
  -- Count actual non-deleted trades this month (by creation date)
  SELECT COUNT(*)::INTEGER INTO v_monthly_count
  FROM public.trades
  WHERE user_id = p_user_id
    AND deleted_at IS NULL
    AND created_at >= GREATEST(v_billing_start, DATE_TRUNC('month', NOW())::DATE);
  
  -- Count all non-deleted trades lifetime
  SELECT COUNT(*)::INTEGER INTO v_total_count
  FROM public.trades
  WHERE user_id = p_user_id AND deleted_at IS NULL;
  
  -- 🔥 IMMUTABLE: Use GREATEST - count can only go up, never down
  UPDATE public.profiles
  SET 
    current_month_trades_count = GREATEST(COALESCE(current_month_trades_count, 0), v_monthly_count),
    trade_count = GREATEST(COALESCE(trade_count, 0), v_total_count),
    updated_at = NOW()
  WHERE id = p_user_id;
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', p_user_id,
    'monthly_synced_to', GREATEST(0, v_monthly_count),
    'total_synced_to', GREATEST(0, v_total_count)
  );
END;
$$;


ALTER FUNCTION "public"."sync_trade_count_for_user"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."sync_trade_count_for_user"("p_user_id" "uuid") IS 'v10.2.0: Syncs trade counters to actual DB count. IMMUTABLE - never decreases. Call when count seems wrong.';



