CREATE OR REPLACE FUNCTION "public"."toggle_newsletter_status"("p_user_id" "uuid", "p_enabled" boolean) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_email TEXT;
  v_current_status TEXT;
  v_caller_role TEXT;
BEGIN
  SELECT role INTO v_caller_role 
  FROM profiles 
  WHERE profiles.id = auth.uid();

  IF v_caller_role IS NULL OR v_caller_role NOT IN ('admin', 'super_admin') THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  SELECT email, newsletter_status
  INTO v_email, v_current_status
  FROM profiles 
  WHERE id = p_user_id;
  
  IF v_email IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;
  
  UPDATE profiles 
  SET 
    newsletter_enabled = p_enabled,
    newsletter_status = CASE WHEN p_enabled THEN 'active' ELSE 'inactive' END,
    newsletter_started_at = CASE 
      WHEN p_enabled AND newsletter_started_at IS NULL THEN NOW()
      ELSE newsletter_started_at
    END,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  RETURN jsonb_build_object(
    'success', true,
    'user_id', p_user_id,
    'email', v_email,
    'newsletter_enabled', p_enabled,
    'previous_status', v_current_status
  );
END;
$$;


ALTER FUNCTION "public"."toggle_newsletter_status"("p_user_id" "uuid", "p_enabled" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."toggle_published_report_featured"("p_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_user_id UUID;
    v_is_admin BOOLEAN;
    v_new_status BOOLEAN;
BEGIN
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Not authenticated');
    END IF;

    SELECT is_admin_user(v_user_id) INTO v_is_admin;
    IF NOT COALESCE(v_is_admin, false) THEN
        RETURN jsonb_build_object('success', false, 'error', 'Admin access required');
    END IF;

    UPDATE published_reports
    SET 
        is_featured = NOT is_featured,
        updated_at = NOW()
    WHERE id = p_id
    RETURNING is_featured INTO v_new_status;

    IF v_new_status IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Report not found');
    END IF;

    RETURN jsonb_build_object('success', true, 'is_featured', v_new_status);
END;
$$;


