  ON CONFLICT (config_key) DO UPDATE SET
    config_value = jsonb_build_object('enabled', p_enabled),
    updated_at = NOW(),
    updated_by = v_admin_id;
  
  RETURN jsonb_build_object(
    'success', true, 
    'key', p_config_key, 
    'enabled', p_enabled
  );
END;
