CREATE OR REPLACE FUNCTION "public"."track_deleted_published_report"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    -- Only track if original_report_id exists
    IF OLD.original_report_id IS NOT NULL THEN
        INSERT INTO deleted_published_reports (report_type, original_report_id, deleted_at)
        VALUES (OLD.report_type, OLD.original_report_id, NOW())
