CREATE OR REPLACE FUNCTION "public"."track_referral_signup"("p_affiliate_code" "text", "p_user_id" "uuid", "p_user_email" "text", "p_signup_plan" "text" DEFAULT 'basic'::"text", "p_coupon_code" "text" DEFAULT NULL::"text", "p_discount_percent" numeric DEFAULT 0, "p_discount_amount" numeric DEFAULT 0) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_affiliate_id UUID;
  v_referral_id UUID;
  v_click_id UUID;
  v_coupon_id UUID;
  v_clean_code TEXT;
BEGIN
  v_clean_code := UPPER(REGEXP_REPLACE(p_affiliate_code, '[^A-Z0-9]', '', 'g'));
  
  -- Find affiliate
  SELECT id INTO v_affiliate_id
  FROM affiliates
  WHERE (affiliate_code = v_clean_code OR coupon_code = v_clean_code)
    AND status = 'active';
  
  IF v_affiliate_id IS NULL THEN
    RETURN NULL;
  END IF;
  
  -- Find recent unconverted click
  SELECT id INTO v_click_id
  FROM affiliate_clicks
  WHERE affiliate_id = v_affiliate_id
    AND converted = FALSE
    AND expires_at > NOW()
  ORDER BY clicked_at DESC
  LIMIT 1;
  
  -- Find coupon if provided
  IF p_coupon_code IS NOT NULL THEN
    SELECT id INTO v_coupon_id
    FROM admin_coupons
    WHERE code = UPPER(p_coupon_code) AND is_active = TRUE;
  END IF;
  
  -- Create referral
  INSERT INTO affiliate_referrals (
    affiliate_id,
    referred_user_id,
    referred_user_email,
    click_id,
    signup_plan,
    coupon_code_used,
    coupon_id_used,
    discount_percent,
    discount_amount_usd,
    status
  ) VALUES (
    v_affiliate_id,
    p_user_id,
    p_user_email,
    v_click_id,
    p_signup_plan,
    p_coupon_code,
    v_coupon_id,
    p_discount_percent,
    p_discount_amount,
    'pending'
  )
  RETURNING id INTO v_referral_id;
  
  -- Mark click as converted
  IF v_click_id IS NOT NULL THEN
    UPDATE affiliate_clicks
    SET converted = TRUE, converted_at = NOW(), converted_user_id = p_user_id
    WHERE id = v_click_id;
  END IF;
  
  -- Increment signup counter
  PERFORM increment_affiliate_signups(v_affiliate_id);
  
  -- Update profile with affiliate code
  UPDATE public.profiles
  SET affiliate_code = v_clean_code
  WHERE id = p_user_id;
  
  RETURN v_referral_id;
END;
$$;


ALTER FUNCTION "public"."track_referral_signup"("p_affiliate_code" "text", "p_user_id" "uuid", "p_user_email" "text", "p_signup_plan" "text", "p_coupon_code" "text", "p_discount_percent" numeric, "p_discount_amount" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."track_referral_signup"("p_affiliate_code" "text", "p_user_id" "uuid", "p_user_email" "text", "p_subscription_id" "text" DEFAULT NULL::"text", "p_subscription_plan" "text" DEFAULT NULL::"text", "p_subscription_type" "text" DEFAULT 'monthly'::"text", "p_subscription_price" numeric DEFAULT NULL::numeric, "p_click_id" "uuid" DEFAULT NULL::"uuid", "p_discount_percent" numeric DEFAULT 0, "p_discount_amount" numeric DEFAULT 0) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_affiliate RECORD;
  v_referral_id UUID;
  v_existing_referral UUID;
BEGIN
  SELECT * INTO v_affiliate
  FROM affiliates
  WHERE (UPPER(affiliate_code) = UPPER(p_affiliate_code) OR UPPER(coupon_code) = UPPER(p_affiliate_code))
    AND status = 'active';
  
  IF v_affiliate IS NULL OR v_affiliate.user_id = p_user_id THEN
    RETURN NULL;  -- Not found or self-referral
  END IF;
  
  -- Check for existing referral
  SELECT id INTO v_existing_referral FROM affiliate_referrals WHERE referred_user_id = p_user_id;
  
  IF v_existing_referral IS NOT NULL THEN
    UPDATE affiliate_referrals SET
      subscription_id = COALESCE(p_subscription_id, subscription_id),
      subscription_plan = COALESCE(p_subscription_plan, subscription_plan),
      subscription_type = COALESCE(p_subscription_type, subscription_type),
      subscription_price_usd = COALESCE(p_subscription_price, subscription_price_usd),
      updated_at = NOW()
    WHERE id = v_existing_referral;
    RETURN v_existing_referral;
  END IF;
  
  -- Create new referral
  INSERT INTO affiliate_referrals (
    affiliate_id, referred_user_id, referred_user_email, click_id, signup_date, signup_plan,
    discount_percent, discount_amount_usd, subscription_id, subscription_plan, subscription_type,
    subscription_price_usd, status, commission_eligible
  ) VALUES (
    v_affiliate.id, p_user_id, p_user_email, p_click_id, NOW(), COALESCE(p_subscription_plan, 'free'),
    COALESCE(p_discount_percent, 0), COALESCE(p_discount_amount, 0), p_subscription_id, p_subscription_plan,
    p_subscription_type, p_subscription_price, 'pending', TRUE
  )
  RETURNING id INTO v_referral_id;
  
  -- Update click if provided
  IF p_click_id IS NOT NULL THEN
    UPDATE affiliate_clicks SET converted = TRUE, converted_at = NOW(), referral_id = v_referral_id
    WHERE id = p_click_id;
  END IF;
  
  -- Update affiliate stats & log
  UPDATE affiliates SET total_signups = COALESCE(total_signups, 0) + 1, last_activity_at = NOW()
  WHERE id = v_affiliate.id;
  
  INSERT INTO affiliate_activity_log (affiliate_id, activity_type, description, metadata, is_system_action)
  VALUES (v_affiliate.id, 'new_signup', 'New signup: ' || p_user_email,
    jsonb_build_object('user_email', p_user_email, 'plan', p_subscription_plan, 'type', p_subscription_type, 'click_id', p_click_id), TRUE);
  
  RETURN v_referral_id;
END;
$$;


ALTER FUNCTION "public"."track_referral_signup"("p_affiliate_code" "text", "p_user_id" "uuid", "p_user_email" "text", "p_subscription_id" "text", "p_subscription_plan" "text", "p_subscription_type" "text", "p_subscription_price" numeric, "p_click_id" "uuid", "p_discount_percent" numeric, "p_discount_amount" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tradovate_vault_read"("p_secret_id" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'vault'
    AS $$
DECLARE
  v_secret TEXT;
BEGIN
  SELECT decrypted_secret
  INTO v_secret
  FROM vault.decrypted_secrets
  WHERE id = p_secret_id::UUID;

  RETURN v_secret;
END;
$$;


ALTER FUNCTION "public"."tradovate_vault_read"("p_secret_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tradovate_vault_upsert"("p_name" "text", "p_secret" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'vault'
    AS $$
DECLARE
  v_id UUID;
BEGIN
  -- Check if secret with this name already exists
  SELECT id INTO v_id
  FROM vault.secrets
  WHERE name = p_name
  LIMIT 1;

  IF v_id IS NOT NULL THEN
    -- Delete the old secret and recreate (Supabase doesn't allow direct UPDATE)
    DELETE FROM vault.secrets WHERE id = v_id;
  END IF;

  -- Create new secret (works regardless)
  SELECT vault.create_secret(p_secret, p_name) INTO v_id;

  RETURN v_id::TEXT;
END;
$$;


