CREATE OR REPLACE FUNCTION "public"."unban_user"("p_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Only admins can unban
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin')
  ) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;
  
  UPDATE public.profiles
  SET 
    is_banned = FALSE,
    banned_at = NULL,
    ban_reason = NULL,
    updated_at = NOW()
  WHERE id = p_user_id;
  
  -- Log action
  PERFORM public.log_admin_action(
    'unban_user',
    'user',
    p_user_id,
    '{}'::jsonb
  );
  
  RETURN FOUND;
END;
$$;


