    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_email TEXT;
BEGIN
  SELECT id, profiles.email INTO v_user_id, v_email
  FROM profiles WHERE newsletter_unsubscribe_token = p_token;

  IF v_user_id IS NULL THEN
    RETURN QUERY SELECT false, NULL::TEXT, 'Invalid or expired link'::TEXT;
    RETURN;
  END IF;

  UPDATE profiles
  SET newsletter_enabled = false, newsletter_unsubscribed_at = NOW()
  WHERE id = v_user_id;

  INSERT INTO newsletter_unsubscribe_log (user_id, email, action, reason)
  VALUES (v_user_id, v_email, 'unsubscribe', 'user_request');

  RETURN QUERY SELECT true, v_email, 'Successfully unsubscribed'::TEXT;
END;
$$;


