CREATE OR REPLACE FUNCTION "public"."update_newsletter_config"("p_config_key" "text", "p_config_value" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_admin_id UUID;
BEGIN
  SELECT id INTO v_admin_id FROM profiles 
  WHERE profiles.id = auth.uid() 
  AND profiles.role IN ('admin', 'super_admin');
  
  IF v_admin_id IS NULL THEN
    RAISE EXCEPTION 'Access denied: Admin only';
  END IF;

  INSERT INTO newsletter_config (config_key, config_value, updated_at, updated_by)
  VALUES (p_config_key, p_config_value, NOW(), v_admin_id)
  ON CONFLICT (config_key) DO UPDATE SET
    config_value = EXCLUDED.config_value,
    updated_at = NOW(),
    updated_by = v_admin_id;
  
  RETURN jsonb_build_object(
    'success', true, 
    'key', p_config_key, 
    'value', p_config_value
  );
END;
$$;


