CREATE OR REPLACE FUNCTION "public"."update_published_report"("p_id" "uuid", "p_is_featured" boolean DEFAULT NULL::boolean, "p_is_pinned" boolean DEFAULT NULL::boolean, "p_target_group" "text" DEFAULT NULL::"text", "p_admin_note" "text" DEFAULT NULL::"text", "p_title" "text" DEFAULT NULL::"text", "p_subtitle" "text" DEFAULT NULL::"text", "p_highlights" "text"[] DEFAULT NULL::"text"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_user_id UUID;
    v_is_admin BOOLEAN;
    v_report RECORD;
BEGIN
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Not authenticated');
    END IF;

    SELECT is_admin_user(v_user_id) INTO v_is_admin;
    IF NOT COALESCE(v_is_admin, false) THEN
        RETURN jsonb_build_object('success', false, 'error', 'Admin access required');
    END IF;

    SELECT * INTO v_report FROM published_reports WHERE id = p_id;
    IF v_report IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Report not found');
    END IF;

    UPDATE published_reports
    SET
        is_featured = COALESCE(p_is_featured, is_featured),
        is_pinned = COALESCE(p_is_pinned, is_pinned),
        target_group = COALESCE(p_target_group, target_group),
        admin_note = CASE 
            WHEN p_admin_note IS NOT NULL THEN p_admin_note 
            ELSE admin_note 
        END,
        title = COALESCE(p_title, title),
        subtitle = COALESCE(p_subtitle, subtitle),
        highlights = COALESCE(p_highlights, highlights),
        updated_at = NOW()
    WHERE id = p_id;

    RETURN jsonb_build_object(
        'success', true,
        'message', 'Report updated successfully',
        'report_id', p_id
    );
END;
$$;


