CREATE OR REPLACE FUNCTION "public"."update_support_ticket_metadata"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Update timestamp
  NEW.updated_at = NOW();
  
  -- Set first_message_at if not set
  IF NEW.first_message_at IS NULL THEN
    NEW.first_message_at = NOW();
  END IF;
  
  -- Count messages
  IF NEW.messages IS NOT NULL THEN
    NEW.message_count = jsonb_array_length(NEW.messages);
  END IF;
  
  -- Set resolved_at when status changes to resolved
  IF NEW.status = 'resolved' AND (OLD IS NULL OR OLD.status != 'resolved') THEN
    NEW.resolved_at = NOW();
  END IF;
  
  -- Track last message timestamps by type
  IF NEW.messages IS NOT NULL AND jsonb_array_length(NEW.messages) > 0 THEN
    DECLARE
      last_msg JSONB;
      msg_type TEXT;
    BEGIN
      -- Get last message
      last_msg := NEW.messages -> (jsonb_array_length(NEW.messages) - 1);
      msg_type := last_msg->>'type';
      
      IF msg_type = 'customer' THEN
        NEW.last_customer_message_at := (last_msg->>'timestamp')::TIMESTAMPTZ;
        NEW.is_read := FALSE; -- Mark unread when customer messages
      ELSIF msg_type = 'admin' THEN
        NEW.last_admin_message_at := (last_msg->>'timestamp')::TIMESTAMPTZ;
      END IF;
    END;
  END IF;
  
  RETURN NEW;
END;
$$;


