CREATE OR REPLACE FUNCTION "public"."upsert_portfolio_from_tradovate"("p_user_id" "uuid", "p_tradovate_account_id" bigint, "p_account_spec" "text", "p_account_name" "text", "p_environment" "text", "p_credential_id" "uuid" DEFAULT NULL::"uuid", "p_connection_label" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id UUID;
BEGIN
  INSERT INTO public.portfolios (
    id,
    user_id,
    name,
    tradovate_account_id,
    tradovate_account_spec,
    environment,
    source,
    is_active,
    created_at,
    updated_at,
    connection_label
  )
  VALUES (
    gen_random_uuid(),
    p_user_id,
    p_account_name,
    p_tradovate_account_id,
    p_account_spec,
    p_environment,
    'tradovate',
    true,
    now(),
    now(),
    p_connection_label
  )
  ON CONFLICT (user_id, tradovate_account_id)
  DO UPDATE SET
    name                   = EXCLUDED.name,
    tradovate_account_spec = EXCLUDED.tradovate_account_spec,
    environment            = EXCLUDED.environment,
    connection_label       = COALESCE(EXCLUDED.connection_label, public.portfolios.connection_label),
    is_active              = true,
    updated_at             = now()
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


