CREATE OR REPLACE FUNCTION "public"."use_journal_discount"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_profile RECORD;
BEGIN
  SELECT journal_discount_available, journal_discount_used, journal_discount_percent
  INTO v_profile FROM profiles WHERE id = p_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  IF NOT v_profile.journal_discount_available THEN
    RETURN jsonb_build_object('success', false, 'error', 'No discount available');
  END IF;

  IF v_profile.journal_discount_used THEN
    RETURN jsonb_build_object('success', false, 'error', 'Discount already used');
  END IF;

  UPDATE profiles SET
    journal_discount_used = TRUE,
    journal_discount_used_at = NOW(),
    updated_at = NOW()
  WHERE id = p_user_id;

  RETURN jsonb_build_object('success', true, 'discount_percent', v_profile.journal_discount_percent, 'used_at', NOW());
END;
$$;


ALTER FUNCTION "public"."use_journal_discount"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_affiliate_code"("p_code" "text") RETURNS TABLE("is_valid" boolean, "affiliate_id" "uuid", "discount_percent" numeric, "affiliate_name" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    TRUE as is_valid,
    a.id as affiliate_id,
    COALESCE(a.discount_percent, 0) as discount_percent,
    a.display_name as affiliate_name
  FROM affiliates a
  WHERE (UPPER(a.affiliate_code) = UPPER(p_code) OR UPPER(a.coupon_code) = UPPER(p_code))
    AND a.status = 'active';
    
  -- If no rows returned, return invalid
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, NULL::UUID, 0::NUMERIC, NULL::TEXT;
  END IF;
END;
$$;


ALTER FUNCTION "public"."validate_affiliate_code"("p_code" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_coupon_code"("p_code" "text", "p_plan" "text" DEFAULT NULL::"text", "p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("is_valid" boolean, "code_type" "text", "affiliate_id" "uuid", "affiliate_name" "text", "coupon_id" "uuid", "coupon_name" "text", "code" "text", "discount_type" "text", "discount_percent" numeric, "discount_amount_usd" numeric, "fixed_price_usd" numeric, "is_affiliate_code" boolean, "pays_commission" boolean, "applicable_plans" "text"[], "can_stack_with_affiliate" boolean, "validation_message" "text", "discount_monthly" numeric, "discount_yearly" numeric, "discount_tier" "public"."discount_tier")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_clean_code TEXT;
  v_affiliate RECORD;
  v_coupon RECORD;
  v_fixed_price NUMERIC;
  v_can_use BOOLEAN;
  v_reason TEXT;
  v_discount_rate NUMERIC;
BEGIN
  v_clean_code := UPPER(REGEXP_REPLACE(p_code, '[^A-Z0-9]', '', 'g'));
  
  -- First check affiliate codes
  SELECT 
    a.id, 
    a.display_name, 
    a.affiliate_code, 
    a.discount_tier, 
    a.commission_enabled, 
    a.affiliate_type
  INTO v_affiliate
  FROM affiliates a
  WHERE (a.affiliate_code = v_clean_code OR a.coupon_code = v_clean_code)
    AND a.status = 'active';
  
  IF v_affiliate IS NOT NULL THEN
    -- Calculate discount rate based on affiliate's discount_tier
    v_discount_rate := CASE v_affiliate.discount_tier 
      WHEN 'vip' THEN 15.00 
      ELSE 10.00 
    END;
    
    RETURN QUERY SELECT 
      TRUE::BOOLEAN,
      'affiliate'::TEXT,
      v_affiliate.id,
      v_affiliate.display_name,
      NULL::UUID,
      NULL::TEXT,
      v_affiliate.affiliate_code,
      'percentage'::TEXT,
      v_discount_rate::NUMERIC,
      NULL::NUMERIC,
      NULL::NUMERIC,
      TRUE::BOOLEAN,
      v_affiliate.commission_enabled AND v_affiliate.affiliate_type = 'regular',
      NULL::TEXT[],
      TRUE::BOOLEAN,  -- Affiliate codes can always stack with admin coupons that allow it
      'Valid affiliate code'::TEXT,
      v_discount_rate::NUMERIC,        -- discount_monthly
      v_discount_rate::NUMERIC,        -- discount_yearly (same rate for affiliates)
      v_affiliate.discount_tier;       -- discount_tier
    RETURN;
  END IF;
  
  -- Then check admin coupons
  SELECT ac.*
  INTO v_coupon
  FROM admin_coupons ac
  WHERE ac.code = v_clean_code
    AND ac.is_active = TRUE
    AND (ac.valid_from IS NULL OR ac.valid_from <= NOW())
    AND (ac.valid_until IS NULL OR ac.valid_until > NOW())
    AND (ac.max_uses IS NULL OR ac.current_uses < ac.max_uses);
  
  IF v_coupon IS NOT NULL THEN
    -- Check if user can use this coupon
    IF p_user_id IS NOT NULL THEN
      SELECT * INTO v_can_use, v_reason FROM can_user_use_coupon(v_coupon.id, p_user_id, p_plan);
      IF NOT v_can_use THEN
        RETURN QUERY SELECT 
          FALSE, 'admin_coupon'::TEXT, NULL::UUID, NULL::TEXT, v_coupon.id, v_coupon.name,
          v_coupon.code, v_coupon.discount_type::TEXT, v_coupon.discount_percent,
          v_coupon.discount_amount_usd, NULL::NUMERIC, FALSE, FALSE,
          v_coupon.applicable_plans, v_coupon.stackable_with_affiliate, v_reason,
          v_coupon.discount_percent::NUMERIC,
          v_coupon.discount_percent::NUMERIC,
          NULL::discount_tier;
        RETURN;
      END IF;
    END IF;
    
    -- Get fixed price for requested plan if applicable
    IF v_coupon.discount_type = 'fixed_price' AND p_plan IS NOT NULL THEN
      SELECT cpp.fixed_price_usd INTO v_fixed_price
      FROM admin_coupon_plan_prices cpp
      WHERE cpp.coupon_id = v_coupon.id AND cpp.plan_name = p_plan;
    END IF;
    
    RETURN QUERY SELECT 
      TRUE::BOOLEAN,
      'admin_coupon'::TEXT,
      NULL::UUID,
      NULL::TEXT,
      v_coupon.id,
      v_coupon.name,
      v_coupon.code,
      v_coupon.discount_type::TEXT,
      v_coupon.discount_percent,
      v_coupon.discount_amount_usd,
      v_fixed_price,
      FALSE::BOOLEAN,
      FALSE::BOOLEAN,  -- Admin coupons don't pay commission
      v_coupon.applicable_plans,
      v_coupon.stackable_with_affiliate,
      'Valid coupon'::TEXT,
      v_coupon.discount_percent::NUMERIC,
      v_coupon.discount_percent::NUMERIC,
      NULL::discount_tier;
    RETURN;
  END IF;
  
  -- Code not found
  RETURN QUERY SELECT 
    FALSE, NULL::TEXT, NULL::UUID, NULL::TEXT, NULL::UUID, NULL::TEXT,
    NULL::TEXT, NULL::TEXT, NULL::NUMERIC, NULL::NUMERIC, NULL::NUMERIC,
    NULL::BOOLEAN, NULL::BOOLEAN, NULL::TEXT[], NULL::BOOLEAN, 'Invalid code'::TEXT,
    NULL::NUMERIC, NULL::NUMERIC, NULL::discount_tier;
END;
$$;


ALTER FUNCTION "public"."validate_coupon_code"("p_code" "text", "p_plan" "text", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_payment_provider"("p_user_id" "uuid", "p_provider" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_current_provider TEXT;
BEGIN
  SELECT payment_provider INTO v_current_provider
  FROM public.profiles
  WHERE id = p_user_id;
  
  -- If no current provider, allow setting
  IF v_current_provider IS NULL OR v_current_provider = '' THEN
    RETURN TRUE;
  END IF;
  
  -- Must match current provider
  RETURN v_current_provider = p_provider;
END;
$$;


