CREATE OR REPLACE FUNCTION "public"."validate_symbol"("p_symbol" "text") RETURNS TABLE("is_valid" boolean, "symbol" "text", "name" "text", "asset_class" "text", "multiplier" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_ticker RECORD;
BEGIN
  SELECT t.* INTO v_ticker
  FROM public.ticker_symbols t
  WHERE UPPER(t.symbol) = UPPER(TRIM(p_symbol));
  
  IF FOUND THEN
    RETURN QUERY SELECT 
      TRUE,
      v_ticker.symbol,
      v_ticker.name,
      v_ticker.asset_class,
      v_ticker.multiplier;
  ELSE
    -- Unknown symbol - return default
    RETURN QUERY SELECT 
      FALSE,
      UPPER(TRIM(p_symbol)),
      'Unknown'::TEXT,
      'unknown'::TEXT,
      1::NUMERIC;
  END IF;
END;
$$;


ALTER FUNCTION "public"."validate_symbol"("p_symbol" "text") OWNER TO "postgres";


