    CONSTRAINT "check_risk_calculation_mode" CHECK ((("risk_calculation_mode")::"text" = ANY ((ARRAY['percentage'::character varying, 'fixed'::character varying])::"text"[]))),
    CONSTRAINT "check_risk_mode" CHECK ((("risk_mode")::"text" = ANY ((ARRAY['percentage'::character varying, 'fixed'::character varying])::"text"[]))),
    CONSTRAINT "profiles_account_type_check" CHECK ((("account_type" IS NULL) OR ("account_type" = ANY (ARRAY['free'::"text", 'basic'::"text", 'premium'::"text", 'trial'::"text", 'admin'::"text", 'vip'::"text", 'beta'::"text", 'newsletter'::"text", 'top_secret'::"text", 'top_secret_bundle'::"text"])))),
    CONSTRAINT "profiles_newsletter_status_check" CHECK ((("newsletter_status" IS NULL) OR ("newsletter_status" = ANY (ARRAY['inactive'::"text", 'trial'::"text", 'active'::"text", 'cancelled'::"text"])))),
    CONSTRAINT "profiles_payment_provider_check" CHECK ((("payment_provider" IS NULL) OR ("payment_provider" = ANY (ARRAY['payplus'::"text", 'stripe'::"text", 'paypal'::"text", 'whop'::"text", 'admin_granted'::"text", 'manual'::"text"])))),
    CONSTRAINT "profiles_platform_billing_interval_check" CHECK ((("platform_billing_interval" IS NULL) OR ("platform_billing_interval" = ANY (ARRAY['monthly'::"text", 'yearly'::"text"])))),
    CONSTRAINT "profiles_platform_bundle_newsletter_choice_check" CHECK ((("platform_bundle_newsletter_choice" IS NULL) OR ("platform_bundle_newsletter_choice" = ANY (ARRAY['included'::"text", 'discounted'::"text", 'declined'::"text"])))),
    CONSTRAINT "profiles_platform_payment_provider_check" CHECK ((("platform_payment_provider" IS NULL) OR ("platform_payment_provider" = ANY (ARRAY['whop'::"text", 'stripe'::"text", 'manual'::"text", 'admin_granted'::"text"])))),
    CONSTRAINT "profiles_platform_plan_check" CHECK ((("platform_plan" IS NULL) OR ("platform_plan" = ANY (ARRAY['free'::"text", 'platform_core'::"text", 'platform_finotaur'::"text", 'platform_enterprise'::"text", 'core'::"text", 'finotaur'::"text", 'enterprise'::"text"])))),
    CONSTRAINT "profiles_platform_subscription_status_check" CHECK ((("platform_subscription_status" IS NULL) OR ("platform_subscription_status" = ANY (ARRAY['active'::"text", 'inactive'::"text", 'trial'::"text", 'past_due'::"text", 'cancelled'::"text", 'expired'::"text"])))),
    CONSTRAINT "profiles_role_check" CHECK (("role" = ANY (ARRAY['user'::"text", 'admin'::"text", 'super_admin'::"text"]))),
    CONSTRAINT "profiles_subscription_interval_check" CHECK ((("subscription_interval" = ANY (ARRAY['monthly'::"text", 'yearly'::"text"])) OR ("subscription_interval" IS NULL))),
    CONSTRAINT "profiles_subscription_status_check" CHECK ((("subscription_status" IS NULL) OR ("subscription_status" = ANY (ARRAY['trial'::"text", 'active'::"text", 'expired'::"text", 'cancelled'::"text", 'inactive'::"text", 'trialing'::"text", 'past_due'::"text"])))),
    CONSTRAINT "profiles_top_secret_interval_check" CHECK ((("top_secret_interval" IS NULL) OR ("top_secret_interval" = ANY (ARRAY['monthly'::"text", 'yearly'::"text"])))),
    CONSTRAINT "profiles_top_secret_status_check" CHECK ((("top_secret_status" IS NULL) OR ("top_secret_status" = ANY (ARRAY['inactive'::"text", 'active'::"text", 'cancelled'::"text"])))),
    CONSTRAINT "profiles_trader_type_check" CHECK (("trader_type" = ANY (ARRAY['day_trader'::"text", 'swing_trader'::"text", 'investor'::"text"])))
);

