CREATE TABLE IF NOT EXISTS "public"."subscription_periods" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "plan" "text" NOT NULL,
    "whop_transaction_id" "text",
    "period_start" timestamp with time zone NOT NULL,
    "period_end" timestamp with time zone NOT NULL,
    "auto_renew" boolean DEFAULT true,
    "canceled_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "subscription_periods_plan_check" CHECK (("plan" = ANY (ARRAY['free'::"text", 'basic'::"text", 'premium'::"text"])))
);


ALTER TABLE "public"."subscription_periods" OWNER TO "postgres";


COMMENT ON TABLE "public"."subscription_periods" IS 'Tracks subscription periods and renewals';



CREATE OR REPLACE VIEW "public"."active_subscriptions" WITH ("security_invoker"='true') AS
 SELECT "sp"."user_id",
    "sp"."plan",
    "sp"."period_start",
    "sp"."period_end",
    "sp"."auto_renew",
    "sp"."canceled_at",
    "p"."email",
    "p"."display_name",
    "p"."account_type",
    "p"."subscription_interval",
    "p"."subscription_cancel_at_period_end",
    (EXTRACT(day FROM ("sp"."period_end" - "now"())))::integer AS "days_remaining",
        CASE
            WHEN ("sp"."period_end" < "now"()) THEN 'expired'::"text"
            WHEN ("sp"."period_end" < ("now"() + '7 days'::interval)) THEN 'expiring_soon'::"text"
            ELSE 'active'::"text"
        END AS "subscription_health"
   FROM ("public"."subscription_periods" "sp"
     JOIN "public"."profiles" "p" ON (("p"."id" = "sp"."user_id")))
  WHERE ("sp"."period_end" > ("now"() - '30 days'::interval))
  ORDER BY "sp"."period_end";


