CREATE OR REPLACE VIEW "public"."admin_coupons_summary" WITH ("security_invoker"='true') AS
 SELECT "id",
    "code",
    "name",
    "discount_type",
    "discount_percent",
    "discount_amount_usd",
    "duration_type",
    "is_active",
    "valid_from",
    "valid_until",
    "max_uses",
    "current_uses",
    "max_uses_per_user",
    "applicable_plans",
    "first_time_only",
    "new_users_only",
    "stackable_with_affiliate",
    "priority",
    "created_at",
        CASE
            WHEN ("discount_type" = 'fixed_price'::"public"."coupon_discount_type") THEN ( SELECT "jsonb_object_agg"("cpp"."plan_name", "cpp"."fixed_price_usd") AS "jsonb_object_agg"
               FROM "public"."admin_coupon_plan_prices" "cpp"
              WHERE ("cpp"."coupon_id" = "ac"."id"))
            ELSE NULL::"jsonb"
        END AS "plan_prices",
        CASE
            WHEN (("valid_until" IS NOT NULL) AND ("valid_until" < "now"())) THEN 'expired'::"text"
            WHEN (("max_uses" IS NOT NULL) AND ("current_uses" >= "max_uses")) THEN 'exhausted'::"text"
            WHEN "is_active" THEN 'active'::"text"
            ELSE 'inactive'::"text"
        END AS "effective_status"
   FROM "public"."admin_coupons" "ac";


