Structure: [{price, quantity, date, pnl, fees?}]. 
Used when trader exits position in multiple parts rather than all at once.
Frontend can calculate weighted average exit price from this data.';



COMMENT ON CONSTRAINT "trades_session_check" ON "public"."trades" IS 'v8.5.11-FINAL-FIX: Session accepts NULL OR any case (asia/Asia/ASIA). Uses LOWER() + TRIM() for validation.';



CREATE OR REPLACE VIEW "public"."admin_stats_view" WITH ("security_invoker"='true') AS
 WITH "admin_check" AS (
         SELECT (EXISTS ( SELECT 1
                   FROM "public"."profiles"
                  WHERE (("profiles"."id" = "auth"."uid"()) AND ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))))) AS "is_admin"
        ), "time_periods" AS (
         SELECT CURRENT_TIMESTAMP AS "now",
            CURRENT_DATE AS "today",
            (CURRENT_TIMESTAMP - '1 day'::interval) AS "one_day_ago",
            (CURRENT_TIMESTAMP - '7 days'::interval) AS "seven_days_ago",
            (CURRENT_TIMESTAMP - '30 days'::interval) AS "thirty_days_ago",
            "date_trunc"('week'::"text", (CURRENT_DATE)::timestamp with time zone) AS "start_of_week",
            "date_trunc"('month'::"text", (CURRENT_DATE)::timestamp with time zone) AS "start_of_month"
        ), "user_counts" AS (
         SELECT "count"(*) AS "total_users",
            "count"(*) FILTER (WHERE ("profiles"."last_login_at" > ( SELECT "time_periods"."thirty_days_ago"
                   FROM "time_periods"))) AS "active_users",
            "count"(*) FILTER (WHERE (("profiles"."created_at")::"date" = ( SELECT "time_periods"."today"
                   FROM "time_periods"))) AS "new_users_today",
            "count"(*) FILTER (WHERE ("profiles"."created_at" >= ( SELECT "time_periods"."start_of_week"
                   FROM "time_periods"))) AS "new_users_this_week",
            "count"(*) FILTER (WHERE ("profiles"."created_at" >= ( SELECT "time_periods"."start_of_month"
                   FROM "time_periods"))) AS "new_users_this_month",
            "count"(*) FILTER (WHERE ("profiles"."account_type" = 'free'::"text")) AS "free_users",
            "count"(*) FILTER (WHERE ("profiles"."account_type" = 'basic'::"text")) AS "basic_users",
            "count"(*) FILTER (WHERE ("profiles"."account_type" = 'premium'::"text")) AS "premium_users",
            "count"(*) FILTER (WHERE ("profiles"."subscription_status" = 'trial'::"text")) AS "trial_users",
            "count"(*) FILTER (WHERE (("profiles"."account_type" = 'basic'::"text") AND ("profiles"."subscription_interval" = 'monthly'::"text"))) AS "basic_monthly_users",
            "count"(*) FILTER (WHERE (("profiles"."account_type" = 'basic'::"text") AND ("profiles"."subscription_interval" = 'yearly'::"text"))) AS "basic_yearly_users",
            "count"(*) FILTER (WHERE (("profiles"."account_type" = 'premium'::"text") AND ("profiles"."subscription_interval" = 'monthly'::"text"))) AS "premium_monthly_users",
            "count"(*) FILTER (WHERE (("profiles"."account_type" = 'premium'::"text") AND ("profiles"."subscription_interval" = 'yearly'::"text"))) AS "premium_yearly_users",
            "count"(*) FILTER (WHERE ("profiles"."last_login_at" > ( SELECT "time_periods"."one_day_ago"
                   FROM "time_periods"))) AS "daily_active_users",
            "count"(*) FILTER (WHERE ("profiles"."last_login_at" > ( SELECT "time_periods"."seven_days_ago"
                   FROM "time_periods"))) AS "weekly_active_users",
            "count"(*) FILTER (WHERE ("profiles"."last_login_at" > ( SELECT "time_periods"."thirty_days_ago"
                   FROM "time_periods"))) AS "monthly_active_users"
           FROM "public"."profiles"
          WHERE ("profiles"."deleted_at" IS NULL)
        ), "trade_counts" AS (
         SELECT "count"(*) AS "total_trades",
            "count"(*) FILTER (WHERE ("trades"."created_at" >= ( SELECT "time_periods"."start_of_week"
                   FROM "time_periods"))) AS "trades_this_week",
            "count"(*) FILTER (WHERE ("trades"."created_at" >= ( SELECT "time_periods"."start_of_month"
                   FROM "time_periods"))) AS "trades_this_month"
           FROM "public"."trades"
        ), "revenue" AS (
         SELECT ((((("uc_1"."basic_monthly_users")::numeric * 15.99) + (("uc_1"."basic_yearly_users")::numeric * 12.99)) + (("uc_1"."premium_monthly_users")::numeric * 24.99)) + (("uc_1"."premium_yearly_users")::numeric * 19.99)) AS "estimated_monthly_revenue"
           FROM "user_counts" "uc_1"
        )
 SELECT
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."total_users"
            ELSE NULL::bigint
        END AS "total_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."active_users"
            ELSE NULL::bigint
        END AS "active_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."new_users_today"
            ELSE NULL::bigint
        END AS "new_users_today",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."new_users_this_week"
            ELSE NULL::bigint
        END AS "new_users_this_week",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."new_users_this_month"
            ELSE NULL::bigint
        END AS "new_users_this_month",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."free_users"
            ELSE NULL::bigint
        END AS "free_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."basic_users"
            ELSE NULL::bigint
        END AS "basic_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."premium_users"
            ELSE NULL::bigint
        END AS "premium_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."trial_users"
            ELSE NULL::bigint
        END AS "trial_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."basic_monthly_users"
            ELSE NULL::bigint
        END AS "basic_monthly_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."basic_yearly_users"
            ELSE NULL::bigint
        END AS "basic_yearly_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."premium_monthly_users"
            ELSE NULL::bigint
        END AS "premium_monthly_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."premium_yearly_users"
            ELSE NULL::bigint
        END AS "premium_yearly_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "r"."estimated_monthly_revenue"
            ELSE NULL::numeric
        END AS "estimated_monthly_revenue",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN ("r"."estimated_monthly_revenue" * (12)::numeric)
            ELSE NULL::numeric
        END AS "estimated_yearly_revenue",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "tc"."total_trades"
            ELSE NULL::bigint
        END AS "total_trades",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "tc"."trades_this_week"
            ELSE NULL::bigint
        END AS "trades_this_week",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "tc"."trades_this_month"
            ELSE NULL::bigint
        END AS "trades_this_month",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN
            CASE
                WHEN ("uc"."total_users" > 0) THEN "round"((("tc"."total_trades")::numeric / ("uc"."total_users")::numeric), 2)
                ELSE (0)::numeric
            END
            ELSE NULL::numeric
        END AS "average_trades_per_user",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."daily_active_users"
            ELSE NULL::bigint
        END AS "daily_active_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."weekly_active_users"
            ELSE NULL::bigint
        END AS "weekly_active_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN "uc"."monthly_active_users"
            ELSE NULL::bigint
        END AS "monthly_active_users",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN
            CASE
                WHEN ((("uc"."free_users" + "uc"."basic_users") + "uc"."premium_users") > 0) THEN "round"((((("uc"."basic_users" + "uc"."premium_users"))::numeric / ((("uc"."free_users" + "uc"."basic_users") + "uc"."premium_users"))::numeric) * (100)::numeric), 2)
                ELSE (0)::numeric
            END
            ELSE NULL::numeric
        END AS "free_to_paying_conversion_rate",
        CASE
            WHEN ( SELECT "admin_check"."is_admin"
               FROM "admin_check") THEN
            CASE
                WHEN ((("uc"."trial_users" + "uc"."basic_users") + "uc"."premium_users") > 0) THEN "round"((((("uc"."basic_users" + "uc"."premium_users"))::numeric / ((("uc"."trial_users" + "uc"."basic_users") + "uc"."premium_users"))::numeric) * (100)::numeric), 2)
                ELSE (0)::numeric
            END
            ELSE NULL::numeric
        END AS "trial_to_paying_conversion_rate",
    ( SELECT "admin_check"."is_admin"
           FROM "admin_check") AS "_is_authorized"
   FROM (("user_counts" "uc"
     CROSS JOIN "trade_counts" "tc")
     CROSS JOIN "revenue" "r");


ALTER VIEW "public"."admin_stats_view" OWNER TO "postgres";


COMMENT ON VIEW "public"."admin_stats_view" IS 'Platform statistics for admin dashboard - returns NULL for non-admins';



CREATE OR REPLACE VIEW "public"."admin_users_list_view" WITH ("security_invoker"='true') AS
 SELECT
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."id"
            ELSE NULL::"uuid"
        END AS "id",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."email"
            ELSE NULL::"text"
        END AS "email",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN COALESCE("p"."display_name", "split_part"("p"."email", '@'::"text", 1))
            ELSE NULL::"text"
        END AS "display_name",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN COALESCE("p"."account_type", 'free'::"text")
            ELSE NULL::"text"
        END AS "account_type",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN COALESCE("p"."role", 'user'::"text")
            ELSE NULL::"text"
        END AS "role",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."subscription_status"
            ELSE NULL::"text"
        END AS "subscription_status",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."subscription_interval"
            ELSE NULL::"text"
        END AS "subscription_interval",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."subscription_expires_at"
            ELSE NULL::timestamp with time zone
        END AS "subscription_expires_at",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."subscription_cancel_at_period_end"
            ELSE NULL::boolean
        END AS "subscription_cancel_at_period_end",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."is_banned"
            ELSE NULL::boolean
        END AS "is_banned",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."last_login_at"
            ELSE NULL::timestamp with time zone
        END AS "last_login_at",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."login_count"
            ELSE NULL::integer
        END AS "login_count",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."created_at"
            ELSE NULL::timestamp with time zone
        END AS "created_at",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."updated_at"
            ELSE NULL::timestamp with time zone
        END AS "updated_at",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."current_portfolio"
            ELSE NULL::numeric
        END AS "current_portfolio",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."initial_portfolio"
            ELSE NULL::numeric
        END AS "initial_portfolio",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."total_pnl"
            ELSE NULL::numeric
        END AS "total_pnl",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."trade_count"
            ELSE NULL::integer
        END AS "trade_count",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."risk_settings"
            ELSE NULL::"jsonb"
        END AS "risk_settings",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."current_month_trades_count"
            ELSE NULL::integer
        END AS "current_month_trades_count",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."max_trades"
            ELSE NULL::integer
        END AS "max_trades",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."portfolio_size"
            ELSE NULL::numeric
        END AS "portfolio_size",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."risk_mode"
            ELSE NULL::character varying
        END AS "risk_mode",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."risk_percentage"
            ELSE NULL::numeric
        END AS "risk_percentage",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "p"."fixed_risk_amount"
            ELSE NULL::numeric
        END AS "fixed_risk_amount",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN
            CASE
                WHEN (("p"."risk_mode")::"text" = 'percentage'::"text") THEN "round"((("p"."portfolio_size" * "p"."risk_percentage") / (100)::numeric), 2)
                WHEN (("p"."risk_mode")::"text" = 'fixed'::"text") THEN "p"."fixed_risk_amount"
                ELSE NULL::numeric
            END
            ELSE NULL::numeric
        END AS "calculated_one_r",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL))
            ELSE NULL::bigint
        END AS "total_closed_trades",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN
            CASE
                WHEN ("count"(DISTINCT "t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL)) > 0) THEN "round"(((("count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'WIN'::"text")))::numeric * 100.0) / ("count"(DISTINCT "t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL)))::numeric), 2)
                ELSE (0)::numeric
            END
            ELSE NULL::numeric
        END AS "win_rate",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'WIN'::"text"))
            ELSE NULL::bigint
        END AS "wins",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'LOSS'::"text"))
            ELSE NULL::bigint
        END AS "losses",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'BE'::"text"))
            ELSE NULL::bigint
        END AS "break_even",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'OPEN'::"text"))
            ELSE NULL::bigint
        END AS "open_trades",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "max"("t"."close_at")
            ELSE NULL::timestamp with time zone
        END AS "last_trade_date",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "round"("avg"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL)), 2)
            ELSE NULL::numeric
        END AS "avg_r",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "max"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL))
            ELSE NULL::numeric
        END AS "best_r",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "min"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL))
            ELSE NULL::numeric
        END AS "worst_r"
   FROM ("public"."profiles" "p"
     LEFT JOIN "public"."trades" "t" ON (("t"."user_id" = "p"."id")))
  WHERE (("p"."deleted_at" IS NULL) AND ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
           FROM "public"."profiles"
          WHERE ("profiles"."id" = "auth"."uid"())))
  GROUP BY "p"."id", "p"."email", "p"."display_name", "p"."account_type", "p"."role", "p"."subscription_status", "p"."subscription_interval", "p"."subscription_expires_at", "p"."subscription_cancel_at_period_end", "p"."is_banned", "p"."last_login_at", "p"."login_count", "p"."created_at", "p"."updated_at", "p"."current_portfolio", "p"."initial_portfolio", "p"."total_pnl", "p"."trade_count", "p"."risk_settings", "p"."current_month_trades_count", "p"."max_trades", "p"."portfolio_size", "p"."risk_mode", "p"."risk_percentage", "p"."fixed_risk_amount"
  ORDER BY "p"."created_at" DESC;


