CREATE OR REPLACE VIEW "public"."affiliate_cron_history" WITH ("security_invoker"='true') AS
 SELECT "j"."jobname",
    "r"."status",
    "r"."return_message",
    "r"."start_time",
    "r"."end_time",
    ("r"."end_time" - "r"."start_time") AS "duration"
   FROM ("cron"."job" "j"
     LEFT JOIN "cron"."job_run_details" "r" ON (("j"."jobid" = "r"."jobid")))
  WHERE ("j"."jobname" ~~ 'affiliate_%'::"text")
  ORDER BY "r"."start_time" DESC
 LIMIT 100;


