);


ALTER TABLE "public"."affiliates" OWNER TO "postgres";


COMMENT ON COLUMN "public"."affiliates"."paypal_email" IS 'PayPal email address for receiving payouts';



CREATE OR REPLACE VIEW "public"."affiliate_dashboard_summary" WITH ("security_invoker"='true') AS
 SELECT "id" AS "affiliate_id",
    "user_id",
    "display_name",
    "email",
    "affiliate_code",
    "coupon_code",
    "referral_link",
    "status",
    "current_tier",
    "discount_tier",
    "affiliate_type",
    "commission_enabled",
    COALESCE("total_clicks", 0) AS "total_clicks",
    COALESCE("total_signups", 0) AS "total_signups",
    COALESCE("total_qualified_referrals", 0) AS "total_qualified_referrals",
    COALESCE("total_active_customers", 0) AS "total_active_customers",
        CASE
            WHEN (COALESCE("total_clicks", 0) > 0) THEN "round"((((COALESCE("total_signups", 0))::numeric / ("total_clicks")::numeric) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS "signup_conversion_rate",
        CASE
            WHEN (COALESCE("total_signups", 0) > 0) THEN "round"((((COALESCE("total_qualified_referrals", 0))::numeric / ("total_signups")::numeric) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS "qualification_rate",
    COALESCE("total_earnings_usd", (0)::numeric) AS "total_earnings_usd",
    COALESCE("total_pending_usd", (0)::numeric) AS "total_pending_usd",
    COALESCE("total_paid_usd", (0)::numeric) AS "total_paid_usd",
        CASE "current_tier"
            WHEN 'tier_3'::"public"."affiliate_tier" THEN 0.20
            WHEN 'tier_2'::"public"."affiliate_tier" THEN 0.15
            ELSE 0.10
        END AS "current_commission_rate",
        CASE "current_tier"
            WHEN 'tier_1'::"public"."affiliate_tier" THEN GREATEST(0, (20 - COALESCE("total_qualified_referrals", 0)))
            WHEN 'tier_2'::"public"."affiliate_tier" THEN GREATEST(0, (75 - COALESCE("total_qualified_referrals", 0)))
            ELSE 0
        END AS "clients_to_next_tier",
    COALESCE("notify_on_signup", true) AS "notify_on_signup",
    COALESCE("notify_on_qualification", true) AS "notify_on_qualification",
    COALESCE("notify_on_commission", true) AS "notify_on_commission",
    COALESCE("notify_on_payout", true) AS "notify_on_payout",
    "paypal_email",
    "payment_method",
    "activated_at",
    "last_activity_at",
    "created_at",
    "updated_at"
   FROM "public"."affiliates" "a"
  WHERE ("status" = ANY (ARRAY['active'::"public"."affiliate_status", 'inactive'::"public"."affiliate_status"]));


ALTER VIEW "public"."affiliate_dashboard_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."affiliate_leaderboard" WITH ("security_invoker"='true') AS
 SELECT "id",
    "display_name",
    "current_tier",
    "total_qualified_referrals",
    "total_earnings_usd",
    "total_active_customers",
    "rank"() OVER (ORDER BY "total_qualified_referrals" DESC) AS "rank_by_referrals",
    "rank"() OVER (ORDER BY "total_earnings_usd" DESC) AS "rank_by_earnings"
   FROM "public"."affiliates" "a"
  WHERE (("status" = 'active'::"public"."affiliate_status") AND ("affiliate_type" = 'regular'::"text"))
  ORDER BY "total_qualified_referrals" DESC;


ALTER VIEW "public"."affiliate_leaderboard" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."affiliate_monthly_performance" WITH ("security_invoker"='true') AS
 SELECT "a"."id" AS "affiliate_id",
    "a"."user_id",
    "a"."display_name",
    ("date_trunc"('month'::"text", ("c"."commission_month")::timestamp with time zone))::"date" AS "month",
    "sum"(
        CASE
            WHEN ("c"."commission_type" = 'monthly_recurring'::"public"."commission_type") THEN "c"."commission_amount_usd"
            ELSE (0)::numeric
        END) AS "recurring_commissions",
    "sum"(
        CASE
            WHEN ("c"."commission_type" = 'annual_upfront'::"public"."commission_type") THEN "c"."commission_amount_usd"
            ELSE (0)::numeric
        END) AS "annual_commissions",
    "sum"(
        CASE
            WHEN ("c"."commission_type" = 'sub_affiliate'::"public"."commission_type") THEN "c"."commission_amount_usd"
            ELSE (0)::numeric
        END) AS "sub_affiliate_commissions",
    "sum"("c"."commission_amount_usd") AS "total_commissions",
    "count"(DISTINCT "c"."referral_id") AS "active_referrals_count"
   FROM ("public"."affiliates" "a"
     LEFT JOIN "public"."affiliate_commissions" "c" ON (("a"."id" = "c"."affiliate_id")))
  WHERE ("c"."status" = ANY (ARRAY['pending'::"public"."commission_status", 'confirmed'::"public"."commission_status", 'paid'::"public"."commission_status"]))
  GROUP BY "a"."id", "a"."user_id", "a"."display_name", ("date_trunc"('month'::"text", ("c"."commission_month")::timestamp with time zone))
  ORDER BY (("date_trunc"('month'::"text", ("c"."commission_month")::timestamp with time zone))::"date") DESC;


ALTER VIEW "public"."affiliate_monthly_performance" OWNER TO "postgres";


