CREATE OR REPLACE VIEW "public"."affiliate_pending_payments" WITH ("security_invoker"='true') AS
 SELECT "ar"."id" AS "referral_id",
    "ar"."affiliate_id",
    "a"."display_name" AS "affiliate_name",
    "ar"."referred_user_email",
    "ar"."signup_date",
    "ar"."signup_plan",
    "ar"."discount_percent",
    EXTRACT(day FROM ("now"() - "ar"."signup_date")) AS "days_since_signup"
   FROM ("public"."affiliate_referrals" "ar"
     JOIN "public"."affiliates" "a" ON (("ar"."affiliate_id" = "a"."id")))
  WHERE ("ar"."status" = 'pending'::"public"."referral_status")
  ORDER BY "ar"."signup_date" DESC;


