CREATE OR REPLACE VIEW "public"."affiliate_pending_verifications" WITH ("security_invoker"='true') AS
 SELECT "ar"."id",
    "ar"."affiliate_id",
    "a"."display_name" AS "affiliate_name",
    "ar"."referred_user_id",
    "ar"."referred_user_email",
    "ar"."first_payment_amount_usd",
    "ar"."first_payment_date",
    "ar"."verification_start",
    "ar"."verification_end",
    ("ar"."verification_end" - "now"()) AS "time_remaining",
    "ar"."subscription_plan",
    "ar"."subscription_type",
    "p"."is_in_trial",
    "p"."trial_ends_at",
        CASE
            WHEN (("p"."trial_ends_at" IS NOT NULL) AND ("p"."trial_ends_at" > "now"())) THEN (EXTRACT(day FROM ("p"."trial_ends_at" - "now"())))::integer
            ELSE 0
        END AS "trial_days_remaining",
        CASE
            WHEN ("ar"."first_payment_date" IS NULL) THEN 'awaiting_payment'::"text"
            WHEN ("ar"."verification_end" > "now"()) THEN 'verification_pending'::"text"
            ELSE 'ready_to_qualify'::"text"
        END AS "qualification_status"
   FROM (("public"."affiliate_referrals" "ar"
     JOIN "public"."affiliates" "a" ON (("ar"."affiliate_id" = "a"."id")))
     JOIN "public"."profiles" "p" ON (("ar"."referred_user_id" = "p"."id")))
  WHERE ("ar"."status" = ANY (ARRAY['pending'::"public"."referral_status", 'verification_pending'::"public"."referral_status"]))
  ORDER BY "ar"."verification_end";


