CREATE OR REPLACE VIEW "public"."archived_users_view" WITH ("security_invoker"='true') AS
 SELECT "pa"."id",
    "pa"."email",
    COALESCE("pa"."display_name", "split_part"("pa"."email", '@'::"text", 1)) AS "display_name",
    "pa"."account_type",
    "pa"."role",
    "pa"."subscription_status",
    "pa"."subscription_interval",
    "pa"."subscription_expires_at",
    "pa"."subscription_cancel_at_period_end",
    "pa"."is_banned",
    "pa"."ban_reason",
    "pa"."banned_at",
    "pa"."last_login_at",
    "pa"."login_count",
    "pa"."created_at",
    "pa"."updated_at",
    "pa"."current_portfolio",
    "pa"."initial_portfolio",
    "pa"."total_pnl",
    "pa"."trade_count",
    "pa"."current_month_trades_count",
    "pa"."max_trades",
    "pa"."portfolio_size",
    "pa"."risk_mode",
    "pa"."risk_percentage",
    "pa"."fixed_risk_amount",
    "pa"."deleted_at",
    "pa"."deleted_by",
    "pa"."archived_at",
    "pa"."archived_by",
    (EXTRACT(day FROM ("now"() - "pa"."archived_at")))::integer AS "days_in_archive",
    "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL)) AS "total_closed_trades",
        CASE
            WHEN ("count"(DISTINCT "t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL)) > 0) THEN "round"(((("count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'WIN'::"text")))::numeric * 100.0) / ("count"(DISTINCT "t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL)))::numeric), 2)
            ELSE (0)::numeric
        END AS "win_rate",
    "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'WIN'::"text")) AS "wins",
    "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'LOSS'::"text")) AS "losses",
    "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'BE'::"text")) AS "break_even",
    "count"(DISTINCT "t"."id") FILTER (WHERE ("t"."outcome" = 'OPEN'::"text")) AS "open_trades",
    "max"("t"."close_at") AS "last_trade_date",
    "round"("avg"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL)), 2) AS "avg_r",
    "max"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL)) AS "best_r",
    "min"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL)) AS "worst_r"
   FROM ("public"."profiles_archive" "pa"
     LEFT JOIN "public"."trades" "t" ON (("t"."user_id" = "pa"."id")))
  GROUP BY "pa"."id", "pa"."email", "pa"."display_name", "pa"."account_type", "pa"."role", "pa"."subscription_status", "pa"."subscription_interval", "pa"."subscription_expires_at", "pa"."subscription_cancel_at_period_end", "pa"."is_banned", "pa"."ban_reason", "pa"."banned_at", "pa"."last_login_at", "pa"."login_count", "pa"."created_at", "pa"."updated_at", "pa"."current_portfolio", "pa"."initial_portfolio", "pa"."total_pnl", "pa"."trade_count", "pa"."current_month_trades_count", "pa"."max_trades", "pa"."portfolio_size", "pa"."risk_mode", "pa"."risk_percentage", "pa"."fixed_risk_amount", "pa"."deleted_at", "pa"."deleted_by", "pa"."archived_at", "pa"."archived_by"
  ORDER BY "pa"."archived_at" DESC;


