CREATE OR REPLACE VIEW "public"."cancellation_analytics_view" WITH ("security_invoker"='true') AS
 SELECT "date_trunc"('month'::"text", "created_at") AS "month",
    "from_plan",
    "count"(*) AS "cancellation_count",
    "count"(*) FILTER (WHERE (("reason" ~~ '%price%'::"text") OR ("reason" ~~ '%expensive%'::"text"))) AS "price_related",
    "count"(*) FILTER (WHERE (("reason" ~~ '%feature%'::"text") OR ("reason" ~~ '%not using%'::"text"))) AS "feature_related",
    "count"(*) FILTER (WHERE (("reason" ~~ '%support%'::"text") OR ("reason" ~~ '%service%'::"text"))) AS "support_related",
    "count"(*) FILTER (WHERE (("reason" IS NULL) OR ("reason" = ''::"text"))) AS "no_reason_given",
    "round"("avg"(EXTRACT(day FROM ("effective_date" - ( SELECT "p"."created_at"
           FROM "public"."profiles" "p"
          WHERE ("p"."id" = "subscription_changes"."user_id"))))), 1) AS "avg_days_before_cancel"
   FROM "public"."subscription_changes"
  WHERE ("change_type" = 'cancel'::"text")
  GROUP BY ("date_trunc"('month'::"text", "created_at")), "from_plan"
  ORDER BY ("date_trunc"('month'::"text", "created_at")) DESC, "from_plan";


