CREATE OR REPLACE VIEW "public"."flow_scanner_health" AS
 SELECT ( SELECT "count"(*) AS "count"
           FROM "public"."flow_scanner_cache") AS "total_cached_items",
    ( SELECT "count"(*) AS "count"
           FROM "public"."flow_scanner_cache"
          WHERE ("flow_scanner_cache"."event_timestamp" > ("now"() - '01:00:00'::interval))) AS "items_last_hour",
    ( SELECT "flow_scanner_stats_cache"."computed_at"
           FROM "public"."flow_scanner_stats_cache"
          WHERE ("flow_scanner_stats_cache"."id" = 'current'::"text")) AS "last_stats_update",
    ( SELECT "flow_scanner_refresh_log"."status"
           FROM "public"."flow_scanner_refresh_log"
          ORDER BY "flow_scanner_refresh_log"."run_at" DESC
         LIMIT 1) AS "last_cron_status",
    ( SELECT "flow_scanner_refresh_log"."run_at"
           FROM "public"."flow_scanner_refresh_log"
          ORDER BY "flow_scanner_refresh_log"."run_at" DESC
         LIMIT 1) AS "last_cron_run";


ALTER VIEW "public"."flow_scanner_health" OWNER TO "postgres";


