    "amount" numeric(10,2) NOT NULL,
    "currency" "text" DEFAULT 'USD'::"text" NOT NULL,
    "status" "text" NOT NULL,
    "plan" "text" NOT NULL,
    "whop_transaction_id" "text",
    "invoice_url" "text",
    "payment_method" "text",
    "error_message" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "is_prorated" boolean DEFAULT false,
    "prorated_days" integer,
    "original_amount" numeric(10,2),
    "discount_amount" numeric(10,2) DEFAULT 0,
    "payment_type" "text" DEFAULT 'subscription'::"text",
    "payment_provider" "text",
    "transaction_id" "text",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb",
    CONSTRAINT "payment_history_plan_check" CHECK (("plan" = ANY (ARRAY['basic'::"text", 'premium'::"text"]))),
    CONSTRAINT "payment_history_provider_check" CHECK ((("payment_provider" = ANY (ARRAY['whop'::"text", 'stripe'::"text", 'paypal'::"text"])) OR ("payment_provider" IS NULL))),
    CONSTRAINT "payment_history_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'completed'::"text", 'failed'::"text", 'refunded'::"text"]))),
    CONSTRAINT "payment_type_check" CHECK (("payment_type" = ANY (ARRAY['subscription'::"text", 'upgrade'::"text", 'renewal'::"text", 'refund'::"text"])))
);


ALTER TABLE "public"."payment_history" OWNER TO "postgres";


COMMENT ON TABLE "public"."payment_history" IS 'Stores all payment transactions for audit and invoicing';



COMMENT ON COLUMN "public"."payment_history"."whop_transaction_id" IS 'v9.4.4: Whop-specific transaction ID';



COMMENT ON COLUMN "public"."payment_history"."is_prorated" IS 'TRUE if this payment was prorated (mid-cycle upgrade)';



COMMENT ON COLUMN "public"."payment_history"."prorated_days" IS 'Number of days remaining in billing cycle at time of upgrade';



COMMENT ON COLUMN "public"."payment_history"."original_amount" IS 'Original full price before proration discount';



COMMENT ON COLUMN "public"."payment_history"."discount_amount" IS 'Discount applied due to proration';



COMMENT ON COLUMN "public"."payment_history"."payment_type" IS 'Type: subscription (new), upgrade, renewal, refund';



COMMENT ON COLUMN "public"."payment_history"."payment_provider" IS 'v9.4.4: Payment provider used for this transaction (whop, stripe, paypal)';



COMMENT ON COLUMN "public"."payment_history"."transaction_id" IS 'v9.4.4: Generic transaction ID';



COMMENT ON COLUMN "public"."payment_history"."metadata" IS 'v9.4.3: Additional payment metadata as JSON';



CREATE OR REPLACE VIEW "public"."payment_analytics" WITH ("security_invoker"='true') AS
 SELECT "plan",
    "status",
    "count"(*) AS "payment_count",
    "sum"("amount") AS "total_amount",
    "avg"("amount") AS "avg_amount",
    "date_trunc"('month'::"text", "created_at") AS "month"
   FROM "public"."payment_history"
  GROUP BY "plan", "status", ("date_trunc"('month'::"text", "created_at"))
  ORDER BY ("date_trunc"('month'::"text", "created_at")) DESC, "plan", "status";


ALTER VIEW "public"."payment_analytics" OWNER TO "postgres";


COMMENT ON VIEW "public"."payment_analytics" IS 'Payment statistics grouped by plan, status, and month';



