    19.99 AS "monthly_equivalent"
UNION ALL
 SELECT 'basic'::"text" AS "plan",
    'yearly'::"text" AS "interval",
    149.00 AS "price",
    12.42 AS "monthly_equivalent"
UNION ALL
 SELECT 'premium'::"text" AS "plan",
    'monthly'::"text" AS "interval",
    39.99 AS "price",
    39.99 AS "monthly_equivalent"
UNION ALL
