CREATE OR REPLACE VIEW "public"."proration_impact_view" WITH ("security_invoker"='true') AS
 SELECT "date_trunc"('month'::"text", "created_at") AS "month",
    "count"(*) FILTER (WHERE ("is_prorated" = true)) AS "prorated_count",
    "count"(*) AS "total_upgrades",
    "round"(((("count"(*) FILTER (WHERE ("is_prorated" = true)))::numeric / (NULLIF("count"(*), 0))::numeric) * (100)::numeric), 1) AS "proration_percentage",
    "round"("sum"("discount_amount") FILTER (WHERE ("is_prorated" = true)), 2) AS "total_discounts_given",
    "round"("avg"("prorated_days") FILTER (WHERE ("is_prorated" = true)), 1) AS "avg_days_remaining",
    "round"("avg"("discount_amount") FILTER (WHERE ("is_prorated" = true)), 2) AS "avg_discount_per_upgrade"
   FROM "public"."payment_history"
  WHERE ("payment_type" = 'upgrade'::"text")
  GROUP BY ("date_trunc"('month'::"text", "created_at"))
  ORDER BY ("date_trunc"('month'::"text", "created_at")) DESC;


ALTER VIEW "public"."proration_impact_view" OWNER TO "postgres";


COMMENT ON VIEW "public"."proration_impact_view" IS '📉 Analysis of proration impact on revenue and customer satisfaction';



