CREATE OR REPLACE VIEW "public"."revenue_analytics_view" WITH ("security_invoker"='true') AS
 WITH "monthly_revenue" AS (
         SELECT "date_trunc"('month'::"text", "payment_history"."created_at") AS "month",
            "payment_history"."payment_type",
            "payment_history"."plan",
            "count"(*) AS "transaction_count",
            "sum"("payment_history"."amount") AS "total_amount",
            "avg"("payment_history"."amount") AS "avg_amount",
            "sum"("payment_history"."discount_amount") AS "total_discounts"
           FROM "public"."payment_history"
          WHERE ("payment_history"."status" = 'completed'::"text")
          GROUP BY ("date_trunc"('month'::"text", "payment_history"."created_at")), "payment_history"."payment_type", "payment_history"."plan"
        )
 SELECT "month",
    "payment_type",
    "plan",
    "transaction_count",
    "round"("total_amount", 2) AS "total_revenue",
    "round"("avg_amount", 2) AS "avg_transaction",
    "round"("total_discounts", 2) AS "total_discounts",
    "round"(("total_amount" - "total_discounts"), 2) AS "net_revenue"
   FROM "monthly_revenue"
  ORDER BY "month" DESC, "payment_type", "plan";


ALTER VIEW "public"."revenue_analytics_view" OWNER TO "postgres";


COMMENT ON VIEW "public"."revenue_analytics_view" IS '💰 Monthly revenue breakdown by payment type and plan';



