CREATE OR REPLACE VIEW "public"."session_performance_view" WITH ("security_invoker"='true') AS
 SELECT "t"."user_id",
    "t"."session",
    "count"(*) FILTER (WHERE ("t"."exit_price" IS NOT NULL)) AS "total_trades",
    "count"(*) FILTER (WHERE ("t"."outcome" = 'WIN'::"text")) AS "wins",
    "count"(*) FILTER (WHERE ("t"."outcome" = 'LOSS'::"text")) AS "losses",
    "count"(*) FILTER (WHERE ("t"."outcome" = 'BE'::"text")) AS "break_even",
    "count"(*) FILTER (WHERE ("t"."outcome" = 'OPEN'::"text")) AS "open_trades",
        CASE
            WHEN ("count"(*) FILTER (WHERE ("t"."exit_price" IS NOT NULL)) > 0) THEN "round"(((("count"(*) FILTER (WHERE ("t"."outcome" = 'WIN'::"text")))::numeric / ("count"(*) FILTER (WHERE ("t"."exit_price" IS NOT NULL)))::numeric) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS "win_rate",
    COALESCE("sum"("t"."pnl") FILTER (WHERE ("t"."exit_price" IS NOT NULL)), (0)::numeric) AS "total_pnl",
    COALESCE("avg"("t"."pnl") FILTER (WHERE ("t"."outcome" = 'WIN'::"text")), (0)::numeric) AS "avg_win",
    COALESCE("avg"("t"."pnl") FILTER (WHERE ("t"."outcome" = 'LOSS'::"text")), (0)::numeric) AS "avg_loss",
    COALESCE("max"("t"."pnl"), (0)::numeric) AS "best_trade",
    COALESCE("min"("t"."pnl"), (0)::numeric) AS "worst_trade",
    COALESCE("avg"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL)), (0)::numeric) AS "avg_r",
    COALESCE("sum"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL)), (0)::numeric) AS "total_r",
    "ts"."description" AS "session_description",
    "ts"."color" AS "session_color",
    "ts"."start_hour_ny",
    "ts"."end_hour_ny"
   FROM ("public"."trades" "t"
     LEFT JOIN "public"."trading_sessions" "ts" ON (("ts"."session_name" = "t"."session")))
  WHERE ("t"."deleted_at" IS NULL)
  GROUP BY "t"."user_id", "t"."session", "ts"."description", "ts"."color", "ts"."start_hour_ny", "ts"."end_hour_ny"
  ORDER BY COALESCE("sum"("t"."pnl") FILTER (WHERE ("t"."exit_price" IS NOT NULL)), (0)::numeric) DESC;


ALTER VIEW "public"."session_performance_view" OWNER TO "postgres";


COMMENT ON VIEW "public"."session_performance_view" IS 'v8.5.2: Trading performance statistics grouped by session';



