    "sync_started_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "sync_completed_at" timestamp with time zone,
    "duration_seconds" integer GENERATED ALWAYS AS ((EXTRACT(epoch FROM ("sync_completed_at" - "sync_started_at")))::integer) STORED,
    "trades_imported" integer DEFAULT 0,
    "trades_skipped" integer DEFAULT 0,
    "trades_failed" integer DEFAULT 0,
    "sync_type" "text" DEFAULT 'manual'::"text",
    "date_range_start" "date",
    "date_range_end" "date",
    "status" "text" DEFAULT 'running'::"text" NOT NULL,
    "error_message" "text",
    "error_details" "jsonb",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "check_completed_status" CHECK (((("status" = 'running'::"text") AND ("sync_completed_at" IS NULL)) OR (("status" <> 'running'::"text") AND ("sync_completed_at" IS NOT NULL)))),
    CONSTRAINT "check_sync_status" CHECK (("status" = ANY (ARRAY['running'::"text", 'completed'::"text", 'failed'::"text", 'cancelled'::"text"]))),
    CONSTRAINT "check_sync_type" CHECK (("sync_type" = ANY (ARRAY['manual'::"text", 'automatic'::"text", 'scheduled'::"text"])))
);


