CREATE MATERIALIZED VIEW "public"."strategy_stats_view" AS
 SELECT "s"."id",
    "s"."user_id",
    "s"."name",
    "s"."status",
    "s"."category",
    "s"."setup_type",
    "s"."default_stop_loss",
    "s"."default_take_profit",
    "s"."created_at",
    "s"."updated_at",
    "count"("t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL)) AS "total_trades",
    "count"("t"."id") FILTER (WHERE ("t"."outcome" = 'WIN'::"text")) AS "wins",
    "count"("t"."id") FILTER (WHERE ("t"."outcome" = 'LOSS'::"text")) AS "losses",
    "count"("t"."id") FILTER (WHERE ("t"."outcome" = 'BE'::"text")) AS "break_even",
    "count"("t"."id") FILTER (WHERE ("t"."outcome" = 'OPEN'::"text")) AS "open_trades",
        CASE
            WHEN ("count"("t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL)) > 0) THEN "round"(((("count"("t"."id") FILTER (WHERE ("t"."outcome" = 'WIN'::"text")))::numeric / ("count"("t"."id") FILTER (WHERE ("t"."exit_price" IS NOT NULL)))::numeric) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS "win_rate",
    COALESCE("sum"("t"."pnl") FILTER (WHERE ("t"."exit_price" IS NOT NULL)), (0)::numeric) AS "total_pnl",
    COALESCE("avg"("t"."pnl") FILTER (WHERE ("t"."outcome" = 'WIN'::"text")), (0)::numeric) AS "avg_win",
    COALESCE("avg"("t"."pnl") FILTER (WHERE ("t"."outcome" = 'LOSS'::"text")), (0)::numeric) AS "avg_loss",
    COALESCE("max"("t"."pnl"), (0)::numeric) AS "best_trade",
    COALESCE("min"("t"."pnl"), (0)::numeric) AS "worst_trade",
    COALESCE("avg"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL)), (0)::numeric) AS "avg_r",
    COALESCE("sum"("t"."actual_r") FILTER (WHERE ("t"."actual_r" IS NOT NULL)), (0)::numeric) AS "total_r",
    COALESCE("max"("t"."actual_r"), (0)::numeric) AS "best_r",
    COALESCE("min"("t"."actual_r"), (0)::numeric) AS "worst_r",
        CASE
            WHEN ("abs"("sum"("t"."pnl") FILTER (WHERE ("t"."outcome" = 'LOSS'::"text"))) > (0)::numeric) THEN "round"("abs"(("sum"("t"."pnl") FILTER (WHERE ("t"."outcome" = 'WIN'::"text")) / "sum"("t"."pnl") FILTER (WHERE ("t"."outcome" = 'LOSS'::"text")))), 2)
            ELSE (0)::numeric
        END AS "profit_factor",
    "max"("t"."close_at") AS "last_trade_date"
   FROM ("public"."strategies" "s"
     LEFT JOIN "public"."trades" "t" ON (("t"."strategy_id" = "s"."id")))
  GROUP BY "s"."id", "s"."user_id", "s"."name", "s"."status", "s"."category", "s"."setup_type", "s"."default_stop_loss", "s"."default_take_profit", "s"."created_at", "s"."updated_at"
  WITH NO DATA;


