CREATE OR REPLACE VIEW "public"."subscription_flow_view" WITH ("security_invoker"='true') AS
 SELECT "date_trunc"('week'::"text", "created_at") AS "week",
    "change_type",
    "from_plan",
    "to_plan",
    "count"(*) AS "change_count",
    "avg"("prorated_days") FILTER (WHERE ("change_type" = 'upgrade'::"text")) AS "avg_prorated_days",
    "avg"("prorated_amount") FILTER (WHERE ("change_type" = 'upgrade'::"text")) AS "avg_prorated_amount",
        CASE
            WHEN ("change_type" = 'upgrade'::"text") THEN "sum"("prorated_amount")
            ELSE (0)::numeric
        END AS "total_revenue_impact"
   FROM "public"."subscription_changes"
  WHERE ("change_type" = ANY (ARRAY['upgrade'::"text", 'downgrade'::"text", 'cancel'::"text", 'reactivate'::"text"]))
  GROUP BY ("date_trunc"('week'::"text", "created_at")), "change_type", "from_plan", "to_plan"
  ORDER BY ("date_trunc"('week'::"text", "created_at")) DESC, "change_type", "from_plan";


