CREATE OR REPLACE VIEW "public"."subscription_health_view" WITH ("security_invoker"='true') AS
 SELECT
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "id"
            ELSE NULL::"uuid"
        END AS "user_id",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "email"
            ELSE NULL::"text"
        END AS "email",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "display_name"
            ELSE NULL::"text"
        END AS "display_name",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "account_type"
            ELSE NULL::"text"
        END AS "account_type",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "subscription_interval"
            ELSE NULL::"text"
        END AS "subscription_interval",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "subscription_status"
            ELSE NULL::"text"
        END AS "subscription_status",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "subscription_expires_at"
            ELSE NULL::timestamp with time zone
        END AS "subscription_expires_at",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "subscription_cancel_at_period_end"
            ELSE NULL::boolean
        END AS "subscription_cancel_at_period_end",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "cancellation_requested_at"
            ELSE NULL::timestamp with time zone
        END AS "cancellation_requested_at",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN "cancellation_effective_date"
            ELSE NULL::timestamp with time zone
        END AS "cancellation_effective_date",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN
            CASE
                WHEN ("subscription_expires_at" IS NULL) THEN NULL::integer
                ELSE (EXTRACT(day FROM ("subscription_expires_at" - "now"())))::integer
            END
            ELSE NULL::integer
        END AS "days_remaining",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN
            CASE
                WHEN ("account_type" = 'free'::"text") THEN 'free'::"text"
                WHEN ("subscription_status" = 'cancelled'::"text") THEN 'cancelled'::"text"
                WHEN ("subscription_cancel_at_period_end" = true) THEN 'cancelling_at_period_end'::"text"
                WHEN ("subscription_expires_at" < "now"()) THEN 'expired'::"text"
                WHEN ("subscription_expires_at" < ("now"() + '7 days'::interval)) THEN 'expiring_soon'::"text"
                WHEN ("subscription_expires_at" < ("now"() + '14 days'::interval)) THEN 'active_expiring'::"text"
                ELSE 'active_healthy'::"text"
            END
            ELSE NULL::"text"
        END AS "health_status",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN ( SELECT "ph"."created_at"
               FROM "public"."payment_history" "ph"
              WHERE (("ph"."user_id" = "p"."id") AND ("ph"."status" = 'completed'::"text"))
              ORDER BY "ph"."created_at" DESC
             LIMIT 1)
            ELSE NULL::timestamp with time zone
        END AS "last_payment_date",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN ( SELECT "ph"."amount"
               FROM "public"."payment_history" "ph"
              WHERE (("ph"."user_id" = "p"."id") AND ("ph"."status" = 'completed'::"text"))
              ORDER BY "ph"."created_at" DESC
             LIMIT 1)
            ELSE NULL::numeric
        END AS "last_payment_amount",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN ( SELECT COALESCE("sum"("ph"."amount"), (0)::numeric) AS "coalesce"
               FROM "public"."payment_history" "ph"
              WHERE (("ph"."user_id" = "p"."id") AND ("ph"."status" = 'completed'::"text")))
            ELSE NULL::numeric
        END AS "lifetime_value",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN ( SELECT "count"(*) AS "count"
               FROM "public"."subscription_changes" "sc"
              WHERE (("sc"."user_id" = "p"."id") AND ("sc"."change_type" = 'renew'::"text")))
            ELSE NULL::bigint
        END AS "renewal_count",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN ( SELECT "sp"."period_start"
               FROM "public"."subscription_periods" "sp"
              WHERE (("sp"."user_id" = "p"."id") AND ("sp"."period_end" > "now"()))
              ORDER BY "sp"."period_end" DESC
             LIMIT 1)
            ELSE NULL::timestamp with time zone
        END AS "current_period_start",
        CASE
            WHEN ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
               FROM "public"."profiles"
              WHERE ("profiles"."id" = "auth"."uid"())) THEN ( SELECT "sp"."auto_renew"
               FROM "public"."subscription_periods" "sp"
              WHERE (("sp"."user_id" = "p"."id") AND ("sp"."period_end" > "now"()))
              ORDER BY "sp"."period_end" DESC
             LIMIT 1)
            ELSE NULL::boolean
        END AS "auto_renew_enabled"
   FROM "public"."profiles" "p"
  WHERE (("deleted_at" IS NULL) AND ( SELECT ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))
           FROM "public"."profiles"
          WHERE ("profiles"."id" = "auth"."uid"())))
  ORDER BY
        CASE "subscription_status"
            WHEN 'active'::"text" THEN 1
            WHEN 'cancelled'::"text" THEN 2
            WHEN 'expired'::"text" THEN 3
            ELSE 4
        END, "p"."subscription_expires_at";


