CREATE OR REPLACE VIEW "public"."upcoming_holidays" WITH ("security_invoker"='true') AS
 SELECT "date",
    "name",
    "type",
    "close_time",
        CASE EXTRACT(dow FROM "date")
            WHEN 0 THEN 'Sunday'::"text"
            WHEN 1 THEN 'Monday'::"text"
            WHEN 2 THEN 'Tuesday'::"text"
            WHEN 3 THEN 'Wednesday'::"text"
            WHEN 4 THEN 'Thursday'::"text"
            WHEN 5 THEN 'Friday'::"text"
            WHEN 6 THEN 'Saturday'::"text"
            ELSE NULL::"text"
        END AS "day_name",
    ("date" - CURRENT_DATE) AS "days_until",
    "year"
   FROM "public"."us_market_holidays"
  WHERE ("date" >= CURRENT_DATE)
  ORDER BY "date"
 LIMIT 30;


