CREATE OR REPLACE VIEW "public"."v_catalyst_type_performance" WITH ("security_invoker"='true') AS
 SELECT "catalyst_type",
    "count"(*) AS "total_picks",
    "count"(*) FILTER (WHERE ("current_return_pct" > (0)::numeric)) AS "winning_picks",
    "round"(((("count"(*) FILTER (WHERE ("current_return_pct" > (0)::numeric)))::numeric / (NULLIF("count"(*), 0))::numeric) * (100)::numeric), 1) AS "win_rate",
    "round"("avg"("current_return_pct"), 2) AS "avg_return",
    "round"("avg"("max_return_pct"), 2) AS "avg_max_return",
    "round"("avg"("min_return_pct"), 2) AS "avg_max_drawdown",
    "round"("avg"("overall_score"), 1) AS "avg_score",
    "round"("avg"("finotaur_score"), 1) AS "avg_finotaur_score",
    "count"(*) FILTER (WHERE "hit_target_1") AS "target_1_hits",
    "count"(*) FILTER (WHERE "hit_target_2") AS "target_2_hits",
    "count"(*) FILTER (WHERE "hit_stop_loss") AS "stop_loss_hits",
    "mode"() WITHIN GROUP (ORDER BY "ai_performance_grade") AS "most_common_grade",
    "max"("pick_date") AS "latest_pick_date"
   FROM "public"."pick_tracking"
  WHERE (("catalyst_type" IS NOT NULL) AND ("status" <> 'active'::"text"))
  GROUP BY "catalyst_type"
  ORDER BY ("round"(((("count"(*) FILTER (WHERE ("current_return_pct" > (0)::numeric)))::numeric / (NULLIF("count"(*), 0))::numeric) * (100)::numeric), 1)) DESC NULLS LAST, ("count"(*)) DESC;


ALTER VIEW "public"."v_catalyst_type_performance" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_copy_log_summary" WITH ("security_invoker"='true') AS
 SELECT "user_id",
    "copy_rule_id",
    "count"(*) AS "total_actions",
    "count"(*) FILTER (WHERE ("action" = ANY (ARRAY['open'::"text", 'close'::"text"]))) AS "success_count",
    "count"(*) FILTER (WHERE ("action" = 'skipped'::"text")) AS "skipped_count",
    "count"(*) FILTER (WHERE ("action" = 'error'::"text")) AS "failed_count",
    COALESCE("sum"("copied_qty"), (0)::bigint) AS "total_contracts_copied",
    "max"("created_at") AS "last_action_at"
   FROM "public"."copy_trade_log"
  GROUP BY "user_id", "copy_rule_id";


ALTER VIEW "public"."v_copy_log_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_current_macro_guidance" WITH ("security_invoker"='true') AS
 SELECT "sector_id",
    "sector_name",
    "sector_etf",
    "stance",
    "conviction",
    "regime",
    "regime_label",
    "primary_driver",
    "primary_driver_value",
    "reversal_trigger",
    "ism_snapshot",
    "source_report_month",
    "effective_date",
    "updated_at"
   FROM "public"."macro_sector_guidance"
  WHERE ("is_current" = true)
  ORDER BY
        CASE "stance"
            WHEN 'overweight'::"text" THEN 1
            WHEN 'neutral'::"text" THEN 2
            WHEN 'underweight'::"text" THEN 3
            WHEN 'avoid'::"text" THEN 4
            ELSE NULL::integer
        END, "conviction" DESC;


ALTER VIEW "public"."v_current_macro_guidance" OWNER TO "postgres";


