    "drastic_move_catalysts",
    "trade_type",
    "direction",
    "risk_level",
    "highlight_1" AS "catalyst",
    "highlight_1",
    "highlight_2"
   FROM "public"."earnings_reports"
  WHERE ("drastic_move_potential" >= 70)
  ORDER BY "drastic_move_potential" DESC;


ALTER VIEW "public"."v_drastic_movers" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_finotaur_calibration" WITH ("security_invoker"='true') AS
 SELECT
        CASE
            WHEN ("finotaur_score" >= 90) THEN '90-100'::"text"
            WHEN ("finotaur_score" >= 75) THEN '75-89'::"text"
            WHEN ("finotaur_score" >= 60) THEN '60-74'::"text"
            WHEN ("finotaur_score" >= 40) THEN '40-59'::"text"
            ELSE '0-39'::"text"
        END AS "score_bucket",
    "count"(*) AS "total",
    "round"("avg"("current_return_pct"), 2) AS "avg_return",
    "round"("avg"("max_return_pct"), 2) AS "avg_max_gain",
    "round"("avg"("min_return_pct"), 2) AS "avg_max_dd",
    "round"(((100.0 * ("count"(*) FILTER (WHERE ("current_return_pct" > (0)::numeric)))::numeric) / (NULLIF("count"(*), 0))::numeric), 1) AS "win_rate",
    "round"(((100.0 * ("count"(*) FILTER (WHERE "hit_target_1"))::numeric) / (NULLIF("count"(*), 0))::numeric), 1) AS "target_1_hit_rate"
   FROM "public"."pick_tracking"
  WHERE ("tracking_days" >= 14)
  GROUP BY
        CASE
