            WHEN ("finotaur_score" >= 40) THEN '40-59'::"text"
            ELSE '0-39'::"text"
        END
  ORDER BY
        CASE
            WHEN ("finotaur_score" >= 90) THEN '90-100'::"text"
            WHEN ("finotaur_score" >= 75) THEN '75-89'::"text"
            WHEN ("finotaur_score" >= 60) THEN '60-74'::"text"
            WHEN ("finotaur_score" >= 40) THEN '40-59'::"text"
            ELSE '0-39'::"text"
        END DESC;


