CREATE OR REPLACE VIEW "public"."v_pattern_matrix" WITH ("security_invoker"='true') AS
 SELECT COALESCE("inflection_stage", 'N/A'::"text") AS "inflection_stage",
    COALESCE("catalyst_type", 'unknown'::"text") AS "catalyst_type",
    "count"(*) AS "total",
    "round"("avg"("current_return_pct"), 2) AS "avg_return",
    "round"(((100.0 * ("count"(*) FILTER (WHERE ("current_return_pct" > (0)::numeric)))::numeric) / (NULLIF("count"(*), 0))::numeric), 1) AS "win_rate",
    "count"(*) FILTER (WHERE ("current_return_pct" > (10)::numeric)) AS "big_wins",
    "round"("avg"("max_return_pct"), 2) AS "avg_max_gain"
   FROM "public"."pick_tracking"
  WHERE ("tracking_days" >= 5)
  GROUP BY "inflection_stage", "catalyst_type"
 HAVING ("count"(*) >= 2)
  ORDER BY ("round"("avg"("current_return_pct"), 2)) DESC;


ALTER VIEW "public"."v_pattern_matrix" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_report_interaction_counts" WITH ("security_invoker"='true') AS
 SELECT "pr"."id" AS "report_id",
    "pr"."title",
    "pr"."report_type",
    COALESCE("likes"."count", (0)::bigint) AS "likes_count",
    COALESCE("bookmarks"."count", (0)::bigint) AS "bookmarks_count"
   FROM (("public"."published_reports" "pr"
     LEFT JOIN ( SELECT "report_likes"."report_id",
            "count"(*) AS "count"
           FROM "public"."report_likes"
          GROUP BY "report_likes"."report_id") "likes" ON (("pr"."id" = "likes"."report_id")))
     LEFT JOIN ( SELECT "report_bookmarks"."report_id",
            "count"(*) AS "count"
           FROM "public"."report_bookmarks"
          GROUP BY "report_bookmarks"."report_id") "bookmarks" ON (("pr"."id" = "bookmarks"."report_id")));


ALTER VIEW "public"."v_report_interaction_counts" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_score_vs_performance" WITH ("security_invoker"='true') AS
 SELECT
        CASE
            WHEN ("overall_score" >= 90) THEN '90-100'::"text"
            WHEN ("overall_score" >= 80) THEN '80-89'::"text"
            WHEN ("overall_score" >= 70) THEN '70-79'::"text"
            WHEN ("overall_score" >= 60) THEN '60-69'::"text"
            ELSE 'Below 60'::"text"
        END AS "score_range",
    "count"(*) AS "total_picks",
    "count"(*) FILTER (WHERE ("current_return_pct" > (0)::numeric)) AS "winning_picks",
    "round"(((("count"(*) FILTER (WHERE ("current_return_pct" > (0)::numeric)))::numeric / (NULLIF("count"(*), 0))::numeric) * (100)::numeric), 1) AS "win_rate",
    "round"("avg"("current_return_pct"), 2) AS "avg_return",
    "round"("avg"("max_return_pct"), 2) AS "avg_max_return",
    "round"(("percentile_cont"((0.5)::double precision) WITHIN GROUP (ORDER BY (("current_return_pct")::double precision)))::numeric, 2) AS "median_return",
    "round"("avg"("finotaur_score"), 1) AS "avg_finotaur_score",
    "count"(*) FILTER (WHERE "hit_target_1") AS "target_1_hits",
    "count"(*) FILTER (WHERE "hit_target_2") AS "target_2_hits"
   FROM "public"."pick_tracking"
  WHERE ("status" <> 'active'::"text")
  GROUP BY
        CASE
            WHEN ("overall_score" >= 90) THEN '90-100'::"text"
            WHEN ("overall_score" >= 80) THEN '80-89'::"text"
            WHEN ("overall_score" >= 70) THEN '70-79'::"text"
            WHEN ("overall_score" >= 60) THEN '60-69'::"text"
            ELSE 'Below 60'::"text"
        END
  ORDER BY
        CASE
            WHEN ("overall_score" >= 90) THEN '90-100'::"text"
            WHEN ("overall_score" >= 80) THEN '80-89'::"text"
            WHEN ("overall_score" >= 70) THEN '70-79'::"text"
            WHEN ("overall_score" >= 60) THEN '60-69'::"text"
            ELSE 'Below 60'::"text"
        END DESC;


ALTER VIEW "public"."v_score_vs_performance" OWNER TO "postgres";


