CREATE OR REPLACE VIEW "public"."v_signal_accuracy" WITH ("security_invoker"='true') AS
 SELECT "x"."key" AS "signal_name",
    "count"(*) AS "total_evaluations",
    "count"(*) FILTER (WHERE ((("x"."value" ->> 'accurate'::"text"))::boolean = true)) AS "accurate_count",
    "round"(((100.0 * ("count"(*) FILTER (WHERE ((("x"."value" ->> 'accurate'::"text"))::boolean = true)))::numeric) / (NULLIF("count"(*), 0))::numeric), 1) AS "accuracy_pct",
    "round"("avg"((("x"."value" ->> 'predicted'::"text"))::numeric), 1) AS "avg_predicted_score"
   FROM "public"."performance_insights",
    LATERAL "jsonb_each"("performance_insights"."signal_accuracy") "x"("key", "value")
  WHERE ("performance_insights"."signal_accuracy" <> '{}'::"jsonb")
  GROUP BY "x"."key"
  ORDER BY ("round"(((100.0 * ("count"(*) FILTER (WHERE ((("x"."value" ->> 'accurate'::"text"))::boolean = true)))::numeric) / (NULLIF("count"(*), 0))::numeric), 1)) DESC;


