CREATE MATERIALIZED VIEW "public"."webhook_stats" AS
 SELECT "user_id",
    "count"(*) AS "total_trades",
    "count"(*) FILTER (WHERE ("broker" = 'tradingview'::"text")) AS "tradingview_trades",
    "count"(*) FILTER (WHERE (("broker" = 'tradingview'::"text") AND ("close_at" IS NULL))) AS "open_tradingview_trades",
    "count"(*) FILTER (WHERE (("broker" = 'tradingview'::"text") AND ("close_at" IS NOT NULL))) AS "closed_tradingview_trades",
    "max"("open_at") FILTER (WHERE ("broker" = 'tradingview'::"text")) AS "last_tradingview_trade_at",
    "max"("created_at") AS "last_trade_created_at"
   FROM "public"."trades"
  WHERE ("broker" = 'tradingview'::"text")
  GROUP BY "user_id"
  WITH NO DATA;


ALTER MATERIALIZED VIEW "public"."webhook_stats" OWNER TO "postgres";


COMMENT ON MATERIALIZED VIEW "public"."webhook_stats" IS 'Aggregated statistics for TradingView webhooks per user. Refresh hourly or on-demand.';



