CREATE TABLE IF NOT EXISTS "public"."weekly_reports" (
    "id" "text" NOT NULL,
    "report_date" "date" NOT NULL,
    "report_title" "text" DEFAULT 'Weekly Tactical Review'::"text",
    "sections" "jsonb",
