CREATE POLICY "Admin access to webhook log" ON "public"."whop_webhook_log" USING ((EXISTS ( SELECT 1
   FROM "public"."profiles"
  WHERE (("profiles"."id" = "auth"."uid"()) AND ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))))));



CREATE POLICY "Admin full access to plan mapping" ON "public"."whop_plan_mapping" USING ((EXISTS ( SELECT 1
   FROM "public"."profiles"
  WHERE (("profiles"."id" = "auth"."uid"()) AND ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))))));



CREATE POLICY "Admins can manage newsletter config" ON "public"."newsletter_config" USING ((EXISTS ( SELECT 1
   FROM "public"."profiles"
  WHERE (("profiles"."id" = "auth"."uid"()) AND ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))))));



CREATE POLICY "Admins can read newsletter config" ON "public"."newsletter_config" FOR SELECT USING ((EXISTS ( SELECT 1
   FROM "public"."profiles"
  WHERE (("profiles"."id" = "auth"."uid"()) AND ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))))));



CREATE POLICY "Admins can read newsletter send logs" ON "public"."newsletter_send_logs" FOR SELECT USING ((EXISTS ( SELECT 1
   FROM "public"."profiles"
  WHERE (("profiles"."id" = "auth"."uid"()) AND ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))))));



CREATE POLICY "Admins can update newsletter config" ON "public"."newsletter_config" FOR UPDATE USING ((EXISTS ( SELECT 1
   FROM "public"."profiles"
  WHERE (("profiles"."id" = "auth"."uid"()) AND ("profiles"."role" = ANY (ARRAY['admin'::"text", 'super_admin'::"text"]))))));



CREATE POLICY "Affiliates can view own clicks" ON "public"."affiliate_clicks" FOR SELECT USING ((EXISTS ( SELECT 1
   FROM "public"."affiliates"
  WHERE (("affiliates"."id" = "affiliate_clicks"."affiliate_id") AND ("affiliates"."user_id" = "auth"."uid"())))));



CREATE POLICY "Public can insert clicks" ON "public"."affiliate_clicks" FOR INSERT WITH CHECK (true);



CREATE POLICY "Public can read active plan mapping" ON "public"."whop_plan_mapping" FOR SELECT USING (("is_active" = true));



CREATE POLICY "Service role access to webhook log" ON "public"."whop_webhook_log" USING (("auth"."role"() = 'service_role'::"text"));



CREATE POLICY "Service role can insert clicks" ON "public"."affiliate_clicks" FOR INSERT WITH CHECK (true);



CREATE POLICY "Service role can insert newsletter send logs" ON "public"."newsletter_send_logs" FOR INSERT WITH CHECK (true);



CREATE POLICY "Service role can manage subscription events" ON "public"."subscription_events" USING (true);



CREATE POLICY "Service role full access" ON "public"."newsletter_cron_logs" USING (true);



CREATE POLICY "Service role full access" ON "public"."newsletter_send_logs" USING (true) WITH CHECK (true);



CREATE POLICY "Service role full access to newsletter config" ON "public"."newsletter_config" USING (("auth"."role"() = 'service_role'::"text"));



CREATE POLICY "Service role full access to newsletter send logs" ON "public"."newsletter_send_logs" USING (("auth"."role"() = 'service_role'::"text"));



CREATE POLICY "Service role full access to reports" ON "public"."newsletter_reports" USING (("auth"."role"() = 'service_role'::"text"));



